export function localizedAgentGuidesPartF(en: Guides): Partial<Record<LandingLocaleCode, Guides>> {
  return {
    'es': {
      'claude-code': {
        ...en['claude-code']!,
        title: "Claude Code para diseño — Open Design",
        description: "Cómo los diseñadores usan Claude Code para diseño de UI y web, y cómo Open Design lo convierte en un verdadero agente de diseño — local-first, BYOK, con una biblioteca curada de skills y sistemas de diseño.",
        breadcrumb: "Claude Code",
        label: "Agente · Claude Code",
        heading: "Claude Code para diseño.",
        lead: "Claude Code es el agente de codificación de terminal de Anthropic. La gente ya lo usa para construir interfaces, sistemas de diseño y landing pages. Open Design lo conecta a un flujo de trabajo de diseño real — usa tu clave de Anthropic o tu suscripción a Claude y mantén cada archivo en local.",
        rich: {"heroCtaLead": "Open Design convierte Claude Code en un agente de diseño open-source y local-first — tu clave de Anthropic o tu suscripción a Claude, tus archivos y una biblioteca curada de skills y sistemas de diseño a su alrededor.", "heroCtaActions": [{"label": "Usa Claude Code dentro de Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dale una estrella en GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Descarga la aplicación de escritorio", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Claude Code es ampliamente considerado el agente de codificación con mejor gusto para el frontend — razona sobre las interfaces con una especificidad inusual, nombrando valores hex exactos, espaciados y escalas tipográficas, y refactoriza la UI a lo largo de una base de código grande sin perder el hilo. Pero, listo para usar, sigue derivando hacia un aspecto genérico a menos que le entregues un sistema de diseño, skills y referencias reales. Esta es una guía práctica y de extremo a extremo para usar Claude Code en trabajo de UI, frontend y sistemas de diseño, y para integrarlo en un flujo de trabajo estructurado con Open Design.", "Cubre qué es realmente Claude Code, por qué es fuerte en frontend, cómo configurarlo desde cero, el flujo de trabajo de CLAUDE.md y Skills, el round-trip oficial con Figma, cómo se compara con Codex y Cursor, los escollos que hacen que el resultado de la IA parezca genérico y cómo Open Design cierra esa brecha como una capa de diseño abierta y local-first."], "heroImage": {"src": "/agents/claude-code-design/claude-code-design-hero.webp", "alt": "Bucle de retroalimentación de diseño de Claude Code: un agente de terminal tomando decisiones de diseño específicas, un navegador renderizando la UI y un espacio de trabajo, con una flecha de retroalimentación que regresa en bucle", "caption": "El bucle central: Claude Code razona decisiones de UI específicas en la terminal, las renderiza y verifica en un navegador real, y converge contra tus referencias."}, "tocLabel": "En esta página", "toc": [{"id": "what-is-claude-code", "label": "Qué es realmente Claude Code"}, {"id": "why-design", "label": "Por qué Claude Code es bueno en diseño"}, {"id": "setup", "label": "Configura Claude Code para diseño (desde cero)"}, {"id": "skills-workflow", "label": "El flujo de trabajo de CLAUDE.md y Skills"}, {"id": "figma", "label": "Round-trip de Claude Code + Figma"}, {"id": "vs", "label": "Claude Code vs Codex vs Cursor"}, {"id": "pitfalls", "label": "Escollos y el aspecto de “bazofia de IA”"}, {"id": "open-design", "label": "Diseñar con Claude Code en Open Design"}, {"id": "faq", "label": "Preguntas frecuentes"}], "sections": [{"id": "what-is-claude-code", "heading": "Qué es realmente Claude Code", "blocks": [{"kind": "p", "text": "Claude Code es la herramienta de codificación agéntica de Anthropic. Lee tu base de código, edita archivos, ejecuta comandos y se integra con tus herramientas de desarrollo — planifica, escribe y verifica el trabajo a partir de tareas en lenguaje natural, en lugar de limitarse a autocompletar líneas."}, {"kind": "p", "text": "Se distribuye en varias superficies que comparten el mismo motor: una CLI de terminal, extensiones de IDE para VS Code, Cursor y JetBrains, una aplicación de escritorio con revisión visual de diferencias, y una experiencia web para tareas de larga duración. Tus archivos CLAUDE.md, ajustes y servidores MCP se trasladan a todas ellas."}, {"kind": "steps", "items": [{"label": "Archivo de instrucciones", "body": "Claude Code lee un archivo CLAUDE.md en la raíz de tu proyecto al inicio de cada sesión — el lugar natural para codificar tus convenciones de diseño, tokens y listas de verificación de revisión."}, {"label": "Skills", "body": "Las Agent Skills empaquetan instrucciones, scripts y recursos reutilizables que Claude carga bajo demanda, incluida la skill oficial de Frontend Design de Anthropic para el gusto."}, {"label": "Planificación y subagentes", "body": "Puede planificar antes de actuar y generar subagentes que trabajan en distintas partes de una tarea en paralelo, lo que mantiene coherentes las refactorizaciones grandes de UI."}]}, {"kind": "ul", "items": ["Proveedor: Anthropic", "Credencial: clave de API de Anthropic (BYOK, a través de la Console) o una suscripción a Claude (Pro / Max)", "Superficies: CLI de terminal, extensiones de VS Code / Cursor / JetBrains, aplicación de escritorio, web"]}]}, {"id": "why-design", "heading": "Por qué Claude Code es bueno en diseño", "blocks": [{"kind": "p", "text": "Entre los agentes de codificación, Claude Code tiene reputación de buen gusto en el trabajo de frontend. Hay varias razones que lo explican."}, {"kind": "steps", "items": [{"label": "Decisiones específicas, no vagas", "body": "Claude Code tiende a comprometerse con opciones concretas — valores hex exactos, escalas de espaciado, rampas tipográficas y jerarquía de componentes — en lugar de andar con rodeos, que es lo que separa una interfaz real de un marcador de posición."}, {"label": "Razonamiento consciente de la base de código", "body": "Con un contexto de trabajo amplio, refactoriza la UI a través de muchos archivos a la vez, reutilizando tus componentes y tokens existentes en lugar de reinventar estilos puntuales."}, {"label": "Una skill de frontend oficial", "body": "Anthropic ofrece una skill de Frontend Design que hace que Claude escriba primero una dirección de diseño y se aleje deliberadamente de las fuentes de sistema genéricas y los predecibles degradados morados."}]}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-taste-triangle.webp", "alt": "Diagrama que muestra el sistema de diseño, la skill y la imagen de referencia convergiendo en un buen resultado de diseño", "caption": "El gusto proviene de tres insumos que tú aportas: un sistema de diseño, una skill e imágenes de referencia reales."}, {"kind": "p", "text": "La lección es la misma que Anthropic plantea sobre sus propios modelos: Claude no tiene gusto por defecto — librado a su suerte, converge hacia el centro estadístico del diseño web (Inter, degradados morados, sombras suaves). Produce buen diseño cuando le das restricciones. Open Design empaqueta exactamente esos insumos, y por eso ambos encajan (más abajo)."}]}, {"id": "setup", "heading": "Configura Claude Code para trabajo de diseño, desde cero", "blocks": [{"kind": "p", "text": "Este es el camino completo desde una máquina limpia hasta un Claude Code capaz de construir y verificar UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Claude Code (native install, recommended)\ncurl -fsSL https://claude.ai/install.sh | bash\n# or: brew install --cask claude-code\n# Windows PowerShell: irm https://claude.ai/install.ps1 | iex\n\n# 2. Start it in your project and sign in on first run\ncd your-project\nclaude            # sign in with your Claude subscription or API key\n\n# 3. Generate project context\n/init             # creates a CLAUDE.md for this project\n\n# 4. Add the official Frontend Design skill\nclaude plugin install frontend-design@claude-plugins-official\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\nclaude plugin install figma@claude-plugins-official"}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-setup-flow.webp", "alt": "Flujo de configuración de cinco pasos: instalar, autenticar, configurar CLAUDE.md, añadir skill, verificar", "caption": "La secuencia de configuración: instalar → autenticar → configurar CLAUDE.md → añadir la skill de Frontend Design → habilitar la verificación en el navegador."}, {"kind": "steps", "items": [{"label": "Codifica tus reglas de diseño", "body": "Coloca tus tokens, primitivas y convenciones en CLAUDE.md y dirige a Claude hacia ellas, para que el resultado coincida con una marca en lugar de recaer en un aspecto genérico."}, {"label": "Añade verificación en el navegador", "body": "Conecta un MCP de Playwright o Chrome para que Claude renderice en un navegador real y compruebe su resultado en distintos breakpoints, en lugar de solo confirmar que la compilación pasa."}]}]}, {"id": "skills-workflow", "heading": "El flujo de trabajo de CLAUDE.md y Skills", "blocks": [{"kind": "p", "text": "El bucle de diseño de mayor apalancamiento con Claude Code es alimentarlo con referencias reales más tu contexto de diseño, y luego iterar hasta que la UI coincida — con CLAUDE.md y Skills llevando las restricciones, para que no las vuelvas a explicar en cada prompt."}, {"kind": "ol", "items": ["Parte de las referencias visuales más claras que tengas — e incluye varios estados (escritorio y móvil, hover, vacío, cargando), no solo una única toma principal.", "Sé específico en el prompt; los prompts vagos producen UI genérica incluso con un agente potente.", "Mantén tu sistema de diseño y tus convenciones en CLAUDE.md, e indícale a Claude dónde viven los tokens y las primitivas canónicas.", "Añade la skill de Frontend Design para que Claude se comprometa con una dirección estética real antes de escribir código.", "Conecta la verificación en el navegador para que Claude renderice, redimensione a los breakpoints y compare con las referencias — no solo confirme que compila."]}, {"kind": "p", "text": "Arrastra una imagen de referencia a la sesión y formula el prompt con restricciones concretas:"}, {"kind": "code", "lang": "bash", "code": "claude \"Implement reference-desktop.png and reference-mobile.png in\n  React + Vite + Tailwind + TypeScript.\n  Reuse the design-system components and tokens described in CLAUDE.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser, verify it matches the references across\n  breakpoints, and iterate until it does.\""}, {"kind": "p", "text": "Ejecuta un servidor de desarrollo en paralelo, mantén los prompts pequeños y enfocados, y confirma las buenas iteraciones / revierte las malas (diciéndole a Claude cuándo reviertes) para que cada pasada parta de una base limpia. Usa el modo de planificación para refactorizaciones más grandes, de modo que puedas revisar el enfoque antes de que se modifique cualquier archivo."}]}, {"id": "figma", "heading": "Claude Code + Figma: round-trip diseño ↔ código", "blocks": [{"kind": "p", "text": "En febrero de 2026, Anthropic y Figma lanzaron una integración bidireccional de primera clase a través del servidor MCP de Figma. Funciona en ambas direcciones."}, {"kind": "steps", "items": [{"label": "Diseño → Código", "body": "Selecciona un frame en Figma o pega un enlace en Claude Code, extrae el contexto de diseño y pídele que implemente el diseño usando tu biblioteca de componentes existente. Code Connect mantiene el resultado alineado con tus componentes reales."}, {"label": "Código → Diseño", "body": "Construye y previsualiza una funcionalidad en el navegador, y luego di “Send this to Figma” para capturar la UI en ejecución como capas editables de Figma — pantalla completa o un elemento seleccionado."}]}, {"kind": "p", "text": "Instálalo una vez con claude plugin install figma@claude-plugins-official (el MCP de Dev Mode requiere un plan de pago de Figma). El mismo MCP de Figma está disponible para Claude Code, Codex, Cursor y VS Code — exactamente el tipo de capacidad portátil y multiagente que Open Design está hecho para orquestar."}]}, {"id": "vs", "heading": "Claude Code vs Codex vs Cursor para diseño", "blocks": [{"kind": "p", "text": "No hay un único ganador para el trabajo de diseño — cada agente tiene una fortaleza distinta, y los equipos con experiencia los combinan. Un resumen justo:"}, {"kind": "table", "columns": ["Agente", "Fortaleza de diseño", "Mejor para"], "rows": [["Claude Code", "Decisiones de diseño específicas (hex, espaciado, tipografía) y razonamiento de UX consciente de la base de código", "Razonamiento de frontend y refactorizaciones de gran contexto"], ["Codex", "Fuerte pulido visual y comprensión de imágenes; compilaciones asíncronas en sandbox", "Compilaciones asíncronas delegadas y reglas portátiles de AGENTS.md"], ["Cursor", "Bucle visual de construir y ver con vista previa en vivo y ediciones en línea", "Trabajo de UI ajustado de iterar y observar dentro de un IDE"]]}, {"kind": "p", "text": "El veredicto recurrente de la comunidad es que el gusto proviene de las personas: los tres recaen en una estética genérica sin skills, referencias y restricciones. Ese es el verdadero problema a resolver — y tiene forma de herramienta de diseño, no de modelo."}]}, {"id": "pitfalls", "heading": "Escollos y cómo evitar el aspecto de “bazofia de IA”", "blocks": [{"kind": "p", "text": "Incluso con la reputación de buen gusto de Claude Code, la queja más común sobre el diseño generado por IA es que parece genérico — fuentes Inter, degradados morados sobre blanco, sombras suaves, esquinas redondeadas excesivas, una estética que “grita que esto lo hizo una IA”. La propia Anthropic lo atribuye a la convergencia distribucional: las opciones seguras dominan los datos de entrenamiento web. Otros problemas reportados incluyen diseños móviles rotos e instrucciones que se filtran en el texto de la UI."}, {"kind": "steps", "items": [{"label": "Instala la skill de Frontend Design", "body": "Obliga a Claude a comprometerse con una dirección real y evita explícitamente las fuentes y degradados sobreutilizados por la IA."}, {"label": "Habilita la verificación en el navegador", "body": "Haz que Claude renderice y se autoverifique en distintos breakpoints para que los diseños no se rompan en silencio en móvil."}, {"label": "Aporta tokens y referencias", "body": "Los tokens de diseño reales y las capturas de referencia son la mayor palanca sobre la calidad del resultado."}, {"label": "Codifica reglas en CLAUDE.md", "body": "Pon reglas de estilo como “sin tarjetas hero, máximo dos tipografías, jerarquía centrada en la marca” donde el agente las lea en cada ejecución."}]}, {"kind": "p", "text": "Observa que cada mitigación consiste en dar al agente un contexto de diseño curado. Mantener ese contexto a mano, proyecto a proyecto, es el trabajo pesado que Open Design elimina."}]}, {"id": "open-design", "heading": "Diseñar con Claude Code dentro de Open Design", "blocks": [{"kind": "p", "text": "Open Design es la capa de diseño open-source que el flujo de trabajo anterior no deja de pedir. Trata a Claude Code como un adaptador de primera parte y lo envuelve en una biblioteca curada de skills y sistemas de diseño, una canalización de render estructurada y una UI de escritorio local — para que el contexto de diseño que hace bueno a Claude Code esté ahí desde la primera ejecución, no se ensamble a mano cada vez."}, {"kind": "ol", "items": ["Instala Open Design y selecciona Claude Code como tu agente.", "Autentícate con tu clave de API de Anthropic (BYOK) o tu suscripción a Claude — las credenciales permanecen en tu máquina y nunca pasan por nuestros servidores.", "Elige un sistema de diseño y una skill, y luego genera presentaciones, prototipos y landing pages con un gusto consistente.", "Cada artefacto y archivo DESIGN.md vive en tu propio repositorio, no en una nube alojada."]}, {"kind": "p", "text": "El mismo agente Claude Code, la misma clave — más un flujo de trabajo de diseño real, portátil y open-source a su alrededor. Es local-first y Apache-2.0, así que nada de tu trabajo ni de tus credenciales sale de tu máquina."}]}], "faqTitle": "Preguntas frecuentes", "faq": [{"name": "¿Es Claude Code bueno para el trabajo de diseño?", "text": "Sí — es ampliamente considerado el agente de codificación con mejor gusto para el frontend, tomando decisiones específicas y conscientes de la base de código sobre valores hex, espaciado y escalas tipográficas. Con la skill de Frontend Design, un sistema de diseño e imágenes de referencia reales en contexto, produce UI responsive de calidad de producción y puede verificarla en un navegador. Sin ese contexto tiende a recaer en un aspecto genérico, que es la brecha que Open Design cubre."}, {"name": "¿Necesito una suscripción a Claude para diseñar con Claude Code?", "text": "Puedes usar una clave de API de Anthropic (BYOK, a través de la Console) o una suscripción a Claude (Pro / Max). En cualquier caso, Open Design nunca actúa como proxy de tus credenciales — las usa directamente tu agente en tu máquina."}, {"name": "¿Claude Code o Codex para diseño de frontend?", "text": "Ambos son fuertes. Claude Code es conocido por decisiones de diseño específicas y conscientes de la base de código y por su razonamiento de frontend; Codex tiene un fuerte pulido visual y destaca en compilaciones delegadas en sandbox. Muchos equipos usan ambos — Open Design te permite cambiar de agente sin cambiar tu flujo de trabajo de diseño."}, {"name": "¿Cómo conecto Claude Code con Figma?", "text": "Instala el plugin oficial de Figma con claude plugin install figma@claude-plugins-official. Después podrás implementar frames de Figma en código usando el contexto de diseño, y enviar una UI en ejecución de vuelta a frames editables de Figma con “Send this to Figma”. El MCP de Dev Mode requiere un plan de pago de Figma."}, {"name": "¿Qué son las Skills y CLAUDE.md?", "text": "CLAUDE.md es un archivo markdown en la raíz de tu proyecto que Claude Code lee al inicio de cada sesión — el lugar para codificar tus convenciones de diseño. Las Skills empaquetan instrucciones y recursos reutilizables que Claude carga bajo demanda, incluida la skill oficial de Frontend Design de Anthropic. Open Design incluye una biblioteca curada de ambos para que te saltes la configuración por proyecto."}, {"name": "¿Cómo evito la estética genérica de “bazofia de IA”?", "text": "Instala la skill de Frontend Design, aporta tokens de diseño reales y capturas de referencia, codifica las reglas de marca en CLAUDE.md y habilita la verificación en el navegador. Open Design incluye todo esto como una biblioteca curada para que te saltes la configuración por proyecto."}, {"name": "¿Está Open Design afiliado a Anthropic?", "text": "No. Claude Code es un producto de Anthropic; Open Design es un proyecto open-source independiente que lo soporta como adaptador de primera parte. Claude y Claude Code son marcas comerciales de Anthropic."}, {"name": "¿Están seguros mis archivos y credenciales?", "text": "Sí — Open Design es local-first y Apache-2.0. Tus archivos, artefactos y DESIGN.md permanecen en tu propio repositorio, y tus credenciales de Anthropic las usa directamente tu agente, sin enrutarse nunca a través de los servidores de Open Design."}], "ctaTitle": "Diseña con Claude Code, a la manera abierta.", "ctaBody": "Usa tu propia clave de Anthropic o tu suscripción a Claude, mantén cada archivo en local y obtén una biblioteca de diseño curada alrededor del agente que ya usas.", "ctaActions": [{"label": "Usa Claude Code dentro de Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dale una estrella en GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Descarga la aplicación de escritorio", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Ver todos los agentes compatibles"},
      },
      'codex': {
        ...en['codex']!,
        title: "Codex para diseño: crea UI con OpenAI Codex — Open Design",
        description: "La guía práctica para diseñar UI y frontends con OpenAI Codex — configuración, la integración con Figma, skills y cómo evitar el aspecto genérico de «IA en serie». Open Design convierte a Codex en un agente de diseño gratuito, local-first y open-source.",
        breadcrumb: "Codex",
        label: "Agente · Codex",
        heading: "Codex para diseño.",
        lead: "Codex es el agente de codificación de OpenAI. Con su plugin de Product Design y su integración con Figma se ha convertido en una herramienta de diseño seria. Open Design conecta a Codex con un flujo de trabajo de diseño open-source — tu clave de OpenAI o tu suscripción a ChatGPT, tus archivos, local-first.",
        rich: {"heroCtaLead": "Open Design convierte a Codex en un agente de diseño open-source y local-first — tu clave de OpenAI, tus archivos y una biblioteca curada de skills y sistemas de diseño a su alrededor.", "heroCtaActions": [{"label": "Usa Codex dentro de Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dale una estrella en GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Descarga la aplicación de escritorio", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenAI Codex empezó como un generador de código, pero en 2026 se convirtió en una herramienta creíble para diseñar interfaces reales — una vez que le das las referencias, skills y el bucle de verificación adecuados. Esta es una guía práctica y de extremo a extremo para usar Codex en trabajo de UI, frontend y sistemas de diseño, y para integrarlo en un flujo de trabajo de diseño estructurado con Open Design.", "Cubre qué es Codex hoy, por qué de repente es bueno en frontend, cómo configurarlo desde cero, el bucle de captura a UI, el round-trip oficial con Figma, cómo se compara con Cursor y Claude Code, los escollos que hacen que el resultado de la IA parezca genérico y cómo Open Design cierra esa brecha como una capa de diseño abierta y local-first."], "heroImage": {"src": "/agents/codex-design/codex-design-workflow-loop.webp", "alt": "Bucle de retroalimentación de diseño de Codex: un agente de terminal, un navegador renderizando la UI y un espacio de trabajo, con una flecha de retroalimentación que regresa en bucle", "caption": "El bucle central: Codex construye la UI en la terminal, la renderiza y verifica en un navegador real, e itera contra tus referencias."}, "tocLabel": "En esta página", "toc": [{"id": "what-is-codex", "label": "Qué es realmente OpenAI Codex"}, {"id": "why-design", "label": "Por qué Codex es bueno en diseño ahora"}, {"id": "setup", "label": "Configura Codex para diseño (desde cero)"}, {"id": "screenshot-workflow", "label": "El flujo de trabajo de captura a UI"}, {"id": "figma", "label": "Round-trip de Codex + Figma"}, {"id": "vs", "label": "Codex vs Cursor vs Claude Code"}, {"id": "pitfalls", "label": "Escollos y el aspecto de “bazofia de IA”"}, {"id": "open-design", "label": "Diseñar con Codex en Open Design"}, {"id": "faq", "label": "Preguntas frecuentes"}], "sections": [{"id": "what-is-codex", "heading": "Qué es realmente OpenAI Codex (y qué no es)", "blocks": [{"kind": "p", "text": "Primero, una aclaración que confunde a casi todos los que buscan “Codex”. El Codex original de OpenAI era un modelo de autocompletado de código de 2021 que impulsaba los primeros GitHub Copilot y fue descontinuado en 2023. No es de eso de lo que trata esta página. El Codex de hoy es la herramienta de codificación agéntica de OpenAI — planifica, escribe, ejecuta y verifica código a partir de tareas en lenguaje natural."}, {"kind": "p", "text": "El Codex moderno se distribuye en cuatro superficies: una CLI de terminal (reescrita en Rust, con licencia Apache-2.0), una extensión de IDE para VS Code, Cursor y Windsurf, una experiencia cloud/web para tareas asíncronas delegadas, y una aplicación de escritorio con un navegador integrado y Computer Use."}, {"kind": "steps", "items": [{"label": "Modelo por defecto", "body": "A mediados de 2026, el modelo recomendado es gpt-5.5, siendo gpt-5.4 el modelo que OpenAI entrenó explícitamente para frontend y computer use."}, {"label": "Archivo de instrucciones", "body": "Codex lee un archivo AGENTS.md en tu proyecto (un estándar entre herramientas) para las reglas del proyecto — el lugar natural para codificar tus convenciones de diseño."}, {"label": "Sandbox", "body": "Se ejecuta en un sandbox a nivel de kernel (workspace-write por defecto), de modo que un agente que edita tu UI no puede salirse del proyecto."}]}, {"kind": "ul", "items": ["Proveedor: OpenAI", "Credencial: clave de API de OpenAI (BYOK) o suscripción a ChatGPT (Free / Go / Plus / Pro / Business / Enterprise)", "Licencia de la CLI: Apache-2.0, open source"]}]}, {"id": "why-design", "heading": "Por qué Codex es bueno en diseño ahora", "blocks": [{"kind": "p", "text": "Tres cosas convergieron a principios de 2026 para convertir a Codex en una verdadera herramienta de diseño en lugar de un generador de código genérico."}, {"kind": "steps", "items": [{"label": "Un modelo entrenado para frontend", "body": "OpenAI lanzó GPT-5.4, su primer modelo principal entrenado para frontend y computer use, con una comprensión de imágenes mucho mejor en todo el flujo de diseño y una autoverificación más sólida. Incluso puede generar mood boards y opciones visuales antes de comprometerse con los assets finales."}, {"label": "Una skill de frontend oficial", "body": "El catálogo openai/skills incluye una skill de frontend curada que impone gusto real: diseños sin tarjetas, heroes a sangre completa, jerarquía centrada en la marca, movimiento contenido, como máximo dos tipografías y un color de acento — y hace que Codex escriba una tesis visual antes de construir."}, {"label": "Verificación en el navegador", "body": "Con la skill de Playwright, Codex abre un navegador real, redimensiona a los breakpoints y compara su resultado con la referencia en lugar de solo comprobar que la compilación pasa."}]}, {"kind": "image", "src": "/agents/codex-design/codex-design-taste-triangle.webp", "alt": "Diagrama que muestra el sistema de diseño, la skill y la imagen de referencia convergiendo en un buen resultado de diseño", "caption": "El gusto proviene de tres insumos que tú aportas: un sistema de diseño, una skill e imágenes de referencia reales."}, {"kind": "p", "text": "La lección detrás de las tres: Codex no tiene gusto por defecto. Produce buen diseño cuando le das restricciones — un sistema de diseño, una skill estética y referencias concretas. Open Design empaqueta exactamente esos insumos, y por eso ambos encajan (más abajo)."}]}, {"id": "setup", "heading": "Configura Codex para trabajo de diseño, desde cero", "blocks": [{"kind": "p", "text": "Este es el camino completo desde una máquina limpia hasta un Codex capaz de construir y verificar UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install the Codex CLI\nnpm install -g @openai/codex\n# or: brew install --cask codex\n# or: curl -fsSL https://chatgpt.com/codex/install.sh | sh\n\n# 2. Authenticate (ChatGPT sign-in recommended for higher limits)\ncodex            # then choose “Sign in with ChatGPT”\n\n# 3. Generate project context\ncodex            # inside your project, run /init to create AGENTS.md\n\n# 4. Add the official frontend skill, then restart Codex\n# (in the Codex app) $skill-installer frontend-skill\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\ncodex mcp add figma --url https://mcp.figma.com/mcp"}, {"kind": "image", "src": "/agents/codex-design/codex-design-setup-flow.webp", "alt": "Flujo de configuración de cinco pasos: instalar, autenticar, configurar, instalar skill, verificar", "caption": "La secuencia de configuración: instalar → autenticar → configurar AGENTS.md → instalar la skill de frontend → habilitar la verificación en el navegador."}, {"kind": "steps", "items": [{"label": "Codifica tus reglas de diseño", "body": "Coloca tus tokens, primitivas y convenciones en AGENTS.md o en un DESIGN.md y dirige a Codex hacia ellas, para que el resultado coincida con una marca en lugar de recaer en un aspecto genérico."}, {"label": "Elige el nivel de razonamiento adecuado", "body": "OpenAI señala que los niveles de razonamiento de bajo a medio suelen producir mejores resultados de frontend que el ajuste más alto."}]}]}, {"id": "screenshot-workflow", "heading": "El flujo de trabajo de captura a UI", "blocks": [{"kind": "p", "text": "El bucle de diseño de mayor apalancamiento con Codex es convertir una imagen de referencia en una UI funcional y responsive e iterar hasta que coincida. La propia guía de OpenAI se reduce a cinco pasos."}, {"kind": "ol", "items": ["Parte de las referencias visuales más claras que tengas — e incluye varios estados (escritorio y móvil, hover, vacío, cargando), no solo una única toma principal.", "Sé específico en el prompt; los prompts vagos producen UI genérica.", "Prepara un sistema de diseño e indícale a Codex dónde viven los tokens y las primitivas canónicas.", "Habilita la skill interactiva de Playwright para que Codex renderice en un navegador real y redimensione a los breakpoints.", "Itera haciendo que Codex compare su implementación con las capturas — no solo que confirme que compila."]}, {"kind": "p", "text": "Alimenta las imágenes arrastrando una captura a la terminal o con el flag de imagen, y luego formula el prompt con restricciones concretas:"}, {"kind": "code", "lang": "bash", "code": "codex -i reference-desktop.png -i reference-mobile.png \\\n  \"Implement this design in React + Vite + Tailwind + TypeScript.\n   Reuse my existing design-system components and tokens.\n   Match spacing, layout, and hierarchy; make it responsive.\n   Use the Playwright skill to verify the UI matches the\n   references and iterate until it does.\""}, {"kind": "p", "text": "Ejecuta un servidor de desarrollo en una segunda terminal, mantén los prompts pequeños y enfocados, y confirma las buenas iteraciones / revierte las malas (diciéndole a Codex cuándo reviertes) para que cada pasada parta de una base limpia."}]}, {"id": "figma", "heading": "Codex + Figma: round-trip diseño ↔ código", "blocks": [{"kind": "p", "text": "En febrero de 2026, OpenAI y Figma anunciaron una asociación oficial, convirtiendo la beta anterior del MCP de Figma en una integración bidireccional de primera clase. Funciona en ambas direcciones."}, {"kind": "steps", "items": [{"label": "Diseño → Código", "body": "Copia el “link to selection” de un frame en Figma, pégalo en Codex con get_design_context y pídele que implemente el diseño usando tu biblioteca de componentes existente."}, {"label": "Código → Diseño", "body": "La herramienta generate_figma_design (“Code to Canvas”) convierte una UI en vivo y en ejecución de vuelta en frames editables de Figma — pantalla completa, un elemento seleccionado o un archivo entero."}]}, {"kind": "p", "text": "El MCP de Figma se ejecuta como un servidor remoto y está exento de límites de tasa. Añádelo una vez y estará disponible para Codex, Claude Code, Cursor, VS Code y más — exactamente el tipo de capacidad portátil y multiagente que Open Design está hecho para orquestar."}]}, {"id": "vs", "heading": "Codex vs Cursor vs Claude Code para diseño", "blocks": [{"kind": "p", "text": "No hay un único ganador para el trabajo de diseño — cada agente tiene una fortaleza distinta, y los equipos con experiencia los combinan. Un resumen justo:"}, {"kind": "table", "columns": ["Agente", "Fortaleza de diseño", "Mejor para"], "rows": [["Codex", "Fuerte pulido visual tras GPT-5.4 + skill de frontend; comprensión de imágenes", "Compilaciones asíncronas delegadas, ejecuciones en sandbox, reglas portátiles de AGENTS.md"], ["Cursor", "Bucle visual de construir y ver con vista previa en vivo y ediciones en línea", "Trabajo de UI ajustado de iterar y observar dentro de un IDE"], ["Claude Code", "Decisiones de diseño específicas (hex, espaciado, tipografía) y UX consciente de la base de código", "Razonamiento de frontend y refactorizaciones de gran contexto"]]}, {"kind": "p", "text": "El veredicto recurrente de la comunidad es que el gusto proviene de las personas: los tres recaen en una estética genérica sin skills, referencias y restricciones. Ese es el verdadero problema a resolver — y tiene forma de herramienta de diseño, no de modelo."}]}, {"id": "pitfalls", "heading": "Escollos y cómo evitar el aspecto de “bazofia de IA”", "blocks": [{"kind": "p", "text": "La queja más común sobre el diseño generado por Codex es que parece genérico — degradados suaves, paneles flotantes, esquinas redondeadas excesivas, sombras dramáticas, un aire de Inter-y-morado que “grita que esto lo hizo una IA”. Otros problemas reportados incluyen diseños móviles rotos, instrucciones que se filtran en el texto de la UI y alcanzar rápidamente los límites de uso."}, {"kind": "steps", "items": [{"label": "Instala una skill de frontend", "body": "Una skill estética curada obliga a Codex a comprometerse con una dirección real en lugar del aspecto por defecto."}, {"label": "Habilita la verificación con Playwright", "body": "Haz que Codex renderice y se autoverifique en distintos breakpoints para que los diseños no se rompan en silencio en móvil."}, {"label": "Aporta tokens y referencias", "body": "Los tokens de diseño reales y las capturas de referencia son la mayor palanca sobre la calidad del resultado."}, {"label": "Codifica reglas en AGENTS.md", "body": "Pon reglas de estilo como “sin tarjetas hero, máximo dos tipografías, jerarquía centrada en la marca” donde el agente las lea en cada ejecución."}]}, {"kind": "p", "text": "Observa que cada mitigación consiste en dar al agente un contexto de diseño curado. Mantener ese contexto a mano, proyecto a proyecto, es el trabajo pesado que Open Design elimina."}]}, {"id": "open-design", "heading": "Diseñar con Codex dentro de Open Design", "blocks": [{"kind": "p", "text": "Open Design es la capa de diseño open-source que el flujo de trabajo anterior no deja de pedir. Trata a Codex como un adaptador de primera parte y lo envuelve en una biblioteca curada de skills y sistemas de diseño, una canalización de render estructurada y una UI de escritorio local — para que el contexto de diseño que hace bueno a Codex esté ahí desde la primera ejecución, no se ensamble a mano cada vez."}, {"kind": "ol", "items": ["Instala Open Design y selecciona Codex como tu agente.", "Autentícate con tu clave de API de OpenAI (BYOK) o tu suscripción a ChatGPT — las credenciales permanecen en tu máquina y nunca pasan por nuestros servidores.", "Elige un sistema de diseño y una skill, y luego genera presentaciones, prototipos y landing pages con un gusto consistente.", "Cada artefacto y archivo DESIGN.md vive en tu propio repositorio, no en una nube alojada."]}, {"kind": "p", "text": "El mismo agente Codex, la misma clave — más un flujo de trabajo de diseño real, portátil y open-source a su alrededor. Es local-first y Apache-2.0, así que nada de tu trabajo ni de tus credenciales sale de tu máquina."}]}], "faqTitle": "Preguntas frecuentes", "faq": [{"name": "¿Puede OpenAI Codex realmente hacer trabajo de diseño?", "text": "Sí — con una skill de frontend, un sistema de diseño e imágenes de referencia reales en contexto, Codex (especialmente con GPT-5.4) produce UI responsive de calidad de producción y puede verificarla en un navegador. Sin ese contexto tiende a recaer en un aspecto genérico, que es la brecha que Open Design cubre."}, {"name": "¿Es este el plugin de Product Design de OpenAI Codex?", "text": "No. Open Design es un proyecto open-source independiente que integra a Codex como agente. Complementa las propias herramientas de OpenAI con una biblioteca de skills y sistemas de diseño abierta y local-first."}, {"name": "¿Necesito una suscripción a ChatGPT para diseñar con Codex?", "text": "Puedes usar una clave de API de OpenAI (BYOK) o tu suscripción a ChatGPT. El inicio de sesión con ChatGPT suele dar límites más generosos; en cualquier caso, Open Design nunca actúa como proxy de tus credenciales."}, {"name": "¿Codex o Claude Code para diseño de frontend?", "text": "Ambos son fuertes. Claude Code es conocido por decisiones de diseño específicas y conscientes de la base de código; Codex tiene un fuerte pulido visual tras GPT-5.4 y destaca en compilaciones delegadas en sandbox. Muchos equipos usan ambos — Open Design te permite cambiar de agente sin cambiar tu flujo de trabajo de diseño."}, {"name": "¿Cómo conecto Codex con Figma?", "text": "Añade el servidor MCP oficial de Figma (codex mcp add figma --url https://mcp.figma.com/mcp). Después podrás implementar frames de Figma en código con get_design_context y enviar una UI en ejecución de vuelta a frames editables de Figma con generate_figma_design."}, {"name": "¿Cómo evito la estética genérica de “bazofia de IA”?", "text": "Instala una skill de frontend, aporta tokens de diseño reales y capturas de referencia, codifica las reglas de marca en AGENTS.md y habilita la verificación con Playwright. Open Design incluye todo esto como una biblioteca curada para que te saltes la configuración por proyecto."}, {"name": "¿Está Open Design afiliado a OpenAI?", "text": "No. Codex es un producto de OpenAI; Open Design es un proyecto open-source independiente que lo soporta como adaptador de primera parte. OpenAI y Codex son marcas comerciales de OpenAI."}, {"name": "¿Están seguros mis archivos y credenciales?", "text": "Sí — Open Design es local-first. Tus archivos, artefactos y DESIGN.md permanecen en tu propio repositorio, y tus credenciales de OpenAI las usa directamente tu agente, sin enrutarse nunca a través de los servidores de Open Design."}], "ctaTitle": "Diseña con Codex, a la manera abierta.", "ctaBody": "Usa tu propia clave de OpenAI, mantén cada archivo en local y obtén una biblioteca de diseño curada alrededor del agente que ya usas.", "ctaActions": [{"label": "Usa Codex dentro de Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dale una estrella en GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Descarga la aplicación de escritorio", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Ver todos los agentes compatibles"},
      },
      'cursor': {
        ...en['cursor']!,
        title: "Cursor para diseñadores — Open Design",
        description: "Cómo los diseñadores usan Cursor para diseño de UI y web — Design Mode, Figma a código, el MCP de Figma — y cómo Open Design convierte a Cursor en un agente de diseño open-source y local-first.",
        breadcrumb: "Cursor Agent",
        label: "Agente · Cursor",
        heading: "Cursor para diseñadores.",
        lead: "Cursor es el editor de código con IA, ahora con un Design Mode visual. Los diseñadores lo usan para editar la UI señalando y dibujando, y para convertir Figma en código. Open Design conecta a Cursor Agent con un flujo de trabajo de diseño open-source que mantiene tus archivos en local.",
        rich: {"heroCtaLead": "Open Design convierte a Cursor en un agente de diseño open-source y local-first — tu cuenta de Cursor o tus claves de modelo, tus archivos y una biblioteca curada de skills y sistemas de diseño a su alrededor.", "heroCtaActions": [{"label": "Usa Cursor dentro de Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dale una estrella en GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Descarga la aplicación de escritorio", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Cursor es el editor de código con IA primero que convirtió el “constrúyelo y míralo renderizar” en la forma por defecto de entregar UI. Con el modo Agent, ediciones en línea, una vista previa dentro del editor y Figma sobre MCP, se ha convertido en una verdadera herramienta de diseño — una vez que le das las referencias, reglas y un bucle de verificación adecuados. Esta es una guía práctica y de extremo a extremo para usar Cursor en trabajo de UI, frontend y sistemas de diseño, y para integrarlo en un flujo de trabajo de diseño estructurado con Open Design.", "Cubre qué es realmente Cursor, por qué su ajustado bucle de iterar y observar es bueno para el diseño, cómo configurarlo desde cero, el bucle de captura y vista previa a UI, el round-trip con Figma sobre MCP, cómo se compara con Codex y Claude Code, los escollos que hacen que el resultado de la IA parezca genérico y cómo Open Design cierra esa brecha como una capa de diseño abierta y local-first."], "heroImage": {"src": "/agents/cursor-design/cursor-design-hero.webp", "alt": "Convergencia de diseño de Cursor: el editor a la izquierda, un hub curado de skills y sistema de diseño en el centro con la marca de Cursor al medio, y una UI renderizada a la derecha", "caption": "La idea central: Cursor edita y renderiza la UI en el editor, mientras un hub de diseño curado le aporta el sistema, las skills y las referencias que hacen que el resultado parezca intencional."}, "tocLabel": "En esta página", "toc": [{"id": "what-is-cursor", "label": "Qué es realmente Cursor"}, {"id": "why-design", "label": "Por qué Cursor es bueno en diseño"}, {"id": "setup", "label": "Configura Cursor para diseño (desde cero)"}, {"id": "preview-workflow", "label": "El flujo de trabajo de vista previa a UI"}, {"id": "figma", "label": "Cursor + Figma sobre MCP"}, {"id": "vs", "label": "Cursor vs Codex vs Claude Code"}, {"id": "pitfalls", "label": "Escollos y el aspecto de “bazofia de IA”"}, {"id": "open-design", "label": "Diseñar con Cursor en Open Design"}, {"id": "faq", "label": "Preguntas frecuentes"}], "sections": [{"id": "what-is-cursor", "heading": "Qué es realmente Cursor", "blocks": [{"kind": "p", "text": "Cursor es un editor de código con IA primero construido por Anysphere. Es un fork de VS Code, por lo que conserva el editor, las extensiones y los atajos de teclado familiares, pero reconstruye el flujo de trabajo en torno a un agente de IA que puede leer todo tu proyecto, editar varios archivos, ejecutar comandos e iterar contigo en el bucle."}, {"kind": "p", "text": "Para el trabajo de diseño, las superficies importantes son el modo Agent (describes un resultado y Cursor planifica y edita a través de los archivos), las ediciones en línea y las completaciones con Tab para ajustes rápidos, una vista previa / navegador dentro del editor para que veas la UI en ejecución sin salir de la ventana, y el soporte de MCP que le permite incorporar contexto externo como un archivo de Figma en vivo."}, {"kind": "steps", "items": [{"label": "Reglas del proyecto", "body": "Cursor lee archivos de instrucciones del proyecto — reglas `.mdc` versionadas bajo `.cursor/rules`, y un `AGENTS.md` simple — para que puedas codificar tus convenciones de diseño donde el agente las lee en cada ejecución."}, {"label": "Modelos", "body": "Cursor es flexible en cuanto a modelos: viene con modelos de frontera a través de tu suscripción y también admite traer tus propias claves de modelo, así que eliges el motor detrás del mismo flujo de trabajo del editor."}, {"label": "MCP", "body": "Habla el Model Context Protocol, así que los servidores externos — el más relevante, el servidor MCP de Figma — se convierten en contexto de primera clase para el agente."}]}, {"kind": "ul", "items": ["Proveedor: Anysphere", "Credencial: cuenta / suscripción de Cursor (Hobby / Pro / Business) o tus propias claves de modelo (BYOK)", "Forma: editor de código con IA primero (fork de VS Code) con un agente y una vista previa dentro del editor"]}]}, {"id": "why-design", "heading": "Por qué Cursor es bueno en diseño", "blocks": [{"kind": "p", "text": "La ventaja de diseño de Cursor no es una sola característica — es lo ajustado del bucle de construir y ver. Tres cosas hacen que se sienta como una herramienta de diseño en lugar de un generador de código genérico."}, {"kind": "steps", "items": [{"label": "Un bucle ajustado de iterar y observar", "body": "Tú formulas el prompt, Cursor edita a través de los archivos, y la vista previa dentro del editor renderiza el resultado de inmediato — así ajustas espaciado, jerarquía y movimiento en segundos en lugar de ir y volver entre una terminal y un navegador separados."}, {"label": "Edición visual directa", "body": "Más allá del chat, Cursor te permite seleccionar elementos en la vista previa y retocar estilos, así que las pequeñas correcciones visuales se sienten como ediciones de diseño en lugar de arqueología de código."}, {"label": "Reglas del proyecto y contexto MCP", "body": "Con `.cursor/rules` (o `AGENTS.md`) y el servidor MCP de Figma, el agente trabaja contra tus tokens, componentes y especificaciones de diseño reales en lugar de adivinar."}]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-taste-triangle.webp", "alt": "Diagrama que muestra el sistema de diseño, la skill y la imagen de referencia convergiendo en un buen resultado de diseño", "caption": "El gusto proviene de tres insumos que tú aportas: un sistema de diseño, una skill e imágenes de referencia reales."}, {"kind": "p", "text": "La lección es la misma que enseña cada agente: Cursor no tiene gusto por defecto. Produce buen diseño cuando le das restricciones — un sistema de diseño, una skill estética y referencias concretas. Open Design empaqueta exactamente esos insumos, y por eso ambos encajan (más abajo)."}]}, {"id": "setup", "heading": "Configura Cursor para trabajo de diseño, desde cero", "blocks": [{"kind": "p", "text": "Este es el camino completo desde una máquina limpia hasta un Cursor capaz de construir, previsualizar y verificar UI contra tu sistema de diseño."}, {"kind": "ol", "items": ["Instala Cursor desde cursor.com e inicia sesión con tu cuenta de Cursor, o configura tus propias claves de modelo (BYOK) en Settings.", "Abre tu proyecto y elige un modelo en el panel de chat / Agent.", "Añade reglas del proyecto: crea `.cursor/rules/*.mdc` para convenciones estructuradas y delimitadas por globs, o un `AGENTS.md` simple para instrucciones sencillas y legibles.", "Conecta el servidor MCP de Figma (opcional) para que el agente pueda leer el contexto de diseño en vivo.", "Ejecuta tu servidor de desarrollo y usa la vista previa dentro del editor para ver y verificar la UI a medida que iteras."]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-setup-flow.webp", "alt": "Flujo de configuración de cinco pasos: instalar, autenticar, configurar reglas, añadir skill, verificar", "caption": "La secuencia de configuración: instalar → autenticar → configurar las reglas del proyecto → añadir una skill → habilitar la verificación con vista previa."}, {"kind": "p", "text": "Un archivo mínimo de reglas del proyecto hace que el agente diseñe para una marca en lugar de recaer en un aspecto genérico. Ponlo donde Cursor lo lea en cada ejecución:"}, {"kind": "code", "lang": "markdown", "code": "# .cursor/rules/design.mdc\n---\ndescription: Project design conventions\nalwaysApply: true\n---\n\n- Reuse existing design-system tokens and components; never hardcode hex or spacing.\n- At most two typefaces and one accent color.\n- Brand-first hierarchy; restrained motion. No hero cards, no oversized rounded corners.\n- Build responsive by default; verify desktop and mobile in the preview before finishing."}, {"kind": "steps", "items": [{"label": "Codifica tus reglas de diseño", "body": "Coloca tus tokens, primitivas y convenciones en `.cursor/rules` o `AGENTS.md` y dirige a Cursor hacia ellas, para que el resultado coincida con una marca en lugar de recaer en un aspecto genérico."}, {"label": "Mantén los prompts pequeños", "body": "El bucle ajustado de Cursor recompensa las peticiones enfocadas — itera un componente o estado a la vez y observa la vista previa entre pasadas."}]}]}, {"id": "preview-workflow", "heading": "El flujo de trabajo de vista previa a UI", "blocks": [{"kind": "p", "text": "El bucle de diseño de mayor apalancamiento con Cursor es convertir una referencia en una UI funcional y responsive e iterar en el editor hasta que coincida — observando la vista previa en vivo todo el tiempo en lugar de adivinar."}, {"kind": "ol", "items": ["Parte de las referencias visuales más claras que tengas — e incluye varios estados (escritorio y móvil, hover, vacío, cargando), no solo una única toma principal.", "Sé específico en el prompt; los prompts vagos producen UI genérica.", "Prepara un sistema de diseño e indícale a Cursor dónde viven los tokens y las primitivas canónicas.", "Mantén abierta la vista previa dentro del editor y tu servidor de desarrollo en marcha para que cada edición renderice de inmediato en los breakpoints que te importan.", "Itera comparando la UI renderizada con las referencias — y usa la selección directa de elementos en la vista previa para pequeñas correcciones visuales."]}, {"kind": "p", "text": "Alimenta las referencias adjuntando una imagen al chat, y luego formula el prompt con restricciones concretas:"}, {"kind": "code", "lang": "text", "code": "Implement this design in React + Vite + Tailwind + TypeScript.\nReuse my existing design-system components and tokens.\nMatch spacing, layout, and hierarchy; make it responsive.\nKeep the preview open — verify desktop and mobile match the\nreferences and iterate until they do."}, {"kind": "p", "text": "Confirma las buenas iteraciones y revierte las malas (diciéndole a Cursor cuándo reviertes) para que cada pasada parta de una base limpia — la misma disciplina que evita que cualquier bucle de agente derive."}]}, {"id": "figma", "heading": "Cursor + Figma: diseño ↔ código sobre MCP", "blocks": [{"kind": "p", "text": "Cursor se conecta a Figma a través del servidor MCP oficial de Figma, que da al agente acceso estructurado a un archivo de Figma en vivo en lugar de una captura plana. Eso elimina las conjeturas del handoff."}, {"kind": "steps", "items": [{"label": "Diseño → Código", "body": "Copia el enlace de un frame en Figma, pégalo en Cursor y pídele que implemente el diseño. El servidor MCP expone contexto de diseño real — componentes, variables, datos de layout, tokens — para que el código generado coincida con la fuente en lugar de aproximarla."}, {"label": "Mantente alineado", "body": "Con los tokens de diseño, estilos y componentes usados de forma consistente en Figma (y Code Connect donde esté disponible), el resultado de Cursor permanece mapeado a tu sistema de diseño real en lugar de reinventar primitivas."}]}, {"kind": "p", "text": "Configura una vez el servidor MCP remoto de Figma y estará disponible para Cursor como contexto de primera clase. Como MCP es un estándar abierto, el mismo servidor es reutilizable en Cursor, Claude Code, Codex y VS Code — exactamente el tipo de capacidad portátil y multiagente que Open Design está hecho para orquestar."}]}, {"id": "vs", "heading": "Cursor vs Codex vs Claude Code para diseño", "blocks": [{"kind": "p", "text": "No hay un único ganador para el trabajo de diseño — cada agente tiene una fortaleza distinta, y los equipos con experiencia los combinan. Un resumen justo:"}, {"kind": "table", "columns": ["Agente", "Fortaleza de diseño", "Mejor para"], "rows": [["Cursor", "Bucle visual de construir y ver con vista previa en vivo dentro del editor y edición directa de elementos", "Trabajo de UI ajustado de iterar y observar dentro de un IDE"], ["Codex", "Fuerte pulido visual con una skill de frontend; comprensión de imágenes y ejecuciones en sandbox", "Compilaciones asíncronas delegadas y reglas portátiles de AGENTS.md"], ["Claude Code", "Decisiones de diseño específicas (hex, espaciado, tipografía) y UX consciente de la base de código", "Razonamiento de frontend y refactorizaciones de gran contexto"]]}, {"kind": "p", "text": "El veredicto recurrente de la comunidad es que el gusto proviene de las personas: los tres recaen en una estética genérica sin skills, referencias y restricciones. Ese es el verdadero problema a resolver — y tiene forma de herramienta de diseño, no de modelo."}]}, {"id": "pitfalls", "heading": "Escollos y cómo evitar el aspecto de “bazofia de IA”", "blocks": [{"kind": "p", "text": "La queja más común sobre el diseño generado por Cursor es que parece genérico — degradados suaves, paneles flotantes, esquinas redondeadas excesivas, sombras dramáticas, un aire de Inter-y-morado que “grita que esto lo hizo una IA”. Otros problemas reportados incluyen diseños que se rompen en móvil e instrucciones que se filtran en el texto de la UI."}, {"kind": "steps", "items": [{"label": "Añade una skill de diseño", "body": "Una skill estética curada obliga a Cursor a comprometerse con una dirección real en lugar del aspecto por defecto."}, {"label": "Usa la vista previa para verificar", "body": "Renderiza y autoverifica en distintos breakpoints en la vista previa dentro del editor para que los diseños no se rompan en silencio en móvil."}, {"label": "Aporta tokens y referencias", "body": "Los tokens de diseño reales y las capturas de referencia son la mayor palanca sobre la calidad del resultado."}, {"label": "Codifica reglas en `.cursor/rules`", "body": "Pon reglas de estilo como “sin tarjetas hero, máximo dos tipografías, jerarquía centrada en la marca” donde el agente las lea en cada ejecución."}]}, {"kind": "p", "text": "Observa que cada mitigación consiste en dar al agente un contexto de diseño curado. Mantener ese contexto a mano, proyecto a proyecto, es el trabajo pesado que Open Design elimina."}]}, {"id": "open-design", "heading": "Diseñar con Cursor dentro de Open Design", "blocks": [{"kind": "p", "text": "Open Design es la capa de diseño open-source que el flujo de trabajo anterior no deja de pedir. Trata a Cursor como un adaptador de primera parte y lo envuelve en una biblioteca curada de skills y sistemas de diseño, una canalización de render estructurada y una UI de escritorio local — para que el contexto de diseño que hace bueno a Cursor esté ahí desde la primera ejecución, no se ensamble a mano cada vez."}, {"kind": "ol", "items": ["Instala Open Design y selecciona Cursor como tu agente.", "Autentícate con tu cuenta de Cursor o tus propias claves de modelo (BYOK) — las credenciales permanecen en tu máquina y nunca pasan por nuestros servidores.", "Elige un sistema de diseño y una skill, y luego genera presentaciones, prototipos y landing pages con un gusto consistente.", "Cada artefacto y archivo DESIGN.md vive en tu propio repositorio, no en una nube alojada."]}, {"kind": "p", "text": "El mismo agente Cursor, la misma clave — más un flujo de trabajo de diseño real, portátil y open-source a su alrededor. Es local-first y Apache-2.0, así que nada de tu trabajo ni de tus credenciales sale de tu máquina."}]}], "faqTitle": "Preguntas frecuentes", "faq": [{"name": "¿Puede Cursor realmente hacer trabajo de diseño?", "text": "Sí — con una skill de diseño, un sistema de diseño e imágenes de referencia reales en contexto, Cursor produce UI responsive de calidad de producción, y su vista previa dentro del editor te permite verificarla y refinarla visualmente. Sin ese contexto tiende a recaer en un aspecto genérico, que es la brecha que Open Design cubre."}, {"name": "¿Es este un producto oficial de Cursor?", "text": "No. Open Design es un proyecto open-source independiente que integra a Cursor como agente. Complementa a Cursor con una biblioteca de skills y sistemas de diseño abierta y local-first."}, {"name": "¿Necesito una suscripción a Cursor para diseñar con Cursor?", "text": "Puedes usar una cuenta / suscripción de Cursor o traer tus propias claves de modelo (BYOK). Open Design nunca actúa como proxy de tus credenciales en ningún caso — las usa directamente tu agente."}, {"name": "¿Cursor o Claude Code para diseño de frontend?", "text": "Ambos son fuertes. Claude Code es conocido por decisiones de diseño específicas y conscientes de la base de código; la ventaja de Cursor es su ajustado bucle de construir y ver con una vista previa en vivo dentro del editor. Muchos equipos usan ambos — Open Design te permite cambiar de agente sin cambiar tu flujo de trabajo de diseño."}, {"name": "¿Cómo conecto Cursor con Figma?", "text": "Añade el servidor MCP oficial de Figma en Cursor, luego pega un enlace de un frame de Figma en el chat y pídele a Cursor que lo implemente. El servidor expone componentes, variables y datos de layout reales para que el código generado coincida con el diseño fuente."}, {"name": "¿Cómo evito la estética genérica de “bazofia de IA”?", "text": "Añade una skill de diseño, aporta tokens de diseño reales y capturas de referencia, codifica las reglas de marca en `.cursor/rules` o `AGENTS.md`, y verifica en distintos breakpoints en la vista previa. Open Design incluye todo esto como una biblioteca curada para que te saltes la configuración por proyecto."}, {"name": "¿Está Open Design afiliado a Cursor o Anysphere?", "text": "No. Cursor es un producto de Anysphere; Open Design es un proyecto open-source independiente que lo soporta como adaptador de primera parte. Cursor y Anysphere son marcas comerciales de Anysphere, Inc."}, {"name": "¿Están seguros mis archivos y credenciales?", "text": "Sí — Open Design es local-first. Tus archivos, artefactos y DESIGN.md permanecen en tu propio repositorio, y tus credenciales de Cursor o de modelo las usa directamente tu agente, sin enrutarse nunca a través de los servidores de Open Design."}], "ctaTitle": "Diseña con Cursor, a la manera abierta.", "ctaBody": "Usa tu propia cuenta de Cursor o claves de modelo, mantén cada archivo en local y obtén una biblioteca de diseño curada alrededor del agente que ya usas.", "ctaActions": [{"label": "Usa Cursor dentro de Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dale una estrella en GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Descarga la aplicación de escritorio", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Ver todos los agentes compatibles"},
      },
      'opencode': {
        ...en['opencode']!,
        title: "OpenCode para diseño — crea UI con el agente open-source",
        description: "Cómo diseñar UI y frontends con OpenCode — archivos design.md, skills de UI/UX, el MCP de Figma — y cómo Open Design convierte a OpenCode en un agente de diseño gratuito, local-first y open-source.",
        breadcrumb: "OpenCode",
        label: "Agente · OpenCode",
        heading: "OpenCode para diseño.",
        lead: "OpenCode es el agente de codificación con IA de terminal y open-source. Los diseñadores le acoplan skills de diseño y archivos DESIGN.md para generar UI real. Open Design lo convierte en un flujo de trabajo estructurado y open-source — usa tus claves de proveedor y mantén todo en local.",
        rich: {"heroCtaLead": "Open Design convierte a OpenCode en un agente de diseño open-source y local-first — cualquier modelo que elijas con tu propia clave de proveedor, tus archivos y una biblioteca curada de skills y sistemas de diseño a su alrededor.", "heroCtaActions": [{"label": "Usa OpenCode dentro de Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dale una estrella en GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Descarga la aplicación de escritorio", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenCode es un agente de codificación con IA, open-source y orientado a la terminal, que es deliberadamente agnóstico respecto al modelo: traes tu propia clave de proveedor y ejecutas el modelo que quieras detrás del mismo flujo de trabajo. Esa apertura lo convierte en una base natural para el trabajo de diseño — pero, como todo agente, solo produce buena UI cuando le das las referencias, skills y un bucle de verificación adecuados. Esta es una guía práctica y de extremo a extremo para usar OpenCode en trabajo de UI, frontend y sistemas de diseño, y para integrarlo en un flujo de trabajo de diseño estructurado con Open Design.", "Cubre qué es realmente OpenCode, por qué un agente abierto y agnóstico respecto al modelo encaja bien con el diseño, cómo configurarlo desde cero, el bucle de captura a UI, cómo AGENTS.md y MCP lo extienden, cómo se compara con Codex, Claude Code y Cursor, los escollos que hacen que el resultado de la IA parezca genérico y cómo Open Design cierra esa brecha como una capa de diseño abierta y local-first — un emparejamiento natural, ya que ambos proyectos son open-source y se ejecutan en tu propia máquina."], "heroImage": {"src": "/agents/opencode-design/opencode-design-hero.webp", "alt": "Bucle de retroalimentación de diseño de OpenCode: un agente TUI de terminal, un navegador renderizando la UI y un espacio de trabajo, con una flecha de retroalimentación que regresa en bucle", "caption": "El bucle central: OpenCode construye la UI en la terminal, la renderiza y verifica en un navegador real, e itera contra tus referencias — con el modelo que elijas."}, "tocLabel": "En esta página", "toc": [{"id": "what-is-opencode", "label": "Qué es realmente OpenCode"}, {"id": "why-design", "label": "Por qué un agente abierto y de cualquier modelo encaja con el diseño"}, {"id": "setup", "label": "Configura OpenCode para diseño (desde cero)"}, {"id": "screenshot-workflow", "label": "El flujo de trabajo de captura a UI"}, {"id": "extend", "label": "AGENTS.md, MCP y sesiones compartibles"}, {"id": "vs", "label": "OpenCode vs Codex vs Claude Code vs Cursor"}, {"id": "pitfalls", "label": "Escollos y el aspecto de “bazofia de IA”"}, {"id": "open-design", "label": "Diseñar con OpenCode en Open Design"}, {"id": "faq", "label": "Preguntas frecuentes"}], "sections": [{"id": "what-is-opencode", "heading": "Qué es realmente OpenCode", "blocks": [{"kind": "p", "text": "OpenCode es un agente de codificación con IA open-source construido para la terminal, mantenido por el equipo detrás de SST (Anomaly Innovations). Lee tu repositorio, ejecuta comandos, edita archivos y se comunica con un modelo de lenguaje grande — pero, a diferencia de los agentes atados a un proveedor, no incluye su propio modelo. Lo apuntas a cualquier proveedor y modelo que quieras y traes tu propia clave."}, {"kind": "p", "text": "Se ejecuta como una UI de terminal (TUI), con una aplicación de escritorio y extensiones de IDE sobre el mismo motor. Por debajo usa una arquitectura cliente/servidor, así que el agente que hace el trabajo está desacoplado de la superficie desde la que lo controlas. Dos agentes integrados — build y plan — se alternan con la tecla Tab."}, {"kind": "steps", "items": [{"label": "Agnóstico respecto al modelo", "body": "Los modelos y proveedores provienen de models.dev, un catálogo abierto. Los configuras en opencode.json con una cadena provider/model-id y puedes deshabilitar los proveedores que no quieras cargar — así el mismo flujo de trabajo de diseño se ejecuta sobre Anthropic, OpenAI, Google, OpenRouter, modelos locales y más."}, {"label": "Archivo de instrucciones", "body": "OpenCode lee un archivo AGENTS.md en tu proyecto (el estándar entre herramientas, también compatible con CLAUDE.md) para las reglas del proyecto — el lugar natural para codificar tus convenciones de diseño. Ejecuta /init para generar uno."}, {"label": "Extensible", "body": "Admite integración con LSP, servidores MCP, temas, atajos de teclado y comandos personalizados, además de enlaces de sesión compartibles para la colaboración."}]}, {"kind": "ul", "items": ["Mantenedor: SST / Anomaly Innovations (proyecto open-source)", "Credencial: tu(s) propia(s) clave(s) de API de proveedor de modelos — BYOK, sin atadura a un proveedor", "Licencia: MIT, open source"]}]}, {"id": "why-design", "heading": "Por qué un agente abierto y de cualquier modelo encaja con el trabajo de diseño", "blocks": [{"kind": "p", "text": "OpenCode no tiene un único “modelo de diseño” como sí lo tiene un agente de proveedor — y ese es el punto. Como es agnóstico respecto al modelo y abierto, puedes ejecutar el mismo flujo de trabajo de diseño sobre el modelo que actualmente sea mejor en frontend, cambiarlo después o recurrir a un modelo local, todo sin cambiar tu configuración."}, {"kind": "p", "text": "Pero la elección del modelo por sí sola no compra gusto. Como todo agente de codificación, OpenCode produce UI genérica a menos que le des restricciones. El buen resultado de diseño proviene de tres insumos que tú aportas."}, {"kind": "steps", "items": [{"label": "Un sistema de diseño", "body": "Tokens, primitivas y convenciones reales que el agente reutiliza, para que el resultado coincida con una marca en lugar de recaer en un aspecto genérico."}, {"label": "Una skill estética", "body": "Una skill curada que impone gusto real — movimiento contenido, jerarquía centrada en la marca, como máximo dos tipografías y un color de acento — y hace que el agente se comprometa con una dirección antes de construir."}, {"label": "Referencias concretas", "body": "Imágenes de referencia reales y varios estados (escritorio y móvil, hover, vacío, cargando), no una única toma principal."}]}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-taste-triangle.webp", "alt": "Diagrama que muestra el sistema de diseño, la skill y la imagen de referencia convergiendo en un buen resultado de diseño", "caption": "El gusto proviene de tres insumos que tú aportas: un sistema de diseño, una skill e imágenes de referencia reales — con independencia del modelo que ejecutes."}, {"kind": "p", "text": "La lección: OpenCode te da libertad de modelo, pero el gusto sigue proviniendo de un contexto de diseño curado. Open Design empaqueta exactamente esos insumos, y por eso ambos encajan — los dos son open-source y local-first (más abajo)."}]}, {"id": "setup", "heading": "Configura OpenCode para trabajo de diseño, desde cero", "blocks": [{"kind": "p", "text": "Este es el camino completo desde una máquina limpia hasta un OpenCode capaz de construir y verificar UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install OpenCode\ncurl -fsSL https://opencode.ai/install | bash\n# or: npm i -g opencode-ai@latest\n# or: brew install sst/tap/opencode\n\n# 2. Start the TUI in your project, then authenticate your provider\nopencode          # then run /login and pick your provider + paste your key\n\n# 3. Generate project context\nopencode          # inside your project, run /init to create AGENTS.md\n\n# 4. Pick your model (any provider, via models.dev)\n#    set \"provider/model-id\" in opencode.json or switch in the TUI\n\n# 5. Add an MCP server (optional, e.g. for design handoff)\n#    configure it under the \"mcp\" key in opencode.json"}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-setup-flow.webp", "alt": "Flujo de configuración de cinco pasos: instalar, autenticar con tu clave de proveedor, configurar AGENTS.md, añadir una skill, verificar", "caption": "La secuencia de configuración: instalar → autenticar (tu clave de proveedor) → configurar AGENTS.md → añadir una skill → verificar en un navegador real."}, {"kind": "steps", "items": [{"label": "Codifica tus reglas de diseño", "body": "Coloca tus tokens, primitivas y convenciones en AGENTS.md (o en un DESIGN.md referenciado desde él) para que el resultado coincida con una marca en lugar de recaer en un aspecto genérico. La opción instructions de opencode.json puede apuntar a archivos de reglas adicionales mediante globs."}, {"label": "Elige un modelo capaz", "body": "Como OpenCode es agnóstico respecto al modelo, elige el proveedor/modelo que actualmente sea más fuerte en frontend para la pasada de diseño — y mantén el resto de tu flujo de trabajo sin cambios."}]}]}, {"id": "screenshot-workflow", "heading": "El flujo de trabajo de captura a UI", "blocks": [{"kind": "p", "text": "El bucle de diseño de mayor apalancamiento con cualquier agente es convertir una imagen de referencia en una UI funcional y responsive e iterar hasta que coincida. La misma forma de cinco pasos aplica en OpenCode."}, {"kind": "ol", "items": ["Parte de las referencias visuales más claras que tengas — e incluye varios estados (escritorio y móvil, hover, vacío, cargando), no solo una única toma principal.", "Sé específico en el prompt; los prompts vagos producen UI genérica.", "Prepara un sistema de diseño e indícale a OpenCode dónde viven los tokens y las primitivas canónicas (en AGENTS.md).", "Ejecuta un servidor de desarrollo y haz que el agente renderice en un navegador real, redimensionando a los breakpoints para comprobar el resultado.", "Itera haciendo que OpenCode compare su implementación con las capturas — no solo que confirme que compila."]}, {"kind": "p", "text": "Referencia archivos con @ en la TUI para una búsqueda difusa de tu directorio de trabajo, ejecuta comandos de shell en línea con un ! inicial, y dirige las acciones con comandos /. Luego formula el prompt con restricciones concretas:"}, {"kind": "code", "lang": "bash", "code": "opencode\n# in the TUI:\n> @reference-desktop.png @reference-mobile.png\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from AGENTS.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, open it in a browser, and iterate until the\n  UI matches the references across breakpoints."}, {"kind": "p", "text": "Mantén los prompts pequeños y enfocados, confirma las buenas iteraciones y revierte las malas (diciéndole a OpenCode cuándo reviertes), para que cada pasada parta de una base limpia."}]}, {"id": "extend", "heading": "AGENTS.md, MCP y sesiones compartibles", "blocks": [{"kind": "p", "text": "Tres puntos de extensión hacen a OpenCode práctico para el trabajo de diseño sostenido, y los tres se mapean limpiamente sobre un flujo de trabajo de diseño abierto."}, {"kind": "steps", "items": [{"label": "Reglas de AGENTS.md", "body": "Las reglas del proyecto viven en un AGENTS.md en la raíz del repositorio (o reglas globales en ~/.config/opencode/AGENTS.md). Es el hogar duradero de tus convenciones de diseño, leído en cada ejecución, y es compatible con los archivos CLAUDE.md que usan otros agentes."}, {"label": "Servidores MCP", "body": "OpenCode admite servidores MCP tanto locales (command) como remotos (URL), configurados bajo la clave mcp — la forma portátil de incorporar contexto de diseño y herramientas externas que funcionan en todos los agentes, no solo en OpenCode."}, {"label": "Sesiones compartibles", "body": "El comando /share crea un enlace público a una conversación para colaboración o revisión, y /unshare lo revoca — útil para obtener feedback sobre una pasada de diseño."}]}, {"kind": "p", "text": "Estas son capacidades portátiles y multiagente — exactamente el tipo de cosa que Open Design está hecho para orquestar, en lugar de recrear en cada proyecto."}]}, {"id": "vs", "heading": "OpenCode vs Codex vs Claude Code vs Cursor para diseño", "blocks": [{"kind": "p", "text": "No hay un único ganador para el trabajo de diseño — cada agente tiene una fortaleza distinta, y los equipos con experiencia los combinan. Un resumen justo:"}, {"kind": "table", "columns": ["Agente", "Fortaleza de diseño", "Mejor para"], "rows": [["OpenCode", "Open-source y agnóstico respecto al modelo; ejecuta cualquier proveedor detrás de un único flujo de trabajo de terminal", "Libertad BYOK, cambio de modelo, configuraciones totalmente abiertas y local-first"], ["Codex", "Fuerte pulido visual con una skill de frontend; comprensión de imágenes", "Async delegado, compilaciones en sandbox, reglas portátiles de AGENTS.md"], ["Claude Code", "Decisiones de diseño específicas (hex, espaciado, tipografía) y UX consciente de la base de código", "Razonamiento de frontend y refactorizaciones de gran contexto"], ["Cursor", "Bucle visual de construir y ver con vista previa en vivo y ediciones en línea", "Trabajo de UI ajustado de iterar y observar dentro de un IDE"]]}, {"kind": "p", "text": "El veredicto recurrente de la comunidad es que el gusto proviene de las personas: todos recaen en una estética genérica sin skills, referencias y restricciones. Ese es el verdadero problema a resolver — y tiene forma de herramienta de diseño, no de modelo, que es precisamente por lo que un agente abierto como OpenCode encaja tan bien con una capa de diseño abierta."}]}, {"id": "pitfalls", "heading": "Escollos y cómo evitar el aspecto de “bazofia de IA”", "blocks": [{"kind": "p", "text": "La queja más común sobre el diseño generado por IA es que parece genérico — degradados suaves, paneles flotantes, esquinas redondeadas excesivas, sombras dramáticas, un aire de Inter-y-morado que “grita que esto lo hizo una IA”. Otros problemas reportados incluyen diseños móviles rotos e instrucciones que se filtran en el texto de la UI. Ninguno de estos es exclusivo de OpenCode; son lo que ocurre cuando cualquier agente se ejecuta sin un contexto de diseño curado."}, {"kind": "steps", "items": [{"label": "Añade una skill estética", "body": "Una skill de diseño curada obliga al agente a comprometerse con una dirección real en lugar del aspecto por defecto."}, {"label": "Verifica en un navegador real", "body": "Renderiza y autoverifica en distintos breakpoints para que los diseños no se rompan en silencio en móvil."}, {"label": "Aporta tokens y referencias", "body": "Los tokens de diseño reales y las capturas de referencia son la mayor palanca sobre la calidad del resultado."}, {"label": "Codifica reglas en AGENTS.md", "body": "Pon reglas de estilo como “sin tarjetas hero, máximo dos tipografías, jerarquía centrada en la marca” donde el agente las lea en cada ejecución."}]}, {"kind": "p", "text": "Observa que cada mitigación consiste en dar al agente un contexto de diseño curado — sin importar qué modelo ejecutes. Mantener ese contexto a mano, proyecto a proyecto, es el trabajo pesado que Open Design elimina."}]}, {"id": "open-design", "heading": "Diseñar con OpenCode dentro de Open Design", "blocks": [{"kind": "p", "text": "Open Design es la capa de diseño open-source que el flujo de trabajo anterior no deja de pedir. Trata a OpenCode como un adaptador de primera parte y lo envuelve en una biblioteca curada de skills y sistemas de diseño, una canalización de render estructurada y una UI de escritorio local — para que el contexto de diseño que hace bueno a cualquier agente esté ahí desde la primera ejecución, no se ensamble a mano cada vez. Ambos proyectos son open-source y local-first, lo que hace que el emparejamiento sea un encaje natural."}, {"kind": "ol", "items": ["Instala Open Design y selecciona OpenCode como tu agente.", "Autentícate con tu propia clave de API de proveedor de modelos (BYOK) — las credenciales permanecen en tu máquina y nunca pasan por nuestros servidores.", "Elige cualquier proveedor y modelo, además de un sistema de diseño y una skill, y luego genera presentaciones, prototipos y landing pages con un gusto consistente.", "Cada artefacto y archivo DESIGN.md vive en tu propio repositorio, no en una nube alojada."]}, {"kind": "p", "text": "El mismo agente OpenCode, la misma libertad de modelo — más un flujo de trabajo de diseño real, portátil y open-source a su alrededor. Es local-first y Apache-2.0, así que nada de tu trabajo ni de tus credenciales sale de tu máquina."}]}], "faqTitle": "Preguntas frecuentes", "faq": [{"name": "¿Puede OpenCode realmente hacer trabajo de diseño?", "text": "Sí — con una skill estética, un sistema de diseño e imágenes de referencia reales en contexto, OpenCode produce UI responsive de calidad de producción y puede verificarla en un navegador. Como es agnóstico respecto al modelo, ejecutas el modelo que actualmente sea mejor en frontend. Sin ese contexto curado tiende a recaer en un aspecto genérico, que es la brecha que Open Design cubre."}, {"name": "¿Qué modelo debería usar con OpenCode para diseño?", "text": "El que prefieras — OpenCode es agnóstico respecto al proveedor a través de models.dev, así que puedes ejecutar Anthropic, OpenAI, Google, OpenRouter o modelos locales detrás del mismo flujo de trabajo y cambiar en cualquier momento. La calidad del resultado de diseño depende mucho más de tu skill, tu sistema de diseño y tus referencias que del modelo por sí solo."}, {"name": "¿Open Design está hecho por el equipo de OpenCode (SST)?", "text": "No. Open Design es un proyecto open-source independiente que integra a OpenCode como agente. Complementa a OpenCode con una biblioteca de skills y sistemas de diseño abierta y local-first."}, {"name": "¿Necesito una suscripción especial para diseñar con OpenCode?", "text": "No — OpenCode es BYOK. Traes tu propia clave de API de proveedor de modelos, y Open Design nunca actúa como proxy de tus credenciales. No hay atadura a un proveedor."}, {"name": "¿OpenCode, Codex o Claude Code para diseño de frontend?", "text": "Todos son fuertes, y muchos equipos los combinan. La ventaja de OpenCode es ser totalmente open-source y agnóstico respecto al modelo; Codex destaca en compilaciones delegadas en sandbox; Claude Code es conocido por decisiones de diseño específicas y conscientes de la base de código. Open Design te permite cambiar de agente sin cambiar tu flujo de trabajo de diseño."}, {"name": "¿Cómo extiendo OpenCode para el contexto de diseño?", "text": "Codifica reglas en AGENTS.md, añade servidores MCP bajo la clave mcp para herramientas portátiles y contexto de diseño, y usa sesiones compartibles para la revisión. Open Design incluye una biblioteca curada de skills y sistemas de diseño para que te saltes la configuración por proyecto."}, {"name": "¿Está Open Design afiliado a OpenCode o SST?", "text": "No. OpenCode es un proyecto open-source mantenido por SST (Anomaly Innovations); Open Design es un proyecto open-source independiente que lo soporta como adaptador de primera parte."}, {"name": "¿Están seguros mis archivos y credenciales?", "text": "Sí — Open Design es local-first. Tus archivos, artefactos y DESIGN.md permanecen en tu propio repositorio, y tus credenciales de proveedor de modelos las usa directamente tu agente, sin enrutarse nunca a través de los servidores de Open Design."}], "ctaTitle": "Diseña con OpenCode, a la manera abierta.", "ctaBody": "Usa tu propia clave de proveedor de modelos, mantén cada archivo en local y obtén una biblioteca de diseño curada alrededor del agente abierto que ya usas.", "ctaActions": [{"label": "Usa OpenCode dentro de Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dale una estrella en GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Descarga la aplicación de escritorio", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Ver todos los agentes compatibles"},
      },
      'gemini': {
        ...en['gemini']!,
        title: "Gemini CLI para diseño — Open Design",
        description: "Cómo la gente usa el Gemini CLI de Google para diseño de interfaces y web: su comprensión multimodal de imágenes, el contexto de 1M de tokens, GEMINI.md y MCP, y cómo Open Design convierte Gemini CLI en un agente de diseño local-first y de código abierto.",
        breadcrumb: "Gemini CLI",
        label: "Agente · Gemini CLI",
        heading: "Gemini CLI para diseño.",
        lead: "Gemini CLI es el agente de terminal de código abierto de Google. Sus modelos multimodales leen capturas de pantalla y su contexto de 1M de tokens abarca todo un sistema de diseño, lo que lo convierte en una herramienta de diseño real, una vez que le proporcionas referencias, convenciones y un bucle de verificación. Open Design lo integra en un flujo de trabajo de diseño de código abierto: tu cuenta de Google o tu clave de API, tus archivos, local-first.",
        rich: {"heroCtaLead": "Open Design convierte Gemini CLI en un agente de diseño local-first y de código abierto: tu cuenta de Google o tu clave de API de Gemini, tus archivos y una biblioteca curada de skills y sistemas de diseño a su alrededor.", "heroCtaActions": [{"label": "Usa Gemini CLI dentro de Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Danos una estrella en GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Descarga la aplicación de escritorio", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Gemini CLI es el agente de IA de código abierto de Google para la terminal. Dos cosas lo hacen interesante específicamente para el diseño: sus modelos son fuertemente multimodales, así que lee una captura de pantalla y razona sobre la disposición, el espaciado y la jerarquía; y su ventana de contexto de 1M de tokens puede abarcar a la vez todo un sistema de diseño y una base de código. Combinado con las referencias y convenciones adecuadas y un bucle de verificación, construye interfaces reales y responsivas, y se puede empezar gratis con una cuenta de Google. Esta es una guía práctica y de principio a fin para usar Gemini CLI en trabajos de interfaz, frontend y sistemas de diseño, y para integrarlo en un flujo de trabajo de diseño estructurado con Open Design.", "Cubre qué es realmente Gemini CLI, por qué sus modelos multimodales y su enorme contexto encajan con el diseño, cómo configurarlo desde cero, el bucle de captura de pantalla a interfaz, cómo lo extienden GEMINI.md y MCP, cómo se compara con Codex, Claude Code y Cursor, los errores que hacen que el resultado de la IA parezca genérico, y cómo Open Design cierra la brecha como una capa de diseño abierta y local-first, un emparejamiento natural, ya que ambos son de código abierto y se ejecutan en tu propia máquina."], "heroImage": {"src": "/agents/gemini-design/gemini-design-hero.webp", "alt": "Bucle de retroalimentación de diseño de Gemini CLI: un agente de terminal leyendo una imagen de referencia, un navegador renderizando la interfaz y un espacio de trabajo, con una flecha de retroalimentación que vuelve atrás", "caption": "El bucle central: Gemini CLI lee tus referencias en la terminal, construye y verifica la interfaz en un navegador real, e itera frente a ellas, con todo un sistema de diseño en contexto."}, "tocLabel": "En esta página", "toc": [{"id": "what-is-gemini-cli", "label": "Qué es realmente Gemini CLI"}, {"id": "why-design", "label": "Por qué lo multimodal + el enorme contexto encajan con el diseño"}, {"id": "setup", "label": "Configura Gemini CLI para diseño (desde cero)"}, {"id": "screenshot-workflow", "label": "El flujo de captura de pantalla a interfaz"}, {"id": "extend", "label": "GEMINI.md, MCP y extensiones"}, {"id": "vs", "label": "Gemini CLI vs Codex vs Claude Code vs Cursor"}, {"id": "pitfalls", "label": "Errores y el aspecto de «basura de IA»"}, {"id": "open-design", "label": "Diseñar con Gemini CLI en Open Design"}, {"id": "faq", "label": "Preguntas frecuentes"}], "sections": [{"id": "what-is-gemini-cli", "heading": "Qué es realmente Gemini CLI", "blocks": [{"kind": "p", "text": "Gemini CLI es un agente de IA de código abierto (Apache-2.0) que Google ofrece para la terminal. Lee tu repositorio, edita archivos, ejecuta comandos de shell, consulta la web y puede fundamentar las respuestas con Google Search, planificando y verificando el trabajo a partir de tareas en lenguaje natural en lugar de simplemente completar líneas. El mismo motor también impulsa el agente de Gemini Code Assist dentro de VS Code."}, {"kind": "p", "text": "Para el trabajo de diseño destacan dos propiedades. Sus modelos son nativamente multimodales, así que puedes entregarle una captura de pantalla y razona sobre la disposición real. Y su ventana de contexto alcanza hasta 1M de tokens, lo bastante grande para abarcar a la vez todo tu sistema de diseño, tu biblioteca de componentes y tu conjunto de referencias en lugar de resumirlos."}, {"kind": "steps", "items": [{"label": "Archivos de contexto", "body": "Gemini CLI lee un archivo GEMINI.md para obtener contexto persistente del proyecto, el lugar natural para codificar tus convenciones de diseño, tokens y listas de revisión. Las configuraciones personales y de equipo se superponen encima."}, {"label": "Herramientas integradas + MCP", "body": "Incluye de fábrica herramientas de archivos, shell, web-fetch y Google Search, y admite servidores MCP (configurados en ~/.gemini/settings.json) para añadir contexto externo, como un archivo de Figma en vivo."}, {"label": "Gratis para empezar", "body": "Iniciar sesión con una cuenta personal de Google ofrece un generoso nivel gratuito de solicitudes a Gemini; también puedes aportar una clave de API de Gemini o usar Vertex AI."}]}, {"kind": "ul", "items": ["Proveedor: Google", "Credencial: cuenta de Google (nivel gratuito) o clave de API de Gemini desde AI Studio (BYOK) o Vertex AI", "Licencia: Apache-2.0, código abierto"]}]}, {"id": "why-design", "heading": "Por qué los modelos multimodales y un enorme contexto encajan con el diseño", "blocks": [{"kind": "p", "text": "La ventaja de Gemini CLI en diseño proviene de dos propiedades del modelo, pero, como con todo agente, el buen gusto aún hay que aportarlo."}, {"kind": "steps", "items": [{"label": "Sólida comprensión multimodal", "body": "Como los modelos de Gemini son nativamente multimodales, el agente lee bien las capturas de pantalla de referencia, comparando su resultado renderizado con una imagen en lugar de adivinar a partir de una descripción en prosa."}, {"label": "Una ventana de contexto de 1M de tokens", "body": "Un contexto amplio significa que todo el sistema de diseño, los tokens y muchos estados de referencia caben a la vez, así que el agente reutiliza tus primitivas reales en lugar de inventar estilos puntuales."}, {"label": "Convenciones en GEMINI.md", "body": "Un GEMINI.md (más el servidor MCP de Figma) dirige al agente hacia tus tokens, componentes y especificaciones reales, así que trabaja sobre una marca en lugar de un aspecto por defecto."}]}, {"kind": "image", "src": "/agents/gemini-design/gemini-design-taste-triangle.webp", "alt": "Diagrama que muestra un sistema de diseño, un skill y una imagen de referencia convergiendo en un buen resultado de diseño", "caption": "El buen gusto proviene de tres entradas que tú aportas: un sistema de diseño, un skill e imágenes de referencia reales."}, {"kind": "p", "text": "La lección es la misma que enseña todo agente: Gemini CLI no tiene buen gusto por defecto. Produce buen diseño cuando le das restricciones: un sistema de diseño, un skill estético y referencias concretas. Open Design empaqueta exactamente esas entradas, y por eso ambos encajan (más abajo)."}]}, {"id": "setup", "heading": "Configura Gemini CLI para trabajo de diseño, desde cero", "blocks": [{"kind": "p", "text": "Este es el camino completo desde una máquina limpia hasta un Gemini CLI capaz de construir y verificar interfaces."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Gemini CLI (Node 20+)\nnpm install -g @google/gemini-cli\n# or run without installing: npx https://github.com/google-gemini/gemini-cli\n\n# 2. Start it in your project and authenticate on first run\ncd your-project\ngemini            # sign in with your Google account, or set GEMINI_API_KEY\n\n# 3. Generate project context\n/init             # scaffolds a GEMINI.md for this project\n\n# 4. Wire the Figma MCP server (optional, for design handoff)\n#    add it under \"mcpServers\" in ~/.gemini/settings.json"}, {"kind": "image", "src": "/agents/gemini-design/gemini-design-setup-flow.webp", "alt": "Flujo de configuración de cinco pasos: instalar, autenticar, configurar GEMINI.md, añadir un skill, verificar", "caption": "La secuencia de configuración: instalar → autenticar → configurar GEMINI.md → añadir un skill → habilitar la verificación en el navegador."}, {"kind": "steps", "items": [{"label": "Codifica tus reglas de diseño", "body": "Pon tus tokens, primitivas y convenciones en GEMINI.md y apunta a Gemini hacia ellos, para que el resultado coincida con una marca en lugar de recurrir a un aspecto genérico."}, {"label": "Añade verificación en el navegador", "body": "Integra Playwright o un MCP de navegador para que Gemini renderice en un navegador real y compruebe su resultado en distintos breakpoints, en lugar de solo confirmar que la compilación pasa."}]}]}, {"id": "screenshot-workflow", "heading": "El flujo de captura de pantalla a interfaz", "blocks": [{"kind": "p", "text": "El bucle de diseño de mayor apalancamiento con Gemini CLI es convertir una imagen de referencia en una interfaz funcional y responsiva e iterar hasta que coincida, apoyándose en el modelo multimodal para comparar el resultado con la referencia."}, {"kind": "ol", "items": ["Parte de las referencias visuales más claras que tengas, e incluye múltiples estados (escritorio y móvil, hover, vacío, cargando), no solo una sola toma principal.", "Sé específico en el prompt; los prompts vagos producen interfaces genéricas incluso con un modelo potente.", "Mantén tu sistema de diseño y tus convenciones en GEMINI.md, e indícale a Gemini dónde viven los tokens y las primitivas canónicas.", "Ejecuta un servidor de desarrollo y haz que Gemini renderice en un navegador real, redimensionando a los breakpoints para comprobar el resultado.", "Itera haciendo que Gemini compare su implementación con las capturas de pantalla, no que solo confirme que compila."]}, {"kind": "p", "text": "Referencia una imagen con @ para adjuntarla al prompt, y luego da restricciones concretas:"}, {"kind": "code", "lang": "bash", "code": "gemini\n# in the prompt:\n> @reference-desktop.png @reference-mobile.png\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from GEMINI.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the references\n  across breakpoints."}, {"kind": "p", "text": "Mantén los prompts pequeños y enfocados, confirma (commit) las buenas iteraciones y revierte las malas (indicándole a Gemini cuándo reviertes), para que cada pasada se construya sobre una base limpia."}]}, {"id": "extend", "heading": "GEMINI.md, MCP y extensiones", "blocks": [{"kind": "p", "text": "Tres puntos de extensión hacen que Gemini CLI sea práctico para un trabajo de diseño sostenido, y los tres se asignan limpiamente a un flujo de trabajo de diseño abierto."}, {"kind": "steps", "items": [{"label": "Contexto en GEMINI.md", "body": "Las reglas del proyecto viven en un GEMINI.md en la raíz del repositorio (con capas global y de equipo). Es el hogar duradero de tus convenciones de diseño, leído en cada ejecución."}, {"label": "Servidores MCP", "body": "Configura servidores MCP en ~/.gemini/settings.json, la forma portátil de incorporar contexto de diseño y herramientas externas, sobre todo el servidor MCP de Figma, que funcionan en distintos agentes, no solo en Gemini."}, {"label": "Extensiones y herramientas integradas", "body": "Las extensiones de Gemini CLI y sus herramientas integradas de Google Search, archivos, shell y web-fetch le permiten reunir referencias y ejecutar el bucle de verificación sin salir de la terminal."}]}, {"kind": "p", "text": "Estas son capacidades portátiles y multiagente, exactamente el tipo de cosas que Open Design está diseñado para orquestar, en lugar de recrearlas en cada proyecto."}]}, {"id": "vs", "heading": "Gemini CLI vs Codex vs Claude Code vs Cursor para diseño", "blocks": [{"kind": "p", "text": "No hay un único ganador para el trabajo de diseño: cada agente tiene una fortaleza distinta, y los equipos con experiencia los combinan. Un resumen justo:"}, {"kind": "table", "columns": ["Agente", "Fortaleza en diseño", "Ideal para"], "rows": [["Gemini CLI", "Sólida comprensión multimodal de imágenes y un contexto de 1M de tokens; código abierto con un nivel gratuito", "Trabajo intensivo en capturas de pantalla y mantener todo un sistema de diseño en contexto"], ["Codex", "Buen acabado visual con un skill de frontend; compilaciones asíncronas en entorno aislado", "Compilaciones asíncronas delegadas y reglas portátiles en AGENTS.md"], ["Claude Code", "Decisiones de diseño específicas (hex, espaciado, tipografía) y UX consciente de la base de código", "Razonamiento de frontend y refactorizaciones con gran contexto"], ["Cursor", "Bucle visual de construir y ver con vista previa en vivo y ediciones en línea", "Trabajo de interfaz ágil de iterar y observar dentro de un IDE"]]}, {"kind": "p", "text": "El veredicto recurrente de la comunidad es que el buen gusto proviene de las personas: todos recurren a una estética genérica sin skills, referencias ni restricciones. Ese es el verdadero problema a resolver, y tiene forma de herramienta de diseño, no de modelo."}]}, {"id": "pitfalls", "heading": "Errores, y cómo evitar el aspecto de «basura de IA»", "blocks": [{"kind": "p", "text": "La queja más común sobre el diseño generado por IA es que parece genérico: degradados suaves, paneles flotantes, esquinas redondeadas excesivas, sombras dramáticas, un rollo de Inter y morado que «grita que esto lo hizo una IA». Otros problemas reportados incluyen diseños móviles rotos e instrucciones que se filtran en los textos de la interfaz. Ninguno de estos es exclusivo de Gemini CLI; es lo que ocurre cuando cualquier agente se ejecuta sin un contexto de diseño curado."}, {"kind": "steps", "items": [{"label": "Añade un skill estético", "body": "Un skill de diseño curado obliga al agente a comprometerse con una dirección real en lugar del aspecto por defecto."}, {"label": "Verifica en un navegador real", "body": "Usa el modelo multimodal para renderizar y autocomprobarse en distintos breakpoints, de modo que los diseños no se rompan silenciosamente en móvil."}, {"label": "Aporta tokens y referencias", "body": "Los tokens de diseño reales y las capturas de pantalla de referencia son la mayor palanca individual sobre la calidad del resultado."}, {"label": "Codifica reglas en GEMINI.md", "body": "Pon reglas del estilo «nada de tarjetas hero, máximo dos tipografías, jerarquía con la marca primero» donde el agente las lea en cada ejecución."}]}, {"kind": "p", "text": "Fíjate en que toda mitigación consiste en darle al agente un contexto de diseño curado. Mantener ese contexto a mano, proyecto a proyecto, es el trabajo tedioso que Open Design elimina."}]}, {"id": "open-design", "heading": "Diseñar con Gemini CLI dentro de Open Design", "blocks": [{"kind": "p", "text": "Open Design es la capa de diseño de código abierto que el flujo de trabajo anterior no deja de pedir. Trata a Gemini CLI como un adaptador de primera categoría y lo envuelve en una biblioteca curada de skills y sistemas de diseño, una canalización de renderizado estructurada y una interfaz de escritorio local, para que el contexto de diseño que hace bueno a Gemini esté ahí desde la primera ejecución, no se arme a mano cada vez. Ambos son de código abierto y local-first, lo que hace que el emparejamiento sea natural."}, {"kind": "ol", "items": ["Instala Open Design y selecciona Gemini CLI como tu agente.", "Autentícate con tu cuenta de Google o tu clave de API de Gemini (BYOK): las credenciales se quedan en tu máquina y nunca pasan por nuestros servidores.", "Elige un sistema de diseño y un skill, y luego genera presentaciones, prototipos y páginas de aterrizaje con un gusto consistente.", "Cada artefacto y archivo DESIGN.md vive en tu propio repositorio, no en una nube alojada."]}, {"kind": "p", "text": "El mismo agente Gemini CLI, la misma clave, más un flujo de trabajo de diseño real, portátil y de código abierto a su alrededor. Es local-first y Apache-2.0, así que nada de tu trabajo ni de tus credenciales sale de tu máquina."}]}], "faqTitle": "Preguntas frecuentes", "faq": [{"name": "¿Gemini CLI puede realmente hacer trabajo de diseño?", "text": "Sí; con un skill estético, un sistema de diseño e imágenes de referencia reales en contexto, Gemini CLI produce interfaces responsivas de calidad de producción, y sus sólidos modelos multimodales verifican el resultado frente a las referencias. Sin ese contexto tiende a recurrir a un aspecto genérico, que es la brecha que Open Design rellena."}, {"name": "¿Necesito pagar para diseñar con Gemini CLI?", "text": "No; iniciar sesión con una cuenta de Google ofrece un generoso nivel gratuito, y también puedes aportar una clave de API de Gemini (BYOK) o usar Vertex AI. Open Design nunca enruta tus credenciales en ningún caso."}, {"name": "¿Qué hace que Gemini CLI sea bueno para el diseño en particular?", "text": "Dos cosas: sus modelos son fuertemente multimodales, así que lee bien las capturas de pantalla de referencia, y su contexto de 1M de tokens puede abarcar a la vez todo un sistema de diseño y un conjunto de referencias. Ambas ayudan, pero el buen gusto aún proviene del sistema de diseño, el skill y las referencias que tú aportas."}, {"name": "¿Gemini CLI o Claude Code para diseño de frontend?", "text": "Ambos son potentes. Claude Code es conocido por decisiones de diseño específicas y conscientes de la base de código; la ventaja de Gemini CLI es la comprensión multimodal más un enorme contexto y un nivel gratuito. Muchos equipos usan ambos: Open Design te permite cambiar de agente sin cambiar tu flujo de trabajo de diseño."}, {"name": "¿Cómo conecto Gemini CLI con Figma?", "text": "Añade el servidor MCP de Figma en mcpServers, dentro de ~/.gemini/settings.json. Gemini puede entonces extraer contexto de diseño real (componentes, variables, datos de disposición) para que el código generado coincida con la fuente en lugar de aproximarla."}, {"name": "¿Open Design está afiliado a Google?", "text": "No. Gemini CLI es un producto de Google; Open Design es un proyecto independiente de código abierto que lo admite como adaptador de primera categoría. Gemini es una marca registrada de Google."}, {"name": "¿Están seguros mis archivos y mis credenciales?", "text": "Sí; Open Design es local-first y Apache-2.0. Tus archivos, artefactos y DESIGN.md permanecen en tu propio repositorio, y tus credenciales de Google las usa directamente tu agente, nunca se enrutan a través de los servidores de Open Design."}], "ctaTitle": "Diseña con Gemini CLI, a la manera abierta.", "ctaBody": "Aporta tu propia cuenta de Google o clave de API de Gemini, mantén cada archivo en local y obtén una biblioteca de diseño curada en torno al agente que ya usas.", "ctaActions": [{"label": "Usa Gemini CLI dentro de Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Danos una estrella en GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Descarga la aplicación de escritorio", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Ver todos los agentes compatibles"},
      },
      'copilot': {
        ...en['copilot']!,
        title: "GitHub Copilot CLI para diseño — Open Design",
        description: "Cómo se usa GitHub Copilot CLI para diseño de interfaces y web — su agente de programación nativo de terminal, sus archivos de instrucciones personalizadas, su compatibilidad con MCP y su elección de varios modelos — y cómo Open Design convierte Copilot CLI en un agente de diseño local-first y de código abierto.",
        breadcrumb: "GitHub Copilot CLI",
        label: "Agente · GitHub Copilot CLI",
        heading: "GitHub Copilot CLI para diseño.",
        lead: "GitHub Copilot CLI es el agente de programación nativo de terminal de GitHub. Planifica y edita en todo tu repositorio, elige entre modelos de frontera como Claude y GPT, y lee las instrucciones de tu repositorio, lo que lo convierte en una verdadera herramienta de diseño una vez que le das referencias, convenciones y un bucle de verificación. Open Design lo integra en un flujo de trabajo de diseño de código abierto: tu suscripción a GitHub Copilot, tus archivos, local-first.",
        rich: {"heroCtaLead": "Open Design convierte GitHub Copilot CLI en un agente de diseño local-first y de código abierto: tu suscripción a GitHub Copilot, tus archivos y una biblioteca curada de skills y sistemas de diseño a su alrededor.", "heroCtaActions": [{"label": "Usa Copilot CLI dentro de Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dale una estrella en GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Descarga la aplicación de escritorio", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["GitHub Copilot CLI es el agente de programación nativo de terminal de GitHub: el mismo entorno agéntico que impulsa el agente de programación de Copilot, llevado a tu línea de comandos. Dos cosas lo hacen interesante específicamente para diseño: lee las instrucciones de tu repositorio y AGENTS.md, de modo que tus convenciones de diseño viajan con el agente en cada ejecución; y te permite elegir entre modelos de frontera de Anthropic, OpenAI y Google según la tarea, así que puedes optar por el que razona mejor sobre una interfaz dada. Combinado con las referencias, convenciones y un bucle de verificación adecuados, construye interfaces reales y adaptables, y funciona con la suscripción de Copilot que quizá ya tengas. Esta es una guía práctica y de extremo a extremo para usar Copilot CLI en trabajo de interfaces, frontend y sistemas de diseño, y para integrarlo en un flujo de trabajo de diseño estructurado con Open Design.", "Cubre qué es realmente Copilot CLI, por qué las instrucciones de repositorio y la elección de modelo encajan con el diseño, cómo configurarlo desde cero, el bucle de captura de pantalla a interfaz, cómo lo amplían las instrucciones personalizadas y MCP, cómo se compara con Codex, Claude Code, Cursor y Gemini CLI, los obstáculos que hacen que la salida de la IA parezca genérica, y cómo Open Design cierra la brecha como una capa de diseño abierta y local-first: tu suscripción y tus credenciales permanecen en tu máquina, y tus artefactos permanecen en tu propio repositorio."], "heroImage": {"src": "/agents/copilot-design/copilot-design-hero.webp", "alt": "Bucle de retroalimentación de diseño de GitHub Copilot CLI: un agente de terminal leyendo una imagen de referencia, un navegador renderizando la interfaz y un espacio de trabajo, con una flecha de retroalimentación que vuelve al inicio", "caption": "El bucle central: Copilot CLI lee tus referencias en la terminal, construye y verifica la interfaz en un navegador real e itera frente a ellas, con tus convenciones de diseño en las instrucciones del repositorio."}, "tocLabel": "En esta página", "toc": [{"id": "what-is-copilot", "label": "Qué es realmente GitHub Copilot CLI"}, {"id": "why-design", "label": "Por qué las instrucciones + la elección de modelo encajan con el diseño"}, {"id": "setup", "label": "Configura Copilot CLI para diseño (desde cero)"}, {"id": "screenshot-workflow", "label": "El flujo de trabajo de captura de pantalla a interfaz"}, {"id": "extend", "label": "Instrucciones personalizadas, MCP y extensiones"}, {"id": "vs", "label": "Copilot CLI vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Obstáculos y el aspecto de «IA descuidada»"}, {"id": "open-design", "label": "Diseñar con Copilot CLI en Open Design"}, {"id": "faq", "label": "Preguntas frecuentes"}], "sections": [{"id": "what-is-copilot", "heading": "Qué es realmente GitHub Copilot CLI", "blocks": [{"kind": "p", "text": "GitHub Copilot CLI es el agente de programación nativo de terminal de GitHub. Lee tu repositorio, edita archivos, ejecuta comandos de shell y trabaja directamente con tu contexto de GitHub —issues, pull requests y repositorios— autenticado con tu cuenta de GitHub existente. Está impulsado por el mismo entorno agéntico que el agente de programación de Copilot de GitHub, de modo que planifica tareas complejas e itera en lugar de limitarse a completar líneas. Alcanzó la disponibilidad general en febrero de 2026, tras una versión preliminar pública que se abrió en septiembre de 2025."}, {"kind": "p", "text": "Para el trabajo de diseño, destacan dos propiedades. Lee archivos de instrucciones personalizadas —reglas para todo el repositorio en .github/copilot-instructions.md más AGENTS.md—, así que tus convenciones de diseño se incluyen automáticamente en cada ejecución. Y admite múltiples proveedores de modelos fundacionales, de modo que puedes cambiar de modelo según la tarea con el comando /model, optando por el que mejor razona sobre una interfaz dada."}, {"kind": "steps", "items": [{"label": "Archivos de instrucciones", "body": "Copilot CLI lee las instrucciones del repositorio en .github/copilot-instructions.md, los archivos específicos por ruta dentro de .github/instructions y AGENTS.md, el lugar natural para codificar tus convenciones de diseño, tokens y listas de comprobación de revisión."}, {"label": "Herramientas integradas + MCP", "body": "Viene con el servidor MCP de GitHub integrado y ejecuta herramientas de archivos y shell, y puedes añadir servidores MCP personalizados con /mcp add (almacenados en mcp-config.json dentro de ~/.copilot) para contexto externo, como un archivo de Figma en vivo."}, {"label": "Elección de modelo", "body": "Usa el comando /model para elegir entre modelos de frontera de Anthropic, OpenAI y Google, cambiando según la tarea, todo con tu suscripción existente de Copilot."}]}, {"kind": "ul", "items": ["Proveedor: GitHub", "Credencial: una suscripción activa a GitHub Copilot (Pro, Pro+, Business o Enterprise)", "Instalación: npm install -g @github/copilot, luego ejecuta copilot"]}]}, {"id": "why-design", "heading": "Por qué las instrucciones de repositorio y la elección de modelo encajan con el diseño", "blocks": [{"kind": "p", "text": "La ventaja de Copilot CLI para diseño proviene de dos propiedades, pero, como con todo agente, el buen gusto sigue teniendo que aportarse."}, {"kind": "steps", "items": [{"label": "Convenciones que viajan con el repositorio", "body": "Como Copilot CLI lee .github/copilot-instructions.md y AGENTS.md automáticamente, tus tokens, primitivas y reglas de revisión están en contexto en cada ejecución: el agente trabaja contra una marca en lugar de un aspecto por defecto."}, {"label": "Elige el modelo adecuado por tarea", "body": "La elección de modelo entre Anthropic, OpenAI y Google significa que puedes recurrir al modelo que mejor razona sobre una maquetación dada y luego cambiar para la siguiente tarea, sin modificar tu flujo de trabajo."}, {"label": "Especificaciones reales mediante MCP", "body": "El servidor MCP de GitHub integrado más un servidor MCP de Figma dirigen al agente a tus tokens, componentes y especificaciones reales, para que construya desde la fuente en lugar de aproximarla."}]}, {"kind": "image", "src": "/agents/copilot-design/copilot-design-taste-triangle.webp", "alt": "Diagrama que muestra cómo el sistema de diseño, el skill y la imagen de referencia convergen en una buena salida de diseño", "caption": "El buen gusto proviene de tres insumos que tú aportas: un sistema de diseño, un skill e imágenes de referencia reales."}, {"kind": "p", "text": "La lección es la misma que enseña cada agente: Copilot CLI no tiene buen gusto por defecto. Produce buen diseño cuando le das restricciones: un sistema de diseño, un skill estético y referencias concretas. Open Design empaqueta exactamente esos insumos, y por eso ambos encajan (más abajo, con más detalle)."}]}, {"id": "setup", "heading": "Configura Copilot CLI para trabajo de diseño, desde cero", "blocks": [{"kind": "p", "text": "Este es el camino completo desde una máquina limpia hasta un Copilot CLI capaz de construir y verificar interfaces."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Copilot CLI (Node.js required)\nnpm install -g @github/copilot\n\n# 2. Start it in your project and authenticate on first run\ncd your-project\ncopilot           # run /login and follow the prompts to sign in\n\n# 3. Choose a model for the task\n#    inside the session:\n/model            # pick a frontier model from Anthropic, OpenAI, or Google\n\n# 4. Add custom instructions and the Figma MCP server (optional)\n#    write .github/copilot-instructions.md or AGENTS.md\n/mcp add          # add the Figma MCP server for design handoff"}, {"kind": "image", "src": "/agents/copilot-design/copilot-design-setup-flow.webp", "alt": "Flujo de configuración de cinco pasos: instalar, autenticarse, elegir un modelo, configurar instrucciones, verificar", "caption": "La secuencia de configuración: instalar → autenticarse → elegir un modelo → escribir instrucciones → habilitar la verificación en el navegador."}, {"kind": "steps", "items": [{"label": "Codifica tus reglas de diseño", "body": "Pon tus tokens, primitivas y convenciones en .github/copilot-instructions.md o AGENTS.md, para que la salida coincida con una marca en lugar de recurrir a un aspecto genérico."}, {"label": "Añade verificación en el navegador", "body": "Conecta un MCP de Playwright o de navegador para que Copilot renderice en un navegador real y compruebe su salida en distintos puntos de quiebre, en lugar de limitarse a confirmar que la compilación pasa."}]}]}, {"id": "screenshot-workflow", "heading": "El flujo de trabajo de captura de pantalla a interfaz", "blocks": [{"kind": "p", "text": "El bucle de diseño de mayor impacto con Copilot CLI es convertir una imagen de referencia en una interfaz funcional y adaptable e iterar hasta que coincida, apoyándose en un modelo multimodal potente para comparar la salida con la referencia."}, {"kind": "ol", "items": ["Parte de las referencias visuales más claras que tengas, e incluye varios estados (escritorio y móvil, hover, vacío, cargando), no solo una captura principal.", "Sé específico en el prompt; los prompts vagos producen interfaces genéricas incluso con un modelo potente.", "Mantén tu sistema de diseño y convenciones en .github/copilot-instructions.md o AGENTS.md, e indícale a Copilot dónde viven los tokens y las primitivas canónicas.", "Ejecuta un servidor de desarrollo y haz que Copilot renderice en un navegador real, redimensionando a los puntos de quiebre para comprobar el resultado.", "Itera haciendo que Copilot compare su implementación con las capturas, no que se limite a confirmar que compila."]}, {"kind": "p", "text": "Dirige a Copilot a tus imágenes de referencia y dale restricciones concretas; previsualiza cada edición de archivo o comando para tu aprobación antes de ejecutarlo:"}, {"kind": "code", "lang": "bash", "code": "copilot\n# in the prompt:\n> Implement the design in reference-desktop.png and reference-mobile.png\n  in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens described in\n  .github/copilot-instructions.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the references\n  across breakpoints."}, {"kind": "p", "text": "Mantén los prompts pequeños y enfocados, confirma las buenas iteraciones y revierte las malas (avisándole a Copilot cuando reviertas), para que cada pasada se construya sobre una base limpia."}]}, {"id": "extend", "heading": "Instrucciones personalizadas, MCP y extensiones", "blocks": [{"kind": "p", "text": "Tres puntos de extensión hacen que Copilot CLI sea práctico para trabajo de diseño sostenido, y los tres encajan limpiamente en un flujo de trabajo de diseño abierto."}, {"kind": "steps", "items": [{"label": "Instrucciones personalizadas", "body": "Las reglas del repositorio viven en .github/copilot-instructions.md (con archivos específicos por ruta dentro de .github/instructions y AGENTS.md). Son el hogar duradero de tus convenciones de diseño, incluidas automáticamente en cada ejecución."}, {"label": "Servidores MCP", "body": "Copilot CLI viene con el servidor MCP de GitHub integrado y te permite añadir servidores personalizados mediante /mcp add (almacenados en mcp-config.json dentro de ~/.copilot): la forma portátil de incorporar contexto de diseño, sobre todo el servidor MCP de Figma, que funciona entre agentes, no solo en Copilot."}, {"label": "Agentes especializados y herramientas integradas", "body": "Los modos especializados de Copilot CLI —para explorar la base de código, ejecutar compilaciones y pruebas, revisar cambios y planificar— más sus herramientas de archivos y shell le permiten reunir referencias y ejecutar el bucle de verificación sin salir de la terminal."}]}, {"kind": "p", "text": "Estas son capacidades portátiles y multiagente, exactamente el tipo de cosas que Open Design está diseñado para orquestar, en lugar de recrearlas en cada proyecto."}]}, {"id": "vs", "heading": "Copilot CLI vs Codex vs Claude Code vs Cursor vs Gemini CLI para diseño", "blocks": [{"kind": "p", "text": "No hay un único ganador para el trabajo de diseño: cada agente tiene una fortaleza distinta, y los equipos con experiencia los combinan. Un resumen justo:"}, {"kind": "table", "columns": ["Agente", "Fortaleza de diseño", "Ideal para"], "rows": [["Copilot CLI", "Elección de varios modelos (Anthropic, OpenAI, Google) e integración profunda con GitHub en tu suscripción de Copilot", "Elegir el mejor modelo por tarea y trabajo guiado por instrucciones ligado a tu repositorio de GitHub"], ["Codex", "Gran pulido visual con un skill de frontend; compilaciones asíncronas en sandbox", "Compilaciones asíncronas delegadas y reglas portátiles de AGENTS.md"], ["Claude Code", "Decisiones de diseño específicas (hex, espaciado, tipografía) y UX consciente de la base de código", "Razonamiento de frontend y refactorizaciones de gran contexto"], ["Cursor", "Bucle visual de construir y ver con vista previa en vivo y ediciones en línea", "Trabajo de interfaz ajustado de iterar y observar dentro de un IDE"], ["Gemini CLI", "Sólida comprensión de imágenes multimodal y un contexto de 1M de tokens; de código abierto con un plan gratuito", "Trabajo con muchas capturas de pantalla y mantener todo un sistema de diseño en contexto"]]}, {"kind": "p", "text": "El veredicto recurrente de la comunidad es que el buen gusto proviene de las personas: todos recurren por defecto a una estética genérica sin skills, referencias y restricciones. Ese es el verdadero problema a resolver, y tiene forma de herramienta de diseño, no de modelo."}]}, {"id": "pitfalls", "heading": "Obstáculos y cómo evitar el aspecto de «IA descuidada»", "blocks": [{"kind": "p", "text": "La queja más común sobre el diseño generado por IA es que parece genérico: degradados suaves, paneles flotantes, esquinas redondeadas demasiado grandes, sombras dramáticas, un aire de Inter y morado que «grita que esto lo hizo una IA». Otros problemas reportados incluyen maquetaciones móviles rotas e instrucciones que se filtran en el texto de la interfaz. Ninguno de ellos es exclusivo de Copilot CLI; son lo que ocurre cuando cualquier agente se ejecuta sin un contexto de diseño curado."}, {"kind": "steps", "items": [{"label": "Añade un skill estético", "body": "Un skill de diseño curado obliga al agente a comprometerse con una dirección real en lugar del aspecto por defecto."}, {"label": "Verifica en un navegador real", "body": "Renderiza y autoverifica en distintos puntos de quiebre con un MCP de navegador para que las maquetaciones no se rompan en silencio en móvil."}, {"label": "Aporta tokens y referencias", "body": "Los tokens de diseño reales y las capturas de referencia son la mayor palanca individual sobre la calidad de la salida."}, {"label": "Codifica reglas en instrucciones personalizadas", "body": "Pon reglas de estilo como «sin tarjetas hero, máximo dos tipografías, jerarquía centrada en la marca» en .github/copilot-instructions.md o AGENTS.md, donde el agente las lee en cada ejecución."}]}, {"kind": "p", "text": "Fíjate en que toda mitigación consiste en dar al agente un contexto de diseño curado. Mantener ese contexto a mano, proyecto a proyecto, es la tarea pesada que Open Design elimina."}]}, {"id": "open-design", "heading": "Diseñar con Copilot CLI dentro de Open Design", "blocks": [{"kind": "p", "text": "Open Design es la capa de diseño de código abierto que el flujo de trabajo anterior no deja de pedir. Trata a GitHub Copilot CLI como un adaptador de primera categoría y lo envuelve en una biblioteca curada de skills y sistemas de diseño, una canalización de renderizado estructurada y una interfaz de escritorio local, de modo que el contexto de diseño que hace bueno a Copilot está ahí desde la primera ejecución, no ensamblado a mano cada vez. Open Design es independiente, de código abierto (Apache-2.0) y local-first, y por eso la combinación encaja: el agente hace el trabajo, y tus archivos y credenciales siguen siendo tuyos."}, {"kind": "ol", "items": ["Instala Open Design y selecciona GitHub Copilot CLI como tu agente.", "Autentícate con tu suscripción a GitHub Copilot: las credenciales permanecen en tu máquina y nunca pasan por nuestros servidores.", "Elige un sistema de diseño y un skill, y luego genera presentaciones, prototipos y páginas de aterrizaje con un gusto consistente.", "Cada artefacto y archivo DESIGN.md vive en tu propio repositorio, no en una nube alojada."]}, {"kind": "p", "text": "El mismo agente Copilot CLI, la misma suscripción, más un flujo de trabajo de diseño real, portátil y de código abierto a su alrededor. Open Design es local-first y Apache-2.0, así que nada de tu trabajo ni de tus credenciales sale de tu máquina."}]}], "faqTitle": "Preguntas frecuentes", "faq": [{"name": "¿Puede GitHub Copilot CLI hacer realmente trabajo de diseño?", "text": "Sí: con un skill estético, un sistema de diseño e imágenes de referencia reales en contexto, Copilot CLI produce interfaces adaptables de calidad de producción, y puedes elegir el modelo que mejor verifica la salida frente a las referencias. Sin ese contexto tiende a recurrir a un aspecto genérico, que es la brecha que Open Design rellena."}, {"name": "¿Necesito una suscripción para diseñar con Copilot CLI?", "text": "Sí: Copilot CLI funciona con una suscripción activa a GitHub Copilot (Pro, Pro+, Business o Enterprise); no es de tipo trae tu propia clave. Te autenticas con tu cuenta de GitHub. Open Design nunca actúa de intermediario con tus credenciales: tu suscripción la usa directamente tu agente."}, {"name": "¿Qué hace bueno a Copilot CLI para diseño en concreto?", "text": "Dos cosas: lee las instrucciones del repositorio y AGENTS.md automáticamente, de modo que tus convenciones de diseño viajan con el repositorio; y te permite cambiar entre modelos de frontera de Anthropic, OpenAI y Google según la tarea. Ambas ayudan, pero el buen gusto sigue proviniendo del sistema de diseño, el skill y las referencias que tú aportas."}, {"name": "¿Copilot CLI o Claude Code para diseño de frontend?", "text": "Ambos son potentes. Claude Code es conocido por decisiones de diseño específicas y conscientes de la base de código; la ventaja de Copilot CLI es la elección de modelo entre proveedores y la integración profunda con GitHub en una suscripción que quizá ya tengas. Muchos equipos usan ambos: Open Design te permite cambiar de agente sin cambiar tu flujo de trabajo de diseño."}, {"name": "¿Cómo conecto Copilot CLI con Figma?", "text": "Añade el servidor MCP de Figma con el comando /mcp add; la configuración se almacena en mcp-config.json dentro de ~/.copilot. Copilot puede entonces extraer contexto de diseño real —componentes, variables, datos de maquetación— para que el código generado coincida con la fuente en lugar de aproximarla."}, {"name": "¿Open Design está afiliado a GitHub o Microsoft?", "text": "No. GitHub Copilot CLI es un producto de GitHub; Open Design es un proyecto independiente de código abierto que lo admite como adaptador de primera categoría. GitHub Copilot es una marca comercial de GitHub, Inc. y Microsoft."}, {"name": "¿Están seguros mis archivos y credenciales?", "text": "Sí: Open Design es local-first y Apache-2.0. Tus archivos, artefactos y DESIGN.md permanecen en tu propio repositorio, y tus credenciales de GitHub Copilot las usa directamente tu agente, sin enrutarse nunca a través de los servidores de Open Design."}], "ctaTitle": "Diseña con GitHub Copilot CLI, a la manera abierta.", "ctaBody": "Trae tu suscripción a GitHub Copilot, mantén cada archivo en local y obtén una biblioteca de diseño curada alrededor del agente que ya usas.", "ctaActions": [{"label": "Usa Copilot CLI dentro de Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dale una estrella en GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Descarga la aplicación de escritorio", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Ver todos los agentes compatibles"},
      },
      'qwen': {
        ...en['qwen']!,
        title: "Qwen Code para diseño — Open Design",
        description: "Cómo se usa el CLI de código abierto Qwen Code de Alibaba para diseño de interfaces y web —sus modelos Qwen3-Coder, su gran ventana de contexto, QWEN.md y MCP— y cómo Open Design convierte Qwen Code en un agente de diseño local-first y de código abierto.",
        breadcrumb: "Qwen Code",
        label: "Agente · Qwen Code",
        heading: "Qwen Code para diseño.",
        lead: "Qwen Code es el agente de terminal de código abierto de Alibaba, adaptado de Gemini CLI y ajustado para los modelos Qwen3-Coder. Su gran ventana de contexto mantiene todo un sistema de diseño a la vez, lo que lo convierte en una verdadera herramienta de diseño, una vez que le das referencias, convenciones y un bucle de verificación. Open Design lo integra en un flujo de trabajo de diseño de código abierto: tu clave de API de DashScope o Qwen, tus archivos, local-first.",
        rich: {"heroCtaLead": "Open Design convierte Qwen Code en un agente de diseño local-first y de código abierto: tu clave de API de DashScope o Qwen, tus archivos y una biblioteca curada de skills y sistemas de diseño a su alrededor.", "heroCtaActions": [{"label": "Usa Qwen Code dentro de Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dale una estrella en GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Descarga la aplicación de escritorio", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Qwen Code es el agente de IA de código abierto de Alibaba para la terminal. Está adaptado de Gemini CLI de Google, con adaptaciones a nivel de parser y de prompt que le permiten sacar el máximo partido a los modelos Qwen3-Coder. Dos cosas lo hacen interesante específicamente para diseño: es un potente modelo de programación agéntica, así que planifica, edita archivos y ejecuta el bucle de compilación y verificación a partir de una tarea en lenguaje natural; y su gran ventana de contexto puede mantener un sistema de diseño y una base de código enteros a la vez. Combinado con las referencias, convenciones y un bucle de verificación adecuados, construye interfaces reales y adaptables, y es de código abierto y BYOK, así que traes tu propia clave. Esta es una guía práctica y de extremo a extremo para usar Qwen Code en trabajo de interfaces, frontend y sistemas de diseño, y para integrarlo en un flujo de trabajo de diseño estructurado con Open Design.", "Cubre qué es realmente Qwen Code, por qué un modelo de programación potente más un gran contexto encajan con el diseño, cómo configurarlo desde cero, el bucle de referencia a interfaz, cómo lo amplían QWEN.md y MCP, cómo se compara con Codex, Claude Code, Cursor y Gemini CLI, los obstáculos que hacen que la salida de la IA parezca genérica, y cómo Open Design cierra la brecha como una capa de diseño abierta y local-first: una combinación natural, ya que ambos son de código abierto y se ejecutan en tu propia máquina."], "heroImage": {"src": "/agents/qwen-design/qwen-design-hero.webp", "alt": "Bucle de retroalimentación de diseño de Qwen Code: un agente de terminal leyendo una imagen de referencia, un navegador renderizando la interfaz y un espacio de trabajo, con una flecha de retroalimentación que vuelve al inicio", "caption": "El bucle central: Qwen Code lee tus referencias en la terminal, construye y verifica la interfaz en un navegador real e itera frente a ellas, con todo un sistema de diseño en contexto."}, "tocLabel": "En esta página", "toc": [{"id": "what-is-qwen", "label": "Qué es realmente Qwen Code"}, {"id": "why-design", "label": "Por qué un modelo de programación potente + un gran contexto encajan con el diseño"}, {"id": "setup", "label": "Configura Qwen Code para diseño (desde cero)"}, {"id": "screenshot-workflow", "label": "El flujo de trabajo de referencia a interfaz"}, {"id": "extend", "label": "QWEN.md, MCP y extensiones"}, {"id": "vs", "label": "Qwen Code vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Obstáculos y el aspecto de «IA descuidada»"}, {"id": "open-design", "label": "Diseñar con Qwen Code en Open Design"}, {"id": "faq", "label": "Preguntas frecuentes"}], "sections": [{"id": "what-is-qwen", "heading": "Qué es realmente Qwen Code", "blocks": [{"kind": "p", "text": "Qwen Code es un agente de IA de código abierto (Apache-2.0) que Alibaba ofrece para la terminal. Lee tu repositorio, edita archivos, ejecuta comandos de shell y trabaja en la web, planificando y verificando el trabajo a partir de tareas en lenguaje natural en lugar de limitarse a completar líneas. Está adaptado de Gemini CLI de Google, con adaptaciones a nivel de parser y de prompt ajustadas para desbloquear los modelos Qwen3-Coder en tareas de programación agéntica."}, {"kind": "p", "text": "Para el trabajo de diseño, destacan dos propiedades. Es un programador agéntico capaz, así que puede tomar una referencia y un encargo claro y construir, ejecutar y autocorregir interfaces adaptables. Y los modelos Qwen3-Coder llevan una gran ventana de contexto, lo bastante grande para mantener tu sistema de diseño, biblioteca de componentes y conjunto de referencias enteros a la vez, en lugar de resumirlos."}, {"kind": "steps", "items": [{"label": "Archivos de contexto", "body": "Qwen Code lee un archivo QWEN.md como contexto persistente del proyecto, el lugar natural para codificar tus convenciones de diseño, tokens y listas de comprobación de revisión. Los ajustes personales y de proyecto se superponen encima."}, {"label": "Herramientas integradas + MCP", "body": "Viene con herramientas de archivos, shell y web de fábrica, y admite servidores MCP (configurados bajo mcpServers en ~/.qwen/settings.json) para añadir contexto externo, como un archivo de Figma en vivo."}, {"label": "BYOK para empezar", "body": "Traes tu propia clave —una clave de API de DashScope (Alibaba Cloud Model Studio), o cualquier endpoint compatible con OpenAI o ModelScope— y la configuras en settings.json."}]}, {"kind": "ul", "items": ["Proveedor: Alibaba", "Credencial: clave de API de DashScope / Qwen (BYOK), o endpoint compatible con OpenAI / ModelScope", "Licencia: Apache-2.0, código abierto (adaptado de Gemini CLI)"]}]}, {"id": "why-design", "heading": "Por qué un modelo de programación potente y un gran contexto encajan con el diseño", "blocks": [{"kind": "p", "text": "La ventaja de Qwen Code para diseño proviene de dos propiedades, pero, como con todo agente, el buen gusto sigue teniendo que aportarse."}, {"kind": "steps", "items": [{"label": "Programación agéntica potente", "body": "Los modelos Qwen3-Coder están ajustados para tareas agénticas, así que el agente planifica, edita, ejecuta la compilación y se autocorrige, convirtiendo una referencia y un encargo claros en marcado adaptable en lugar de una conjetura de un solo intento."}, {"label": "Una gran ventana de contexto", "body": "El gran contexto de Qwen3-Coder significa que todo el sistema de diseño, los tokens y muchos estados de referencia caben a la vez, así que el agente reutiliza tus primitivas reales en lugar de inventar estilos puntuales."}, {"label": "Convenciones en QWEN.md", "body": "Un QWEN.md (más el servidor MCP de Figma) dirige al agente a tus tokens, componentes y especificaciones reales, para que trabaje contra una marca en lugar de un aspecto por defecto."}]}, {"kind": "image", "src": "/agents/qwen-design/qwen-design-taste-triangle.webp", "alt": "Diagrama que muestra cómo el sistema de diseño, el skill y la imagen de referencia convergen en una buena salida de diseño", "caption": "El buen gusto proviene de tres insumos que tú aportas: un sistema de diseño, un skill e imágenes de referencia reales."}, {"kind": "p", "text": "La lección es la misma que enseña cada agente: Qwen Code no tiene buen gusto por defecto. Produce buen diseño cuando le das restricciones: un sistema de diseño, un skill estético y referencias concretas. Open Design empaqueta exactamente esos insumos, y por eso ambos encajan (más abajo, con más detalle)."}]}, {"id": "setup", "heading": "Configura Qwen Code para trabajo de diseño, desde cero", "blocks": [{"kind": "p", "text": "Este es el camino completo desde una máquina limpia hasta un Qwen Code capaz de construir y verificar interfaces."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Qwen Code (Node 22+)\nnpm install -g @qwen-code/qwen-code@latest\n# or: brew install qwen-code\n\n# 2. Start it in your project and authenticate on first run\ncd your-project\nqwen              # run /auth, or set a key in ~/.qwen/settings.json\n\n# 3. Configure a DashScope (OpenAI-compatible) key in settings.json\n#    baseUrl: https://dashscope.aliyuncs.com/compatible-mode/v1\n#    model:   qwen3-coder-plus   (set DASHSCOPE_API_KEY)\n\n# 4. Add a QWEN.md and wire the Figma MCP server (optional)\n#    add MCP under \"mcpServers\" in ~/.qwen/settings.json"}, {"kind": "image", "src": "/agents/qwen-design/qwen-design-setup-flow.webp", "alt": "Flujo de configuración de cinco pasos: instalar, autenticarse, configurar QWEN.md, añadir un skill, verificar", "caption": "La secuencia de configuración: instalar → autenticarse → configurar QWEN.md → añadir un skill → habilitar la verificación en el navegador."}, {"kind": "steps", "items": [{"label": "Codifica tus reglas de diseño", "body": "Pon tus tokens, primitivas y convenciones en QWEN.md y dirige a Qwen Code hacia ellos, para que la salida coincida con una marca en lugar de recurrir a un aspecto genérico."}, {"label": "Añade verificación en el navegador", "body": "Conecta un MCP de Playwright o de navegador para que Qwen Code renderice en un navegador real y compruebe su salida en distintos puntos de quiebre, en lugar de limitarse a confirmar que la compilación pasa."}]}]}, {"id": "screenshot-workflow", "heading": "El flujo de trabajo de referencia a interfaz", "blocks": [{"kind": "p", "text": "El bucle de diseño de mayor impacto con Qwen Code es convertir una referencia en una interfaz funcional y adaptable e iterar hasta que coincida, apoyándose en el agente para construir, renderizar y comparar su salida con la referencia."}, {"kind": "ol", "items": ["Parte de las referencias visuales más claras que tengas, y describe varios estados (escritorio y móvil, hover, vacío, cargando), no solo una captura principal.", "Sé específico en el prompt; los prompts vagos producen interfaces genéricas incluso con un modelo potente.", "Mantén tu sistema de diseño y convenciones en QWEN.md, e indícale a Qwen Code dónde viven los tokens y las primitivas canónicas.", "Ejecuta un servidor de desarrollo y haz que Qwen Code renderice en un navegador real, redimensionando a los puntos de quiebre para comprobar el resultado.", "Itera haciendo que Qwen Code compare su implementación con las referencias, no que se limite a confirmar que compila."]}, {"kind": "p", "text": "Referencia un archivo con @ para adjuntarlo al prompt, y luego da restricciones concretas:"}, {"kind": "code", "lang": "bash", "code": "qwen\n# in the prompt:\n> @reference-desktop.png @reference-mobile.png\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from QWEN.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the references\n  across breakpoints."}, {"kind": "p", "text": "Mantén los prompts pequeños y enfocados, confirma las buenas iteraciones y revierte las malas (avisándole a Qwen Code cuando reviertas), para que cada pasada se construya sobre una base limpia."}]}, {"id": "extend", "heading": "QWEN.md, MCP y extensiones", "blocks": [{"kind": "p", "text": "Tres puntos de extensión hacen que Qwen Code sea práctico para trabajo de diseño sostenido, y los tres encajan limpiamente en un flujo de trabajo de diseño abierto."}, {"kind": "steps", "items": [{"label": "Contexto de QWEN.md", "body": "Las reglas del proyecto viven en un QWEN.md en la raíz del repositorio (con capas global y de proyecto). Es el hogar duradero de tus convenciones de diseño, leído en cada ejecución."}, {"label": "Servidores MCP", "body": "Configura servidores MCP bajo mcpServers en ~/.qwen/settings.json: la forma portátil de incorporar contexto de diseño y herramientas externas, sobre todo el servidor MCP de Figma, que funcionan entre agentes, no solo en Qwen Code."}, {"label": "Skills y herramientas integradas", "body": "Los skills de Qwen Code y sus herramientas integradas de archivos, shell y web le permiten reunir referencias y ejecutar el bucle de verificación sin salir de la terminal."}]}, {"kind": "p", "text": "Estas son capacidades portátiles y multiagente, exactamente el tipo de cosas que Open Design está diseñado para orquestar, en lugar de recrearlas en cada proyecto."}]}, {"id": "vs", "heading": "Qwen Code vs Codex vs Claude Code vs Cursor vs Gemini CLI para diseño", "blocks": [{"kind": "p", "text": "No hay un único ganador para el trabajo de diseño: cada agente tiene una fortaleza distinta, y los equipos con experiencia los combinan. Un resumen justo:"}, {"kind": "table", "columns": ["Agente", "Fortaleza de diseño", "Ideal para"], "rows": [["Qwen Code", "Programación agéntica potente sobre los modelos abiertos Qwen3-Coder con un gran contexto; de código abierto y BYOK", "Compilaciones de código abierto y flexibles en cuanto a clave que mantienen todo un sistema de diseño en contexto"], ["Codex", "Gran pulido visual con un skill de frontend; compilaciones asíncronas en sandbox", "Compilaciones asíncronas delegadas y reglas portátiles de AGENTS.md"], ["Claude Code", "Decisiones de diseño específicas (hex, espaciado, tipografía) y UX consciente de la base de código", "Razonamiento de frontend y refactorizaciones de gran contexto"], ["Cursor", "Bucle visual de construir y ver con vista previa en vivo y ediciones en línea", "Trabajo de interfaz ajustado de iterar y observar dentro de un IDE"], ["Gemini CLI", "Sólida comprensión de imágenes multimodal y un contexto de 1M de tokens; el agente del que se adapta Qwen Code", "Trabajo con muchas capturas de pantalla y contexto muy grande"]]}, {"kind": "p", "text": "El veredicto recurrente de la comunidad es que el buen gusto proviene de las personas: todos recurren por defecto a una estética genérica sin skills, referencias y restricciones. Ese es el verdadero problema a resolver, y tiene forma de herramienta de diseño, no de modelo."}]}, {"id": "pitfalls", "heading": "Obstáculos y cómo evitar el aspecto de «IA descuidada»", "blocks": [{"kind": "p", "text": "La queja más común sobre el diseño generado por IA es que parece genérico: degradados suaves, paneles flotantes, esquinas redondeadas demasiado grandes, sombras dramáticas, un aire de Inter y morado que «grita que esto lo hizo una IA». Otros problemas reportados incluyen maquetaciones móviles rotas e instrucciones que se filtran en el texto de la interfaz. Ninguno de ellos es exclusivo de Qwen Code; son lo que ocurre cuando cualquier agente se ejecuta sin un contexto de diseño curado."}, {"kind": "steps", "items": [{"label": "Añade un skill estético", "body": "Un skill de diseño curado obliga al agente a comprometerse con una dirección real en lugar del aspecto por defecto."}, {"label": "Verifica en un navegador real", "body": "Haz que el agente renderice y autoverifique en distintos puntos de quiebre para que las maquetaciones no se rompan en silencio en móvil."}, {"label": "Aporta tokens y referencias", "body": "Los tokens de diseño reales y las capturas de referencia son la mayor palanca individual sobre la calidad de la salida."}, {"label": "Codifica reglas en QWEN.md", "body": "Pon reglas de estilo como «sin tarjetas hero, máximo dos tipografías, jerarquía centrada en la marca» donde el agente las lee en cada ejecución."}]}, {"kind": "p", "text": "Fíjate en que toda mitigación consiste en dar al agente un contexto de diseño curado. Mantener ese contexto a mano, proyecto a proyecto, es la tarea pesada que Open Design elimina."}]}, {"id": "open-design", "heading": "Diseñar con Qwen Code dentro de Open Design", "blocks": [{"kind": "p", "text": "Open Design es la capa de diseño de código abierto que el flujo de trabajo anterior no deja de pedir. Trata a Qwen Code como un adaptador de primera categoría y lo envuelve en una biblioteca curada de skills y sistemas de diseño, una canalización de renderizado estructurada y una interfaz de escritorio local, de modo que el contexto de diseño que hace bueno a Qwen Code está ahí desde la primera ejecución, no ensamblado a mano cada vez. Ambos son de código abierto y local-first, lo que hace que la combinación encaje de forma natural."}, {"kind": "ol", "items": ["Instala Open Design y selecciona Qwen Code como tu agente.", "Autentícate con tu clave de API de DashScope o Qwen (BYOK): las credenciales permanecen en tu máquina y nunca pasan por nuestros servidores.", "Elige un sistema de diseño y un skill, y luego genera presentaciones, prototipos y páginas de aterrizaje con un gusto consistente.", "Cada artefacto y archivo DESIGN.md vive en tu propio repositorio, no en una nube alojada."]}, {"kind": "p", "text": "El mismo agente Qwen Code, la misma clave, más un flujo de trabajo de diseño real, portátil y de código abierto a su alrededor. Es local-first y Apache-2.0, así que nada de tu trabajo ni de tus credenciales sale de tu máquina."}]}], "faqTitle": "Preguntas frecuentes", "faq": [{"name": "¿Puede Qwen Code hacer realmente trabajo de diseño?", "text": "Sí: con un skill estético, un sistema de diseño e imágenes de referencia reales en contexto, Qwen Code produce interfaces adaptables de calidad de producción, y su bucle agéntico construye, renderiza y verifica la salida frente a las referencias. Sin ese contexto tiende a recurrir a un aspecto genérico, que es la brecha que Open Design rellena."}, {"name": "¿Tengo que pagar para diseñar con Qwen Code?", "text": "Qwen Code es gratuito y de código abierto, pero es BYOK: traes una clave de API de DashScope (Alibaba Cloud Model Studio), un endpoint compatible con OpenAI o ModelScope. Alibaba también ofrece un plan de programación de tarifa fija. Open Design nunca actúa de intermediario con tus credenciales en ningún caso."}, {"name": "¿Qué hace bueno a Qwen Code para diseño en concreto?", "text": "Dos cosas: los modelos Qwen3-Coder están ajustados para programación agéntica, así que el agente construye y autocorrige interfaces adaptables, y su gran contexto puede mantener un sistema de diseño y un conjunto de referencias enteros a la vez. Ambas ayudan, pero el buen gusto sigue proviniendo del sistema de diseño, el skill y las referencias que tú aportas."}, {"name": "¿Qwen Code es lo mismo que Gemini CLI?", "text": "No. Qwen Code está adaptado de Gemini CLI de Google —el mismo linaje de código abierto— con adaptaciones a nivel de parser y de prompt que lo ajustan para los modelos Qwen3-Coder. Open Design admite ambos, así que puedes cambiar de agente sin cambiar tu flujo de trabajo de diseño."}, {"name": "¿Cómo conecto Qwen Code con Figma?", "text": "Añade el servidor MCP de Figma bajo mcpServers en ~/.qwen/settings.json. Qwen Code puede entonces extraer contexto de diseño real —componentes, variables, datos de maquetación— para que el código generado coincida con la fuente en lugar de aproximarla."}, {"name": "¿Open Design está afiliado a Alibaba o Qwen?", "text": "No. Qwen Code es un producto de Alibaba; Open Design es un proyecto independiente de código abierto que lo admite como adaptador de primera categoría. Qwen es una marca comercial de Alibaba."}, {"name": "¿Están seguros mis archivos y credenciales?", "text": "Sí: Open Design es local-first y Apache-2.0. Tus archivos, artefactos y DESIGN.md permanecen en tu propio repositorio, y tus credenciales de DashScope o Qwen las usa directamente tu agente, sin enrutarse nunca a través de los servidores de Open Design."}], "ctaTitle": "Diseña con Qwen Code, a la manera abierta.", "ctaBody": "Trae tu propia clave de API de DashScope o Qwen, mantén cada archivo en local y obtén una biblioteca de diseño curada alrededor del agente que ya usas.", "ctaActions": [{"label": "Usa Qwen Code dentro de Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dale una estrella en GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Descarga la aplicación de escritorio", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Ver todos los agentes compatibles"},
      },
      'grok': {
        ...en['grok']!,
        title: "Grok Build para diseño — Open Design",
        description: "Cómo se usa Grok Build (Grok Build) de xAI para diseño de interfaces y web —su modo plan, AGENTS.md y MCP, los modelos Grok con reconocimiento de imágenes y un gran contexto— y cómo Open Design convierte Grok Build en un agente de diseño local-first y de código abierto.",
        breadcrumb: "Grok Build",
        label: "Agente · Grok Build",
        heading: "Grok Build para diseño.",
        lead: "Grok Build es el agente de programación de terminal de xAI. Planifica el trabajo de varios pasos antes de tocar tus archivos, lee imágenes junto al código y ejecuta el bucle de construir y verificar en tu repositorio, lo que lo convierte en una verdadera herramienta de diseño una vez que le das referencias, convenciones y un paso de verificación. Open Design lo integra en un flujo de trabajo de diseño de código abierto: tu inicio de sesión de SuperGrok o tu clave de API de xAI, tus archivos, local-first.",
        rich: {"heroCtaLead": "Open Design convierte Grok Build en un agente de diseño local-first y de código abierto: tu inicio de sesión de SuperGrok o tu clave de API de xAI, tus archivos y una biblioteca curada de skills y sistemas de diseño a su alrededor.", "heroCtaActions": [{"label": "Usa Grok Build dentro de Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dale una estrella en GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Descarga la aplicación de escritorio", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Grok Build —el agente de programación de terminal de xAI, distribuido como Grok Build— es una herramienta agéntica que vive en tu terminal. Dos cosas lo hacen interesante específicamente para diseño: planifica el trabajo arriesgado antes de actuar, así que puedes revisar un enfoque propuesto antes de que cambie ningún archivo; y sus modelos Grok aceptan entrada de imágenes, de modo que puede razonar sobre una captura de referencia junto al código que escribe. Combinado con las referencias, convenciones y un bucle de verificación adecuados, construye interfaces reales y adaptables, autenticado directamente a través de tu cuenta de SuperGrok o X Premium+, sin tener que hacer malabares con claves de API. Esta es una guía práctica y de extremo a extremo para usar Grok Build en trabajo de interfaces, frontend y sistemas de diseño, y para integrarlo en un flujo de trabajo de diseño estructurado con Open Design.", "Cubre qué es realmente Grok Build, por qué el modo plan y los modelos con reconocimiento de imágenes encajan con el diseño, cómo configurarlo desde cero, el bucle de captura de pantalla a interfaz, cómo lo amplían AGENTS.md y MCP, cómo se compara con Codex, Claude Code, Cursor y Gemini CLI, los obstáculos que hacen que la salida de la IA parezca genérica, y cómo Open Design cierra la brecha como una capa de diseño abierta y local-first: tus credenciales y artefactos nunca salen de tu máquina."], "heroImage": {"src": "/agents/grok-design/grok-design-hero.webp", "alt": "Bucle de retroalimentación de diseño de Grok Build: un agente de terminal planificando a partir de una imagen de referencia, un navegador renderizando la interfaz y un espacio de trabajo, con una flecha de retroalimentación que vuelve al inicio", "caption": "El bucle central: Grok Build planifica a partir de tus referencias en la terminal, construye y verifica la interfaz en un navegador real e itera frente a ellas, con tus convenciones en AGENTS.md."}, "tocLabel": "En esta página", "toc": [{"id": "what-is-grok", "label": "Qué es realmente Grok Build"}, {"id": "why-design", "label": "Por qué el modo plan + la entrada de imágenes encajan con el diseño"}, {"id": "setup", "label": "Configura Grok Build para diseño (desde cero)"}, {"id": "screenshot-workflow", "label": "El flujo de trabajo de captura de pantalla a interfaz"}, {"id": "extend", "label": "AGENTS.md, MCP y subagentes"}, {"id": "vs", "label": "Grok Build vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Obstáculos y el aspecto de «IA descuidada»"}, {"id": "open-design", "label": "Diseñar con Grok Build en Open Design"}, {"id": "faq", "label": "Preguntas frecuentes"}], "sections": [{"id": "what-is-grok", "heading": "Qué es realmente Grok Build", "blocks": [{"kind": "p", "text": "Grok Build es el agente de programación de terminal de xAI, distribuido bajo el nombre de Grok Build. Lee tu repositorio, edita archivos, ejecuta comandos de shell y planifica trabajo de ingeniería de varios pasos a partir de tareas en lenguaje natural en lugar de limitarse a completar líneas. Está construido en torno a los modelos Grok de xAI —expuestos en la API de xAI como la familia de modelos grok-build— y se autentica a través de tu cuenta de xAI, así que el agente y los modelos provienen del mismo proveedor."}, {"kind": "p", "text": "Para el trabajo de diseño, destacan dos propiedades. Tiene un modo plan que redacta un enfoque estructurado que puedes aprobar, comentar o reescribir antes de que aterrice ningún cambio, una compuerta útil cuando estás iterando sobre la interfaz. Y sus modelos Grok aceptan entrada de imágenes, así que puedes entregarle una captura de referencia y razona sobre la maquetación real en lugar de adivinar a partir de una descripción en prosa."}, {"kind": "steps", "items": [{"label": "Archivos de contexto", "body": "Grok Build lee un archivo AGENTS.md como contexto persistente del proyecto, el lugar natural para codificar tus convenciones de diseño, tokens y listas de comprobación de revisión. Sigue la misma convención abierta de AGENTS.md que usan Codex y otros agentes."}, {"label": "Herramientas, MCP + subagentes", "body": "Edita archivos, ejecuta comandos de shell y admite servidores MCP para añadir contexto externo, como un archivo de Figma en vivo; para tareas más grandes puede delegar en subagentes paralelos que investigan, construyen y revisan a la vez."}, {"label": "Inicia sesión con tu cuenta", "body": "Te autenticas iniciando sesión a través de tu navegador con una suscripción a SuperGrok o X Premium+; también puedes traer una clave de API de xAI para uso headless y en CI."}]}, {"kind": "ul", "items": ["Proveedor: xAI", "Credencial: OAuth de SuperGrok de xAI (`grok login`), o una clave de API de xAI (BYOK) para uso headless", "Modelos: modelos Grok de xAI (la familia grok-build en la API de xAI), con entrada de imágenes"]}]}, {"id": "why-design", "heading": "Por qué el modo plan y los modelos con reconocimiento de imágenes encajan con el diseño", "blocks": [{"kind": "p", "text": "La ventaja de Grok Build para diseño proviene de dos propiedades, pero, como con todo agente, el buen gusto sigue teniendo que aportarse."}, {"kind": "steps", "items": [{"label": "Razonamiento con reconocimiento de imágenes", "body": "Como los modelos Grok aceptan entrada de imágenes, el agente lee capturas de referencia, comparando su salida renderizada con una imagen en lugar de adivinar a partir de una descripción en prosa."}, {"label": "Modo plan antes de que aterricen los cambios", "body": "El modo plan redacta un enfoque estructurado que apruebas antes de que cambien los archivos, así que la intención de diseño se revisa de antemano en lugar de descubrirse después del diff."}, {"label": "Convenciones en AGENTS.md", "body": "Un AGENTS.md (más el servidor MCP de Figma) dirige al agente a tus tokens, componentes y especificaciones reales, para que trabaje contra una marca en lugar de un aspecto por defecto."}]}, {"kind": "image", "src": "/agents/grok-design/grok-design-taste-triangle.webp", "alt": "Diagrama que muestra cómo el sistema de diseño, el skill y la imagen de referencia convergen en una buena salida de diseño", "caption": "El buen gusto proviene de tres insumos que tú aportas: un sistema de diseño, un skill e imágenes de referencia reales."}, {"kind": "p", "text": "La lección es la misma que enseña cada agente: Grok Build no tiene buen gusto por defecto. Produce buen diseño cuando le das restricciones: un sistema de diseño, un skill estético y referencias concretas. Open Design empaqueta exactamente esos insumos, y por eso ambos encajan (más abajo, con más detalle)."}]}, {"id": "setup", "heading": "Configura Grok Build para trabajo de diseño, desde cero", "blocks": [{"kind": "p", "text": "Este es el camino completo desde una máquina limpia hasta un Grok Build capaz de construir y verificar interfaces."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Grok Build (Grok Build) on macOS/Linux\ncurl -fsSL https://x.ai/cli/install.sh | bash\n\n# 2. Start it in your project and authenticate on first run\ncd your-project\ngrok login   # opens your browser; sign in with SuperGrok / X Premium+\n#   or, for headless / CI use, set an xAI API key:\n#   export XAI_API_KEY=xai-...\n\n# 3. Add project context\n#    create an AGENTS.md at the repo root with your design conventions\n\n# 4. Wire the Figma MCP server (optional, for design handoff)\n#    add it to your MCP server configuration"}, {"kind": "image", "src": "/agents/grok-design/grok-design-setup-flow.webp", "alt": "Flujo de configuración de cinco pasos: instalar, autenticarse, configurar AGENTS.md, añadir un skill, verificar", "caption": "La secuencia de configuración: instalar → autenticarse → configurar AGENTS.md → añadir un skill → habilitar la verificación en el navegador."}, {"kind": "steps", "items": [{"label": "Codifica tus reglas de diseño", "body": "Pon tus tokens, primitivas y convenciones en AGENTS.md y dirige a Grok hacia ellos, para que la salida coincida con una marca en lugar de recurrir a un aspecto genérico."}, {"label": "Añade verificación en el navegador", "body": "Conecta un MCP de Playwright o de navegador para que Grok renderice en un navegador real y compruebe su salida en distintos puntos de quiebre, en lugar de limitarse a confirmar que la compilación pasa."}]}]}, {"id": "screenshot-workflow", "heading": "El flujo de trabajo de captura de pantalla a interfaz", "blocks": [{"kind": "p", "text": "El bucle de diseño de mayor impacto con Grok Build es convertir una imagen de referencia en una interfaz funcional y adaptable e iterar hasta que coincida, apoyándose en el modo plan para acordar el enfoque y en el modelo con reconocimiento de imágenes para comparar la salida con la referencia."}, {"kind": "ol", "items": ["Parte de las referencias visuales más claras que tengas, e incluye varios estados (escritorio y móvil, hover, vacío, cargando), no solo una captura principal.", "Sé específico en el prompt; los prompts vagos producen interfaces genéricas incluso con un modelo potente.", "Mantén tu sistema de diseño y convenciones en AGENTS.md, e indícale a Grok dónde viven los tokens y las primitivas canónicas.", "Usa el modo plan para revisar el enfoque, luego ejecuta un servidor de desarrollo y haz que Grok renderice en un navegador real, redimensionando a los puntos de quiebre para comprobar el resultado.", "Itera haciendo que Grok compare su implementación con las capturas, no que se limite a confirmar que compila."]}, {"kind": "p", "text": "Adjunta tus imágenes de referencia y da restricciones concretas:"}, {"kind": "code", "lang": "bash", "code": "grok\n# in the prompt (attach reference-desktop.png and reference-mobile.png):\n> Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from AGENTS.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Show me the plan first, then render it in the browser and iterate\n  until it matches the references across breakpoints."}, {"kind": "p", "text": "Mantén los prompts pequeños y enfocados, confirma las buenas iteraciones y revierte las malas (avisándole a Grok cuando reviertas), para que cada pasada se construya sobre una base limpia."}]}, {"id": "extend", "heading": "AGENTS.md, MCP y subagentes", "blocks": [{"kind": "p", "text": "Tres puntos de extensión hacen que Grok Build sea práctico para trabajo de diseño sostenido, y los tres encajan limpiamente en un flujo de trabajo de diseño abierto."}, {"kind": "steps", "items": [{"label": "Contexto de AGENTS.md", "body": "Las reglas del proyecto viven en un AGENTS.md en la raíz del repositorio. Es el hogar duradero de tus convenciones de diseño, leído en cada ejecución, y es el mismo formato abierto que entienden otros agentes, así que las reglas viajan contigo."}, {"label": "Servidores MCP", "body": "Configura servidores MCP para incorporar contexto de diseño y herramientas externas, sobre todo el servidor MCP de Figma: la forma portátil de inyectar especificaciones reales en el código, que funciona entre agentes, no solo en Grok."}, {"label": "Subagentes y herramientas integradas", "body": "Grok Build puede generar subagentes paralelos para investigar, construir y revisar a la vez, y sus herramientas de archivos, shell y búsqueda le permiten reunir referencias y ejecutar el bucle de verificación sin salir de la terminal."}]}, {"kind": "p", "text": "Estas son capacidades portátiles y multiagente, exactamente el tipo de cosas que Open Design está diseñado para orquestar, en lugar de recrearlas en cada proyecto."}]}, {"id": "vs", "heading": "Grok Build vs Codex vs Claude Code vs Cursor vs Gemini CLI para diseño", "blocks": [{"kind": "p", "text": "No hay un único ganador para el trabajo de diseño: cada agente tiene una fortaleza distinta, y los equipos con experiencia los combinan. Un resumen justo:"}, {"kind": "table", "columns": ["Agente", "Fortaleza de diseño", "Ideal para"], "rows": [["Grok Build", "Revisión en modo plan antes de que aterricen los cambios, modelos Grok con reconocimiento de imágenes y subagentes paralelos; inicia sesión con tu cuenta de SuperGrok", "Compilaciones de interfaz revisadas y con el plan primero, con los modelos de xAI en el bucle"], ["Codex", "Gran pulido visual con un skill de frontend; compilaciones asíncronas en sandbox", "Compilaciones asíncronas delegadas y reglas portátiles de AGENTS.md"], ["Claude Code", "Decisiones de diseño específicas (hex, espaciado, tipografía) y UX consciente de la base de código", "Razonamiento de frontend y refactorizaciones de gran contexto"], ["Cursor", "Bucle visual de construir y ver con vista previa en vivo y ediciones en línea", "Trabajo de interfaz ajustado de iterar y observar dentro de un IDE"], ["Gemini CLI", "Sólida comprensión de imágenes multimodal y un contexto muy grande; de código abierto con un plan gratuito", "Trabajo con muchas capturas de pantalla y mantener todo un sistema de diseño en contexto"]]}, {"kind": "p", "text": "El veredicto recurrente de la comunidad es que el buen gusto proviene de las personas: todos recurren por defecto a una estética genérica sin skills, referencias y restricciones. Ese es el verdadero problema a resolver, y tiene forma de herramienta de diseño, no de modelo."}]}, {"id": "pitfalls", "heading": "Obstáculos y cómo evitar el aspecto de «IA descuidada»", "blocks": [{"kind": "p", "text": "La queja más común sobre el diseño generado por IA es que parece genérico: degradados suaves, paneles flotantes, esquinas redondeadas demasiado grandes, sombras dramáticas, un aire de Inter y morado que «grita que esto lo hizo una IA». Otros problemas reportados incluyen maquetaciones móviles rotas e instrucciones que se filtran en el texto de la interfaz. Ninguno de ellos es exclusivo de Grok Build; son lo que ocurre cuando cualquier agente se ejecuta sin un contexto de diseño curado."}, {"kind": "steps", "items": [{"label": "Añade un skill estético", "body": "Un skill de diseño curado obliga al agente a comprometerse con una dirección real en lugar del aspecto por defecto."}, {"label": "Verifica en un navegador real", "body": "Renderiza y autoverifica en distintos puntos de quiebre para que las maquetaciones no se rompan en silencio en móvil."}, {"label": "Aporta tokens y referencias", "body": "Los tokens de diseño reales y las capturas de referencia son la mayor palanca individual sobre la calidad de la salida."}, {"label": "Codifica reglas en AGENTS.md", "body": "Pon reglas de estilo como «sin tarjetas hero, máximo dos tipografías, jerarquía centrada en la marca» donde el agente las lee en cada ejecución."}]}, {"kind": "p", "text": "Fíjate en que toda mitigación consiste en dar al agente un contexto de diseño curado. Mantener ese contexto a mano, proyecto a proyecto, es la tarea pesada que Open Design elimina."}]}, {"id": "open-design", "heading": "Diseñar con Grok Build dentro de Open Design", "blocks": [{"kind": "p", "text": "Open Design es la capa de diseño de código abierto que el flujo de trabajo anterior no deja de pedir. Trata a Grok Build como un adaptador de primera categoría y lo envuelve en una biblioteca curada de skills y sistemas de diseño, una canalización de renderizado estructurada y una interfaz de escritorio local, de modo que el contexto de diseño que hace bueno a Grok está ahí desde la primera ejecución, no ensamblado a mano cada vez. Open Design es independiente y Apache-2.0, y se ejecuta en tu propia máquina, lo que hace que la combinación encaje de forma natural."}, {"kind": "ol", "items": ["Instala Open Design y selecciona Grok Build como tu agente.", "Autentícate con tu cuenta de SuperGrok o una clave de API de xAI (BYOK): las credenciales permanecen en tu máquina y nunca pasan por nuestros servidores.", "Elige un sistema de diseño y un skill, y luego genera presentaciones, prototipos y páginas de aterrizaje con un gusto consistente.", "Cada artefacto y archivo DESIGN.md vive en tu propio repositorio, no en una nube alojada."]}, {"kind": "p", "text": "El mismo agente Grok Build, las mismas credenciales, más un flujo de trabajo de diseño real, portátil y de código abierto a su alrededor. Es local-first y Apache-2.0, así que nada de tu trabajo ni de tus credenciales sale de tu máquina."}]}], "faqTitle": "Preguntas frecuentes", "faq": [{"name": "¿Puede Grok Build hacer realmente trabajo de diseño?", "text": "Sí: con un skill estético, un sistema de diseño e imágenes de referencia reales en contexto, Grok Build produce interfaces adaptables de calidad de producción, y sus modelos Grok con reconocimiento de imágenes ayudan a verificar la salida frente a las referencias. Sin ese contexto tiende a recurrir a un aspecto genérico, que es la brecha que Open Design rellena."}, {"name": "¿Cómo me autentico en Grok Build?", "text": "Inicias sesión a través de tu navegador con una suscripción a SuperGrok o X Premium+ (`grok login`), así que no hay ninguna clave de API que gestionar. Para uso headless o en CI puedes traer una clave de API de xAI en su lugar. Open Design nunca actúa de intermediario con tus credenciales en ningún caso."}, {"name": "¿Qué hace bueno a Grok Build para diseño en concreto?", "text": "Dos cosas: su modo plan te permite revisar el enfoque antes de que aterrice ningún cambio, y sus modelos Grok aceptan entrada de imágenes, así que lee bien las capturas de referencia. Ambas ayudan, pero el buen gusto sigue proviniendo del sistema de diseño, el skill y las referencias que tú aportas."}, {"name": "¿Grok Build o Claude Code para diseño de frontend?", "text": "Ambos son potentes. Claude Code es conocido por decisiones de diseño específicas y conscientes de la base de código; la ventaja de Grok Build es la revisión en modo plan y los modelos de xAI con reconocimiento de imágenes. Muchos equipos usan ambos: Open Design te permite cambiar de agente sin cambiar tu flujo de trabajo de diseño."}, {"name": "¿Cómo conecto Grok Build con Figma?", "text": "Añade el servidor MCP de Figma a tu configuración de MCP. Grok puede entonces extraer contexto de diseño real —componentes, variables, datos de maquetación— para que el código generado coincida con la fuente en lugar de aproximarla."}, {"name": "¿Open Design está afiliado a xAI?", "text": "No. Grok Build es un producto de xAI; Open Design es un proyecto independiente de código abierto que lo admite como adaptador de primera categoría. Grok es una marca comercial de xAI."}, {"name": "¿Están seguros mis archivos y credenciales?", "text": "Sí: Open Design es local-first y Apache-2.0. Tus archivos, artefactos y DESIGN.md permanecen en tu propio repositorio, y tus credenciales de xAI las usa directamente tu agente, sin enrutarse nunca a través de los servidores de Open Design."}], "ctaTitle": "Diseña con Grok Build, a la manera abierta.", "ctaBody": "Trae tu propia cuenta de SuperGrok o clave de API de xAI, mantén cada archivo en local y obtén una biblioteca de diseño curada alrededor del agente que ya usas.", "ctaActions": [{"label": "Usa Grok Build dentro de Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dale una estrella en GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Descarga la aplicación de escritorio", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Ver todos los agentes compatibles"},
      },
      'kimi': {
        ...en['kimi']!,
        title: "Kimi CLI para diseño — Open Design",
        description: "Cómo se usa Kimi CLI de Moonshot AI para diseño de interfaces y web —sus modelos agénticos de la serie Kimi K2, un gran contexto, AGENTS.md y MCP— y cómo Open Design convierte Kimi CLI en un agente de diseño local-first y de código abierto.",
        breadcrumb: "Kimi CLI",
        label: "Agente · Kimi CLI",
        heading: "Kimi CLI para diseño.",
        lead: "Kimi CLI es el agente de terminal de código abierto de Moonshot AI, impulsado por la serie de modelos Kimi K2. Su potente programación agéntica y su gran ventana de contexto le permiten mantener todo un sistema de diseño e iterar frente a referencias: una vez que le das convenciones y un bucle de verificación, se convierte en una verdadera herramienta de diseño. Open Design lo integra en un flujo de trabajo de diseño de código abierto: tu clave de API de Moonshot, tus archivos, local-first.",
        rich: {"heroCtaLead": "Open Design convierte Kimi CLI en un agente de diseño local-first y de código abierto: tu clave de API de Moonshot, tus archivos y una biblioteca curada de skills y sistemas de diseño a su alrededor.", "heroCtaActions": [{"label": "Usa Kimi CLI dentro de Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dale una estrella en GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Descarga la aplicación de escritorio", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Kimi CLI es el agente de IA de código abierto de Moonshot AI para la terminal. Dos cosas lo hacen interesante específicamente para diseño: está impulsado por la serie Kimi K2 —un modelo de mezcla de expertos de un billón de parámetros meticulosamente optimizado para programación agéntica y uso de herramientas—; y ese modelo lleva una gran ventana de contexto (256k tokens en las versiones recientes de K2), lo bastante grande para mantener un sistema de diseño y una base de código enteros a la vez. Combinado con las referencias, convenciones y un bucle de verificación adecuados, construye interfaces reales y adaptables, y puedes empezar con un inicio de sesión OAuth o tu propia clave de API de Moonshot. Esta es una guía práctica y de extremo a extremo para usar Kimi CLI en trabajo de interfaces, frontend y sistemas de diseño, y para integrarlo en un flujo de trabajo de diseño estructurado con Open Design.", "Cubre qué es realmente Kimi CLI, por qué sus modelos agénticos Kimi K2 y su gran contexto encajan con el diseño, cómo configurarlo desde cero, el bucle de referencia a interfaz, cómo lo amplían AGENTS.md, MCP y los subagentes, cómo se compara con Codex, Claude Code, Cursor y Gemini CLI, los obstáculos que hacen que la salida de la IA parezca genérica, y cómo Open Design cierra la brecha como una capa de diseño abierta y local-first: una combinación natural, ya que ambos son de código abierto y se ejecutan en tu propia máquina."], "heroImage": {"src": "/agents/kimi-design/kimi-design-hero.webp", "alt": "Bucle de retroalimentación de diseño de Kimi CLI: un agente de terminal leyendo una imagen de referencia, un navegador renderizando la interfaz y un espacio de trabajo, con una flecha de retroalimentación que vuelve al inicio", "caption": "El bucle central: Kimi CLI lee tus referencias en la terminal, construye y verifica la interfaz en un navegador real e itera frente a ellas, con todo un sistema de diseño en contexto."}, "tocLabel": "En esta página", "toc": [{"id": "what-is-kimi", "label": "Qué es realmente Kimi CLI"}, {"id": "why-design", "label": "Por qué el K2 agéntico + un gran contexto encajan con el diseño"}, {"id": "setup", "label": "Configura Kimi CLI para diseño (desde cero)"}, {"id": "screenshot-workflow", "label": "El flujo de trabajo de referencia a interfaz"}, {"id": "extend", "label": "AGENTS.md, MCP y subagentes"}, {"id": "vs", "label": "Kimi CLI vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Obstáculos y el aspecto de «IA descuidada»"}, {"id": "open-design", "label": "Diseñar con Kimi CLI en Open Design"}, {"id": "faq", "label": "Preguntas frecuentes"}], "sections": [{"id": "what-is-kimi", "heading": "Qué es realmente Kimi CLI", "blocks": [{"kind": "p", "text": "Kimi CLI es un agente de IA de código abierto (Apache-2.0) que Moonshot AI ofrece para la terminal. Lee tu repositorio, edita archivos, ejecuta comandos de shell, busca archivos, obtiene páginas web y elige su siguiente paso a partir de la retroalimentación que recibe, planificando y verificando el trabajo a partir de tareas en lenguaje natural en lugar de limitarse a completar líneas. Es una herramienta de Python, instalada con uv, y por debajo impulsa la familia de modelos Kimi K2."}, {"kind": "p", "text": "Para el trabajo de diseño, destacan dos propiedades. Los modelos Kimi K2 están ajustados explícitamente para programación agéntica de largo alcance y uso de herramientas, así que el agente puede llevar una construcción de varios pasos hasta un resultado funcional. Y la ventana de contexto alcanza hasta 256k tokens en las versiones recientes de K2, lo bastante grande para mantener tu sistema de diseño, biblioteca de componentes y conjunto de referencias enteros a la vez, en lugar de resumirlos."}, {"kind": "steps", "items": [{"label": "Archivos de contexto", "body": "Kimi CLI lee un archivo AGENTS.md como contexto persistente del proyecto, el lugar natural para codificar tus convenciones de diseño, tokens y listas de comprobación de revisión. Ejecuta /init para generar uno en un proyecto que no lo tenga."}, {"label": "MCP, ACP + subagentes", "body": "Gestiona servidores MCP de forma conversacional con /mcp-config, expone una sesión a través del Agent Client Protocol (kimi acp) a Zed y JetBrains, y puede despachar subagentes integrados de coder, explore y plan en contextos aislados."}, {"label": "Inicio de sesión o BYOK", "body": "En el primer arranque, /login te permite autorizar vía OAuth (Kimi Code) o introducir tu propia clave de API de Moonshot; la plataforma de Kimi también expone endpoints compatibles con OpenAI y Anthropic."}]}, {"kind": "ul", "items": ["Proveedor: Moonshot AI", "Credencial: clave de API de Moonshot (BYOK), o inicio de sesión OAuth vía Kimi Code", "Licencia: Apache-2.0, código abierto"]}]}, {"id": "why-design", "heading": "Por qué los modelos agénticos K2 y un gran contexto encajan con el diseño", "blocks": [{"kind": "p", "text": "La ventaja de Kimi CLI para diseño proviene de dos propiedades del modelo, pero, como con todo agente, el buen gusto sigue teniendo que aportarse."}, {"kind": "steps", "items": [{"label": "Programación agéntica de largo alcance", "body": "Los modelos Kimi K2 están optimizados para el uso de herramientas y el trabajo de varios pasos, así que el agente puede tomar una referencia y un encargo y de verdad construir, ejecutar y refinar la interfaz en lugar de detenerse en un primer borrador."}, {"label": "Una gran ventana de contexto", "body": "Hasta 256k tokens en las versiones recientes de K2 significa que todo el sistema de diseño, los tokens y muchos estados de referencia caben a la vez, así que el agente reutiliza tus primitivas reales en lugar de inventar estilos puntuales."}, {"label": "Convenciones en AGENTS.md", "body": "Un AGENTS.md (más un servidor MCP como Figma) dirige al agente a tus tokens, componentes y especificaciones reales, para que trabaje contra una marca en lugar de un aspecto por defecto."}]}, {"kind": "image", "src": "/agents/kimi-design/kimi-design-taste-triangle.webp", "alt": "Diagrama que muestra cómo el sistema de diseño, el skill y la imagen de referencia convergen en una buena salida de diseño", "caption": "El buen gusto proviene de tres insumos que tú aportas: un sistema de diseño, un skill e imágenes de referencia reales."}, {"kind": "p", "text": "La lección es la misma que enseña cada agente: Kimi CLI no tiene buen gusto por defecto. Produce buen diseño cuando le das restricciones: un sistema de diseño, un skill estético y referencias concretas. Open Design empaqueta exactamente esos insumos, y por eso ambos encajan (más abajo, con más detalle)."}]}, {"id": "setup", "heading": "Configura Kimi CLI para trabajo de diseño, desde cero", "blocks": [{"kind": "p", "text": "Este es el camino completo desde una máquina limpia hasta un Kimi CLI capaz de construir y verificar interfaces."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Kimi CLI (uses uv; Python 3.12–3.14, 3.13 recommended)\ncurl -LsSf https://code.kimi.com/install.sh | bash\n# or, if you already have uv:\nuv tool install --python 3.13 kimi-cli\n\n# 2. Start it in your project and authenticate on first run\ncd your-project\nkimi              # then run /login: OAuth via Kimi Code, or paste a Moonshot API key\n\n# 3. Generate project context\n/init             # scaffolds an AGENTS.md for this project\n\n# 4. Wire an MCP server (optional, e.g. Figma for design handoff)\n/mcp-config       # add, edit, and authenticate MCP servers conversationally"}, {"kind": "image", "src": "/agents/kimi-design/kimi-design-setup-flow.webp", "alt": "Flujo de configuración de cinco pasos: instalar, autenticarse, configurar AGENTS.md, añadir un skill, verificar", "caption": "La secuencia de configuración: instalar → autenticarse → configurar AGENTS.md → añadir un skill → habilitar la verificación en el navegador."}, {"kind": "steps", "items": [{"label": "Codifica tus reglas de diseño", "body": "Pon tus tokens, primitivas y convenciones en AGENTS.md y dirige a Kimi hacia ellos, para que la salida coincida con una marca en lugar de recurrir a un aspecto genérico."}, {"label": "Añade verificación en el navegador", "body": "Conecta un MCP de Playwright o de navegador para que Kimi renderice en un navegador real y compruebe su salida en distintos puntos de quiebre, en lugar de limitarse a confirmar que la compilación pasa."}]}]}, {"id": "screenshot-workflow", "heading": "El flujo de trabajo de referencia a interfaz", "blocks": [{"kind": "p", "text": "El bucle de diseño de mayor impacto con Kimi CLI es convertir material de referencia en una interfaz funcional y adaptable e iterar hasta que coincida, alimentando al agente con tus referencias y haciendo que compare su salida renderizada con ellas en un navegador real."}, {"kind": "ol", "items": ["Parte de las referencias más claras que tengas, e incluye varios estados (escritorio y móvil, hover, vacío, cargando), no solo una captura principal.", "Sé específico en el prompt; los prompts vagos producen interfaces genéricas incluso con un agente potente.", "Mantén tu sistema de diseño y convenciones en AGENTS.md, e indícale a Kimi dónde viven los tokens y las primitivas canónicas.", "Ejecuta un servidor de desarrollo y haz que Kimi renderice en un navegador real, redimensionando a los puntos de quiebre para comprobar el resultado.", "Itera haciendo que Kimi compare su implementación con las referencias, no que se limite a confirmar que compila."]}, {"kind": "p", "text": "Dirige a Kimi a tus referencias y al servidor de desarrollo, y luego da restricciones concretas:"}, {"kind": "code", "lang": "bash", "code": "kimi\n# in the prompt:\n> Implement the design in ./references (reference-desktop.png,\n  reference-mobile.png) using React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from AGENTS.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, render it in the browser, and iterate until it\n  matches the references across breakpoints."}, {"kind": "p", "text": "Mantén los prompts pequeños y enfocados, confirma las buenas iteraciones y revierte las malas (avisándole a Kimi cuando reviertas), para que cada pasada se construya sobre una base limpia. Kimi CLI también puede tomar una breve grabación de pantalla o un clip de demostración cuando un flujo es difícil de describir con palabras."}]}, {"id": "extend", "heading": "AGENTS.md, MCP y subagentes", "blocks": [{"kind": "p", "text": "Tres puntos de extensión hacen que Kimi CLI sea práctico para trabajo de diseño sostenido, y los tres encajan limpiamente en un flujo de trabajo de diseño abierto."}, {"kind": "steps", "items": [{"label": "Contexto de AGENTS.md", "body": "Las reglas del proyecto viven en un AGENTS.md en la raíz del repositorio. Es el hogar duradero de tus convenciones de diseño, leído en cada ejecución, y es el mismo formato portátil que usan otros agentes."}, {"label": "Servidores MCP", "body": "Añade servidores MCP de forma conversacional con /mcp-config: la forma portátil de incorporar contexto de diseño y herramientas externas, sobre todo el servidor MCP de Figma, que funcionan entre agentes, no solo en Kimi."}, {"label": "Subagentes y el marketplace de plugins", "body": "Despacha subagentes integrados de coder, explore y plan en contextos aislados, e instala skills, servidores MCP y fuentes de datos desde el marketplace o cualquier repositorio de GitHub para reunir referencias y ejecutar el bucle de verificación."}]}, {"kind": "p", "text": "Estas son capacidades portátiles y multiagente, exactamente el tipo de cosas que Open Design está diseñado para orquestar, en lugar de recrearlas en cada proyecto."}]}, {"id": "vs", "heading": "Kimi CLI vs Codex vs Claude Code vs Cursor vs Gemini CLI para diseño", "blocks": [{"kind": "p", "text": "No hay un único ganador para el trabajo de diseño: cada agente tiene una fortaleza distinta, y los equipos con experiencia los combinan. Un resumen justo:"}, {"kind": "table", "columns": ["Agente", "Fortaleza de diseño", "Ideal para"], "rows": [["Kimi CLI", "Modelos agénticos Kimi K2 ajustados para programación de largo alcance y uso de herramientas, con un gran contexto; de código abierto y BYOK", "Construcciones de varios pasos y mantener todo un sistema de diseño en contexto de forma asequible"], ["Codex", "Gran pulido visual con un skill de frontend; compilaciones asíncronas en sandbox", "Compilaciones asíncronas delegadas y reglas portátiles de AGENTS.md"], ["Claude Code", "Decisiones de diseño específicas (hex, espaciado, tipografía) y UX consciente de la base de código", "Razonamiento de frontend y refactorizaciones de gran contexto"], ["Cursor", "Bucle visual de construir y ver con vista previa en vivo y ediciones en línea", "Trabajo de interfaz ajustado de iterar y observar dentro de un IDE"], ["Gemini CLI", "Sólida comprensión de imágenes multimodal y un contexto de 1M de tokens; plan gratuito", "Trabajo con muchas capturas de pantalla y contexto muy grande"]]}, {"kind": "p", "text": "El veredicto recurrente de la comunidad es que el buen gusto proviene de las personas: todos recurren por defecto a una estética genérica sin skills, referencias y restricciones. Ese es el verdadero problema a resolver, y tiene forma de herramienta de diseño, no de modelo."}]}, {"id": "pitfalls", "heading": "Obstáculos y cómo evitar el aspecto de «IA descuidada»", "blocks": [{"kind": "p", "text": "La queja más común sobre el diseño generado por IA es que parece genérico: degradados suaves, paneles flotantes, esquinas redondeadas demasiado grandes, sombras dramáticas, un aire de Inter y morado que «grita que esto lo hizo una IA». Otros problemas reportados incluyen maquetaciones móviles rotas e instrucciones que se filtran en el texto de la interfaz. Ninguno de ellos es exclusivo de Kimi CLI; son lo que ocurre cuando cualquier agente se ejecuta sin un contexto de diseño curado."}, {"kind": "steps", "items": [{"label": "Añade un skill estético", "body": "Un skill de diseño curado obliga al agente a comprometerse con una dirección real en lugar del aspecto por defecto."}, {"label": "Verifica en un navegador real", "body": "Haz que Kimi renderice y autoverifique en distintos puntos de quiebre para que las maquetaciones no se rompan en silencio en móvil."}, {"label": "Aporta tokens y referencias", "body": "Los tokens de diseño reales y las capturas de referencia son la mayor palanca individual sobre la calidad de la salida."}, {"label": "Codifica reglas en AGENTS.md", "body": "Pon reglas de estilo como «sin tarjetas hero, máximo dos tipografías, jerarquía centrada en la marca» donde el agente las lee en cada ejecución."}]}, {"kind": "p", "text": "Fíjate en que toda mitigación consiste en dar al agente un contexto de diseño curado. Mantener ese contexto a mano, proyecto a proyecto, es la tarea pesada que Open Design elimina."}]}, {"id": "open-design", "heading": "Diseñar con Kimi CLI dentro de Open Design", "blocks": [{"kind": "p", "text": "Open Design es la capa de diseño de código abierto que el flujo de trabajo anterior no deja de pedir. Trata a Kimi CLI como un adaptador de primera categoría y lo envuelve en una biblioteca curada de skills y sistemas de diseño, una canalización de renderizado estructurada y una interfaz de escritorio local, de modo que el contexto de diseño que hace bueno a Kimi está ahí desde la primera ejecución, no ensamblado a mano cada vez. Ambos son de código abierto y local-first, lo que hace que la combinación encaje de forma natural."}, {"kind": "ol", "items": ["Instala Open Design y selecciona Kimi CLI como tu agente.", "Autentícate con tu clave de API de Moonshot (BYOK): las credenciales permanecen en tu máquina y nunca pasan por nuestros servidores.", "Elige un sistema de diseño y un skill, y luego genera presentaciones, prototipos y páginas de aterrizaje con un gusto consistente.", "Cada artefacto y archivo DESIGN.md vive en tu propio repositorio, no en una nube alojada."]}, {"kind": "p", "text": "El mismo agente Kimi CLI, la misma clave, más un flujo de trabajo de diseño real, portátil y de código abierto a su alrededor. Es local-first y Apache-2.0, así que nada de tu trabajo ni de tus credenciales sale de tu máquina."}]}], "faqTitle": "Preguntas frecuentes", "faq": [{"name": "¿Puede Kimi CLI hacer realmente trabajo de diseño?", "text": "Sí: con un skill estético, un sistema de diseño e imágenes de referencia reales en contexto, Kimi CLI produce interfaces adaptables de calidad de producción, y sus modelos agénticos Kimi K2 pueden renderizar y verificar la salida frente a las referencias. Sin ese contexto tiende a recurrir a un aspecto genérico, que es la brecha que Open Design rellena."}, {"name": "¿Tengo que pagar para diseñar con Kimi CLI?", "text": "Traes tus propias credenciales: autoriza vía el inicio de sesión OAuth de Kimi Code o pega una clave de API de Moonshot (BYOK), facturada por la plataforma de Moonshot. Open Design nunca actúa de intermediario con tus credenciales en ningún caso."}, {"name": "¿Qué hace bueno a Kimi CLI para diseño en concreto?", "text": "Dos cosas: los modelos Kimi K2 están ajustados para programación agéntica de largo alcance y uso de herramientas, así que el agente puede construir y refinar hasta un resultado funcional, y la ventana de contexto alcanza hasta 256k tokens, suficiente para mantener un sistema de diseño y un conjunto de referencias enteros a la vez. Ambas ayudan, pero el buen gusto sigue proviniendo del sistema de diseño, el skill y las referencias que tú aportas."}, {"name": "¿Kimi CLI o Claude Code para diseño de frontend?", "text": "Ambos son potentes. Claude Code es conocido por decisiones de diseño específicas y conscientes de la base de código; la ventaja de Kimi CLI son sus modelos agénticos Kimi K2 y un gran contexto con la economía de BYOK. Muchos equipos usan ambos: Open Design te permite cambiar de agente sin cambiar tu flujo de trabajo de diseño."}, {"name": "¿Cómo conecto Kimi CLI con Figma?", "text": "Ejecuta /mcp-config dentro de Kimi CLI para añadir y autenticar el servidor MCP de Figma. Kimi puede entonces extraer contexto de diseño real —componentes, variables, datos de maquetación— para que el código generado coincida con la fuente en lugar de aproximarla."}, {"name": "¿Open Design está afiliado a Moonshot AI?", "text": "No. Kimi CLI es un producto de Moonshot AI; Open Design es un proyecto independiente de código abierto que lo admite como adaptador de primera categoría. Kimi es una marca comercial de Moonshot AI."}, {"name": "¿Están seguros mis archivos y credenciales?", "text": "Sí: Open Design es local-first y Apache-2.0. Tus archivos, artefactos y DESIGN.md permanecen en tu propio repositorio, y tus credenciales de Moonshot las usa directamente tu agente, sin enrutarse nunca a través de los servidores de Open Design."}], "ctaTitle": "Diseña con Kimi CLI, a la manera abierta.", "ctaBody": "Trae tu propia clave de API de Moonshot, mantén cada archivo en local y obtén una biblioteca de diseño curada alrededor del agente que ya usas.", "ctaActions": [{"label": "Usa Kimi CLI dentro de Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dale una estrella en GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Descarga la aplicación de escritorio", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Ver todos los agentes compatibles"},
      },
      'deepseek': {
        ...en['deepseek']!,
        title: "DeepSeek TUI para diseño — Open Design",
        description: "Cómo se usa un agente de programación de terminal impulsado por DeepSeek para diseño de interfaces y web —sus potentes modelos de programación, un contexto de 1M de tokens, su eficiencia de costes, los archivos de contexto y MCP— y cómo Open Design convierte la DeepSeek TUI en un agente de diseño local-first y de código abierto.",
        breadcrumb: "DeepSeek TUI",
        label: "Agente · DeepSeek TUI",
        heading: "DeepSeek TUI para diseño.",
        lead: "DeepSeek TUI es un agente de programación de terminal impulsado por los modelos de DeepSeek. Sus potentes modelos de programación con buena eficiencia de costes y su contexto de 1M de tokens pueden mantener un sistema de diseño y una base de código enteros a la vez, lo que lo convierte en una verdadera herramienta de diseño, una vez que le das referencias, convenciones y un bucle de verificación. Open Design lo integra en un flujo de trabajo de diseño de código abierto: tu clave de API de DeepSeek, tus archivos, local-first.",
        rich: {"heroCtaLead": "Open Design convierte la DeepSeek TUI en un agente de diseño local-first y de código abierto: tu clave de API de DeepSeek, tus archivos y una biblioteca curada de skills y sistemas de diseño a su alrededor.", "heroCtaActions": [{"label": "Usa DeepSeek TUI dentro de Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dale una estrella en GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Descarga la aplicación de escritorio", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["DeepSeek TUI es un agente de programación de IA basado en terminal impulsado por los modelos de DeepSeek. Dos cosas lo hacen interesante específicamente para diseño: sus modelos de programación son potentes e inusualmente eficientes en costes, así que puedes iterar de forma agresiva sin estar mirando el contador; y su ventana de contexto alcanza hasta 1M de tokens, lo bastante grande para mantener un sistema de diseño y una base de código enteros a la vez, en lugar de resumirlos. Combinado con las referencias, convenciones y un bucle de verificación adecuados, construye interfaces reales y adaptables. Esta es una guía práctica y de extremo a extremo para usar un agente de terminal impulsado por DeepSeek en trabajo de interfaces, frontend y sistemas de diseño, y para integrarlo en un flujo de trabajo de diseño estructurado con Open Design.", "Cubre qué es realmente la DeepSeek TUI, por qué los potentes modelos de programación, un enorme contexto y el bajo coste encajan con el diseño, cómo configurarlo desde cero, el bucle de referencia a interfaz, cómo lo amplían los archivos de contexto y MCP, cómo se compara con Codex, Claude Code, Cursor y Gemini CLI, los obstáculos que hacen que la salida de la IA parezca genérica, y cómo Open Design cierra la brecha como una capa de diseño abierta y local-first: una combinación natural, ya que ambos son abiertos y se ejecutan en tu propia máquina."], "heroImage": {"src": "/agents/deepseek-design/deepseek-design-hero.webp", "alt": "Bucle de retroalimentación de diseño de DeepSeek TUI: un agente de terminal leyendo referencias y convenciones, un navegador renderizando la interfaz y un espacio de trabajo, con una flecha de retroalimentación que vuelve al inicio", "caption": "El bucle central: DeepSeek TUI lee tus referencias y convenciones en la terminal, construye y verifica la interfaz en un navegador real e itera frente a ellas, con todo un sistema de diseño en contexto."}, "tocLabel": "En esta página", "toc": [{"id": "what-is-deepseek", "label": "Qué es realmente DeepSeek TUI"}, {"id": "why-design", "label": "Por qué los potentes modelos de programación + un enorme contexto encajan con el diseño"}, {"id": "setup", "label": "Configura DeepSeek TUI para diseño (desde cero)"}, {"id": "screenshot-workflow", "label": "El flujo de trabajo de referencia a interfaz"}, {"id": "extend", "label": "Archivos de contexto, MCP y herramientas"}, {"id": "vs", "label": "DeepSeek TUI vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Obstáculos y el aspecto de «IA descuidada»"}, {"id": "open-design", "label": "Diseñar con DeepSeek TUI en Open Design"}, {"id": "faq", "label": "Preguntas frecuentes"}], "sections": [{"id": "what-is-deepseek", "heading": "Qué es realmente DeepSeek TUI", "blocks": [{"kind": "p", "text": "Una DeepSeek TUI es un agente de IA de terminal controlado por teclado que ejecuta los modelos de DeepSeek. Lee tu repositorio, edita archivos, ejecuta comandos de shell, gestiona git y puede buscar en la web, planificando y verificando el trabajo a partir de tareas en lenguaje natural en lugar de limitarse a completar líneas. DeepSeek en sí es el proveedor de modelos: una API compatible con OpenAI (también expone un endpoint en formato Anthropic), así que una amplia gama de agentes de terminal de la comunidad puede apuntar a DeepSeek estableciendo una URL base y una clave. Varias TUI de código abierto incluyen DeepSeek como proveedor de primera categoría."}, {"kind": "p", "text": "Para el trabajo de diseño, destacan tres propiedades. Los modelos de programación de DeepSeek son potentes, así que el agente razona sobre la maquetación, la estructura y la jerarquía de componentes a partir de una descripción clara. Su ventana de contexto alcanza hasta 1M de tokens, lo bastante grande para mantener tu sistema de diseño y biblioteca de componentes enteros a la vez. Y su precio por token es muy bajo, con caché de contexto por prefijo encima, así que iterar sobre un diseño cuesta poco."}, {"kind": "steps", "items": [{"label": "Archivos de contexto", "body": "Los agentes de terminal leen un archivo de contexto del proyecto (un archivo al estilo AGENTS.md, o la propia convención del agente) en busca de reglas persistentes, el lugar natural para codificar tus convenciones de diseño, tokens y listas de comprobación de revisión."}, {"label": "Herramientas + MCP", "body": "La mayoría de las DeepSeek TUI incluyen herramientas de archivos, shell, git y web, y admiten servidores MCP para añadir contexto externo, como un archivo de Figma en vivo: la API de DeepSeek admite la llamada a herramientas, de la que dependen estos agentes."}, {"label": "Trae tu propia clave", "body": "Te autenticas con una clave de API de DeepSeek de la plataforma de DeepSeek. Como la API es compatible con OpenAI, apuntar un agente a DeepSeek suele ser cuestión de dos líneas: la URL base y la clave."}]}, {"kind": "ul", "items": ["Proveedor: DeepSeek (proveedor de modelo y API)", "Credencial: clave de API de DeepSeek (BYOK) de la plataforma de DeepSeek", "Modelos: deepseek-v4-flash y deepseek-v4-pro (solo texto; sin entrada de imágenes nativa)"]}]}, {"id": "why-design", "heading": "Por qué los potentes modelos de programación y un enorme contexto encajan con el diseño", "blocks": [{"kind": "p", "text": "La ventaja de DeepSeek TUI para diseño proviene del modelo y su economía, pero, como con todo agente, el buen gusto sigue teniendo que aportarse."}, {"kind": "steps", "items": [{"label": "Programación potente y eficiente en costes", "body": "Los modelos de programación de DeepSeek son capaces y económicos, así que el agente razona bien sobre la maquetación y la estructura, y puedes iterar muchas veces sin que el coste sea la limitación."}, {"label": "Una ventana de contexto de 1M de tokens", "body": "Un gran contexto significa que todo el sistema de diseño, los tokens y muchos estados de referencia caben a la vez, así que el agente reutiliza tus primitivas reales en lugar de inventar estilos puntuales, y la caché de contexto mantiene baratos los prompts repetidos."}, {"label": "Convenciones en un archivo de contexto", "body": "Un archivo de contexto del proyecto (más el servidor MCP de Figma) dirige al agente a tus tokens, componentes y especificaciones reales, para que trabaje contra una marca en lugar de un aspecto por defecto."}]}, {"kind": "image", "src": "/agents/deepseek-design/deepseek-design-taste-triangle.webp", "alt": "Diagrama que muestra cómo el sistema de diseño, el skill y la referencia convergen en una buena salida de diseño", "caption": "El buen gusto proviene de tres insumos que tú aportas: un sistema de diseño, un skill y referencias reales."}, {"kind": "p", "text": "La lección es la misma que enseña cada agente: DeepSeek TUI no tiene buen gusto por defecto. Produce buen diseño cuando le das restricciones: un sistema de diseño, un skill estético y referencias concretas. Open Design empaqueta exactamente esos insumos, y por eso ambos encajan (más abajo, con más detalle)."}]}, {"id": "setup", "heading": "Configura DeepSeek TUI para trabajo de diseño, desde cero", "blocks": [{"kind": "p", "text": "Este es el camino completo desde una máquina limpia hasta una DeepSeek TUI capaz de construir y verificar interfaces. Los nombres exactos de instalación y de comandos varían según el agente de terminal que elijas, así que los pasos siguientes se mantienen en el nivel que es válido para todos ellos."}, {"kind": "code", "lang": "bash", "code": "# 1. Get a DeepSeek API key from the DeepSeek platform\n#    https://platform.deepseek.com\nexport DEEPSEEK_API_KEY=sk-...\n\n# 2. Install a DeepSeek-capable terminal agent (follow its README),\n#    then point it at DeepSeek. The API is OpenAI-compatible:\n#      base URL: https://api.deepseek.com\n#      model:    deepseek-v4-flash (or deepseek-v4-pro)\n#    (an Anthropic-format endpoint also exists at /anthropic)\n\n# 3. Start it in your project and generate project context\ncd your-project\n#   create/scaffold a project context file with your design rules\n\n# 4. Wire the Figma MCP server (optional, for design handoff)\n#    add it to the agent's MCP server configuration"}, {"kind": "image", "src": "/agents/deepseek-design/deepseek-design-setup-flow.webp", "alt": "Flujo de configuración de cinco pasos: obtener la clave, instalar el agente, configurar el archivo de contexto, añadir un skill, verificar", "caption": "La secuencia de configuración: obtener una clave → apuntar el agente a DeepSeek → configurar un archivo de contexto → añadir un skill → habilitar la verificación en el navegador."}, {"kind": "steps", "items": [{"label": "Codifica tus reglas de diseño", "body": "Pon tus tokens, primitivas y convenciones en el archivo de contexto del agente y dirígelo hacia ellos, para que la salida coincida con una marca en lugar de recurrir a un aspecto genérico."}, {"label": "Añade verificación en el navegador", "body": "Conecta un MCP de Playwright o de navegador para que el agente renderice en un navegador real y compruebe su salida en distintos puntos de quiebre, en lugar de limitarse a confirmar que la compilación pasa."}]}]}, {"id": "screenshot-workflow", "heading": "El flujo de trabajo de referencia a interfaz", "blocks": [{"kind": "p", "text": "Los modelos de DeepSeek son solo de texto —no leen imágenes de forma nativa—, así que el bucle de diseño de mayor impacto es convertir referencias claras y maquetaciones descritas en una interfaz funcional y adaptable, y luego verificar el resultado en un navegador real en lugar de pedirle al modelo que mire una captura."}, {"kind": "ol", "items": ["Parte de las referencias más claras que tengas, y describe varios estados (escritorio y móvil, hover, vacío, cargando), no solo una captura principal.", "Sé específico en el prompt; los prompts vagos producen interfaces genéricas incluso con un modelo potente. Detalla el espaciado, la jerarquía y los componentes a reutilizar.", "Mantén tu sistema de diseño y convenciones en el archivo de contexto, e indícale al agente dónde viven los tokens y las primitivas canónicas.", "Ejecuta un servidor de desarrollo y haz que el agente renderice en un navegador real, redimensionando a los puntos de quiebre para comprobar el resultado: aquí es donde ocurre la verificación, ya que el modelo no puede ver la imagen en sí.", "Itera haciendo que el agente compare el DOM renderizado y los estilos computados con tu especificación descrita, no que se limite a confirmar que compila."]}, {"kind": "p", "text": "Describe el objetivo con precisión y da restricciones concretas:"}, {"kind": "code", "lang": "bash", "code": "# in the agent's prompt:\n> Implement this design in React + Vite + Tailwind + TypeScript.\n  Layout: two-column dashboard, 240px sidebar, 24px gutters,\n  card grid at 3/2/1 columns for desktop/tablet/mobile.\n  Reuse my existing design-system components and tokens from the\n  context file. Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, render it in the browser, and iterate against the\n  spec across breakpoints until it matches."}, {"kind": "p", "text": "Mantén los prompts pequeños y enfocados, confirma las buenas iteraciones y revierte las malas (avisándole al agente cuando reviertas), para que cada pasada se construya sobre una base limpia."}]}, {"id": "extend", "heading": "Archivos de contexto, MCP y herramientas", "blocks": [{"kind": "p", "text": "Tres puntos de extensión hacen que una DeepSeek TUI sea práctica para trabajo de diseño sostenido, y los tres encajan limpiamente en un flujo de trabajo de diseño abierto."}, {"kind": "steps", "items": [{"label": "Archivo de contexto del proyecto", "body": "Las reglas del proyecto viven en un archivo de contexto en la raíz del repositorio (con capas global y de equipo). Es el hogar duradero de tus convenciones de diseño, leído en cada ejecución."}, {"label": "Servidores MCP", "body": "Configura servidores MCP en el agente: la forma portátil de incorporar contexto de diseño y herramientas externas, sobre todo el servidor MCP de Figma, que funcionan entre agentes, no solo en uno. La API de DeepSeek admite la llamada a herramientas de la que dependen estos servidores."}, {"label": "Herramientas integradas", "body": "Las DeepSeek TUI incluyen herramientas de archivos, shell, git y web para que el agente pueda reunir referencias y ejecutar el bucle de verificación sin salir de la terminal."}]}, {"kind": "p", "text": "Estas son capacidades portátiles y multiagente, exactamente el tipo de cosas que Open Design está diseñado para orquestar, en lugar de recrearlas en cada proyecto."}]}, {"id": "vs", "heading": "DeepSeek TUI vs Codex vs Claude Code vs Cursor vs Gemini CLI para diseño", "blocks": [{"kind": "p", "text": "No hay un único ganador para el trabajo de diseño: cada agente tiene una fortaleza distinta, y los equipos con experiencia los combinan. Un resumen justo:"}, {"kind": "table", "columns": ["Agente", "Fortaleza de diseño", "Ideal para"], "rows": [["DeepSeek TUI", "Modelos de programación potentes y muy eficientes en costes con pesos abiertos y un contexto de 1M de tokens; solo texto (sin visión nativa)", "Iteración de alto volumen con presupuesto ajustado y mantener todo un sistema de diseño en contexto"], ["Codex", "Gran pulido visual con un skill de frontend; compilaciones asíncronas en sandbox", "Compilaciones asíncronas delegadas y reglas portátiles de AGENTS.md"], ["Claude Code", "Decisiones de diseño específicas (hex, espaciado, tipografía) y UX consciente de la base de código", "Razonamiento de frontend y refactorizaciones de gran contexto"], ["Cursor", "Bucle visual de construir y ver con vista previa en vivo y ediciones en línea", "Trabajo de interfaz ajustado de iterar y observar dentro de un IDE"], ["Gemini CLI", "Comprensión de imágenes multimodal nativa y un contexto de 1M de tokens; de código abierto con un plan gratuito", "Trabajo con muchas capturas de pantalla donde el agente lee las referencias directamente"]]}, {"kind": "p", "text": "El veredicto recurrente de la comunidad es que el buen gusto proviene de las personas: todos recurren por defecto a una estética genérica sin skills, referencias y restricciones. Ese es el verdadero problema a resolver, y tiene forma de herramienta de diseño, no de modelo."}]}, {"id": "pitfalls", "heading": "Obstáculos y cómo evitar el aspecto de «IA descuidada»", "blocks": [{"kind": "p", "text": "La queja más común sobre el diseño generado por IA es que parece genérico: degradados suaves, paneles flotantes, esquinas redondeadas demasiado grandes, sombras dramáticas, un aire de Inter y morado que «grita que esto lo hizo una IA». Otros problemas reportados incluyen maquetaciones móviles rotas e instrucciones que se filtran en el texto de la interfaz. Ninguno de ellos es exclusivo de DeepSeek TUI; son lo que ocurre cuando cualquier agente se ejecuta sin un contexto de diseño curado. Como DeepSeek es solo de texto, es especialmente importante verificar en un navegador real en lugar de confiar en que el modelo «mire» el resultado."}, {"kind": "steps", "items": [{"label": "Añade un skill estético", "body": "Un skill de diseño curado obliga al agente a comprometerse con una dirección real en lugar del aspecto por defecto."}, {"label": "Verifica en un navegador real", "body": "Renderiza y autoverifica en distintos puntos de quiebre con una herramienta de navegador —esencial aquí, ya que el modelo no puede leer una captura por sí mismo— para que las maquetaciones no se rompan en silencio en móvil."}, {"label": "Aporta tokens y referencias", "body": "Los tokens de diseño reales y las referencias concretas y descritas son la mayor palanca individual sobre la calidad de la salida."}, {"label": "Codifica reglas en el archivo de contexto", "body": "Pon reglas de estilo como «sin tarjetas hero, máximo dos tipografías, jerarquía centrada en la marca» donde el agente las lee en cada ejecución."}]}, {"kind": "p", "text": "Fíjate en que toda mitigación consiste en dar al agente un contexto de diseño curado. Mantener ese contexto a mano, proyecto a proyecto, es la tarea pesada que Open Design elimina."}]}, {"id": "open-design", "heading": "Diseñar con DeepSeek TUI dentro de Open Design", "blocks": [{"kind": "p", "text": "Open Design es la capa de diseño de código abierto que el flujo de trabajo anterior no deja de pedir. Trata al agente DeepSeek como un adaptador de primera categoría y lo envuelve en una biblioteca curada de skills y sistemas de diseño, una canalización de renderizado estructurada y una interfaz de escritorio local, de modo que el contexto de diseño que hace bueno a DeepSeek está ahí desde la primera ejecución, no ensamblado a mano cada vez. Ambos son abiertos y local-first, lo que hace que la combinación encaje de forma natural."}, {"kind": "ol", "items": ["Instala Open Design y selecciona la DeepSeek TUI como tu agente.", "Autentícate con tu propia clave de API de DeepSeek (BYOK): las credenciales permanecen en tu máquina y nunca pasan por nuestros servidores.", "Elige un sistema de diseño y un skill, y luego genera presentaciones, prototipos y páginas de aterrizaje con un gusto consistente.", "Cada artefacto y archivo DESIGN.md vive en tu propio repositorio, no en una nube alojada."]}, {"kind": "p", "text": "El mismo agente DeepSeek, la misma clave, más un flujo de trabajo de diseño real, portátil y de código abierto a su alrededor. Es local-first y Apache-2.0, así que nada de tu trabajo ni de tus credenciales sale de tu máquina."}]}], "faqTitle": "Preguntas frecuentes", "faq": [{"name": "¿Puede DeepSeek TUI hacer realmente trabajo de diseño?", "text": "Sí: con un skill estético, un sistema de diseño y referencias concretas en contexto, un agente de terminal impulsado por DeepSeek produce interfaces adaptables de calidad de producción, y verificas la salida en un navegador real. Los modelos de DeepSeek son solo de texto, así que el bucle de verificación sustituye a la lectura nativa de imágenes. Sin ese contexto tiende a recurrir a un aspecto genérico, que es la brecha que Open Design rellena."}, {"name": "¿Cuánto cuesta diseñar con DeepSeek TUI?", "text": "Poco: la API de DeepSeek está entre las más baratas por token, y la caché de contexto por prefijo reduce aún más el coste de los prompts repetidos, así que puedes iterar de forma agresiva. Traes tu propia clave de API de DeepSeek (BYOK); Open Design nunca actúa de intermediario con tus credenciales."}, {"name": "¿Qué hace bueno a DeepSeek para diseño en concreto?", "text": "Modelos de programación potentes y eficientes en costes, pesos abiertos y un contexto de 1M de tokens que mantiene un sistema de diseño y un conjunto de referencias enteros a la vez. DeepSeek es solo de texto —no lee imágenes de forma nativa—, así que el buen gusto sigue proviniendo del sistema de diseño, el skill y las referencias descritas que tú aportas, verificadas en un navegador."}, {"name": "¿DeepSeek TUI o Claude Code para diseño de frontend?", "text": "Ambos son potentes. Claude Code es conocido por decisiones de diseño específicas y conscientes de la base de código; la ventaja de DeepSeek TUI son los pesos abiertos, el coste muy bajo y un enorme contexto para iteración de alto volumen. Muchos equipos usan ambos: Open Design te permite cambiar de agente sin cambiar tu flujo de trabajo de diseño."}, {"name": "¿Cómo conecto DeepSeek TUI con Figma?", "text": "Añade el servidor MCP de Figma en la configuración de MCP de tu agente de terminal. El agente puede entonces extraer contexto de diseño real —componentes, variables, datos de maquetación— para que el código generado coincida con la fuente en lugar de aproximarla. La API de DeepSeek admite la llamada a herramientas de la que depende MCP."}, {"name": "¿Open Design está afiliado a DeepSeek?", "text": "No. DeepSeek es el proveedor de modelo y API; Open Design es un proyecto independiente de código abierto que admite agentes de terminal impulsados por DeepSeek como adaptador de primera categoría. DeepSeek es una marca comercial de DeepSeek."}, {"name": "¿Están seguros mis archivos y credenciales?", "text": "Sí: Open Design es local-first y Apache-2.0. Tus archivos, artefactos y DESIGN.md permanecen en tu propio repositorio, y tu clave de API de DeepSeek la usa directamente tu agente, sin enrutarse nunca a través de los servidores de Open Design."}], "ctaTitle": "Diseña con DeepSeek TUI, a la manera abierta.", "ctaBody": "Trae tu propia clave de API de DeepSeek, mantén cada archivo en local y obtén una biblioteca de diseño curada alrededor del agente que ya usas.", "ctaActions": [{"label": "Usa DeepSeek TUI dentro de Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dale una estrella en GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Descarga la aplicación de escritorio", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Ver todos los agentes compatibles"},
      },
      'trae-cli': {
        ...en['trae-cli']!,
        title: "Trae CLI para diseño — Open Design",
        description: "Cómo se usa el Trae CLI de ByteDance (trae-agent) para diseño de interfaces y web —su agente de CLI de código abierto y agnóstico al modelo, su proveedor de LLM «trae el tuyo» y su flujo de trabajo basado en configuración— y cómo Open Design convierte a Trae CLI en un agente de diseño local-first y de código abierto sobre ACP.",
        breadcrumb: "Trae CLI",
        label: "Agente · Trae CLI",
        heading: "Trae CLI para diseño.",
        lead: "Trae CLI es el agente de terminal de código abierto de ByteDance (trae-agent). Es agnóstico al modelo —lo apuntas al proveedor de LLM en el que confías— y lee tu repositorio, edita archivos y ejecuta comandos a partir de tareas en lenguaje natural, lo que lo convierte en una verdadera herramienta de diseño una vez que le das referencias, convenciones y un bucle de verificación. Open Design lo integra en un flujo de diseño de código abierto sobre ACP: tu propia clave de proveedor, tus archivos, local-first.",
        rich: {"heroCtaLead": "Open Design convierte a Trae CLI en un agente de diseño local-first y de código abierto: tu propia clave de proveedor de LLM, tus archivos y una biblioteca curada de skills y sistemas de diseño a su alrededor, gobernado sobre ACP.", "heroCtaActions": [{"label": "Usa Trae CLI dentro de Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dale una estrella en GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Descarga la app de escritorio", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Trae CLI es el agente de IA de código abierto para la terminal de ByteDance, distribuido como el proyecto trae-agent. Dos cosas lo hacen interesante específicamente para el diseño: es agnóstico al modelo, así que puedes traer el proveedor de LLM en el que confíes en lugar de quedar atado a un único fabricante; y es un agente transparente con licencia MIT que lee tu código base, edita archivos y ejecuta comandos de shell a partir de tareas en lenguaje natural. Combinado con las referencias, convenciones y un bucle de verificación adecuados, construye interfaces reales y adaptables, y empezar es gratis y abierto: solo aportas una clave de proveedor. Esta es una guía práctica y de principio a fin para usar Trae CLI en interfaces, frontend y trabajo con sistemas de diseño, y para integrarlo en un flujo de diseño estructurado con Open Design.", "Cubre qué es realmente Trae CLI, por qué un agente abierto y agnóstico al modelo encaja con el diseño, cómo configurarlo desde cero, el bucle de captura de pantalla a interfaz, cómo lo extienden su archivo de configuración y sus herramientas, cómo se compara con Codex, Claude Code, Cursor y Gemini CLI, los errores que hacen que el resultado de la IA luzca genérico, y cómo Open Design cierra la brecha como una capa de diseño abierta y local-first, una combinación natural, ya que ambos son de código abierto y se ejecutan en tu propia máquina, con Open Design gobernando a Trae CLI sobre el Agent Client Protocol (ACP)."], "heroImage": {"src": "/agents/trae-cli-design/trae-cli-design-hero.webp", "alt": "Bucle de retroalimentación de diseño de Trae CLI: un agente de terminal leyendo una imagen de referencia, un navegador renderizando la interfaz y un espacio de trabajo, con una flecha de retroalimentación que regresa", "caption": "El bucle central: Trae CLI lee tus referencias y convenciones en la terminal, construye y verifica la interfaz en un navegador real e itera contra ellas."}, "tocLabel": "En esta página", "toc": [{"id": "what-is-trae-cli", "label": "Qué es realmente Trae CLI"}, {"id": "why-design", "label": "Por qué un agente abierto y agnóstico al modelo encaja con el diseño"}, {"id": "setup", "label": "Configura Trae CLI para diseño (desde cero)"}, {"id": "screenshot-workflow", "label": "El flujo de captura de pantalla a interfaz"}, {"id": "extend", "label": "Configuración, herramientas y proveedores"}, {"id": "vs", "label": "Trae CLI frente a Codex, Claude Code, Cursor y Gemini CLI"}, {"id": "pitfalls", "label": "Errores comunes y el aspecto de «basura de IA»"}, {"id": "open-design", "label": "Diseñar con Trae CLI en Open Design"}, {"id": "faq", "label": "Preguntas frecuentes"}], "sections": [{"id": "what-is-trae-cli", "heading": "Qué es realmente Trae CLI", "blocks": [{"kind": "p", "text": "Trae CLI es el agente de línea de comandos del proyecto de código abierto trae-agent de ByteDance. Lee tu repositorio, visualiza, crea y edita archivos, y ejecuta comandos de shell en un entorno persistente, planificando y verificando el trabajo a partir de tareas en lenguaje natural en lugar de limitarse a completar líneas. Tiene licencia MIT y está construido en torno a una arquitectura transparente y modular, por lo que es fácil de inspeccionar y extender. Es distinto del Trae IDE independiente, el editor de IA basado en VS Code de ByteDance, aunque ambos provienen del mismo fabricante."}, {"kind": "p", "text": "Para el trabajo de diseño destacan dos propiedades. Es agnóstico al modelo: tú eliges el proveedor de LLM, así que nunca quedas atado a las fortalezas o los límites de un único modelo. Y es totalmente abierto y basado en configuración, así que su comportamiento, sus herramientas y su proveedor pueden fijarse en el control de versiones junto a tu proyecto en lugar de quedar ocultos tras un servicio alojado."}, {"kind": "steps", "items": [{"label": "Modos run e interactivo", "body": "Trae CLI ejecuta una sola tarea con `trae-cli run \"...\"` o mantiene una sesión continua con `trae-cli interactive`, el lugar natural para iterar sobre una interfaz contra tus convenciones de diseño."}, {"label": "Herramientas integradas", "body": "Incluye de serie herramientas de edición de archivos, ejecución de bash/shell y razonamiento estructurado, así que puede construir, levantar un servidor de desarrollo e inspeccionar errores en tiempo de ejecución sin salir de la terminal."}, {"label": "Trae tu propio proveedor", "body": "Aportas una clave de API del proveedor en el que confías —OpenAI, Anthropic, Google, OpenRouter, Doubao, Azure o un modelo local de Ollama— mediante variables de entorno o un archivo de configuración."}]}, {"kind": "ul", "items": ["Fabricante: ByteDance (proyecto de código abierto trae-agent)", "Credencial: una clave de API de un proveedor de LLM (BYOK), p. ej. OpenAI, Anthropic, Google, OpenRouter, Doubao, Azure o un modelo local de Ollama", "Licencia: MIT, código abierto"]}]}, {"id": "why-design", "heading": "Por qué un agente abierto y agnóstico al modelo encaja con el diseño", "blocks": [{"kind": "p", "text": "La ventaja de Trae CLI para el diseño viene de ser abierto y flexible en cuanto a proveedores, pero, como ocurre con todo agente, el criterio estético hay que aportarlo igualmente."}, {"kind": "steps", "items": [{"label": "Agnóstico al modelo por diseño", "body": "Como tú eliges el proveedor, puedes encaminar el trabajo de diseño al modelo que mejor razone hoy sobre maquetación y código de frontend, y cambiarlo más adelante sin alterar tu flujo de trabajo."}, {"label": "Abierto y basado en configuración", "body": "El agente, sus herramientas y su proveedor quedan fijados en un archivo de configuración que puedes versionar, así que un equipo obtiene el mismo comportamiento del agente en cada máquina en lugar de desviarse según cada desarrollador."}, {"label": "Convenciones en tu repositorio", "body": "Apunta el agente a tus tokens, componentes y especificaciones reales —guardados en tu proyecto— para que trabaje contra una marca en lugar de caer en un aspecto genérico por defecto."}]}, {"kind": "image", "src": "/agents/trae-cli-design/trae-cli-design-taste-triangle.webp", "alt": "Diagrama que muestra cómo un sistema de diseño, una skill y una imagen de referencia convergen en un buen resultado de diseño", "caption": "El criterio estético proviene de tres insumos que tú aportas: un sistema de diseño, una skill e imágenes de referencia reales."}, {"kind": "p", "text": "La lección es la misma que enseña todo agente: Trae CLI no tiene criterio estético por defecto. Produce buen diseño cuando le das restricciones: un sistema de diseño, una skill estética y referencias concretas. Open Design empaqueta exactamente esos insumos y se los entrega a Trae CLI sobre ACP, por lo que ambos encajan (más abajo se explica)."}]}, {"id": "setup", "heading": "Configura Trae CLI para el trabajo de diseño, desde cero", "blocks": [{"kind": "p", "text": "Este es el recorrido completo, desde una máquina limpia hasta un Trae CLI capaz de construir y verificar interfaces. Trae CLI se instala desde el código fuente con uv y luego se configura con el proveedor de LLM que quieras usar."}, {"kind": "code", "lang": "bash", "code": "# 1. Get Trae CLI (trae-agent) from source — needs uv\ngit clone https://github.com/bytedance/trae-agent.git\ncd trae-agent\nuv sync --all-extras\nsource .venv/bin/activate\n\n# 2. Authenticate by pointing it at your LLM provider key\n#    set it in the environment (or a trae_config.yaml file)\nexport OPENAI_API_KEY=...        # or ANTHROPIC_API_KEY, GOOGLE_API_KEY, etc.\n\n# 3. Run a task in your project\ntrae-cli run \"Create a hello world page\"\n#    or hold a session:\ntrae-cli interactive\n\n# 4. Check the resolved configuration (keys are masked)\ntrae-cli show-config"}, {"kind": "image", "src": "/agents/trae-cli-design/trae-cli-design-setup-flow.webp", "alt": "Flujo de configuración en cinco pasos: instalar, autenticarse, configurar convenciones, añadir una skill, verificar", "caption": "La secuencia de configuración: instalar → autenticarse con una clave de proveedor → configurar tus convenciones de diseño → añadir una skill → habilitar la verificación en el navegador."}, {"kind": "steps", "items": [{"label": "Codifica tus reglas de diseño", "body": "Mantén tus tokens, primitivos y convenciones en el repositorio y apunta Trae CLI hacia ellos, para que el resultado se ajuste a una marca en lugar de caer en un aspecto genérico por defecto."}, {"label": "Añade verificación en el navegador", "body": "Haz que Trae CLI levante un servidor de desarrollo y renderice en un navegador real para que compruebe su resultado en los distintos breakpoints, en lugar de limitarse a confirmar que el build pasa."}]}]}, {"id": "screenshot-workflow", "heading": "El flujo de captura de pantalla a interfaz", "blocks": [{"kind": "p", "text": "El bucle de diseño de mayor rendimiento con Trae CLI consiste en convertir una imagen de referencia en una interfaz funcional y adaptable e iterar hasta que coincida. Como Trae CLI es agnóstico al modelo, apúntalo a un proveedor cuyo modelo maneje bien tus referencias, y apóyate en un navegador real para comprobar el resultado."}, {"kind": "ol", "items": ["Parte de las referencias visuales más claras que tengas, y describe varios estados (escritorio y móvil, hover, vacío, cargando), no solo una imagen principal.", "Sé específico en el prompt; los prompts vagos producen interfaces genéricas incluso con un modelo potente.", "Mantén tu sistema de diseño y tus convenciones en el repositorio, e indícale a Trae CLI dónde viven los tokens y los primitivos canónicos.", "Levanta un servidor de desarrollo y haz que Trae CLI renderice en un navegador real, redimensionando a los distintos breakpoints para comprobar el resultado.", "Itera haciendo que Trae CLI compare su implementación con las referencias, no solo que confirme que compila."]}, {"kind": "p", "text": "Ejecuta una sesión interactiva y da restricciones concretas en lugar de una petición de una sola línea:"}, {"kind": "code", "lang": "bash", "code": "trae-cli interactive\n# in the session:\n> Implement the attached reference design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, render it in the browser, and iterate until it\n  matches the references across breakpoints."}, {"kind": "p", "text": "Mantén los prompts breves y enfocados, confirma las buenas iteraciones y revierte las malas (avisando a Trae CLI cuando reviertas), para que cada pasada parta de una base limpia."}]}, {"id": "extend", "heading": "Configuración, herramientas y proveedores", "blocks": [{"kind": "p", "text": "Tres puntos de extensión hacen que Trae CLI sea práctico para un trabajo de diseño sostenido, y los tres encajan limpiamente en un flujo de diseño abierto."}, {"kind": "steps", "items": [{"label": "Archivo de configuración", "body": "Trae CLI lee un trae_config.yaml que fija tu proveedor, modelo y ajustes: el hogar duradero y versionable de cómo se ejecuta el agente en un proyecto."}, {"label": "Elección de proveedor", "body": "Como admite muchos proveedores (OpenAI, Anthropic, Google, OpenRouter, Doubao, Azure, Ollama), encaminas el trabajo de diseño al modelo en el que confías y lo cambias sin rehacer tu flujo de trabajo."}, {"label": "Herramientas integradas", "body": "Sus herramientas de edición de archivos, shell y razonamiento estructurado le permiten reunir contexto, construir, levantar un servidor de desarrollo y ejecutar el bucle de verificación sin salir de la terminal."}]}, {"kind": "p", "text": "Son capacidades portátiles a nivel de agente: exactamente el tipo de cosa que Open Design está diseñado para orquestar sobre ACP, en lugar de recrearla en cada proyecto."}]}, {"id": "vs", "heading": "Trae CLI frente a Codex, Claude Code, Cursor y Gemini CLI para diseño", "blocks": [{"kind": "p", "text": "No hay un único ganador para el trabajo de diseño: cada agente tiene una fortaleza distinta, y los equipos con experiencia los combinan. Un resumen honesto:"}, {"kind": "table", "columns": ["Agente", "Fortaleza de diseño", "Ideal para"], "rows": [["Trae CLI", "Código abierto (MIT) y agnóstico al modelo; trae tu propia clave de proveedor, basado en configuración y transparente", "Equipos que quieren un agente gratuito e inspeccionable y la libertad de elegir o cambiar de proveedores de LLM"], ["Codex", "Gran acabado visual con una skill de frontend; builds asíncronos en entorno aislado", "Builds asíncronos delegados y reglas portátiles en AGENTS.md"], ["Claude Code", "Decisiones de diseño concretas (hex, espaciado, tipografía) y UX consciente del código base", "Razonamiento de frontend y refactorizaciones de contexto amplio"], ["Cursor", "Bucle visual de construir y ver con vista previa en vivo y ediciones en línea", "Trabajo de interfaz iterativo y supervisado dentro de un IDE"], ["Gemini CLI", "Gran comprensión multimodal de imágenes y un contexto de 1M de tokens; de código abierto con un plan gratuito", "Trabajo con muchas capturas de pantalla y mantener todo un sistema de diseño en contexto"]]}, {"kind": "p", "text": "El veredicto recurrente de la comunidad es que el criterio estético proviene de las personas: todos ellos tienden por defecto a una estética genérica sin skills, referencias ni restricciones. Ese es el verdadero problema a resolver, y tiene forma de herramienta de diseño, no de modelo."}]}, {"id": "pitfalls", "heading": "Errores comunes y cómo evitar el aspecto de «basura de IA»", "blocks": [{"kind": "p", "text": "La queja más común sobre el diseño generado por IA es que luce genérico: degradados suaves, paneles flotantes, esquinas redondeadas exageradas, sombras dramáticas, un aire de Inter y morado que «grita que esto lo hizo una IA». Otros problemas reportados incluyen maquetaciones móviles rotas e instrucciones que se filtran en el texto de la interfaz. Ninguno de estos es exclusivo de Trae CLI; son lo que ocurre cuando cualquier agente se ejecuta sin un contexto de diseño curado."}, {"kind": "steps", "items": [{"label": "Añade una skill estética", "body": "Una skill de diseño curada obliga al agente a comprometerse con una dirección real en lugar del aspecto por defecto."}, {"label": "Verifica en un navegador real", "body": "Haz que Trae CLI renderice y se autoverifique en los distintos breakpoints para que las maquetaciones no se rompan en silencio en el móvil."}, {"label": "Aporta tokens y referencias", "body": "Los tokens de diseño reales y las capturas de referencia son la mayor palanca sobre la calidad del resultado."}, {"label": "Codifica reglas en tu repositorio", "body": "Coloca reglas del estilo «sin tarjetas hero, máximo dos tipografías, jerarquía con la marca primero» donde el agente las lea en cada ejecución."}]}, {"kind": "p", "text": "Fíjate en que toda mitigación consiste en dar al agente un contexto de diseño curado. Mantener ese contexto a mano, proyecto a proyecto, es el trabajo tedioso que Open Design elimina."}]}, {"id": "open-design", "heading": "Diseñar con Trae CLI dentro de Open Design", "blocks": [{"kind": "p", "text": "Open Design es la capa de diseño de código abierto que el flujo de trabajo anterior reclama una y otra vez. Trata a Trae CLI como un adaptador de primera clase —gobernándolo sobre el Agent Client Protocol (ACP) mediante su binario trae-cli— y lo envuelve en una biblioteca curada de skills y sistemas de diseño, una canalización de renderizado estructurada y una interfaz de escritorio local, para que el contexto de diseño que hace bueno a Trae CLI esté presente desde la primera ejecución, no ensamblado a mano cada vez. Ambos son de código abierto y local-first, lo que hace de esta combinación un encaje natural."}, {"kind": "ol", "items": ["Instala Open Design y selecciona Trae CLI como tu agente.", "Autentícate con tu propia clave de proveedor de LLM (BYOK): las credenciales permanecen en tu máquina y nunca se enrutan a través de nosotros.", "Elige un sistema de diseño y una skill, y luego genera presentaciones, prototipos y páginas de aterrizaje con un criterio estético consistente.", "Cada artefacto y archivo DESIGN.md vive en tu propio repositorio, no en una nube alojada."]}, {"kind": "p", "text": "El mismo agente Trae CLI, la misma clave de proveedor, más un flujo de diseño real, portátil y de código abierto a su alrededor. Es local-first y de código abierto, así que nada de tu trabajo ni de tus credenciales sale de tu máquina."}]}], "faqTitle": "Preguntas frecuentes", "faq": [{"name": "¿De verdad puede Trae CLI hacer trabajo de diseño?", "text": "Sí: con una skill estética, un sistema de diseño y un contexto de referencia real, Trae CLI produce interfaces adaptables de calidad de producción, y como es agnóstico al modelo puedes encaminar el trabajo al proveedor que mejor razone sobre tu frontend. Sin ese contexto tiende a caer en un aspecto genérico, que es la brecha que Open Design llena."}, {"name": "¿Necesito pagar para diseñar con Trae CLI?", "text": "Trae CLI en sí es gratuito y de código abierto (MIT). Tú traes tu propia clave de proveedor de LLM, así que tu único coste es lo que ese proveedor cobre, o nada si ejecutas un modelo local mediante Ollama. En cualquier caso, Open Design nunca enruta tus credenciales."}, {"name": "¿Qué hace que Trae CLI sea bueno para el diseño en concreto?", "text": "Dos cosas: es agnóstico al modelo, así que eliges el proveedor de LLM más adecuado para el trabajo de frontend, y es totalmente abierto y basado en configuración, así que su comportamiento es transparente y reproducible en todo un equipo. Pero el criterio estético sigue viniendo del sistema de diseño, la skill y las referencias que tú aportes."}, {"name": "¿Trae CLI o Claude Code para diseño de frontend?", "text": "Ambos son capaces. Claude Code es conocido por decisiones de diseño concretas y conscientes del código base; la ventaja de Trae CLI es ser de código abierto y flexible en cuanto a proveedores, así que nunca quedas atado a un único modelo. Muchos equipos usan los dos: Open Design te permite cambiar de agente sin cambiar tu flujo de diseño."}, {"name": "¿Qué necesita Open Design para ejecutar Trae CLI?", "text": "Open Design gobierna el binario trae-cli de Trae CLI sobre el Agent Client Protocol (ACP) y usa la clave de proveedor de LLM que hayas configurado. Seleccionas Trae CLI como tu agente, lo apuntas a un proveedor y Open Design aporta el contexto de diseño curado a su alrededor."}, {"name": "¿Está Open Design afiliado a ByteDance o Trae?", "text": "No. Trae CLI (trae-agent) es un producto de ByteDance; Open Design es un proyecto de código abierto independiente que lo admite como adaptador de primera clase. Trae es una marca registrada de ByteDance."}, {"name": "¿Están seguros mis archivos y credenciales?", "text": "Sí: Open Design es local-first y de código abierto. Tus archivos, artefactos y DESIGN.md permanecen en tu propio repositorio, y tus credenciales de proveedor de LLM las usa directamente tu agente, sin pasar nunca por los servidores de Open Design."}], "ctaTitle": "Diseña con Trae CLI, a la manera abierta.", "ctaBody": "Trae tu propia clave de proveedor de LLM, mantén cada archivo en local y obtén una biblioteca de diseño curada en torno al agente que ya usas.", "ctaActions": [{"label": "Usa Trae CLI dentro de Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dale una estrella en GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Descarga la app de escritorio", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Ver todos los agentes compatibles"},
      },
      'aider': {
        ...en['aider']!,
        title: "Aider para diseño — Open Design",
        description: "Cómo se usa Aider —el programador en pareja con IA de código abierto y agnóstico al modelo que vive en tu terminal— para diseño de interfaces y web, con ediciones nativas de git, un archivo CONVENTIONS.md, soporte de imágenes y BYOK, y cómo Open Design convierte a Aider en un agente de diseño local-first y de código abierto.",
        breadcrumb: "Aider",
        label: "Agente · Aider",
        heading: "Aider para diseño.",
        lead: "Aider es el programador en pareja con IA de código abierto que vive en tu terminal y trabaja directamente sobre tu repositorio git. Es agnóstico al modelo —apúntalo a Claude, GPT-4o, DeepSeek o Gemini con tu propia clave— y edita archivos, hace commits automáticamente y lee imágenes en modelos con visión. Eso lo convierte en una verdadera herramienta de diseño una vez que le das referencias, convenciones y un bucle de verificación. Open Design lo integra en un flujo de diseño de código abierto: tus claves de proveedor, tus archivos, local-first.",
        rich: {"heroCtaLead": "Open Design convierte a Aider en un agente de diseño local-first y de código abierto: tus propias claves de API de proveedor, tus archivos y una biblioteca curada de skills y sistemas de diseño a su alrededor.", "heroCtaActions": [{"label": "Usa Aider dentro de Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dale una estrella en GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Descarga la app de escritorio", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Aider es una herramienta de programación en pareja con IA de código abierto que se ejecuta en tu terminal y trabaja sobre el código de tu repositorio git. Dos cosas la hacen interesante específicamente para el diseño: es agnóstica al modelo, así que traes tu propia clave para casi cualquier LLM —Claude, GPT-4o, DeepSeek, Gemini o un modelo local— y es nativa de git, editando archivos en su sitio y confirmando cada cambio con un mensaje sensato para que cada iteración sea revisable y reversible. En modelos con visión también puede leer imágenes, de modo que una captura de pantalla pasa a formar parte del prompt. Combinada con las referencias, convenciones y un bucle de verificación adecuados, construye interfaces reales y adaptables. Esta es una guía práctica y de principio a fin para usar Aider en interfaces, frontend y trabajo con sistemas de diseño, y para integrarlo en un flujo de diseño estructurado con Open Design.", "Cubre qué es realmente Aider, por qué una herramienta agnóstica al modelo y nativa de git encaja con el diseño, cómo configurarlo desde cero, el bucle de captura de pantalla a interfaz, cómo lo extienden CONVENTIONS.md y los comandos de Aider, cómo se compara con Codex, Claude Code, Cursor y Gemini CLI, los errores que hacen que el resultado de la IA luzca genérico, y cómo Open Design cierra la brecha como una capa de diseño abierta y local-first, una combinación natural, ya que ambos son de código abierto y se ejecutan en tu propia máquina."], "heroImage": {"src": "/agents/aider-design/aider-design-hero.webp", "alt": "Bucle de retroalimentación de diseño de Aider: un agente de terminal leyendo una imagen de referencia, un repositorio git con commits, un navegador renderizando la interfaz, con una flecha de retroalimentación que regresa", "caption": "El bucle central: Aider lee tus referencias en la terminal, edita y confirma la interfaz en tu repositorio git e itera contra ellas, con el modelo que tú traigas."}, "tocLabel": "En esta página", "toc": [{"id": "what-is-aider", "label": "Qué es realmente Aider"}, {"id": "why-design", "label": "Por qué lo agnóstico al modelo y lo nativo de git encajan con el diseño"}, {"id": "setup", "label": "Configura Aider para diseño (desde cero)"}, {"id": "screenshot-workflow", "label": "El flujo de captura de pantalla a interfaz"}, {"id": "extend", "label": "CONVENTIONS.md, imágenes y comandos"}, {"id": "vs", "label": "Aider frente a Codex, Claude Code, Cursor y Gemini CLI"}, {"id": "pitfalls", "label": "Errores comunes y el aspecto de «basura de IA»"}, {"id": "open-design", "label": "Diseñar con Aider en Open Design"}, {"id": "faq", "label": "Preguntas frecuentes"}], "sections": [{"id": "what-is-aider", "heading": "Qué es realmente Aider", "blocks": [{"kind": "p", "text": "Aider es una herramienta de programación en pareja con IA de código abierto (Apache-2.0) que se ejecuta en tu terminal. Lee tu código base existente, mapea todo el repositorio para obtener contexto, edita archivos en su sitio y confirma automáticamente cada cambio con un mensaje sensato, de modo que puedes comparar, gestionar y deshacer el trabajo de la IA con las herramientas de git que ya usas. Funciona con más de 100 lenguajes de programación e inicia proyectos nuevos o amplía los existentes."}, {"kind": "p", "text": "Para el trabajo de diseño destacan dos propiedades. Aider es agnóstico al modelo: traes tu propia clave y la conectas a casi cualquier LLM —Claude, GPT-4o, DeepSeek, Gemini o un modelo local— así que nunca quedas atado a un único proveedor. Y en modelos con visión como GPT-4o y Claude, puede leer archivos de imagen, convirtiendo una captura de referencia en parte del prompt."}, {"kind": "steps", "items": [{"label": "Archivo de convenciones", "body": "Aider lee un archivo CONVENTIONS.md que cargas con /read CONVENTIONS.md (o aider --read CONVENTIONS.md): el lugar natural para codificar tus convenciones de diseño, tokens y listas de revisión como contexto de solo lectura."}, {"label": "Ediciones nativas de git", "body": "Cada cambio se aplica a los archivos de tu repositorio y se confirma automáticamente, así que cada iteración de diseño es revisable y reversible con las herramientas de git de siempre."}, {"label": "Trae tu propio modelo", "body": "Conecta OpenAI, Anthropic, DeepSeek, Gemini o un modelo local con tu propia clave de API; Aider no está atado a un único fabricante ni a un backend alojado."}]}, {"kind": "ul", "items": ["Fabricante: Aider (Aider-AI, código abierto), agnóstico al modelo", "Credencial: tu propia clave de API de proveedor, BYOK (OpenAI, Anthropic, DeepSeek, Gemini o un modelo local)", "Licencia: Apache-2.0, código abierto"]}]}, {"id": "why-design", "heading": "Por qué una herramienta agnóstica al modelo y nativa de git encaja con el diseño", "blocks": [{"kind": "p", "text": "La ventaja de Aider para el diseño viene de cómo trabaja con tu repositorio y con el modelo que elijas, pero, como ocurre con todo agente, el criterio estético hay que aportarlo igualmente."}, {"kind": "steps", "items": [{"label": "Agnóstico al modelo, BYOK", "body": "Elige el modelo que mejor diseñe para tu tarea y tu presupuesto —Claude, GPT-4o, DeepSeek, Gemini— y cambia con libertad sin alterar tu flujo de trabajo, todo con tu propia clave."}, {"label": "Iteración nativa de git", "body": "Los commits automáticos convierten cada pasada de diseño en un diff revisable que puedes revertir, así iteras contra una base limpia en lugar de un montón de ediciones sin seguimiento."}, {"label": "Convenciones en CONVENTIONS.md", "body": "Un CONVENTIONS.md (cargado en solo lectura) apunta al agente hacia tus tokens, componentes y reglas, para que trabaje contra una marca en lugar de un aspecto por defecto."}]}, {"kind": "image", "src": "/agents/aider-design/aider-design-taste-triangle.webp", "alt": "Diagrama que muestra cómo un sistema de diseño, una skill y una imagen de referencia convergen en un buen resultado de diseño", "caption": "El criterio estético proviene de tres insumos que tú aportas: un sistema de diseño, una skill e imágenes de referencia reales."}, {"kind": "p", "text": "La lección es la misma que enseña todo agente: Aider no tiene criterio estético por defecto. Produce buen diseño cuando le das restricciones: un sistema de diseño, una skill estética y referencias concretas. Open Design empaqueta exactamente esos insumos, por lo que ambos encajan (más abajo se explica)."}]}, {"id": "setup", "heading": "Configura Aider para el trabajo de diseño, desde cero", "blocks": [{"kind": "p", "text": "Este es el recorrido completo, desde una máquina limpia hasta un Aider capaz de construir y verificar interfaces."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Aider (recommended installer; Python 3.8–3.13)\npython -m pip install aider-install\naider-install\n# or with pipx: pipx install aider-chat\n\n# 2. Start it in your git project and bring your own key\ncd your-project\naider --model sonnet --api-key anthropic=<your-key>\n# or: aider --api-key openai=<your-key>   (also deepseek=, gemini=)\n\n# 3. Load your design conventions as read-only context\naider --read CONVENTIONS.md\n\n# 4. Add a reference image (on a vision-capable model)\n#    inside the chat: /add reference-desktop.png"}, {"kind": "image", "src": "/agents/aider-design/aider-design-setup-flow.webp", "alt": "Flujo de configuración en cinco pasos: instalar, traer tu propia clave, cargar CONVENTIONS.md, añadir una referencia, verificar", "caption": "La secuencia de configuración: instalar → traer tu propia clave → cargar CONVENTIONS.md → añadir una referencia → habilitar la verificación en el navegador."}, {"kind": "steps", "items": [{"label": "Codifica tus reglas de diseño", "body": "Coloca tus tokens, primitivos y convenciones en CONVENTIONS.md y cárgalo en solo lectura, para que el resultado se ajuste a una marca en lugar de caer en un aspecto genérico por defecto."}, {"label": "Añade verificación en el navegador", "body": "Levanta un servidor de desarrollo y haz que Aider renderice en un navegador real, comprobando su resultado en los distintos breakpoints en lugar de limitarse a confirmar que el build pasa."}]}]}, {"id": "screenshot-workflow", "heading": "El flujo de captura de pantalla a interfaz", "blocks": [{"kind": "p", "text": "El bucle de diseño de mayor rendimiento con Aider consiste en convertir una imagen de referencia en una interfaz funcional y adaptable e iterar hasta que coincida, usando un modelo con visión para comparar el resultado con la referencia, con cada pasada confirmada en git."}, {"kind": "ol", "items": ["Parte de las referencias visuales más claras que tengas, e incluye varios estados (escritorio y móvil, hover, vacío, cargando), no solo una imagen principal.", "Sé específico en el prompt; los prompts vagos producen interfaces genéricas incluso con un modelo potente.", "Mantén tu sistema de diseño y tus convenciones en CONVENTIONS.md, e indícale a Aider dónde viven los tokens y los primitivos canónicos.", "Levanta un servidor de desarrollo y comprueba el resultado renderizado en un navegador real, redimensionando a los distintos breakpoints.", "Itera haciendo que Aider compare su implementación con las capturas de pantalla, no solo que confirme que compila."]}, {"kind": "p", "text": "Añade una imagen con /add (o /paste desde el portapapeles) en un modelo con visión, y luego da restricciones concretas:"}, {"kind": "code", "lang": "bash", "code": "aider --model gpt-4o --read CONVENTIONS.md\n# in the chat:\n> /add reference-desktop.png\n> /add reference-mobile.png\n> Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from CONVENTIONS.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  I'll render it in the browser and tell you what to fix until it matches\n  the references across breakpoints."}, {"kind": "p", "text": "Mantén los prompts breves y enfocados. Como Aider confirma cada cambio, conservas las buenas iteraciones y usas git (o /undo) para revertir las malas, de modo que cada pasada parte de una base limpia."}]}, {"id": "extend", "heading": "CONVENTIONS.md, imágenes y comandos", "blocks": [{"kind": "p", "text": "Tres capacidades hacen que Aider sea práctico para un trabajo de diseño sostenido, y las tres encajan limpiamente en un flujo de diseño abierto."}, {"kind": "steps", "items": [{"label": "Contexto de CONVENTIONS.md", "body": "Carga las convenciones de código y diseño con /read CONVENTIONS.md o aider --read CONVENTIONS.md, o define read: CONVENTIONS.md en .aider.conf.yml para cargarlo en cada ejecución. Es el hogar duradero de tus tokens, primitivos y reglas."}, {"label": "Imágenes y páginas web", "body": "En modelos con visión, usa /add con un archivo de imagen o /paste desde el portapapeles para dar a Aider una referencia real; /web <url> extrae el texto de una página al chat como contexto adicional."}, {"label": "Comandos dentro del chat", "body": "Comandos como /add para traer archivos al contexto, /read para referencias de solo lectura y /undo para deshacer el último commit le permiten reunir referencias y ejecutar el bucle de verificación sin salir de la terminal."}]}, {"kind": "p", "text": "Son capacidades portátiles y nativas del repositorio: exactamente el tipo de cosa que Open Design está diseñado para orquestar, en lugar de recrearla en cada proyecto."}]}, {"id": "vs", "heading": "Aider frente a Codex, Claude Code, Cursor y Gemini CLI para diseño", "blocks": [{"kind": "p", "text": "No hay un único ganador para el trabajo de diseño: cada agente tiene una fortaleza distinta, y los equipos con experiencia los combinan. Un resumen honesto:"}, {"kind": "table", "columns": ["Agente", "Fortaleza de diseño", "Ideal para"], "rows": [["Aider", "Código abierto, agnóstico al modelo (BYOK) y nativo de git; los commits automáticos hacen cada iteración revisable y reversible", "Iteración nativa del repositorio sobre tu código base existente con el modelo que mejor diseñe"], ["Codex", "Gran acabado visual con una skill de frontend; builds asíncronos en entorno aislado", "Builds asíncronos delegados y reglas portátiles en AGENTS.md"], ["Claude Code", "Decisiones de diseño concretas (hex, espaciado, tipografía) y UX consciente del código base", "Razonamiento de frontend y refactorizaciones de contexto amplio"], ["Cursor", "Bucle visual de construir y ver con vista previa en vivo y ediciones en línea", "Trabajo de interfaz iterativo y supervisado dentro de un IDE"], ["Gemini CLI", "Gran comprensión multimodal de imágenes y un contexto de 1M de tokens; de código abierto con un plan gratuito", "Trabajo con muchas capturas de pantalla y mantener todo un sistema de diseño en contexto"]]}, {"kind": "p", "text": "El veredicto recurrente de la comunidad es que el criterio estético proviene de las personas: todos ellos tienden por defecto a una estética genérica sin skills, referencias ni restricciones. Ese es el verdadero problema a resolver, y tiene forma de herramienta de diseño, no de modelo."}]}, {"id": "pitfalls", "heading": "Errores comunes y cómo evitar el aspecto de «basura de IA»", "blocks": [{"kind": "p", "text": "La queja más común sobre el diseño generado por IA es que luce genérico: degradados suaves, paneles flotantes, esquinas redondeadas exageradas, sombras dramáticas, un aire de Inter y morado que «grita que esto lo hizo una IA». Otros problemas reportados incluyen maquetaciones móviles rotas e instrucciones que se filtran en el texto de la interfaz. Ninguno de estos es exclusivo de Aider; son lo que ocurre cuando cualquier agente se ejecuta sin un contexto de diseño curado."}, {"kind": "steps", "items": [{"label": "Añade una skill estética", "body": "Una skill de diseño curada obliga al agente a comprometerse con una dirección real en lugar del aspecto por defecto."}, {"label": "Verifica en un navegador real", "body": "Renderiza y autoverifica en los distintos breakpoints para que las maquetaciones no se rompan en silencio en el móvil; en un modelo con visión, vuelve a inyectarle las capturas de pantalla."}, {"label": "Aporta tokens y referencias", "body": "Los tokens de diseño reales y las capturas de referencia son la mayor palanca sobre la calidad del resultado."}, {"label": "Codifica reglas en CONVENTIONS.md", "body": "Coloca reglas del estilo «sin tarjetas hero, máximo dos tipografías, jerarquía con la marca primero» donde el agente las lea en cada ejecución."}]}, {"kind": "p", "text": "Fíjate en que toda mitigación consiste en dar al agente un contexto de diseño curado. Mantener ese contexto a mano, proyecto a proyecto, es el trabajo tedioso que Open Design elimina."}]}, {"id": "open-design", "heading": "Diseñar con Aider dentro de Open Design", "blocks": [{"kind": "p", "text": "Open Design es la capa de diseño de código abierto que el flujo de trabajo anterior reclama una y otra vez. Trata a Aider como un adaptador de primera clase y lo envuelve en una biblioteca curada de skills y sistemas de diseño, una canalización de renderizado estructurada y una interfaz de escritorio local, para que el contexto de diseño que hace bueno a Aider esté presente desde la primera ejecución, no ensamblado a mano cada vez. Ambos son de código abierto y local-first, lo que hace de esta combinación un encaje natural."}, {"kind": "ol", "items": ["Instala Open Design y selecciona Aider como tu agente.", "Autentícate con tu propia clave de API de proveedor (BYOK) —OpenAI, Anthropic, DeepSeek o Gemini—; las credenciales permanecen en tu máquina y nunca se enrutan a través de nosotros.", "Elige un sistema de diseño y una skill, y luego genera presentaciones, prototipos y páginas de aterrizaje con un criterio estético consistente.", "Cada artefacto y archivo DESIGN.md vive en tu propio repositorio git, no en una nube alojada."]}, {"kind": "p", "text": "El mismo agente Aider, la misma clave, más un flujo de diseño real, portátil y de código abierto a su alrededor. Es local-first y de código abierto, así que nada de tu trabajo ni de tus credenciales sale de tu máquina."}]}], "faqTitle": "Preguntas frecuentes", "faq": [{"name": "¿De verdad puede Aider hacer trabajo de diseño?", "text": "Sí: con una skill estética, un sistema de diseño e imágenes de referencia reales en contexto, Aider produce interfaces adaptables de calidad de producción, y en modelos con visión lee capturas de pantalla para verificar el resultado contra las referencias. Sin ese contexto tiende a caer en un aspecto genérico, que es la brecha que Open Design llena."}, {"name": "¿Qué modelos puedo usar con Aider para diseño?", "text": "Aider es agnóstico al modelo. Traes tu propia clave de API y conectas casi cualquier LLM —Claude, GPT-4o, DeepSeek, Gemini o un modelo local—. Para trabajo de diseño basado en imágenes, usa un modelo con visión como GPT-4o o Claude. Open Design nunca enruta tus credenciales."}, {"name": "¿Qué hace que Aider sea bueno para el diseño en concreto?", "text": "Dos cosas: es agnóstico al modelo, así que eliges el modelo que mejor diseñe para tu tarea, y es nativo de git, confirmando cada cambio para que cada iteración de diseño sea revisable y reversible. Ambas ayudan, pero el criterio estético sigue viniendo del sistema de diseño, la skill y las referencias que tú aportes."}, {"name": "¿Aider edita mis archivos y hace commit en git?", "text": "Sí. Aider edita archivos directamente en tu repositorio y confirma automáticamente cada cambio con un mensaje sensato, de modo que puedes comparar, gestionar y deshacer el trabajo de la IA con las herramientas de git que ya usas."}, {"name": "¿Cómo le doy a Aider mis convenciones de diseño?", "text": "Crea un CONVENTIONS.md con tus tokens, primitivos y reglas, y luego cárgalo en solo lectura con /read CONVENTIONS.md o aider --read CONVENTIONS.md (o define read: CONVENTIONS.md en .aider.conf.yml para cargarlo en cada ejecución). Aider trabaja entonces contra tu marca en lugar de un aspecto por defecto."}, {"name": "¿Está Open Design afiliado a Aider?", "text": "No. Aider es un proyecto de código abierto independiente (Aider-AI); Open Design es un proyecto de código abierto independiente y aparte que admite a Aider como adaptador de primera clase. Ambos no están afiliados."}, {"name": "¿Están seguros mis archivos y credenciales?", "text": "Sí: Open Design es local-first y de código abierto. Tus archivos, artefactos y DESIGN.md permanecen en tu propio repositorio git, y tus claves de API de proveedor las usa directamente tu agente, sin pasar nunca por los servidores de Open Design."}], "ctaTitle": "Diseña con Aider, a la manera abierta.", "ctaBody": "Trae tu propia clave de API de proveedor, mantén cada archivo en local en tu repositorio git y obtén una biblioteca de diseño curada en torno al agente que ya usas.", "ctaActions": [{"label": "Usa Aider dentro de Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dale una estrella en GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Descarga la app de escritorio", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Ver todos los agentes compatibles"},
      },
      'antigravity': {
        ...en['antigravity']!,
        title: "Antigravity para diseño — Open Design",
        description: "Cómo se usa Google Antigravity —la plataforma de desarrollo centrada en agentes de Google, impulsada por los modelos multimodales Gemini 3.x, con su Editor View, su Manager Surface, su control de navegador integrado y sus Artifacts— para diseño de interfaces y web, y cómo Open Design convierte a Antigravity en un agente de diseño local-first y de código abierto.",
        breadcrumb: "Antigravity",
        label: "Agente · Antigravity",
        heading: "Antigravity para diseño.",
        lead: "Antigravity es la plataforma de desarrollo centrada en agentes de Google. Sus modelos Gemini 3.x leen capturas de pantalla y razonan sobre la maquetación, su navegador integrado permite a los agentes verificar lo que construyen, y sus Artifacts convierten el trabajo del agente en entregables revisables, lo que lo convierte en una verdadera herramienta de diseño una vez que le das referencias, convenciones y un bucle de verificación. Open Design lo integra en un flujo de diseño de código abierto: tu cuenta de Google, tus archivos, local-first.",
        rich: {"heroCtaLead": "Open Design convierte a Antigravity en un agente de diseño local-first y de código abierto: tu cuenta de Google, tus archivos y una biblioteca curada de skills y sistemas de diseño a su alrededor.", "heroCtaActions": [{"label": "Usa Antigravity dentro de Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dale una estrella en GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Descarga la app de escritorio", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Antigravity es la plataforma de desarrollo centrada en agentes de Google, lanzada junto a Gemini 3. Tres cosas la hacen interesante específicamente para el diseño: sus agentes se ejecutan sobre modelos Gemini 3.x nativamente multimodales, así que leen una captura de pantalla y razonan sobre maquetación, espaciado y jerarquía; incluye un navegador integrado que el agente puede gobernar, así que renderiza y comprueba su propia interfaz en lugar de adivinar; y produce Artifacts —listas de tareas, planes de implementación, capturas de pantalla y grabaciones del navegador— que convierten el trabajo del agente en algo que realmente puedes revisar. Combinada con las referencias, convenciones y un bucle de verificación adecuados, construye interfaces reales y adaptables, y empezar es gratis con una cuenta de Google. Esta es una guía práctica y de principio a fin para usar Antigravity en interfaces, frontend y trabajo con sistemas de diseño, y para integrarlo en un flujo de diseño estructurado con Open Design.", "Cubre qué es realmente Antigravity, por qué Gemini multimodal y un navegador integrado encajan con el diseño, cómo configurarlo desde cero, el bucle de captura de pantalla a interfaz, cómo lo extienden su contexto de agente y su utillaje, cómo se compara con Codex, Claude Code, Cursor y Gemini CLI, los errores que hacen que el resultado de la IA luzca genérico, y cómo Open Design cierra la brecha como una capa de diseño abierta y local-first, una combinación natural, ya que Open Design es de código abierto y se ejecuta en tu propia máquina."], "heroImage": {"src": "/agents/antigravity-design/antigravity-design-hero.webp", "alt": "Bucle de retroalimentación de diseño de Antigravity: un IDE centrado en agentes leyendo una imagen de referencia, un navegador integrado renderizando la interfaz y un Manager Surface, con una flecha de retroalimentación que regresa", "caption": "El bucle central: un agente de Antigravity lee tus referencias, construye y verifica la interfaz en su navegador integrado e itera contra ellas, mostrando el trabajo como Artifacts revisables."}, "tocLabel": "En esta página", "toc": [{"id": "what-is-antigravity", "label": "Qué es realmente Antigravity"}, {"id": "why-design", "label": "Por qué Gemini multimodal y un navegador integrado encajan con el diseño"}, {"id": "setup", "label": "Configura Antigravity para diseño (desde cero)"}, {"id": "screenshot-workflow", "label": "El flujo de captura de pantalla a interfaz"}, {"id": "extend", "label": "Contexto del agente, herramientas y Artifacts"}, {"id": "vs", "label": "Antigravity frente a Codex, Claude Code, Cursor y Gemini CLI"}, {"id": "pitfalls", "label": "Errores comunes y el aspecto de «basura de IA»"}, {"id": "open-design", "label": "Diseñar con Antigravity en Open Design"}, {"id": "faq", "label": "Preguntas frecuentes"}], "sections": [{"id": "what-is-antigravity", "heading": "Qué es realmente Antigravity", "blocks": [{"kind": "p", "text": "Antigravity es la plataforma de desarrollo centrada en agentes de Google: un IDE impulsado por IA construido para que sean agentes autónomos, no chatbots en una barra lateral, quienes hagan el trabajo. Anunciada el 18 de noviembre de 2025 junto a Gemini 3 y disponible en vista previa pública sin coste para particulares, te permite delegar tareas de software complejas y multiherramienta a un agente que opera a través del editor, la terminal y un navegador integrado. Sus agentes se ejecutan principalmente sobre los modelos multimodales Gemini 3.x de Google."}, {"kind": "p", "text": "Para el trabajo de diseño destacan tres propiedades. Sus agentes leen capturas de pantalla y razonan sobre la maquetación real, porque Gemini 3.x es nativamente multimodal. Puede gobernar un navegador real, así que renderiza y verifica lo que construye. Y muestra Artifacts —listas de tareas, planes, capturas de pantalla y grabaciones del navegador— para que revises resultados tangibles en lugar de registros crudos de herramientas."}, {"kind": "steps", "items": [{"label": "Editor View + Manager Surface", "body": "El Editor View es un IDE de IA familiar con autocompletado con tabulador y comandos en línea; el Manager Surface te permite lanzar, orquestar y observar varios agentes trabajando de forma asíncrona en distintos espacios de trabajo, el lugar natural para ejecutar una tarea de diseño larga."}, {"label": "Navegador integrado + Artifacts", "body": "Los agentes pueden actuar en un navegador integrado y emitir Artifacts (capturas de pantalla, grabaciones del navegador, listas de tareas, planes) sobre los que puedes dejar comentarios: un bucle de verificación incorporado a la plataforma en lugar de añadido por encima."}, {"label": "Empezar es gratis", "body": "Iniciar sesión con una cuenta personal de Google ofrece límites de uso generosos en Gemini 3.x; la plataforma se ejecuta en macOS, Windows y Linux."}]}, {"kind": "ul", "items": ["Fabricante: Google", "Credencial: cuenta de Google (Gmail personal), gratuita durante la vista previa pública", "Binario: se lanza con agy; se ejecuta en macOS, Windows y Linux"]}]}, {"id": "why-design", "heading": "Por qué Gemini multimodal y un navegador integrado encajan con el diseño", "blocks": [{"kind": "p", "text": "La ventaja de Antigravity para el diseño viene del modelo y la plataforma juntos, pero, como ocurre con todo agente, el criterio estético hay que aportarlo igualmente."}, {"kind": "steps", "items": [{"label": "Gran comprensión multimodal", "body": "Como Gemini 3.x es nativamente multimodal, el agente lee bien las capturas de referencia, comparando su resultado renderizado con una imagen en lugar de adivinar a partir de una descripción en prosa."}, {"label": "Un navegador integrado para verificar", "body": "El agente gobierna un navegador real, así que renderiza la interfaz, la comprueba en distintos estados y detecta maquetaciones rotas, y captura el resultado como un Artifact de grabación del navegador que puedes revisar."}, {"label": "Convenciones que el agente lee", "body": "Codifica tus tokens, componentes y reglas de revisión en el contexto de proyecto del agente para que trabaje contra tu marca en lugar de un aspecto por defecto."}]}, {"kind": "image", "src": "/agents/antigravity-design/antigravity-design-taste-triangle.webp", "alt": "Diagrama que muestra cómo un sistema de diseño, una skill y una imagen de referencia convergen en un buen resultado de diseño", "caption": "El criterio estético proviene de tres insumos que tú aportas: un sistema de diseño, una skill e imágenes de referencia reales."}, {"kind": "p", "text": "La lección es la misma que enseña todo agente: Antigravity no tiene criterio estético por defecto. Produce buen diseño cuando le das restricciones: un sistema de diseño, una skill estética y referencias concretas. Open Design empaqueta exactamente esos insumos, por lo que ambos encajan (más abajo se explica)."}]}, {"id": "setup", "heading": "Configura Antigravity para el trabajo de diseño, desde cero", "blocks": [{"kind": "p", "text": "Este es el recorrido completo, desde una máquina limpia hasta un agente de Antigravity capaz de construir y verificar interfaces. Los menús exactos dentro de la app pueden cambiar durante la vista previa, así que esto se mantiene al nivel en el que puedes confiar."}, {"kind": "code", "lang": "bash", "code": "# 1. Download Antigravity for your OS (macOS, Windows, Linux)\n#    from the official download page: antigravity.google/download\n\n# 2. Launch it and sign in\nagy               # opens Antigravity; sign in with your Google account\n\n# 3. Accept the data-use policy, pick a theme, and open your project folder\n\n# 4. Start an agent task in the Editor View or the Manager Surface,\n#    selecting a Gemini 3.x model (e.g. Gemini 3.1 Pro)"}, {"kind": "image", "src": "/agents/antigravity-design/antigravity-design-setup-flow.webp", "alt": "Flujo de configuración en cinco pasos: descargar, iniciar sesión con Google, abrir el proyecto, añadir reglas de diseño y una skill, habilitar la verificación en el navegador", "caption": "La secuencia de configuración: descargar → iniciar sesión con Google → abrir tu proyecto → añadir reglas de diseño y una skill → usar el navegador integrado para verificar."}, {"kind": "steps", "items": [{"label": "Codifica tus reglas de diseño", "body": "Coloca tus tokens, primitivos y convenciones en el contexto de proyecto del agente para que el resultado se ajuste a una marca en lugar de caer en un aspecto genérico por defecto."}, {"label": "Usa el navegador integrado", "body": "Haz que el agente renderice en el navegador integrado de Antigravity y compruebe su resultado en los distintos breakpoints, verificando que la interfaz se ve bien, no solo que el build pasa."}]}]}, {"id": "screenshot-workflow", "heading": "El flujo de captura de pantalla a interfaz", "blocks": [{"kind": "p", "text": "El bucle de diseño de mayor rendimiento con Antigravity consiste en convertir una imagen de referencia en una interfaz funcional y adaptable e iterar hasta que coincida, apoyándose en el modelo multimodal para comparar el resultado con la referencia y en el navegador integrado para verificarlo."}, {"kind": "ol", "items": ["Parte de las referencias visuales más claras que tengas, e incluye varios estados (escritorio y móvil, hover, vacío, cargando), no solo una imagen principal.", "Sé específico en el prompt; los prompts vagos producen interfaces genéricas incluso con un modelo potente.", "Mantén tu sistema de diseño y tus convenciones en el contexto de proyecto del agente, e indícale dónde viven los tokens y los primitivos canónicos.", "Deja que el agente renderice en el navegador integrado de Antigravity, redimensionando a los distintos breakpoints para comprobar el resultado.", "Itera haciendo que el agente compare su implementación con las capturas de pantalla —no solo que confirme que compila— y revisa los Artifacts de grabación del navegador y de captura de pantalla que produce."]}, {"kind": "p", "text": "Adjunta tus imágenes de referencia y da restricciones concretas, y luego deja que el agente verifique en el navegador:"}, {"kind": "code", "lang": "text", "code": "# In an Antigravity agent task, attach reference-desktop.png and\n# reference-mobile.png, then prompt:\n\nImplement this design in React + Vite + Tailwind + TypeScript.\nReuse my existing design-system components and tokens.\nMatch spacing, layout, and hierarchy; make it responsive.\nRender it in the integrated browser and iterate until it matches\nthe references across breakpoints, and show me the screenshots."}, {"kind": "p", "text": "Mantén los prompts breves y enfocados, confirma las buenas iteraciones y revierte las malas (avisando al agente cuando reviertas), para que cada pasada parta de una base limpia."}]}, {"id": "extend", "heading": "Contexto del agente, herramientas y Artifacts", "blocks": [{"kind": "p", "text": "Tres puntos de extensión hacen que Antigravity sea práctico para un trabajo de diseño sostenido, y los tres encajan limpiamente en un flujo de diseño abierto."}, {"kind": "steps", "items": [{"label": "Contexto de proyecto", "body": "Las reglas de proyecto persistentes son el hogar duradero de tus convenciones de diseño: tokens, primitivos y listas de revisión que el agente lee en cada tarea, para que el resultado se mantenga fiel a la marca."}, {"label": "Navegador integrado + terminal", "body": "Los agentes actúan a través del editor, la terminal y un navegador integrado, así que pueden reunir referencias, levantar un servidor de desarrollo y verificar la interfaz renderizada sin salir de la plataforma."}, {"label": "Artifacts que revisas", "body": "Las listas de tareas, los planes de implementación, las capturas de pantalla y las grabaciones del navegador hacen legible el trabajo del agente; dejas comentarios sobre el Artifact y el agente incorpora las correcciones."}]}, {"kind": "p", "text": "Son las capacidades que necesita un bucle de diseño serio: exactamente el tipo de cosa que Open Design está diseñado para orquestar, en lugar de recrearla en cada proyecto."}]}, {"id": "vs", "heading": "Antigravity frente a Codex, Claude Code, Cursor y Gemini CLI para diseño", "blocks": [{"kind": "p", "text": "No hay un único ganador para el trabajo de diseño: cada agente tiene una fortaleza distinta, y los equipos con experiencia los combinan. Un resumen honesto:"}, {"kind": "table", "columns": ["Agente", "Fortaleza de diseño", "Ideal para"], "rows": [["Antigravity", "IDE centrado en agentes con Gemini 3.x multimodal, un navegador integrado para autoverificación y Artifacts revisables; gratis en vista previa", "Builds multiagente asíncronos con verificación de la interfaz en navegador integrado"], ["Codex", "Gran acabado visual con una skill de frontend; builds asíncronos en entorno aislado", "Builds asíncronos delegados y reglas portátiles en AGENTS.md"], ["Claude Code", "Decisiones de diseño concretas (hex, espaciado, tipografía) y UX consciente del código base", "Razonamiento de frontend y refactorizaciones de contexto amplio"], ["Cursor", "Bucle visual de construir y ver con vista previa en vivo y ediciones en línea", "Trabajo de interfaz iterativo y supervisado dentro de un IDE"], ["Gemini CLI", "Agente de terminal de código abierto sobre Gemini multimodal con un contexto de 1M de tokens y plan gratuito", "Trabajo de terminal con muchas capturas de pantalla y mantener todo un sistema de diseño en contexto"]]}, {"kind": "p", "text": "El veredicto recurrente de la comunidad es que el criterio estético proviene de las personas: todos ellos tienden por defecto a una estética genérica sin skills, referencias ni restricciones. Ese es el verdadero problema a resolver, y tiene forma de herramienta de diseño, no de modelo."}]}, {"id": "pitfalls", "heading": "Errores comunes y cómo evitar el aspecto de «basura de IA»", "blocks": [{"kind": "p", "text": "La queja más común sobre el diseño generado por IA es que luce genérico: degradados suaves, paneles flotantes, esquinas redondeadas exageradas, sombras dramáticas, un aire de Inter y morado que «grita que esto lo hizo una IA». Otros problemas reportados incluyen maquetaciones móviles rotas e instrucciones que se filtran en el texto de la interfaz. Ninguno de estos es exclusivo de Antigravity; son lo que ocurre cuando cualquier agente se ejecuta sin un contexto de diseño curado."}, {"kind": "steps", "items": [{"label": "Añade una skill estética", "body": "Una skill de diseño curada obliga al agente a comprometerse con una dirección real en lugar del aspecto por defecto."}, {"label": "Verifica en el navegador integrado", "body": "Usa el modelo multimodal y el navegador integrado de Antigravity para renderizar y autoverificar en los distintos breakpoints, de modo que las maquetaciones no se rompan en silencio en el móvil."}, {"label": "Aporta tokens y referencias", "body": "Los tokens de diseño reales y las capturas de referencia son la mayor palanca sobre la calidad del resultado."}, {"label": "Codifica reglas en el contexto de proyecto", "body": "Coloca reglas del estilo «sin tarjetas hero, máximo dos tipografías, jerarquía con la marca primero» donde el agente las lea en cada tarea."}]}, {"kind": "p", "text": "Fíjate en que toda mitigación consiste en dar al agente un contexto de diseño curado. Mantener ese contexto a mano, proyecto a proyecto, es el trabajo tedioso que Open Design elimina."}]}, {"id": "open-design", "heading": "Diseñar con Antigravity dentro de Open Design", "blocks": [{"kind": "p", "text": "Open Design es la capa de diseño de código abierto que el flujo de trabajo anterior reclama una y otra vez. Trata a Antigravity como un adaptador de primera clase y lo envuelve en una biblioteca curada de skills y sistemas de diseño, una canalización de renderizado estructurada y una interfaz de escritorio local, para que el contexto de diseño que hace bueno a Antigravity esté presente desde la primera ejecución, no ensamblado a mano cada vez. Open Design es de código abierto y local-first, lo que hace de esta combinación un encaje natural."}, {"kind": "ol", "items": ["Instala Open Design y selecciona Antigravity como tu agente.", "Autentícate con tu cuenta de Google: las credenciales permanecen en tu máquina y nunca se enrutan a través de nosotros.", "Elige un sistema de diseño y una skill, y luego genera presentaciones, prototipos y páginas de aterrizaje con un criterio estético consistente.", "Cada artefacto y archivo DESIGN.md vive en tu propio repositorio, no en una nube alojada."]}, {"kind": "p", "text": "El mismo agente Antigravity, la misma cuenta de Google, más un flujo de diseño real, portátil y de código abierto a su alrededor. Open Design es local-first y Apache-2.0, así que nada de tu trabajo ni de tus credenciales sale de tu máquina."}]}], "faqTitle": "Preguntas frecuentes", "faq": [{"name": "¿De verdad puede Antigravity hacer trabajo de diseño?", "text": "Sí: con una skill estética, un sistema de diseño e imágenes de referencia reales en contexto, Antigravity produce interfaces adaptables de calidad de producción, y sus agentes multimodales Gemini 3.x verifican el resultado en el navegador integrado. Sin ese contexto tiende a caer en un aspecto genérico, que es la brecha que Open Design llena."}, {"name": "¿Necesito pagar para diseñar con Antigravity?", "text": "Antigravity está disponible en vista previa pública sin coste para particulares, con límites de uso generosos en Gemini 3.x cuando inicias sesión con una cuenta personal de Google. En cualquier caso, Open Design nunca enruta tus credenciales."}, {"name": "¿Qué hace que Antigravity sea bueno para el diseño en concreto?", "text": "Tres cosas: sus agentes se ejecutan sobre modelos Gemini 3.x nativamente multimodales que leen bien las capturas de referencia, incluye un navegador integrado que el agente puede gobernar para verificar la interfaz, y muestra Artifacts —capturas de pantalla y grabaciones del navegador— que puedes revisar. El criterio estético sigue viniendo del sistema de diseño, la skill y las referencias que tú aportes."}, {"name": "¿Antigravity o Claude Code para diseño de frontend?", "text": "Ambos son potentes. Claude Code es conocido por decisiones de diseño concretas y conscientes del código base; la ventaja de Antigravity es su plataforma centrada en agentes: Gemini 3.x multimodal, un navegador integrado para verificación y Artifacts revisables. Muchos equipos usan los dos: Open Design te permite cambiar de agente sin cambiar tu flujo de diseño."}, {"name": "¿Cómo verifico lo que construye Antigravity?", "text": "Antigravity incluye un navegador integrado que sus agentes pueden gobernar, así que renderizan la interfaz, la comprueban en los distintos breakpoints y capturan capturas de pantalla y grabaciones del navegador como Artifacts. Revisar esos Artifacts —y hacer que el agente compare su resultado con tus referencias— es cómo mantienes el resultado dentro de lo especificado."}, {"name": "¿Está Open Design afiliado a Google?", "text": "No. Antigravity es un producto de Google; Open Design es un proyecto de código abierto independiente que lo admite como adaptador de primera clase. Antigravity y Gemini son marcas registradas de Google."}, {"name": "¿Están seguros mis archivos y credenciales?", "text": "Sí: Open Design es local-first y Apache-2.0. Tus archivos, artefactos y DESIGN.md permanecen en tu propio repositorio, y tus credenciales de Google las usa directamente tu agente, sin pasar nunca por los servidores de Open Design."}], "ctaTitle": "Diseña con Antigravity, a la manera abierta.", "ctaBody": "Trae tu propia cuenta de Google, mantén cada archivo en local y obtén una biblioteca de diseño curada en torno al agente que ya usas.", "ctaActions": [{"label": "Usa Antigravity dentro de Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dale una estrella en GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Descarga la app de escritorio", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Ver todos los agentes compatibles"},
      },
      'reasonix': {
        ...en['reasonix']!,
        title: "DeepSeek Reasonix para diseño — Open Design",
        description: "Cómo se usa DeepSeek Reasonix —el agente de programación de terminal creado por la comunidad y nativo de DeepSeek— para diseño de interfaces y web, y cómo Open Design lo convierte en un agente de diseño local-first y de código abierto. BYOK con tu propia clave de API de DeepSeek.",
        breadcrumb: "DeepSeek Reasonix",
        label: "Agente · DeepSeek Reasonix",
        heading: "DeepSeek Reasonix para diseño.",
        lead: "DeepSeek Reasonix es un agente de programación de terminal de código abierto, creado por la comunidad e impulsado por modelos de DeepSeek. Lee tu repositorio, edita archivos y ejecuta tu bucle de verificación de forma económica: todo su diseño está construido en torno a la caché de prefijos de DeepSeek para mantener asequibles las sesiones largas. Con referencias, convenciones y una comprobación en el navegador, se convierte en una verdadera herramienta de diseño. Open Design lo integra en un flujo de diseño de código abierto: tu propia clave de API de DeepSeek, tus archivos, local-first.",
        rich: {"heroCtaLead": "Open Design convierte a DeepSeek Reasonix en un agente de diseño local-first y de código abierto: tu propia clave de API de DeepSeek, tus archivos y una biblioteca curada de skills y sistemas de diseño a su alrededor.", "heroCtaActions": [{"label": "Usa DeepSeek Reasonix dentro de Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dale una estrella en GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Descarga la app de escritorio", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["DeepSeek Reasonix es un agente de programación con IA de código abierto para la terminal, creado por la comunidad e impulsado por los modelos de DeepSeek. No es un producto oficial de DeepSeek: lo mantienen el autor de GitHub esengine y la comunidad, y está construido específicamente en torno a la mecánica de caché de prefijos de DeepSeek para que las sesiones largas e iterativas sigan siendo económicas. Lee tu repositorio, edita archivos, ejecuta comandos y trabaja a partir de tareas en lenguaje natural en lugar de limitarse a completar líneas. Tú traes tu propia clave de API de DeepSeek (BYOK), y el agente se ejecuta sobre modelos de DeepSeek como deepseek-v4-pro y deepseek-v4-flash. Esta es una guía práctica y de principio a fin para usar DeepSeek Reasonix en interfaces, frontend y trabajo con sistemas de diseño, y para integrarlo en un flujo de diseño estructurado con Open Design.", "Cubre qué es realmente DeepSeek Reasonix, por qué un agente impulsado por DeepSeek y de bajo coste encaja con el diseño iterativo, cómo configurarlo desde cero con tu propia clave, el bucle de referencia a interfaz, cómo lo extienden las skills y MCP, cómo se compara con Codex, Claude Code, Cursor y Gemini CLI, los errores que hacen que el resultado de la IA luzca genérico, y cómo Open Design cierra la brecha como una capa de diseño abierta y local-first, una combinación natural, ya que ambos son de código abierto y se ejecutan en tu propia máquina."], "heroImage": {"src": "/agents/reasonix-design/reasonix-design-hero.webp", "alt": "Bucle de retroalimentación de diseño de DeepSeek Reasonix: un agente de terminal leyendo referencias de diseño, un navegador renderizando la interfaz y un espacio de trabajo, con una flecha de retroalimentación que regresa", "caption": "El bucle central: DeepSeek Reasonix trabaja en la terminal contra tus referencias y convenciones, tú verificas la interfaz en un navegador real y él itera, de forma económica gracias a la caché de prefijos de DeepSeek."}, "tocLabel": "En esta página", "toc": [{"id": "what-is-reasonix", "label": "Qué es realmente DeepSeek Reasonix"}, {"id": "why-design", "label": "Por qué un agente de DeepSeek de bajo coste encaja con el diseño"}, {"id": "setup", "label": "Configura DeepSeek Reasonix para diseño (desde cero)"}, {"id": "screenshot-workflow", "label": "El flujo de referencia a interfaz"}, {"id": "extend", "label": "Skills, MCP y configuración"}, {"id": "vs", "label": "DeepSeek Reasonix frente a Codex, Claude Code, Cursor y Gemini CLI"}, {"id": "pitfalls", "label": "Errores comunes y el aspecto de «basura de IA»"}, {"id": "open-design", "label": "Diseñar con DeepSeek Reasonix en Open Design"}, {"id": "faq", "label": "Preguntas frecuentes"}], "sections": [{"id": "what-is-reasonix", "heading": "Qué es realmente DeepSeek Reasonix", "blocks": [{"kind": "p", "text": "DeepSeek Reasonix es un agente de programación con IA de código abierto (MIT) para la terminal, creado por el autor de GitHub esengine y la comunidad. Es nativo de DeepSeek: está diseñado en torno a la mecánica de caché de prefijos de DeepSeek para que las sesiones largas e iterativas sigan siendo económicas. Lee tu repositorio, edita archivos con un editor SEARCH/REPLACE con revisión previa, ejecuta comandos de shell y trabaja a partir de tareas en lenguaje natural, planificando y verificando en lugar de limitarse a completar líneas. Es importante dejar claro que se trata de un proyecto de la comunidad, no de un producto oficial de la empresa DeepSeek."}, {"kind": "p", "text": "Para el trabajo de diseño, lo que importa es que es un agente de programación competente y consciente del repositorio que se ejecuta sobre modelos potentes de DeepSeek a bajo coste. Los modelos de DeepSeek que usa son solo de texto —no leen imágenes de forma nativa—, así que el bucle de diseño práctico se guía por referencias y se verifica en un navegador real, en lugar de que el agente «vea» una captura directamente. La eficiencia de costes es la ventaja relevante para el diseño: puedes iterar sobre la interfaz muchas veces sin la factura que normalmente desincentiva los bucles ajustados."}, {"kind": "steps", "items": [{"label": "Nativo de DeepSeek, BYOK", "body": "Reasonix se ejecuta sobre modelos de DeepSeek como deepseek-v4-pro y deepseek-v4-flash. Tú traes tu propia clave de API de DeepSeek: la credencial vive en tu entorno, no en la configuración del agente."}, {"label": "Edición consciente del repositorio", "body": "Lee y edita archivos en tu proyecto con un editor con revisión previa y ejecuta comandos de shell, así que puede construir e iterar sobre código de interfaz real en tu propio repositorio."}, {"label": "Skills + MCP", "body": "Admite skills escritas en Markdown y servidores MCP, así que puedes darle convenciones duraderas y conectar contexto externo como una fuente de diseño."}]}, {"kind": "ul", "items": ["Fabricante: comunidad / el autor de GitHub esengine (no la empresa DeepSeek)", "Credencial: tu propia clave de API de DeepSeek (BYOK), aportada mediante el entorno", "Licencia: MIT, código abierto"]}]}, {"id": "why-design", "heading": "Por qué un agente de DeepSeek de bajo coste encaja con el diseño", "blocks": [{"kind": "p", "text": "La ventaja de DeepSeek Reasonix para el diseño tiene menos que ver con una única capacidad llamativa y más con hacer que el trabajo iterativo de interfaz sea económico y repetible, pero, como ocurre con todo agente, el criterio estético hay que aportarlo igualmente."}, {"kind": "steps", "items": [{"label": "Iteración económica y ajustada", "body": "Como está diseñado en torno a la caché de prefijos de DeepSeek, las sesiones largas de diseño siguen siendo asequibles, así que puedes ejecutar el bucle de construir-verificar-refinar muchas veces en lugar de racionarlo."}, {"label": "Reutilización consciente del repositorio", "body": "Edita archivos directamente en tu repositorio, así que puede reutilizar tus componentes y tokens existentes en lugar de inventar estilos puntuales, cuando lo apuntas hacia ellos."}, {"label": "Convenciones en skills", "body": "Las skills en Markdown y la configuración del proyecto te permiten codificar tokens, componentes y reglas de revisión, para que el agente trabaje contra tu marca en lugar de un aspecto por defecto."}]}, {"kind": "image", "src": "/agents/reasonix-design/reasonix-design-taste-triangle.webp", "alt": "Diagrama que muestra cómo un sistema de diseño, una skill y una imagen de referencia convergen en un buen resultado de diseño", "caption": "El criterio estético proviene de tres insumos que tú aportas: un sistema de diseño, una skill e imágenes de referencia reales."}, {"kind": "p", "text": "La lección es la misma que enseña todo agente: DeepSeek Reasonix no tiene criterio estético por defecto. Produce buen diseño cuando le das restricciones —un sistema de diseño, una skill estética y referencias concretas descritas— y un navegador contra el cual verificar. Open Design empaqueta exactamente esos insumos, por lo que ambos encajan (más abajo se explica)."}]}, {"id": "setup", "heading": "Configura DeepSeek Reasonix para el trabajo de diseño, desde cero", "blocks": [{"kind": "p", "text": "Este es el recorrido, desde una máquina limpia hasta un DeepSeek Reasonix capaz de construir y verificar interfaces. Como es un proyecto de la comunidad, sigue siempre las instrucciones de instalación del README del repositorio; el esquema de abajo es la forma general."}, {"kind": "code", "lang": "bash", "code": "# 1. Install DeepSeek Reasonix (Node 22+) — see the repo README\nnpm install -g reasonix\n\n# 2. Bring your own DeepSeek API key (BYOK)\n#    Reasonix reads it from your environment, not from config files.\nexport DEEPSEEK_API_KEY=sk-...    # your DeepSeek key\n\n# 3. Start it in your project\ncd your-project\nreasonix                         # see README for the exact subcommands\n\n# 4. Add a design source via MCP (optional)\n#    e.g. a Figma MCP server, configured per the repo docs"}, {"kind": "image", "src": "/agents/reasonix-design/reasonix-design-setup-flow.webp", "alt": "Flujo de configuración en cinco pasos: instalar, añadir tu clave de DeepSeek, configurar convenciones, añadir una skill, verificar en un navegador", "caption": "La secuencia de configuración: instalar → añadir tu clave de API de DeepSeek → codificar convenciones → añadir una skill → habilitar la verificación en el navegador."}, {"kind": "steps", "items": [{"label": "Codifica tus reglas de diseño", "body": "Coloca tus tokens, primitivos y convenciones en una skill o en la configuración del proyecto y apunta Reasonix hacia ellos, para que el resultado se ajuste a una marca en lugar de caer en un aspecto genérico por defecto."}, {"label": "Añade verificación en el navegador", "body": "Como los modelos de DeepSeek son solo de texto, conecta un Playwright o un MCP de navegador para que el agente renderice en un navegador real y compruebe su resultado en los distintos breakpoints, en lugar de limitarse a confirmar que el build pasa."}]}]}, {"id": "screenshot-workflow", "heading": "El flujo de referencia a interfaz", "blocks": [{"kind": "p", "text": "El bucle de diseño de mayor rendimiento con DeepSeek Reasonix consiste en convertir referencias claras en una interfaz funcional y adaptable e iterar hasta que coincida. Como los modelos de DeepSeek son solo de texto, las referencias se aportan como descripciones detalladas y especificaciones —no se leen de forma nativa como imágenes— y la coincidencia se confirma renderizando en un navegador real."}, {"kind": "ol", "items": ["Traduce tus referencias a especificaciones concretas: describe en palabras la maquetación, el espaciado, la jerarquía y los estados (escritorio y móvil, hover, vacío, cargando), ya que el modelo lee texto, no píxeles.", "Sé específico en el prompt; los prompts vagos producen interfaces genéricas incluso con un modelo potente.", "Mantén tu sistema de diseño y tus convenciones en una skill o en la configuración del proyecto, e indícale a Reasonix dónde viven los tokens y los primitivos canónicos.", "Levanta un servidor de desarrollo y verifica el resultado en un navegador real, redimensionando a los distintos breakpoints; conecta un MCP de navegador para que el agente pueda autoverificarse.", "Itera comparando la interfaz renderizada con tus referencias en el navegador, no solo confirmando que compila."]}, {"kind": "p", "text": "Da al agente restricciones concretas en el prompt en lugar de un encargo vago:"}, {"kind": "code", "lang": "bash", "code": "reasonix\n# in the prompt:\n> Implement this design in React + Vite + Tailwind + TypeScript.\n  Reference: a two-column hero, 48px vertical rhythm, brand teal\n  accent, system-ui type — desktop and mobile described in DESIGN.md.\n  Reuse my existing design-system components and tokens.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in a browser and iterate until it matches the spec\n  across breakpoints."}, {"kind": "p", "text": "Mantén los prompts breves y enfocados, confirma las buenas iteraciones y revierte las malas (avisando a Reasonix cuando reviertas), para que cada pasada parta de una base limpia y para que el bucle económico y amigable con la caché se mantenga productivo."}]}, {"id": "extend", "heading": "Skills, MCP y configuración", "blocks": [{"kind": "p", "text": "Unos pocos puntos de extensión hacen que DeepSeek Reasonix sea práctico para un trabajo de diseño sostenido, y encajan limpiamente en un flujo de diseño abierto."}, {"kind": "steps", "items": [{"label": "Skills en Markdown", "body": "Reasonix admite skills escritas en Markdown: el hogar duradero de tus convenciones de diseño, tokens y listas de revisión, aplicadas en cada ejecución."}, {"label": "Servidores MCP", "body": "Integra servidores MCP, la forma portátil de incorporar contexto de diseño y herramientas externas —lo más relevante, una fuente de diseño como un servidor MCP de Figma— que funcionan en distintos agentes, no solo en Reasonix."}, {"label": "Configuración del proyecto y herramientas integradas", "body": "La configuración por proyecto, junto con herramientas integradas de archivos, shell y web, le permite reunir contexto y ejecutar el bucle de verificación sin salir de la terminal. Consulta el README del repositorio para las rutas exactas de configuración."}]}, {"kind": "p", "text": "Son capacidades portátiles y multiagente: exactamente el tipo de cosa que Open Design está diseñado para orquestar, en lugar de recrearla en cada proyecto."}]}, {"id": "vs", "heading": "DeepSeek Reasonix frente a Codex, Claude Code, Cursor y Gemini CLI para diseño", "blocks": [{"kind": "p", "text": "No hay un único ganador para el trabajo de diseño: cada agente tiene una fortaleza distinta, y los equipos con experiencia los combinan. Un resumen honesto:"}, {"kind": "table", "columns": ["Agente", "Fortaleza de diseño", "Ideal para"], "rows": [["DeepSeek Reasonix", "De código abierto e impulsado por DeepSeek; eficiente en costes mediante la caché de prefijos, BYOK con tu propia clave de DeepSeek (creado por la comunidad, modelos solo de texto)", "Iteración económica y de alto volumen sobre la interfaz en tu propio repositorio"], ["Codex", "Gran acabado visual con una skill de frontend; builds asíncronos en entorno aislado", "Builds asíncronos delegados y reglas portátiles en AGENTS.md"], ["Claude Code", "Decisiones de diseño concretas (hex, espaciado, tipografía) y UX consciente del código base", "Razonamiento de frontend y refactorizaciones de contexto amplio"], ["Cursor", "Bucle visual de construir y ver con vista previa en vivo y ediciones en línea", "Trabajo de interfaz iterativo y supervisado dentro de un IDE"], ["Gemini CLI", "Gran comprensión multimodal de imágenes y un contexto de 1M de tokens; de código abierto con un plan gratuito", "Trabajo con muchas capturas de pantalla y mantener todo un sistema de diseño en contexto"]]}, {"kind": "p", "text": "El veredicto recurrente de la comunidad es que el criterio estético proviene de las personas: todos ellos tienden por defecto a una estética genérica sin skills, referencias ni restricciones. Ese es el verdadero problema a resolver, y tiene forma de herramienta de diseño, no de modelo."}]}, {"id": "pitfalls", "heading": "Errores comunes y cómo evitar el aspecto de «basura de IA»", "blocks": [{"kind": "p", "text": "La queja más común sobre el diseño generado por IA es que luce genérico: degradados suaves, paneles flotantes, esquinas redondeadas exageradas, sombras dramáticas, un aire de Inter y morado que «grita que esto lo hizo una IA». Otros problemas reportados incluyen maquetaciones móviles rotas e instrucciones que se filtran en el texto de la interfaz. Ninguno de estos es exclusivo de DeepSeek Reasonix; son lo que ocurre cuando cualquier agente se ejecuta sin un contexto de diseño curado, y como sus modelos son solo de texto, describir las referencias con precisión importa aún más."}, {"kind": "steps", "items": [{"label": "Añade una skill estética", "body": "Una skill de diseño curada obliga al agente a comprometerse con una dirección real en lugar del aspecto por defecto."}, {"label": "Verifica en un navegador real", "body": "Como el modelo no puede ver, renderiza y autoverifica en los distintos breakpoints en un navegador real para que las maquetaciones no se rompan en silencio en el móvil."}, {"label": "Aporta tokens y referencias descritas", "body": "Los tokens de diseño reales y los estados de referencia descritos con precisión son la mayor palanca sobre la calidad del resultado para un agente solo de texto."}, {"label": "Codifica reglas en una skill o configuración", "body": "Coloca reglas del estilo «sin tarjetas hero, máximo dos tipografías, jerarquía con la marca primero» donde el agente las lea en cada ejecución."}]}, {"kind": "p", "text": "Fíjate en que toda mitigación consiste en dar al agente un contexto de diseño curado. Mantener ese contexto a mano, proyecto a proyecto, es el trabajo tedioso que Open Design elimina."}]}, {"id": "open-design", "heading": "Diseñar con DeepSeek Reasonix dentro de Open Design", "blocks": [{"kind": "p", "text": "Open Design es la capa de diseño de código abierto que el flujo de trabajo anterior reclama una y otra vez. Trata a DeepSeek Reasonix como un adaptador de primera clase y lo envuelve en una biblioteca curada de skills y sistemas de diseño, una canalización de renderizado estructurada y una interfaz de escritorio local, para que el contexto de diseño que hace bueno a Reasonix esté presente desde la primera ejecución, no ensamblado a mano cada vez. Ambos son de código abierto y local-first, lo que hace de esta combinación un encaje natural."}, {"kind": "ol", "items": ["Instala Open Design y selecciona DeepSeek Reasonix como tu agente.", "Autentícate con tu propia clave de API de DeepSeek (BYOK): las credenciales permanecen en tu máquina y nunca se enrutan a través de nosotros.", "Elige un sistema de diseño y una skill, y luego genera presentaciones, prototipos y páginas de aterrizaje con un criterio estético consistente.", "Cada artefacto y archivo DESIGN.md vive en tu propio repositorio, no en una nube alojada."]}, {"kind": "p", "text": "El mismo agente DeepSeek Reasonix, la misma clave, más un flujo de diseño real, portátil y de código abierto a su alrededor. Es local-first y de código abierto, así que nada de tu trabajo ni de tus credenciales sale de tu máquina."}]}], "faqTitle": "Preguntas frecuentes", "faq": [{"name": "¿De verdad puede DeepSeek Reasonix hacer trabajo de diseño?", "text": "Sí: con una skill estética, un sistema de diseño y referencias descritas con precisión en contexto, DeepSeek Reasonix produce interfaces adaptables de calidad de producción en tu propio repositorio, y tú verificas el resultado en un navegador real. Sus modelos de DeepSeek son solo de texto, así que el bucle consiste en describir y verificar referencias en lugar de leer imágenes. Sin ese contexto tiende a caer en un aspecto genérico, que es la brecha que Open Design llena."}, {"name": "¿Necesito pagar para diseñar con DeepSeek Reasonix?", "text": "Tú traes tu propia clave de API de DeepSeek, así que pagas a DeepSeek por el uso (BYOK), pero el agente está construido en torno a la caché de prefijos de DeepSeek para mantener bajo ese coste en sesiones largas. Reasonix en sí es gratuito y tiene licencia MIT. Open Design nunca enruta tus credenciales."}, {"name": "¿Es DeepSeek Reasonix un producto oficial de DeepSeek?", "text": "No. DeepSeek Reasonix es un proyecto de código abierto creado por la comunidad por el autor de GitHub esengine; se ejecuta sobre los modelos de DeepSeek y usa una clave de API de DeepSeek, pero no está hecho ni respaldado por la empresa DeepSeek. DeepSeek es una marca registrada de su respectivo propietario."}, {"name": "¿DeepSeek Reasonix o Claude Code para diseño de frontend?", "text": "Ambos pueden hacer trabajo de diseño real. Claude Code es conocido por decisiones de diseño concretas y conscientes del código base; la ventaja de DeepSeek Reasonix es ser de código abierto y eficiente en costes, ejecutando una iteración económica y de alto volumen sobre modelos de DeepSeek con tu propia clave. Muchos equipos usan más de uno: Open Design te permite cambiar de agente sin cambiar tu flujo de diseño."}, {"name": "¿Cómo conecto DeepSeek Reasonix a una fuente de diseño como Figma?", "text": "Reasonix admite servidores MCP, así que puedes añadir un MCP de fuente de diseño (como un servidor MCP de Figma) según la documentación del repositorio. El agente puede entonces extraer contexto de diseño real —componentes, variables, datos de maquetación— como texto sobre el que actuar, para que el código generado coincida con la fuente en lugar de aproximarla."}, {"name": "¿Está Open Design afiliado a DeepSeek?", "text": "No. DeepSeek Reasonix es un proyecto de la comunidad que se ejecuta sobre los modelos de DeepSeek; Open Design es un proyecto de código abierto independiente que lo admite como adaptador de primera clase. No está afiliado ni a la empresa DeepSeek ni a los mantenedores de Reasonix. DeepSeek es una marca registrada de su respectivo propietario."}, {"name": "¿Están seguros mis archivos y credenciales?", "text": "Sí: Open Design es local-first y de código abierto. Tus archivos, artefactos y DESIGN.md permanecen en tu propio repositorio, y tu clave de API de DeepSeek la usa directamente tu agente, sin pasar nunca por los servidores de Open Design."}], "ctaTitle": "Diseña con DeepSeek Reasonix, a la manera abierta.", "ctaBody": "Trae tu propia clave de API de DeepSeek, mantén cada archivo en local y obtén una biblioteca de diseño curada en torno al agente de código abierto que ya usas.", "ctaActions": [{"label": "Usa DeepSeek Reasonix dentro de Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dale una estrella en GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Descarga la app de escritorio", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Ver todos los agentes compatibles"},
      },
      'hermes': {
        ...en['hermes']!,
        title: "Hermes para diseño — Open Design",
        description: "Cómo se usa Hermes, de Nous Research —el agente de programación de terminal autónomo y multiproveedor— para diseño de interfaces y web, y cómo Open Design lo convierte en un agente de diseño local-first y de código abierto con tu propia clave de xAI, OpenAI o Anthropic.",
        breadcrumb: "Hermes",
        label: "Agente · Hermes",
        heading: "Hermes para diseño.",
        lead: "Hermes es el agente de terminal autónomo y de código abierto de Nous Research. Planifica, ejecuta y delega trabajo en su propia máquina, y es agnóstico al proveedor, así que traes tu propia clave de xAI, OpenAI o Anthropic. Esa autonomía lo convierte en una verdadera herramienta de diseño una vez que le das referencias, convenciones y un bucle de verificación. Open Design lo integra en un flujo de diseño de código abierto: tu clave, tus archivos, local-first.",
        rich: {"heroCtaLead": "Open Design convierte a Hermes en un agente de diseño local-first y de código abierto: tu propia clave de xAI, OpenAI o Anthropic, tus archivos y una biblioteca curada de skills y sistemas de diseño a su alrededor.", "heroCtaActions": [{"label": "Usa Hermes dentro de Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dale una estrella en GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Descarga la app de escritorio", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Hermes es el agente de IA autónomo y de código abierto de Nous Research. Dos cosas lo hacen interesante específicamente para el diseño: es genuinamente agéntico, así que planifica una tarea, la ejecuta y delega partes a subagentes aislados en lugar de limitarse a completar líneas; y es agnóstico al proveedor, así que lo apuntas al modelo en el que confíes —xAI Grok por defecto, u OpenAI y Anthropic mediante «trae tu propia clave»—. Combinado con las referencias, convenciones y un bucle de verificación adecuados, construye interfaces reales y adaptables en tu propia máquina. Esta es una guía práctica y de principio a fin para usar Hermes en interfaces, frontend y trabajo con sistemas de diseño, y para integrarlo en un flujo de diseño estructurado con Open Design.", "Cubre qué es realmente Hermes, por qué un agente autónomo y multiproveedor encaja con el diseño, cómo configurarlo desde cero, el bucle de captura de pantalla a interfaz, cómo lo extienden las skills y los subagentes, cómo se compara con Codex, Claude Code, Cursor y Gemini CLI, los errores que hacen que el resultado de la IA luzca genérico, y cómo Open Design cierra la brecha como una capa de diseño abierta y local-first, una combinación natural, ya que ambos son de código abierto y se ejecutan en tu propia máquina."], "heroImage": {"src": "/agents/hermes-design/hermes-design-hero.webp", "alt": "Bucle de retroalimentación de diseño de Hermes: un agente de terminal autónomo leyendo una imagen de referencia, delegando a subagentes, un navegador renderizando la interfaz y un espacio de trabajo, con una flecha de retroalimentación que regresa", "caption": "El bucle central: Hermes lee tus referencias en la terminal, planifica y delega la construcción, verifica la interfaz en un navegador real e itera contra ellas, con el modelo que tú traigas."}, "tocLabel": "En esta página", "toc": [{"id": "what-is-hermes", "label": "Qué es realmente Hermes"}, {"id": "why-design", "label": "Por qué un agente autónomo y multiproveedor encaja con el diseño"}, {"id": "setup", "label": "Configura Hermes para diseño (desde cero)"}, {"id": "screenshot-workflow", "label": "El flujo de captura de pantalla a interfaz"}, {"id": "extend", "label": "Skills, subagentes y proveedores"}, {"id": "vs", "label": "Hermes frente a Codex, Claude Code, Cursor y Gemini CLI"}, {"id": "pitfalls", "label": "Errores comunes y el aspecto de «basura de IA»"}, {"id": "open-design", "label": "Diseñar con Hermes en Open Design"}, {"id": "faq", "label": "Preguntas frecuentes"}], "sections": [{"id": "what-is-hermes", "heading": "Qué es realmente Hermes", "blocks": [{"kind": "p", "text": "Hermes es un agente de IA autónomo de código abierto (MIT) de Nous Research. Se ejecuta de forma persistente en tu propia máquina o servidor, lee tu repositorio, edita archivos, ejecuta comandos de shell, busca en la web y —algo crucial— planifica y ejecuta trabajo de varios pasos por su cuenta, delegando partes a subagentes aislados. Es un agente autónomo, no un copiloto atado a un IDE."}, {"kind": "p", "text": "Para el trabajo de diseño destacan dos propiedades. Es genuinamente agéntico, así que puedes encomendarle un objetivo y él planifica, construye y verifica en lugar de esperar indicaciones línea a línea. Y es agnóstico al proveedor: traes tu propia clave, con xAI Grok por defecto pero con libertad para apuntarlo a OpenAI, Anthropic o cualquier otro endpoint compatible, así que tú controlas qué modelo razona sobre tu diseño."}, {"kind": "steps", "items": [{"label": "Skills", "body": "Hermes construye y reutiliza skills —memoria procedimental que crea a partir de la experiencia—, el lugar natural para capturar tus convenciones de diseño, tokens y listas de revisión de modo que persistan entre ejecuciones."}, {"label": "Subagentes + herramientas", "body": "Lanza subagentes aislados para flujos de trabajo en paralelo e incluye utillaje de archivos, shell, web y navegador, así que puede reunir referencias y ejecutar un bucle de construir y verificar sin salir de la terminal."}, {"label": "Trae tu propia clave", "body": "Hermes usa xAI Grok por defecto y admite OpenAI, Anthropic, OpenRouter y muchos otros proveedores mediante BYOK: define una clave o ejecuta un flujo OAuth y elige tu modelo."}]}, {"kind": "ul", "items": ["Fabricante: Nous Research", "Credencial: clave de proveedor mediante BYOK —xAI (Grok, por defecto), OpenAI o Anthropic— añadida con hermes auth add", "Licencia: MIT, código abierto"]}]}, {"id": "why-design", "heading": "Por qué un agente autónomo y multiproveedor encaja con el diseño", "blocks": [{"kind": "p", "text": "La ventaja de Hermes para el diseño viene de dos propiedades, pero, como ocurre con todo agente, el criterio estético hay que aportarlo igualmente."}, {"kind": "steps", "items": [{"label": "Planificar y ejecutar de forma autónoma", "body": "Como Hermes planifica, ejecuta y delega por su cuenta, puede tomar un objetivo de diseño —ajústate a esta referencia, hazlo adaptable— e iterar hacia él en lugar de necesitar que se le detalle cada paso."}, {"label": "Trae el modelo en el que confías", "body": "El BYOK agnóstico al proveedor significa que eliges el modelo de razonamiento para el trabajo: xAI Grok por defecto, o modelos de OpenAI y Anthropic cuando quieras sus fortalezas, sin quedar atado a la estética de un único fabricante."}, {"label": "Convenciones en skills", "body": "Las skills (más un servidor MCP como Figma) apuntan al agente hacia tus tokens, componentes y especificaciones reales, para que trabaje contra una marca en lugar de un aspecto por defecto."}]}, {"kind": "image", "src": "/agents/hermes-design/hermes-design-taste-triangle.webp", "alt": "Diagrama que muestra cómo un sistema de diseño, una skill y una imagen de referencia convergen en un buen resultado de diseño", "caption": "El criterio estético proviene de tres insumos que tú aportas: un sistema de diseño, una skill e imágenes de referencia reales."}, {"kind": "p", "text": "La lección es la misma que enseña todo agente: Hermes no tiene criterio estético por defecto. Produce buen diseño cuando le das restricciones: un sistema de diseño, una skill estética y referencias concretas. Open Design empaqueta exactamente esos insumos, por lo que ambos encajan (más abajo se explica)."}]}, {"id": "setup", "heading": "Configura Hermes para el trabajo de diseño, desde cero", "blocks": [{"kind": "p", "text": "Este es el recorrido completo, desde una máquina limpia hasta un Hermes capaz de construir y verificar interfaces."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Hermes (one-line installer from Nous Research)\ncurl -fsSL https://hermes-agent.nousresearch.com/install.sh | bash\n\n# 2. Run the setup wizard\nhermes setup\n\n# 3. Add a provider and authenticate (BYOK)\n#    default is xAI Grok; OpenAI / Anthropic also supported\nhermes auth add        # add a provider key or run its OAuth flow\nhermes model           # pick the provider and model (grok-4.3 by default)\n\n# 4. Wire a Figma MCP server (optional, for design handoff)\n#    configure it among Hermes' MCP / tool settings"}, {"kind": "image", "src": "/agents/hermes-design/hermes-design-setup-flow.webp", "alt": "Flujo de configuración en cinco pasos: instalar, autenticarse, configurar una skill, añadir un sistema de diseño, verificar", "caption": "La secuencia de configuración: instalar → añadir una clave de proveedor → capturar reglas de diseño en una skill → añadir un sistema de diseño → habilitar la verificación en el navegador."}, {"kind": "steps", "items": [{"label": "Codifica tus reglas de diseño", "body": "Captura tus tokens, primitivos y convenciones en una skill de Hermes y apunta el agente hacia ellos, para que el resultado se ajuste a una marca en lugar de caer en un aspecto genérico por defecto."}, {"label": "Añade verificación en el navegador", "body": "Conecta un Playwright o un MCP de navegador para que Hermes renderice en un navegador real y compruebe su resultado en los distintos breakpoints, en lugar de limitarse a confirmar que el build pasa."}]}]}, {"id": "screenshot-workflow", "heading": "El flujo de captura de pantalla a interfaz", "blocks": [{"kind": "p", "text": "El bucle de diseño de mayor rendimiento con Hermes consiste en convertir una imagen de referencia en una interfaz funcional y adaptable e iterar hasta que coincida, dejando que el agente autónomo planifique la construcción y compare su resultado con la referencia."}, {"kind": "ol", "items": ["Parte de las referencias visuales más claras que tengas, e incluye varios estados (escritorio y móvil, hover, vacío, cargando), no solo una imagen principal.", "Sé específico en el prompt; los prompts vagos producen interfaces genéricas incluso con un modelo potente.", "Mantén tu sistema de diseño y tus convenciones en una skill, e indícale a Hermes dónde viven los tokens y los primitivos canónicos.", "Levanta un servidor de desarrollo y haz que Hermes renderice en un navegador real, redimensionando a los distintos breakpoints para comprobar el resultado.", "Itera haciendo que Hermes compare su implementación con las capturas de pantalla, no solo que confirme que compila."]}, {"kind": "p", "text": "Apunta Hermes a tus referencias y da restricciones concretas:"}, {"kind": "code", "lang": "bash", "code": "hermes\n# in the prompt:\n> Use reference-desktop.png and reference-mobile.png in this folder.\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from my skill.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the references\n  across breakpoints."}, {"kind": "p", "text": "Mantén los prompts breves y enfocados, confirma las buenas iteraciones y revierte las malas (avisando a Hermes cuando reviertas), para que cada pasada parta de una base limpia."}]}, {"id": "extend", "heading": "Skills, subagentes y proveedores", "blocks": [{"kind": "p", "text": "Tres puntos de extensión hacen que Hermes sea práctico para un trabajo de diseño sostenido, y los tres encajan limpiamente en un flujo de diseño abierto."}, {"kind": "steps", "items": [{"label": "Skills", "body": "Hermes construye y reutiliza skills: memoria procedimental creada a partir de la experiencia. Son el hogar duradero de tus convenciones de diseño, aplicadas en ejecuciones posteriores en lugar de reexplicarse cada vez."}, {"label": "Subagentes y MCP", "body": "Delega trabajo a subagentes aislados y admite servidores MCP: la forma portátil de incorporar contexto de diseño y herramientas externas —lo más relevante, un servidor MCP de Figma— que funcionan en distintos agentes, no solo en Hermes."}, {"label": "Elección de proveedor", "body": "Como Hermes es agnóstico al proveedor (xAI Grok por defecto, OpenAI y Anthropic mediante BYOK), puedes ajustar el modelo a la tarea sin rehacer tu flujo de trabajo."}]}, {"kind": "p", "text": "Son capacidades portátiles y multiagente: exactamente el tipo de cosa que Open Design está diseñado para orquestar, en lugar de recrearla en cada proyecto."}]}, {"id": "vs", "heading": "Hermes frente a Codex, Claude Code, Cursor y Gemini CLI para diseño", "blocks": [{"kind": "p", "text": "No hay un único ganador para el trabajo de diseño: cada agente tiene una fortaleza distinta, y los equipos con experiencia los combinan. Un resumen honesto:"}, {"kind": "table", "columns": ["Agente", "Fortaleza de diseño", "Ideal para"], "rows": [["Hermes", "Agente autónomo que planifica, ejecuta y delega; BYOK agnóstico al proveedor (xAI Grok por defecto, también OpenAI/Anthropic); de código abierto y autoalojado", "Builds autónomos sin intervención sobre el modelo en el que confíes, mantenidos en local"], ["Codex", "Gran acabado visual con una skill de frontend; builds asíncronos en entorno aislado", "Builds asíncronos delegados y reglas portátiles en AGENTS.md"], ["Claude Code", "Decisiones de diseño concretas (hex, espaciado, tipografía) y UX consciente del código base", "Razonamiento de frontend y refactorizaciones de contexto amplio"], ["Cursor", "Bucle visual de construir y ver con vista previa en vivo y ediciones en línea", "Trabajo de interfaz iterativo y supervisado dentro de un IDE"], ["Gemini CLI", "Gran comprensión multimodal de imágenes y un contexto de 1M de tokens; plan gratuito", "Trabajo con muchas capturas de pantalla y mantener todo un sistema de diseño en contexto"]]}, {"kind": "p", "text": "El veredicto recurrente de la comunidad es que el criterio estético proviene de las personas: todos ellos tienden por defecto a una estética genérica sin skills, referencias ni restricciones. Ese es el verdadero problema a resolver, y tiene forma de herramienta de diseño, no de modelo."}]}, {"id": "pitfalls", "heading": "Errores comunes y cómo evitar el aspecto de «basura de IA»", "blocks": [{"kind": "p", "text": "La queja más común sobre el diseño generado por IA es que luce genérico: degradados suaves, paneles flotantes, esquinas redondeadas exageradas, sombras dramáticas, un aire de Inter y morado que «grita que esto lo hizo una IA». Otros problemas reportados incluyen maquetaciones móviles rotas e instrucciones que se filtran en el texto de la interfaz. Ninguno de estos es exclusivo de Hermes; son lo que ocurre cuando cualquier agente se ejecuta sin un contexto de diseño curado."}, {"kind": "steps", "items": [{"label": "Añade una skill estética", "body": "Una skill de diseño curada obliga al agente a comprometerse con una dirección real en lugar del aspecto por defecto."}, {"label": "Verifica en un navegador real", "body": "Haz que Hermes renderice y se autoverifique en los distintos breakpoints para que las maquetaciones no se rompan en silencio en el móvil."}, {"label": "Aporta tokens y referencias", "body": "Los tokens de diseño reales y las capturas de referencia son la mayor palanca sobre la calidad del resultado."}, {"label": "Codifica reglas en una skill", "body": "Coloca reglas del estilo «sin tarjetas hero, máximo dos tipografías, jerarquía con la marca primero» en una skill que el agente aplique en cada ejecución."}]}, {"kind": "p", "text": "Fíjate en que toda mitigación consiste en dar al agente un contexto de diseño curado. Mantener ese contexto a mano, proyecto a proyecto, es el trabajo tedioso que Open Design elimina."}]}, {"id": "open-design", "heading": "Diseñar con Hermes dentro de Open Design", "blocks": [{"kind": "p", "text": "Open Design es la capa de diseño de código abierto que el flujo de trabajo anterior reclama una y otra vez. Trata a Hermes como un adaptador de primera clase y lo envuelve en una biblioteca curada de skills y sistemas de diseño, una canalización de renderizado estructurada y una interfaz de escritorio local, para que el contexto de diseño que hace bueno a Hermes esté presente desde la primera ejecución, no ensamblado a mano cada vez. Ambos son de código abierto y local-first, lo que hace de esta combinación un encaje natural."}, {"kind": "ol", "items": ["Instala Open Design y selecciona Hermes como tu agente.", "Autentícate con tu propia clave de proveedor (BYOK) —xAI Grok por defecto, u OpenAI o Anthropic—; las credenciales permanecen en tu máquina y nunca se enrutan a través de nosotros.", "Elige un sistema de diseño y una skill, y luego genera presentaciones, prototipos y páginas de aterrizaje con un criterio estético consistente.", "Cada artefacto y archivo DESIGN.md vive en tu propio repositorio, no en una nube alojada."]}, {"kind": "p", "text": "El mismo agente Hermes, la misma clave, más un flujo de diseño real, portátil y de código abierto a su alrededor. Es local-first y Apache-2.0, así que nada de tu trabajo ni de tus credenciales sale de tu máquina."}]}], "faqTitle": "Preguntas frecuentes", "faq": [{"name": "¿De verdad puede Hermes hacer trabajo de diseño?", "text": "Sí: con una skill estética, un sistema de diseño e imágenes de referencia reales en contexto, Hermes produce interfaces adaptables de calidad de producción, y como agente autónomo puede renderizar y verificar el resultado contra las referencias por su cuenta. Sin ese contexto tiende a caer en un aspecto genérico, que es la brecha que Open Design llena."}, {"name": "¿Qué modelos y claves usa Hermes?", "text": "Hermes es agnóstico al proveedor y «trae tu propia clave». Usa xAI Grok por defecto (por ejemplo grok-4.3) y también admite OpenAI, Anthropic, OpenRouter y muchos otros proveedores: añades una clave de proveedor (o ejecutas su flujo OAuth) con hermes auth add y eliges un modelo con hermes model. Open Design nunca enruta tus credenciales."}, {"name": "¿Qué hace que Hermes sea bueno para el diseño en concreto?", "text": "Dos cosas: es genuinamente autónomo, así que planifica, construye y verifica la interfaz en lugar de esperar indicaciones línea a línea; y es agnóstico al proveedor, así que puedes ejecutar el modelo de razonamiento en el que confíes. Ambas ayudan, pero el criterio estético sigue viniendo del sistema de diseño, la skill y las referencias que tú aportes."}, {"name": "¿Hermes o Claude Code para diseño de frontend?", "text": "Ambos son potentes. Claude Code es conocido por decisiones de diseño concretas y conscientes del código base; la ventaja de Hermes es la planificación y ejecución autónomas más la elección de proveedor, y hasta puedes apuntar Hermes a una clave de Anthropic. Muchos equipos usan los dos: Open Design te permite cambiar de agente sin cambiar tu flujo de diseño."}, {"name": "¿Cómo conecto Hermes a Figma?", "text": "Añade un servidor MCP de Figma en la configuración de herramientas de Hermes. Hermes puede entonces extraer contexto de diseño real —componentes, variables, datos de maquetación— para que el código generado coincida con la fuente en lugar de aproximarla."}, {"name": "¿Está Open Design afiliado a Nous Research?", "text": "No. Hermes es un producto de Nous Research; Open Design es un proyecto de código abierto independiente que lo admite como adaptador de primera clase. Hermes y Nous Research son marcas registradas de su respectivo propietario."}, {"name": "¿Están seguros mis archivos y credenciales?", "text": "Sí: Open Design es local-first y Apache-2.0. Tus archivos, artefactos y DESIGN.md permanecen en tu propio repositorio, y tus credenciales de proveedor las usa directamente tu agente, sin pasar nunca por los servidores de Open Design."}], "ctaTitle": "Diseña con Hermes, a la manera abierta.", "ctaBody": "Trae tu propia clave de xAI, OpenAI o Anthropic, mantén cada archivo en local y obtén una biblioteca de diseño curada en torno al agente que ya usas.", "ctaActions": [{"label": "Usa Hermes dentro de Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dale una estrella en GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Descarga la app de escritorio", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Ver todos los agentes compatibles"},
      },
      'devin': {
        ...en['devin']!,
        title: "Devin for Terminal para diseño — Open Design",
        description: "Cómo se usa Devin for Terminal —el ingeniero de software con IA autónomo de Cognition en la línea de comandos— para diseño de interfaces y web, y cómo Open Design lo convierte en un agente de diseño local-first y de código abierto con una biblioteca curada de skills y sistemas de diseño.",
        breadcrumb: "Devin for Terminal",
        label: "Agente · Devin",
        heading: "Devin for Terminal para diseño.",
        lead: "Devin for Terminal es el ingeniero de software con IA autónomo de Cognition, ejecutándose en tu terminal. Planifica y ejecuta tareas de varios pasos por su cuenta y puede traspasar una sesión a un agente en la nube en entorno aislado, lo que lo convierte en una forma real de entregar trabajo de frontend, una vez que le das referencias, convenciones y un bucle de verificación. Open Design lo integra en un flujo de diseño de código abierto: tu cuenta de Devin, tus archivos, local-first.",
        rich: {"heroCtaLead": "Open Design convierte a Devin for Terminal en un agente de diseño local-first y de código abierto: tu cuenta de Devin, tus archivos y una biblioteca curada de skills y sistemas de diseño a su alrededor.", "heroCtaActions": [{"label": "Usa Devin dentro de Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dale una estrella en GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Descarga la app de escritorio", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Devin for Terminal es el ingeniero de software con IA autónomo de Cognition, llevado a la línea de comandos local. Dos cosas lo hacen interesante específicamente para el diseño: es genuinamente agéntico, así que planifica y ejecuta una tarea de varios pasos de principio a fin en lugar de limitarse a completar líneas; y puede traspasar una sesión a un agente en la nube en entorno aislado con su propio ordenador, de modo que las construcciones más largas siguen ejecutándose después de que cierres tu portátil. Combinado con las referencias, convenciones y un bucle de verificación adecuados, construye interfaces reales y adaptables. Esta es una guía práctica y de principio a fin para usar Devin for Terminal en interfaces, frontend y trabajo con sistemas de diseño, y para integrarlo en un flujo de diseño estructurado con Open Design.", "Cubre qué es realmente Devin for Terminal, por qué un ingeniero de software autónomo encaja con el trabajo de diseño, cómo configurarlo desde cero, el bucle de captura de pantalla a interfaz, cómo lo extienden las reglas de proyecto y las herramientas externas, cómo se compara con Codex, Claude Code, Cursor y Gemini CLI, los errores que hacen que el resultado de la IA luzca genérico, y cómo Open Design cierra la brecha como una capa de diseño abierta y local-first, una combinación natural para cualquier agente capaz de planificar y entregar trabajo de frontend."], "heroImage": {"src": "/agents/devin-design/devin-design-hero.webp", "alt": "Bucle de retroalimentación de diseño de Devin for Terminal: un agente de terminal autónomo leyendo una imagen de referencia, un navegador renderizando la interfaz y un espacio de trabajo, con una flecha de retroalimentación que regresa", "caption": "El bucle central: Devin lee tus referencias en la terminal, planifica y construye la interfaz, la verifica en un navegador real e itera contra ellas, traspasando las ejecuciones más largas a la nube cuando hace falta."}, "tocLabel": "En esta página", "toc": [{"id": "what-is-devin", "label": "Qué es realmente Devin for Terminal"}, {"id": "why-design", "label": "Por qué un ingeniero de software autónomo encaja con el diseño"}, {"id": "setup", "label": "Configura Devin para diseño (desde cero)"}, {"id": "screenshot-workflow", "label": "El flujo de captura de pantalla a interfaz"}, {"id": "extend", "label": "Reglas de proyecto, herramientas y traspaso a la nube"}, {"id": "vs", "label": "Devin frente a Codex, Claude Code, Cursor y Gemini CLI"}, {"id": "pitfalls", "label": "Errores comunes y el aspecto de «basura de IA»"}, {"id": "open-design", "label": "Diseñar con Devin en Open Design"}, {"id": "faq", "label": "Preguntas frecuentes"}], "sections": [{"id": "what-is-devin", "heading": "Qué es realmente Devin for Terminal", "blocks": [{"kind": "p", "text": "Devin for Terminal es la versión de línea de comandos de Devin, el ingeniero de software con IA autónomo de Cognition. Se ejecuta como un agente de programación local con acceso a tu código base, tus herramientas y tu entorno, leyendo tu repositorio, editando archivos, ejecutando comandos de shell y planificando y verificando el trabajo a partir de una tarea en lenguaje natural en lugar de limitarse a completar líneas. Cognition construyó una biblioteca de renderizado de terminal a medida en Rust para que la interfaz se mantenga rápida y reactiva."}, {"kind": "p", "text": "Para el trabajo de diseño destacan dos propiedades. Es genuinamente autónomo, así que puedes describir un resultado y él ejecuta el recorrido de varios pasos para alcanzarlo. Y cuando una construcción supera la capacidad de tu portátil, puedes traspasar la sesión a un agente en la nube que se ejecuta en su propio entorno aislado y sigue trabajando de forma asíncrona, de modo que puedes volver a un pull request terminado."}, {"kind": "steps", "items": [{"label": "Ejecución autónoma y agéntica", "body": "Devin planifica y ejecuta una tarea de varios pasos por su cuenta —implementando una funcionalidad, construyendo la interfaz, ejecutándola y probándola— guiado por prompts claros con criterios de finalización explícitos."}, {"label": "Agente local, traspaso a la nube", "body": "Se ejecuta localmente en tu terminal y puede escalar una sesión a un agente en la nube en entorno aislado que tiene su propio ordenador y continúa el trabajo después de que te apartes."}, {"label": "Basado en cuenta, con elección de modelo", "body": "Inicias sesión con una cuenta de Devin (Cognition); Devin se ejecuta sobre modelos de frontera, y puedes elegir entre opciones como el propio SWE-1.6 de Cognition y otros modelos de frontera."}]}, {"kind": "ul", "items": ["Fabricante: Cognition", "Credencial: cuenta de Devin (Cognition), inicio de sesión basado en suscripción/cuenta, no «trae tu propia clave»", "Formato: agente de terminal local con traspaso opcional a la nube en entorno aislado"]}]}, {"id": "why-design", "heading": "Por qué un ingeniero de software autónomo encaja con el diseño", "blocks": [{"kind": "p", "text": "La ventaja de Devin para el diseño viene de cómo trabaja —ejecución autónoma y de principio a fin—, pero, como ocurre con todo agente, el criterio estético hay que aportarlo igualmente."}, {"kind": "steps", "items": [{"label": "Construcciones de principio a fin y de varios pasos", "body": "Como Devin planifica y ejecuta tareas completas, puede crear el andamiaje de una página, conectar componentes, levantar un servidor de desarrollo y probar el resultado de una sola vez en lugar de detenerse en un fragmento."}, {"label": "Ejecuciones en la nube en entorno aislado", "body": "El trabajo de frontend más largo —una página de aterrizaje completa, un flujo de varias pantallas— puede traspasarse a un agente en la nube en entorno aislado y seguir construyendo, de modo que la iteración no quede bloqueada por tu portátil."}, {"label": "Convenciones en las reglas de proyecto", "body": "Apunta el agente hacia tus tokens, componentes y especificaciones reales mediante las reglas y la documentación de tu proyecto, para que trabaje contra una marca en lugar de un aspecto por defecto."}]}, {"kind": "image", "src": "/agents/devin-design/devin-design-taste-triangle.webp", "alt": "Diagrama que muestra cómo un sistema de diseño, una skill y una imagen de referencia convergen en un buen resultado de diseño", "caption": "El criterio estético proviene de tres insumos que tú aportas: un sistema de diseño, una skill e imágenes de referencia reales."}, {"kind": "p", "text": "La lección es la misma que enseña todo agente: Devin no tiene criterio estético por defecto. Produce buen diseño cuando le das restricciones: un sistema de diseño, una skill estética y referencias concretas. Open Design empaqueta exactamente esos insumos, por lo que ambos encajan (más abajo se explica)."}]}, {"id": "setup", "heading": "Configura Devin para el trabajo de diseño, desde cero", "blocks": [{"kind": "p", "text": "Este es el recorrido completo, desde una máquina limpia hasta un Devin for Terminal capaz de construir y verificar interfaces."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Devin for Terminal\ncurl -fsSL https://cli.devin.ai/install.sh | bash\n\n# 2. Start it in your project and sign in on first run\ncd your-project\ndevin             # sign in with your Devin (Cognition) account\n\n# 3. Describe the task in natural language, with clear\n#    completion criteria, and let Devin plan and execute.\n\n# 4. When a build outgrows your laptop, hand the session\n#    off to a sandboxed cloud agent that keeps working."}, {"kind": "image", "src": "/agents/devin-design/devin-design-setup-flow.webp", "alt": "Flujo de configuración en cinco pasos: instalar, iniciar sesión, codificar reglas de diseño, añadir referencias, verificar en un navegador", "caption": "La secuencia de configuración: instalar → iniciar sesión → codificar tus reglas de diseño → aportar referencias → verificar en un navegador real."}, {"kind": "steps", "items": [{"label": "Codifica tus reglas de diseño", "body": "Coloca tus tokens, primitivos y convenciones donde el agente los lea —en las reglas y la documentación de tu proyecto— para que el resultado se ajuste a una marca en lugar de caer en un aspecto genérico por defecto."}, {"label": "Añade verificación en el navegador", "body": "Haz que Devin renderice en un navegador real y compruebe su resultado en los distintos breakpoints, para que verifique contra el diseño en lugar de limitarse a confirmar que el build pasa."}]}]}, {"id": "screenshot-workflow", "heading": "El flujo de captura de pantalla a interfaz", "blocks": [{"kind": "p", "text": "El bucle de diseño de mayor rendimiento con Devin consiste en convertir una imagen de referencia en una interfaz funcional y adaptable e iterar hasta que coincida, dejando que el agente autónomo construya, ejecute y compare su resultado con la referencia."}, {"kind": "ol", "items": ["Parte de las referencias visuales más claras que tengas, e incluye varios estados (escritorio y móvil, hover, vacío, cargando), no solo una imagen principal.", "Sé específico en el prompt y da criterios de finalización explícitos; los prompts vagos producen interfaces genéricas incluso con un agente potente.", "Mantén tu sistema de diseño y tus convenciones en las reglas de tu proyecto, e indícale a Devin dónde viven los tokens y los primitivos canónicos.", "Levanta un servidor de desarrollo y haz que Devin renderice en un navegador real, redimensionando a los distintos breakpoints para comprobar el resultado.", "Itera haciendo que Devin compare su implementación con las referencias —no solo que confirme que compila— y traspasa a la nube las pasadas más largas."]}, {"kind": "p", "text": "Da a Devin las referencias y restricciones concretas, con una definición clara de «hecho»:"}, {"kind": "code", "lang": "bash", "code": "devin\n# in the prompt:\n> Implement the attached reference (desktop + mobile) in\n  React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the\n  references across breakpoints. Done = pixel-close on both\n  desktop and mobile with no console errors."}, {"kind": "p", "text": "Mantén los prompts enfocados, confirma las buenas iteraciones y revierte las malas (avisando a Devin cuando reviertas), para que cada pasada parta de una base limpia."}]}, {"id": "extend", "heading": "Reglas de proyecto, herramientas y traspaso a la nube", "blocks": [{"kind": "p", "text": "Tres puntos de extensión hacen que Devin for Terminal sea práctico para un trabajo de diseño sostenido, y los tres encajan limpiamente en un flujo de diseño abierto."}, {"kind": "steps", "items": [{"label": "Reglas y contexto del proyecto", "body": "Mantén tus convenciones de diseño, tokens y listas de revisión en las reglas y la documentación de tu proyecto, para que el agente las lea en cada ejecución y trabaje contra tu marca."}, {"label": "Código base, herramientas y entorno", "body": "Devin se ejecuta como un agente local con acceso a tu código base, tus herramientas y tu entorno: puede levantar un servidor de desarrollo, ejecutar el build y verificar el resultado sin salir de la terminal."}, {"label": "Traspaso a la nube en entorno aislado", "body": "Traspasa una sesión a un agente en la nube en su propio entorno aislado para ejecutar de forma asíncrona construcciones más largas, pruebas y la creación de PR, y luego vuelve a un pull request terminado."}]}, {"kind": "p", "text": "Son exactamente el tipo de capacidades portátiles y con forma de agente que Open Design está diseñado para orquestar, en lugar de recrearlas en cada proyecto."}]}, {"id": "vs", "heading": "Devin frente a Codex, Claude Code, Cursor y Gemini CLI para diseño", "blocks": [{"kind": "p", "text": "No hay un único ganador para el trabajo de diseño: cada agente tiene una fortaleza distinta, y los equipos con experiencia los combinan. Un resumen honesto:"}, {"kind": "table", "columns": ["Agente", "Fortaleza de diseño", "Ideal para"], "rows": [["Devin", "Ingeniero de software totalmente autónomo; planifica y ejecuta construcciones de varios pasos y traspasa a un agente en la nube en entorno aislado", "Delegar construcciones de frontend de principio a fin que siguen ejecutándose después de que te apartes"], ["Codex", "Gran acabado visual con una skill de frontend; builds asíncronos en entorno aislado", "Builds asíncronos delegados y reglas portátiles en AGENTS.md"], ["Claude Code", "Decisiones de diseño concretas (hex, espaciado, tipografía) y UX consciente del código base", "Razonamiento de frontend y refactorizaciones de contexto amplio"], ["Cursor", "Bucle visual de construir y ver con vista previa en vivo y ediciones en línea", "Trabajo de interfaz iterativo y supervisado dentro de un IDE"], ["Gemini CLI", "Gran comprensión multimodal de imágenes y un contexto de 1M de tokens; de código abierto con un plan gratuito", "Trabajo con muchas capturas de pantalla y mantener todo un sistema de diseño en contexto"]]}, {"kind": "p", "text": "El veredicto recurrente de la comunidad es que el criterio estético proviene de las personas: todos ellos tienden por defecto a una estética genérica sin skills, referencias ni restricciones. Ese es el verdadero problema a resolver, y tiene forma de herramienta de diseño, no de modelo."}]}, {"id": "pitfalls", "heading": "Errores comunes y cómo evitar el aspecto de «basura de IA»", "blocks": [{"kind": "p", "text": "La queja más común sobre el diseño generado por IA es que luce genérico: degradados suaves, paneles flotantes, esquinas redondeadas exageradas, sombras dramáticas, un aire de Inter y morado que «grita que esto lo hizo una IA». Otros problemas reportados incluyen maquetaciones móviles rotas e instrucciones que se filtran en el texto de la interfaz. Ninguno de estos es exclusivo de Devin; son lo que ocurre cuando cualquier agente se ejecuta sin un contexto de diseño curado."}, {"kind": "steps", "items": [{"label": "Añade una skill estética", "body": "Una skill de diseño curada obliga al agente a comprometerse con una dirección real en lugar del aspecto por defecto."}, {"label": "Verifica en un navegador real", "body": "Haz que Devin renderice y se autoverifique en los distintos breakpoints para que las maquetaciones no se rompan en silencio en el móvil."}, {"label": "Aporta tokens y referencias", "body": "Los tokens de diseño reales y las capturas de referencia son la mayor palanca sobre la calidad del resultado."}, {"label": "Codifica reglas en el contexto de proyecto", "body": "Coloca reglas del estilo «sin tarjetas hero, máximo dos tipografías, jerarquía con la marca primero» donde el agente las lea en cada ejecución, con criterios de finalización explícitos."}]}, {"kind": "p", "text": "Fíjate en que toda mitigación consiste en dar al agente un contexto de diseño curado. Mantener ese contexto a mano, proyecto a proyecto, es el trabajo tedioso que Open Design elimina."}]}, {"id": "open-design", "heading": "Diseñar con Devin dentro de Open Design", "blocks": [{"kind": "p", "text": "Open Design es la capa de diseño de código abierto que el flujo de trabajo anterior reclama una y otra vez. Trata a Devin for Terminal como un adaptador de primera clase y lo envuelve en una biblioteca curada de skills y sistemas de diseño, una canalización de renderizado estructurada y una interfaz de escritorio local, para que el contexto de diseño que hace bueno a Devin esté presente desde la primera ejecución, no ensamblado a mano cada vez. Open Design es de código abierto y local-first, lo que hace de esta combinación un encaje natural para un agente que ya ejecutas en tu terminal."}, {"kind": "ol", "items": ["Instala Open Design y selecciona Devin for Terminal como tu agente.", "Autentícate con tu cuenta de Devin (Cognition): las credenciales las usa directamente tu agente y nunca se enrutan a través de nosotros.", "Elige un sistema de diseño y una skill, y luego genera presentaciones, prototipos y páginas de aterrizaje con un criterio estético consistente.", "Cada artefacto y archivo DESIGN.md vive en tu propio repositorio, no en una nube alojada."]}, {"kind": "p", "text": "El mismo agente Devin, la misma cuenta, más un flujo de diseño real, portátil y de código abierto a su alrededor. Open Design es local-first y Apache-2.0, así que nada de tu trabajo ni de tus credenciales sale de tu máquina a través de nosotros."}]}], "faqTitle": "Preguntas frecuentes", "faq": [{"name": "¿De verdad puede Devin for Terminal hacer trabajo de diseño?", "text": "Sí: con una skill estética, un sistema de diseño e imágenes de referencia reales en contexto, Devin produce interfaces adaptables de calidad de producción, y como agente autónomo puede construir, ejecutar y verificar el resultado contra tus referencias. Sin ese contexto tiende a caer en un aspecto genérico, que es la brecha que Open Design llena."}, {"name": "¿Cómo inicio sesión en Devin?", "text": "Devin se basa en cuenta: inicias sesión con una cuenta de Devin (Cognition) en lugar de traer tu propia clave de modelo. Instala Devin for Terminal, ejecútalo en tu proyecto y autentícate en la primera ejecución. Open Design nunca enruta tus credenciales: tu agente las usa directamente."}, {"name": "¿Qué hace que Devin sea bueno para el diseño en concreto?", "text": "Es un ingeniero de software totalmente autónomo: planifica y ejecuta construcciones de frontend de varios pasos de principio a fin, y puede traspasar una sesión a un agente en la nube en entorno aislado que sigue trabajando después de que te apartes. El criterio estético sigue viniendo del sistema de diseño, la skill y las referencias que tú aportes."}, {"name": "¿Devin o Claude Code para diseño de frontend?", "text": "Ambos son potentes. Claude Code es conocido por decisiones de diseño concretas y conscientes del código base; la ventaja de Devin es la ejecución totalmente autónoma y de principio a fin con un traspaso a la nube en entorno aislado. Muchos equipos usan los dos: Open Design te permite cambiar de agente sin cambiar tu flujo de diseño."}, {"name": "¿Devin se ejecuta en un entorno aislado?", "text": "Devin for Terminal se ejecuta localmente con acceso a tu código base y tu entorno, y puede traspasar una sesión a un agente en la nube que se ejecuta en su propio entorno aislado, útil para construcciones más largas, pruebas y creación de PR que continúan de forma asíncrona."}, {"name": "¿Está Open Design afiliado a Cognition?", "text": "No. Devin for Terminal es un producto de Cognition; Open Design es un proyecto de código abierto independiente que lo admite como adaptador de primera clase. Devin es una marca registrada de Cognition."}, {"name": "¿Están seguros mis archivos y credenciales?", "text": "Sí: Open Design es local-first y Apache-2.0. Tus archivos, artefactos y DESIGN.md permanecen en tu propio repositorio, y tus credenciales de Devin las usa directamente tu agente, sin pasar nunca por los servidores de Open Design."}], "ctaTitle": "Diseña con Devin, a la manera abierta.", "ctaBody": "Inicia sesión con tu cuenta de Devin, mantén cada archivo en local y obtén una biblioteca de diseño curada en torno al agente autónomo que ya usas.", "ctaActions": [{"label": "Usa Devin dentro de Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dale una estrella en GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Descarga la app de escritorio", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Ver todos los agentes compatibles"},
      },
      'pi': {
        ...en['pi']!,
        title: "Pi para diseño — Open Design",
        description: "Cómo se usa Pi, el agente de programación de terminal multiproveedor y de código abierto, para diseño de interfaces y web —su enrutamiento a cualquier modelo, sus claves de proveedor BYOK, sus Skills y Extensions— y cómo Open Design convierte a Pi en un agente de diseño local-first y de código abierto.",
        breadcrumb: "Pi",
        label: "Agente · Pi",
        heading: "Pi para diseño.",
        lead: "Pi es un agente de programación de terminal de código abierto que enruta a cualquier modelo —Anthropic, OpenAI, Google y más de 20 proveedores— con tus propias claves de API. Ese núcleo agnóstico al proveedor lo convierte en una herramienta de diseño flexible: elige el modelo que mejor lea capturas de pantalla hoy, cámbialo mañana, conserva tu flujo de trabajo. Open Design lo integra en un flujo de diseño de código abierto: tus claves de proveedor, tus archivos, local-first.",
        rich: {"heroCtaLead": "Open Design convierte a Pi en un agente de diseño local-first y de código abierto: tus propias claves de API de proveedor, tus archivos y una biblioteca curada de skills y sistemas de diseño a su alrededor.", "heroCtaActions": [{"label": "Usa Pi dentro de Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dale una estrella en GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Descarga la app de escritorio", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Pi es un agente de programación con IA de código abierto (MIT) para la terminal. Lo que lo hace interesante específicamente para el diseño es que es agnóstico al proveedor: normaliza entre Anthropic, OpenAI, Google y más de 20 proveedores tras una única interfaz, así que te autenticas con tus propias claves de API (BYOK) y eliges el modelo adecuado para la tarea, y puedes cambiar de modelo a mitad de sesión sin volver a aprender la herramienta. Combinado con las referencias, convenciones y un bucle de verificación adecuados, construye interfaces reales y adaptables. Esta es una guía práctica y de principio a fin para usar Pi en interfaces, frontend y trabajo con sistemas de diseño, y para integrarlo en un flujo de diseño estructurado con Open Design.", "Cubre qué es realmente Pi, por qué un agente multiproveedor con BYOK encaja con el diseño, cómo configurarlo desde cero, el bucle de captura de pantalla a interfaz, cómo lo extienden las Skills y las Extensions, cómo se compara con Codex, Claude Code, Cursor y Gemini CLI, los errores que hacen que el resultado de la IA luzca genérico, y cómo Open Design cierra la brecha como una capa de diseño abierta y local-first, una combinación natural, ya que ambos son de código abierto y se ejecutan en tu propia máquina."], "heroImage": {"src": "/agents/pi-design/pi-design-hero.webp", "alt": "Bucle de retroalimentación de diseño de Pi: un agente de terminal leyendo una imagen de referencia, un navegador renderizando la interfaz y un espacio de trabajo, con una flecha de retroalimentación que regresa", "caption": "El bucle central: Pi lee tus referencias en la terminal, construye y verifica la interfaz en un navegador real e itera contra ellas, con el proveedor al que lo apuntes."}, "tocLabel": "En esta página", "toc": [{"id": "what-is-pi", "label": "Qué es realmente Pi"}, {"id": "why-design", "label": "Por qué un agente multiproveedor con BYOK encaja con el diseño"}, {"id": "setup", "label": "Configura Pi para diseño (desde cero)"}, {"id": "screenshot-workflow", "label": "El flujo de captura de pantalla a interfaz"}, {"id": "extend", "label": "Skills, Extensions y temas"}, {"id": "vs", "label": "Pi frente a Codex, Claude Code, Cursor y Gemini CLI"}, {"id": "pitfalls", "label": "Errores comunes y el aspecto de «basura de IA»"}, {"id": "open-design", "label": "Diseñar con Pi en Open Design"}, {"id": "faq", "label": "Preguntas frecuentes"}], "sections": [{"id": "what-is-pi", "heading": "Qué es realmente Pi", "blocks": [{"kind": "p", "text": "Pi es un agente de programación con IA de código abierto (MIT) para la terminal, parte del kit de herramientas pi de earendil-works. Lee tu repositorio, edita archivos y ejecuta comandos de shell, planificando y verificando el trabajo a partir de tareas en lenguaje natural en lugar de limitarse a completar líneas. Su núcleo es deliberadamente pequeño: cuatro herramientas por defecto —read, write, edit y bash— además de grep, find y ls integrados."}, {"kind": "p", "text": "Para el trabajo de diseño, la propiedad que destaca es que Pi es agnóstico al proveedor. Normaliza entre Anthropic, OpenAI, Google y muchos otros proveedores tras una API unificada, así que traes tus propias claves y eliges el modelo por tarea —por ejemplo, un modelo multimodal potente para leer capturas de referencia— y cambias con /model o Ctrl+L a mitad de sesión sin alterar tu flujo de trabajo."}, {"kind": "steps", "items": [{"label": "Cualquier modelo, tus claves", "body": "Pi enruta a más de 20 proveedores, incluidos Anthropic y OpenAI. Te autenticas con tus propias claves de API (BYOK), o inicias sesión en una suscripción de Claude Pro/Max, ChatGPT Plus/Pro o GitHub Copilot con /login."}, {"label": "Skills + Extensions", "body": "Pi carga Skills (paquetes de capacidades en Markdown que siguen el estándar Agent Skills) y Extensions en TypeScript: el lugar natural para codificar tus convenciones de diseño y añadir herramientas personalizadas."}, {"label": "Sesiones ramificadas", "body": "Las sesiones se almacenan como árboles JSONL, así que puedes ramificar una exploración y navegar por el historial en un único archivo sin perder las pasadas anteriores."}]}, {"kind": "ul", "items": ["Fabricante: earendil-works (proyecto de la comunidad de código abierto)", "Credencial: tu propia clave de API de proveedor (BYOK: Anthropic, OpenAI, Google, etc.) o un inicio de sesión por suscripción mediante /login; almacenada localmente en ~/.pi/agent/auth.json (0600)", "Licencia: MIT, código abierto"]}]}, {"id": "why-design", "heading": "Por qué un agente multiproveedor con BYOK encaja con el diseño", "blocks": [{"kind": "p", "text": "La ventaja de Pi para el diseño es la flexibilidad, no un único modelo integrado, pero, como ocurre con todo agente, el criterio estético hay que aportarlo igualmente."}, {"kind": "steps", "items": [{"label": "Elige el modelo adecuado por tarea", "body": "Como Pi enruta a cualquier proveedor, puedes recurrir a un modelo multimodal potente para leer capturas de referencia y luego cambiar a otro para la refactorización, sin salir del agente."}, {"label": "Tus claves, sin ataduras", "body": "BYOK significa que no quedas atado a los precios ni a los límites de contexto de un único fabricante; elige el modelo cuyas fortalezas encajen con el trabajo de diseño que tienes delante."}, {"label": "Convenciones en Skills", "body": "Una Skill (más una fuente MCP como un servidor de Figma) apunta al agente hacia tus tokens, componentes y especificaciones reales, para que trabaje contra una marca en lugar de un aspecto por defecto."}]}, {"kind": "image", "src": "/agents/pi-design/pi-design-taste-triangle.webp", "alt": "Diagrama que muestra cómo un sistema de diseño, una skill y una imagen de referencia convergen en un buen resultado de diseño", "caption": "El criterio estético proviene de tres insumos que tú aportas: un sistema de diseño, una skill e imágenes de referencia reales."}, {"kind": "p", "text": "La lección es la misma que enseña todo agente: Pi no tiene criterio estético por defecto, y ninguna elección de modelo lo aporta. Produce buen diseño cuando le das restricciones: un sistema de diseño, una skill estética y referencias concretas. Open Design empaqueta exactamente esos insumos, por lo que ambos encajan (más abajo se explica)."}]}, {"id": "setup", "heading": "Configura Pi para el trabajo de diseño, desde cero", "blocks": [{"kind": "p", "text": "Este es el recorrido completo, desde una máquina limpia hasta un Pi capaz de construir y verificar interfaces."}, {"kind": "code", "lang": "bash", "code": "# 1. Install the Pi coding agent CLI (Node)\nnpm install -g --ignore-scripts @earendil-works/pi-coding-agent\n\n# 2. Authenticate with your own provider key (BYOK)\nexport ANTHROPIC_API_KEY=sk-ant-...   # or OPENAI_API_KEY=sk-...\n#    (or run /login inside Pi for a Claude / ChatGPT / Copilot subscription)\n\n# 3. Start it in your project\ncd your-project\npi\n\n# 4. Switch models any time with /model or Ctrl+L"}, {"kind": "image", "src": "/agents/pi-design/pi-design-setup-flow.webp", "alt": "Flujo de configuración en cinco pasos: instalar, autenticarse, codificar reglas de diseño, añadir una skill, verificar", "caption": "La secuencia de configuración: instalar → autenticarse (BYOK) → codificar reglas de diseño en una Skill → elegir un modelo → habilitar la verificación en el navegador."}, {"kind": "steps", "items": [{"label": "Codifica tus reglas de diseño", "body": "Coloca tus tokens, primitivos y convenciones en una Skill y apunta Pi hacia ellos, para que el resultado se ajuste a una marca en lugar de caer en un aspecto genérico por defecto."}, {"label": "Añade verificación en el navegador", "body": "Conecta un Playwright o un MCP de navegador para que Pi renderice en un navegador real y compruebe su resultado en los distintos breakpoints, en lugar de limitarse a confirmar que el build pasa."}]}]}, {"id": "screenshot-workflow", "heading": "El flujo de captura de pantalla a interfaz", "blocks": [{"kind": "p", "text": "El bucle de diseño de mayor rendimiento con Pi consiste en convertir una imagen de referencia en una interfaz funcional y adaptable e iterar hasta que coincida, apoyándose en un modelo multimodal para comparar el resultado con la referencia. Como Pi es agnóstico al proveedor, apúntalo al modelo que mejor lea imágenes para esta pasada."}, {"kind": "ol", "items": ["Parte de las referencias visuales más claras que tengas, e incluye varios estados (escritorio y móvil, hover, vacío, cargando), no solo una imagen principal.", "Elige un modelo multimodal potente para la pasada con /model, ya que la comprensión de imágenes es lo que determina la calidad de la captura a interfaz.", "Sé específico en el prompt; los prompts vagos producen interfaces genéricas incluso con un modelo potente.", "Mantén tu sistema de diseño y tus convenciones en una Skill, e indícale a Pi dónde viven los tokens y los primitivos canónicos.", "Levanta un servidor de desarrollo y haz que Pi renderice en un navegador real, redimensionando a los distintos breakpoints, y luego itera comparando su implementación con las capturas de pantalla, no solo confirmando que compila."]}, {"kind": "p", "text": "Da al agente las referencias y restricciones concretas desde el principio:"}, {"kind": "code", "lang": "bash", "code": "pi\n# in the prompt:\n> Implement reference-desktop.png and reference-mobile.png in\n  React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens (see the Skill).\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the references\n  across breakpoints."}, {"kind": "p", "text": "Mantén los prompts breves y enfocados, confirma las buenas iteraciones y revierte las malas (avisando a Pi cuando reviertas), para que cada pasada parta de una base limpia. Las sesiones JSONL ramificadas de Pi también te permiten explorar una alternativa sin perder el hilo original."}]}, {"id": "extend", "heading": "Skills, Extensions y temas", "blocks": [{"kind": "p", "text": "Pi se autoextiende en tiempo de ejecución mediante unas pocas capas, y estas encajan limpiamente en un flujo de diseño abierto."}, {"kind": "steps", "items": [{"label": "Skills", "body": "Paquetes de capacidades en Markdown que siguen el estándar Agent Skills: el hogar duradero y portátil de tus convenciones de diseño, tokens y listas de revisión. La misma Skill funciona en distintos agentes compatibles, no solo en Pi."}, {"label": "Extensions y plantillas de prompt", "body": "Las Extensions en TypeScript añaden herramientas, comandos e interfaz personalizados; las plantillas de prompt reutilizables se ejecutan mediante /nombre. Ambas te permiten programar el bucle de verificación sin salir de la terminal."}, {"label": "MCP y temas", "body": "Pi se conecta a servidores MCP para incorporar contexto de diseño externo (lo más relevante, un servidor MCP de Figma), y los temas se recargan en caliente para que la interfaz de la terminal se mantenga legible mientras trabajas."}]}, {"kind": "p", "text": "Son capacidades portátiles —Skills y MCP en especial— exactamente el tipo de cosa que Open Design está diseñado para orquestar, en lugar de recrearla en cada proyecto."}]}, {"id": "vs", "heading": "Pi frente a Codex, Claude Code, Cursor y Gemini CLI para diseño", "blocks": [{"kind": "p", "text": "No hay un único ganador para el trabajo de diseño: cada agente tiene una fortaleza distinta, y los equipos con experiencia los combinan. Un resumen honesto:"}, {"kind": "table", "columns": ["Agente", "Fortaleza de diseño", "Ideal para"], "rows": [["Pi", "Agnóstico al proveedor y BYOK: enruta a cualquier modelo (Anthropic, OpenAI, Google…) y cambia a mitad de sesión; MIT, autoextensible", "Elegir el mejor modelo por tarea sin quedar atado a un fabricante"], ["Codex", "Gran acabado visual con una skill de frontend; builds asíncronos en entorno aislado", "Builds asíncronos delegados y reglas portátiles en AGENTS.md"], ["Claude Code", "Decisiones de diseño concretas (hex, espaciado, tipografía) y UX consciente del código base", "Razonamiento de frontend y refactorizaciones de contexto amplio"], ["Cursor", "Bucle visual de construir y ver con vista previa en vivo y ediciones en línea", "Trabajo de interfaz iterativo y supervisado dentro de un IDE"], ["Gemini CLI", "Gran comprensión multimodal de imágenes y un contexto de 1M de tokens; plan gratuito", "Trabajo con muchas capturas de pantalla y mantener todo un sistema de diseño en contexto"]]}, {"kind": "p", "text": "El enfoque de Pi es ortogonal al de los demás: es el agente que te permite usar cualquiera de esos modelos subyacentes con tus propias claves. El veredicto recurrente de la comunidad sigue vigente: el criterio estético proviene de las personas; todos ellos tienden por defecto a una estética genérica sin skills, referencias ni restricciones. Ese es el verdadero problema a resolver, y tiene forma de herramienta de diseño, no de modelo."}]}, {"id": "pitfalls", "heading": "Errores comunes y cómo evitar el aspecto de «basura de IA»", "blocks": [{"kind": "p", "text": "La queja más común sobre el diseño generado por IA es que luce genérico: degradados suaves, paneles flotantes, esquinas redondeadas exageradas, sombras dramáticas, un aire de Inter y morado que «grita que esto lo hizo una IA». Otros problemas reportados incluyen maquetaciones móviles rotas e instrucciones que se filtran en el texto de la interfaz. Ninguno de estos es exclusivo de Pi ni de un único modelo; son lo que ocurre cuando cualquier agente se ejecuta sin un contexto de diseño curado."}, {"kind": "steps", "items": [{"label": "Añade una skill estética", "body": "Una skill de diseño curada obliga al agente a comprometerse con una dirección real en lugar del aspecto por defecto, y como es una Skill portátil, te acompaña entre distintos modelos."}, {"label": "Verifica en un navegador real", "body": "Elige un modelo multimodal y haz que Pi renderice y se autoverifique en los distintos breakpoints para que las maquetaciones no se rompan en silencio en el móvil."}, {"label": "Aporta tokens y referencias", "body": "Los tokens de diseño reales y las capturas de referencia son la mayor palanca sobre la calidad del resultado."}, {"label": "Codifica reglas donde Pi las lea", "body": "Coloca reglas del estilo «sin tarjetas hero, máximo dos tipografías, jerarquía con la marca primero» en una Skill que el agente cargue en cada ejecución."}]}, {"kind": "p", "text": "Fíjate en que toda mitigación consiste en dar al agente un contexto de diseño curado, independientemente del proveedor al que enrutes. Mantener ese contexto a mano, proyecto a proyecto, es el trabajo tedioso que Open Design elimina."}]}, {"id": "open-design", "heading": "Diseñar con Pi dentro de Open Design", "blocks": [{"kind": "p", "text": "Open Design es la capa de diseño de código abierto que el flujo de trabajo anterior reclama una y otra vez. Trata a Pi como un adaptador de primera clase y lo envuelve en una biblioteca curada de skills y sistemas de diseño, una canalización de renderizado estructurada y una interfaz de escritorio local, para que el contexto de diseño que hace bueno a Pi esté presente desde la primera ejecución, no ensamblado a mano cada vez. Ambos son de código abierto y local-first, lo que hace de esta combinación un encaje natural."}, {"kind": "ol", "items": ["Instala Open Design y selecciona Pi como tu agente.", "Autentícate con tu propia clave de API de proveedor (BYOK) o un inicio de sesión por suscripción: las credenciales permanecen en tu máquina en ~/.pi/agent/auth.json y nunca se enrutan a través de nosotros.", "Elige un sistema de diseño y una skill, y luego genera presentaciones, prototipos y páginas de aterrizaje con un criterio estético consistente.", "Cada artefacto y archivo DESIGN.md vive en tu propio repositorio, no en una nube alojada."]}, {"kind": "p", "text": "El mismo agente Pi, las mismas claves, la misma libertad para cambiar de modelo, más un flujo de diseño real, portátil y de código abierto a su alrededor. Es local-first y MIT, así que nada de tu trabajo ni de tus credenciales sale de tu máquina."}]}], "faqTitle": "Preguntas frecuentes", "faq": [{"name": "¿De verdad puede Pi hacer trabajo de diseño?", "text": "Sí: con una skill estética, un sistema de diseño e imágenes de referencia reales en contexto, Pi produce interfaces adaptables de calidad de producción, y puedes enrutarlo a un modelo multimodal potente para verificar el resultado contra las referencias. Sin ese contexto tiende a caer en un aspecto genérico, que es la brecha que Open Design llena."}, {"name": "¿Necesito pagar para diseñar con Pi?", "text": "Pi en sí es gratuito y de código abierto (MIT). Solo pagas por el modelo subyacente: trae tu propia clave de API de proveedor (BYOK) o usa una suscripción de Claude Pro/Max, ChatGPT Plus/Pro o GitHub Copilot mediante /login. En cualquier caso, Open Design nunca enruta tus credenciales."}, {"name": "¿Qué hace que Pi sea bueno para el diseño en concreto?", "text": "Es agnóstico al proveedor: traes tus propias claves y enrutas a cualquiera de los más de 20 proveedores, eligiendo el modelo cuyas fortalezas encajen con la tarea y cambiando a mitad de sesión. Pero el criterio estético sigue viniendo del sistema de diseño, la skill y las referencias que tú aportes, no del modelo."}, {"name": "¿Qué modelo debería usar con Pi para diseño de frontend?", "text": "Pi enruta a muchos proveedores, así que elige por tarea: un modelo multimodal potente lee bien las capturas de referencia, mientras que otros pueden encajar para la refactorización. La ventaja de Pi es que puedes cambiar sin alterar tu flujo de trabajo. Open Design te permite conservar el mismo contexto de diseño con cualquier modelo que elijas."}, {"name": "¿Cómo conecto Pi a Figma?", "text": "Pi admite servidores MCP, así que puedes añadir un servidor MCP de Figma y extraer contexto de diseño real —componentes, variables, datos de maquetación— para que el código generado coincida con la fuente en lugar de aproximarla."}, {"name": "¿Está Open Design afiliado a Pi?", "text": "No. Pi es un proyecto de código abierto independiente de earendil-works; Open Design es un proyecto de código abierto independiente y aparte que admite a Pi como adaptador de primera clase."}, {"name": "¿Están seguros mis archivos y credenciales?", "text": "Sí: Open Design es local-first y de código abierto. Tus archivos, artefactos y DESIGN.md permanecen en tu propio repositorio, y tus claves de proveedor las usa directamente Pi (almacenadas localmente en ~/.pi/agent/auth.json), sin pasar nunca por los servidores de Open Design."}], "ctaTitle": "Diseña con Pi, a la manera abierta.", "ctaBody": "Trae tus propias claves de proveedor, enruta a cualquier modelo, mantén cada archivo en local y obtén una biblioteca de diseño curada en torno al agente que ya usas.", "ctaActions": [{"label": "Usa Pi dentro de Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dale una estrella en GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Descarga la app de escritorio", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Ver todos los agentes compatibles"},
      },
      'kiro': {
        ...en['kiro']!,
        title: "Kiro CLI para diseño — Open Design",
        description: "Cómo se usa el Kiro CLI de Amazon para diseño de interfaces y web —su desarrollo guiado por especificaciones, sus agent hooks, sus archivos de orientación (steering) y MCP— y cómo Open Design convierte a Kiro CLI en un agente de diseño local-first y de código abierto.",
        breadcrumb: "Kiro CLI",
        label: "Agente · Kiro CLI",
        heading: "Kiro CLI para diseño.",
        lead: "Kiro CLI es el agente de terminal de Amazon para el desarrollo guiado por especificaciones: convierte un prompt en una especificación de requisitos, un documento de diseño y una lista de tareas antes de escribir código. Esa estructura es justo lo que necesita el trabajo de diseño: primero la intención, luego la construcción. Open Design lo integra en un flujo de diseño de código abierto: tu Builder ID o inicio de sesión, tus archivos, local-first.",
        rich: {"heroCtaLead": "Open Design convierte a Kiro CLI en un agente de diseño local-first y de código abierto: tu AWS Builder ID o inicio de sesión, tus archivos y una biblioteca curada de skills y sistemas de diseño a su alrededor.", "heroCtaActions": [{"label": "Usa Kiro CLI dentro de Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dale una estrella en GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Descarga la app de escritorio", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Kiro CLI es el agente de terminal de Amazon para el desarrollo guiado por especificaciones. Lo que lo distingue es el flujo de trabajo: en lugar de saltar directamente de un prompt al código, Kiro formaliza los requisitos en una especificación, produce un documento de diseño y una lista de tareas secuenciada, y solo entonces implementa, manteniendo la construcción responsable ante la intención declarada. También incluye agent hooks que se disparan ante eventos como guardar un archivo, archivos de orientación (steering) que llevan tus estándares y convenciones a cada ejecución, y soporte del Model Context Protocol para herramientas externas. Kiro está en vista previa, disponible como IDE, CLI e interfaz web, y puedes empezar gratis. Esta es una guía práctica y de principio a fin para usar Kiro CLI en interfaces, frontend y trabajo con sistemas de diseño, y para integrarlo en un flujo de diseño estructurado con Open Design.", "Cubre qué es realmente Kiro CLI, por qué un flujo guiado por especificaciones encaja con el diseño, cómo configurarlo desde cero, el bucle de captura de pantalla a interfaz, cómo lo extienden los archivos de orientación, los hooks y MCP, cómo se compara con Codex, Claude Code, Cursor y Gemini CLI, los errores que hacen que el resultado de la IA luzca genérico, y cómo Open Design cierra la brecha como una capa de diseño abierta y local-first a su alrededor."], "heroImage": {"src": "/agents/kiro-design/kiro-design-hero.webp", "alt": "Bucle de retroalimentación de diseño de Kiro CLI: un agente de terminal convirtiendo una especificación en un diseño, un navegador renderizando la interfaz y un espacio de trabajo, con una flecha de retroalimentación que regresa", "caption": "El bucle central: Kiro CLI convierte tu intención en una especificación y una lista de tareas en la terminal, construye y verifica la interfaz en un navegador real e itera contra tus referencias."}, "tocLabel": "En esta página", "toc": [{"id": "what-is-kiro", "label": "Qué es realmente Kiro CLI"}, {"id": "why-design", "label": "Por qué el desarrollo guiado por especificaciones encaja con el diseño"}, {"id": "setup", "label": "Configura Kiro CLI para diseño (desde cero)"}, {"id": "screenshot-workflow", "label": "El flujo de captura de pantalla a interfaz"}, {"id": "extend", "label": "Especificaciones, orientación (steering), hooks y MCP"}, {"id": "vs", "label": "Kiro frente a Codex, Claude Code, Cursor y Gemini CLI"}, {"id": "pitfalls", "label": "Errores comunes y el aspecto de «basura de IA»"}, {"id": "open-design", "label": "Diseñar con Kiro CLI en Open Design"}, {"id": "faq", "label": "Preguntas frecuentes"}], "sections": [{"id": "what-is-kiro", "heading": "Qué es realmente Kiro CLI", "blocks": [{"kind": "p", "text": "Kiro es una IA agéntica de Amazon que se distribuye como IDE, interfaz de línea de comandos e interfaz web, construida para llevarte del prototipo a la producción con desarrollo guiado por especificaciones. El Kiro CLI lleva ese agente a tu terminal: puedes iniciar una sesión de chat interactiva, crear y gestionar agentes, y ejecutar servidores del Model Context Protocol, todo desde la línea de comandos. Kiro está en vista previa."}, {"kind": "p", "text": "Para el trabajo de diseño, la propiedad definitoria es el flujo de trabajo. En lugar de convertir un prompt directamente en código, Kiro primero escribe una especificación —requisitos, un documento de diseño y una lista de tareas secuenciada— e implementa contra ella. Eso hace que el plan del agente sea visible y revisable antes de construir cualquier interfaz, lo que encaja limpiamente con cómo deben tomarse las decisiones de diseño: primero la intención, luego la ejecución."}, {"kind": "steps", "items": [{"label": "Especificaciones", "body": "Kiro convierte un prompt en una especificación estructurada —requisitos, un documento de diseño y tareas discretas— antes de escribir código, de modo que el plan es revisable de antemano."}, {"label": "Orientación (steering) + hooks", "body": "Los archivos de orientación (steering) llevan tus estándares, convenciones y herramientas preferidas a cada ejecución; los agent hooks se disparan ante eventos como guardar un archivo para ejecutar tareas en segundo plano de forma automática."}, {"label": "Empezar es gratis, listo para MCP", "body": "Inicia sesión con un Builder ID, Google, GitHub o tu organización y empieza gratis; Kiro CLI también gestiona servidores MCP para incorporar contexto externo."}]}, {"kind": "ul", "items": ["Fabricante: Amazon (AWS)", "Credencial: AWS Builder ID, Google, GitHub o AWS IAM Identity Center mediante kiro-cli login (no se requiere cuenta de AWS)", "Estado: en vista previa; disponible como IDE, CLI e interfaz web"]}]}, {"id": "why-design", "heading": "Por qué el desarrollo guiado por especificaciones encaja con el diseño", "blocks": [{"kind": "p", "text": "La ventaja de Kiro CLI para el diseño viene de su flujo de trabajo, pero, como ocurre con todo agente, el criterio estético hay que aportarlo igualmente."}, {"kind": "steps", "items": [{"label": "La intención antes que los píxeles", "body": "Como Kiro escribe primero una especificación y un documento de diseño, puedes corregir la maquetación, la jerarquía y el alcance en la etapa de planificación, antes de que el agente se haya comprometido con una implementación genérica."}, {"label": "La orientación (steering) lleva tu marca", "body": "Los archivos de orientación (steering) mantienen tus tokens, componentes y convenciones frente al agente en cada ejecución, para que el resultado trabaje contra una marca en lugar de un aspecto por defecto."}, {"label": "Los hooks hacen cumplir el bucle", "body": "Los agent hooks pueden ejecutar comprobaciones automáticamente al guardar, un lugar para incorporar un paso de verificación o revisión en lugar de depender de que el agente lo recuerde."}]}, {"kind": "image", "src": "/agents/kiro-design/kiro-design-taste-triangle.webp", "alt": "Diagrama que muestra cómo un sistema de diseño, una skill y una imagen de referencia convergen en un buen resultado de diseño", "caption": "El criterio estético proviene de tres insumos que tú aportas: un sistema de diseño, una skill e imágenes de referencia reales."}, {"kind": "p", "text": "La lección es la misma que enseña todo agente: Kiro CLI no tiene criterio estético por defecto. Una especificación mantiene honesta a una construcción, pero produce buen diseño solo cuando le das restricciones: un sistema de diseño, una skill estética y referencias concretas. Open Design empaqueta exactamente esos insumos, por lo que ambos encajan (más abajo se explica)."}]}, {"id": "setup", "heading": "Configura Kiro CLI para el trabajo de diseño, desde cero", "blocks": [{"kind": "p", "text": "Este es el recorrido completo, desde una máquina limpia hasta un Kiro CLI capaz de construir y verificar interfaces."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Kiro CLI (see kiro.dev/docs/cli for the macOS/Linux/Windows command)\n\n# 2. Authenticate — opens your browser to complete sign-in\nkiro-cli login   # choose Builder ID, Google, GitHub, or your organization\n\n# 3. Confirm you are signed in\nkiro-cli whoami\n\n# 4. Start an interactive session in your project\ncd your-project\nkiro-cli chat\n\n# 5. Wire MCP servers (optional, e.g. for design handoff)\nkiro-cli mcp add ..."}, {"kind": "image", "src": "/agents/kiro-design/kiro-design-setup-flow.webp", "alt": "Flujo de configuración en cinco pasos: instalar, autenticarse, añadir orientación (steering), añadir una skill, verificar", "caption": "La secuencia de configuración: instalar → autenticarse → añadir orientación (steering) y una especificación de diseño → añadir una skill → habilitar la verificación en el navegador."}, {"kind": "steps", "items": [{"label": "Codifica tus reglas de diseño", "body": "Coloca tus tokens, primitivos y convenciones en archivos de orientación (steering) para que el agente los lea en cada ejecución, y el resultado se ajuste a una marca en lugar de caer en un aspecto genérico por defecto."}, {"label": "Añade verificación en el navegador", "body": "Conecta un servidor de Playwright o un MCP de navegador para que Kiro renderice en un navegador real y compruebe su resultado en los distintos breakpoints, en lugar de limitarse a confirmar que el build pasa."}]}]}, {"id": "screenshot-workflow", "heading": "El flujo de captura de pantalla a interfaz", "blocks": [{"kind": "p", "text": "El bucle de diseño de mayor rendimiento con Kiro CLI consiste en convertir una imagen de referencia en una interfaz funcional y adaptable e iterar hasta que coincida, dejando que la especificación capture primero la intención y construyendo después contra ella."}, {"kind": "ol", "items": ["Parte de las referencias visuales más claras que tengas, e incluye varios estados (escritorio y móvil, hover, vacío, cargando), no solo una imagen principal.", "Deja que Kiro escriba una especificación y un documento de diseño a partir de tu prompt, y revisa el plan antes de que construya: aquí es donde detectas pronto los problemas de maquetación y alcance.", "Mantén tu sistema de diseño y tus convenciones en archivos de orientación (steering), e indícale a Kiro dónde viven los tokens y los primitivos canónicos.", "Levanta un servidor de desarrollo y haz que Kiro renderice en un navegador real, redimensionando a los distintos breakpoints para comprobar el resultado.", "Itera haciendo que Kiro compare su implementación con las referencias, no solo que confirme que compila."]}, {"kind": "p", "text": "Abre una sesión interactiva y da restricciones concretas desde el principio, para que la especificación que escriba refleje tu intención real:"}, {"kind": "code", "lang": "bash", "code": "kiro-cli chat\n# in the prompt:\n> Here are my references: reference-desktop.png and reference-mobile.png.\n  Write a spec, then implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens (see my steering files).\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the references\n  across breakpoints."}, {"kind": "p", "text": "Mantén las tareas breves y enfocadas, confirma las buenas iteraciones y revierte las malas (avisando a Kiro cuando reviertas), para que cada pasada parta de una base limpia."}]}, {"id": "extend", "heading": "Especificaciones, orientación (steering), hooks y MCP", "blocks": [{"kind": "p", "text": "Cuatro puntos de extensión hacen que Kiro CLI sea práctico para un trabajo de diseño sostenido, y los cuatro encajan limpiamente en un flujo de diseño abierto."}, {"kind": "steps", "items": [{"label": "Especificaciones", "body": "Requisitos, un documento de diseño y una lista de tareas secuenciada: el registro duradero de lo que se supone que debe ser una funcionalidad, revisable antes y durante la construcción."}, {"label": "Archivos de orientación (steering)", "body": "Añade contexto, estándares de código y flujos de trabajo o herramientas preferidas que el agente lee en cada ejecución: el hogar natural de tus convenciones de diseño y tokens."}, {"label": "Agent hooks", "body": "Automatizaciones que se disparan ante eventos como guardar un archivo, ejecutando tareas en segundo plano como comprobaciones o documentación: un lugar para hacer cumplir un paso de verificación de forma automática."}, {"label": "Servidores MCP", "body": "Kiro CLI gestiona servidores del Model Context Protocol, la forma portátil de incorporar contexto de diseño externo y herramientas que funcionan en distintos agentes, no solo en Kiro."}]}, {"kind": "p", "text": "Son capacidades portátiles y multiagente: exactamente el tipo de cosa que Open Design está diseñado para orquestar, en lugar de recrearla en cada proyecto."}]}, {"id": "vs", "heading": "Kiro frente a Codex, Claude Code, Cursor y Gemini CLI para diseño", "blocks": [{"kind": "p", "text": "No hay un único ganador para el trabajo de diseño: cada agente tiene una fortaleza distinta, y los equipos con experiencia los combinan. Un resumen honesto:"}, {"kind": "table", "columns": ["Agente", "Fortaleza de diseño", "Ideal para"], "rows": [["Kiro CLI", "Flujo guiado por especificaciones: requisitos, documento de diseño y lista de tareas antes del código; los archivos de orientación y los hooks mantienen las construcciones fieles a la marca", "Construcciones estructuradas y revisables donde la intención y el alcance quedan fijados antes de la implementación"], ["Codex", "Gran acabado visual con una skill de frontend; builds asíncronos en entorno aislado", "Builds asíncronos delegados y reglas portátiles en AGENTS.md"], ["Claude Code", "Decisiones de diseño concretas (hex, espaciado, tipografía) y UX consciente del código base", "Razonamiento de frontend y refactorizaciones de contexto amplio"], ["Cursor", "Bucle visual de construir y ver con vista previa en vivo y ediciones en línea", "Trabajo de interfaz iterativo y supervisado dentro de un IDE"], ["Gemini CLI", "Gran comprensión multimodal de imágenes y un contexto muy amplio; de código abierto con un plan gratuito", "Trabajo con muchas capturas de pantalla y mantener todo un sistema de diseño en contexto"]]}, {"kind": "p", "text": "El veredicto recurrente de la comunidad es que el criterio estético proviene de las personas: todos ellos tienden por defecto a una estética genérica sin skills, referencias ni restricciones. Ese es el verdadero problema a resolver, y tiene forma de herramienta de diseño, no de modelo."}]}, {"id": "pitfalls", "heading": "Errores comunes y cómo evitar el aspecto de «basura de IA»", "blocks": [{"kind": "p", "text": "La queja más común sobre el diseño generado por IA es que luce genérico: degradados suaves, paneles flotantes, esquinas redondeadas exageradas, sombras dramáticas, un aire de Inter y morado que «grita que esto lo hizo una IA». Otros problemas reportados incluyen maquetaciones móviles rotas e instrucciones que se filtran en el texto de la interfaz. Ninguno de estos es exclusivo de Kiro CLI; son lo que ocurre cuando cualquier agente se ejecuta sin un contexto de diseño curado: una especificación mantiene a una construcción centrada en la tarea, pero no aporta criterio estético."}, {"kind": "steps", "items": [{"label": "Añade una skill estética", "body": "Una skill de diseño curada obliga al agente a comprometerse con una dirección real en lugar del aspecto por defecto."}, {"label": "Verifica en un navegador real", "body": "Renderiza y autoverifica en los distintos breakpoints —conéctalo como un hook si puedes— para que las maquetaciones no se rompan en silencio en el móvil."}, {"label": "Aporta tokens y referencias", "body": "Los tokens de diseño reales y las capturas de referencia son la mayor palanca sobre la calidad del resultado."}, {"label": "Codifica reglas en archivos de orientación (steering)", "body": "Coloca reglas del estilo «sin tarjetas hero, máximo dos tipografías, jerarquía con la marca primero» donde el agente las lea en cada ejecución."}]}, {"kind": "p", "text": "Fíjate en que toda mitigación consiste en dar al agente un contexto de diseño curado. Mantener ese contexto a mano, proyecto a proyecto, es el trabajo tedioso que Open Design elimina."}]}, {"id": "open-design", "heading": "Diseñar con Kiro CLI dentro de Open Design", "blocks": [{"kind": "p", "text": "Open Design es la capa de diseño de código abierto que el flujo de trabajo anterior reclama una y otra vez. Trata a Kiro CLI como un adaptador de primera clase y lo envuelve en una biblioteca curada de skills y sistemas de diseño, una canalización de renderizado estructurada y una interfaz de escritorio local, para que el contexto de diseño que hace bueno a Kiro esté presente desde la primera ejecución, no ensamblado a mano cada vez. Open Design es local-first, lo que mantiene simple la combinación: tus archivos y tu inicio de sesión permanecen en tu máquina."}, {"kind": "ol", "items": ["Instala Open Design y selecciona Kiro CLI como tu agente.", "Autentícate con tu AWS Builder ID u otro inicio de sesión: las credenciales permanecen en tu máquina y nunca se enrutan a través de nosotros.", "Elige un sistema de diseño y una skill, y luego genera presentaciones, prototipos y páginas de aterrizaje con un criterio estético consistente.", "Cada artefacto y archivo DESIGN.md vive en tu propio repositorio, no en una nube alojada."]}, {"kind": "p", "text": "El mismo agente Kiro CLI, el mismo inicio de sesión, más un flujo de diseño real, portátil y de código abierto a su alrededor. Open Design es local-first y Apache-2.0, así que nada de tu trabajo ni de tus credenciales sale de tu máquina."}]}], "faqTitle": "Preguntas frecuentes", "faq": [{"name": "¿De verdad puede Kiro CLI hacer trabajo de diseño?", "text": "Sí: con una skill estética, un sistema de diseño e imágenes de referencia reales en contexto, Kiro CLI produce interfaces adaptables de calidad de producción, y su flujo guiado por especificaciones mantiene la construcción responsable ante la intención declarada. Sin ese contexto tiende a caer en un aspecto genérico, que es la brecha que Open Design llena."}, {"name": "¿Necesito una cuenta de AWS para usar Kiro CLI?", "text": "No: Kiro te permite iniciar sesión con un AWS Builder ID, Google, GitHub o tu organización (AWS IAM Identity Center), y no necesitas una cuenta de AWS para usarlo. Kiro está en vista previa y empezar es gratis. En cualquier caso, Open Design nunca enruta tus credenciales."}, {"name": "¿Qué hace que Kiro CLI sea bueno para el diseño en concreto?", "text": "Su flujo guiado por especificaciones: Kiro escribe requisitos, un documento de diseño y una lista de tareas antes de programar, así que corriges la maquetación y el alcance antes de que la construcción se comprometa. Los archivos de orientación (steering) llevan tus convenciones y los hooks pueden hacer cumplir comprobaciones, pero el criterio estético sigue viniendo del sistema de diseño, la skill y las referencias que tú aportes."}, {"name": "¿Kiro CLI o Claude Code para diseño de frontend?", "text": "Ambos son potentes. Claude Code es conocido por decisiones de diseño concretas y conscientes del código base; la ventaja de Kiro CLI es su flujo guiado por especificaciones y revisable, con orientación (steering) y hooks. Muchos equipos usan los dos: Open Design te permite cambiar de agente sin cambiar tu flujo de diseño."}, {"name": "¿Cómo conecto Kiro CLI a herramientas de diseño externas?", "text": "Kiro CLI gestiona servidores del Model Context Protocol (MCP): usa kiro-cli mcp para añadirlos. Un servidor MCP puede incorporar contexto de diseño real y herramientas al agente para que el código generado coincida con la fuente en lugar de aproximarla."}, {"name": "¿Está Open Design afiliado a Amazon o AWS?", "text": "No. Kiro es un producto de Amazon (AWS); Open Design es un proyecto de código abierto independiente que lo admite como adaptador de primera clase. Kiro es una marca registrada de Amazon."}, {"name": "¿Están seguros mis archivos y credenciales?", "text": "Sí: Open Design es local-first y Apache-2.0. Tus archivos, artefactos y DESIGN.md permanecen en tu propio repositorio, y tu inicio de sesión de Kiro lo usa directamente tu agente, sin pasar nunca por los servidores de Open Design."}], "ctaTitle": "Diseña con Kiro CLI, a la manera abierta.", "ctaBody": "Trae tu propio AWS Builder ID o inicio de sesión, mantén cada archivo en local y obtén una biblioteca de diseño curada en torno al agente que ya usas.", "ctaActions": [{"label": "Usa Kiro CLI dentro de Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dale una estrella en GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Descarga la app de escritorio", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Ver todos los agentes compatibles"},
      },
      'kilo': {
        ...en['kilo']!,
        title: "Kilo Code para diseño — Open Design",
        description: "Cómo se usa Kilo Code —el agente de programación con IA de código abierto y agnóstico al modelo— para diseño de interfaces y web: sus modos Architect/Code, su soporte de MCP, su BYOK con muchos proveedores, y cómo Open Design convierte a Kilo en un agente de diseño local-first y de código abierto.",
        breadcrumb: "Kilo",
        label: "Agente · Kilo",
        heading: "Kilo Code para diseño.",
        lead: "Kilo Code es un agente de programación con IA de código abierto y agnóstico al modelo para tu IDE y tu CLI. Como puedes apuntarlo a casi cualquier modelo y traer tus propias claves de proveedor, se convierte en una verdadera herramienta de diseño una vez que le das referencias, convenciones y un bucle de verificación. Open Design lo integra en un flujo de diseño de código abierto: tus claves de proveedor, tus archivos, local-first.",
        rich: {"heroCtaLead": "Open Design convierte a Kilo Code en un agente de diseño local-first y de código abierto: tus claves de proveedor, tus archivos y una biblioteca curada de skills y sistemas de diseño a su alrededor.", "heroCtaActions": [{"label": "Usa Kilo Code dentro de Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dale una estrella en GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Descarga la app de escritorio", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Kilo Code es un agente de programación con IA de código abierto que se ejecuta en VS Code, en los IDE de JetBrains y en la terminal. Dos cosas lo hacen interesante específicamente para el diseño: es agnóstico al modelo, así que puedes gobernarlo con el modelo de frontera con visión que mejor lea una captura de pantalla; y es BYOK con muchos proveedores, así que mantienes el control del coste y de las credenciales. Combinado con las referencias, convenciones y un bucle de verificación adecuados, construye interfaces reales y adaptables. Esta es una guía práctica y de principio a fin para usar Kilo Code en interfaces, frontend y trabajo con sistemas de diseño, y para integrarlo en un flujo de diseño estructurado con Open Design.", "Cubre qué es realmente Kilo Code, por qué un agente abierto y agnóstico al modelo encaja con el diseño, cómo configurarlo desde cero, el bucle de captura de pantalla a interfaz, cómo lo extienden las reglas personalizadas y MCP, cómo se compara con Codex, Claude Code, Cursor y Gemini CLI, los errores que hacen que el resultado de la IA luzca genérico, y cómo Open Design cierra la brecha como una capa de diseño abierta y local-first, una combinación natural, ya que ambos son de código abierto y se ejecutan en tu propia máquina."], "heroImage": {"src": "/agents/kilo-design/kilo-design-hero.webp", "alt": "Bucle de retroalimentación de diseño de Kilo Code: un agente en el IDE y la terminal leyendo una imagen de referencia, un navegador renderizando la interfaz y un espacio de trabajo, con una flecha de retroalimentación que regresa", "caption": "El bucle central: Kilo Code lee tus referencias en el IDE o la CLI, construye y verifica la interfaz en un navegador real e itera contra ellas, con el modelo que elijas."}, "tocLabel": "En esta página", "toc": [{"id": "what-is-kilo", "label": "Qué es realmente Kilo Code"}, {"id": "why-design", "label": "Por qué un agente abierto y agnóstico al modelo encaja con el diseño"}, {"id": "setup", "label": "Configura Kilo Code para diseño (desde cero)"}, {"id": "screenshot-workflow", "label": "El flujo de captura de pantalla a interfaz"}, {"id": "extend", "label": "Modos, reglas personalizadas y MCP"}, {"id": "vs", "label": "Kilo Code frente a Codex, Claude Code, Cursor y Gemini CLI"}, {"id": "pitfalls", "label": "Errores comunes y el aspecto de «basura de IA»"}, {"id": "open-design", "label": "Diseñar con Kilo Code en Open Design"}, {"id": "faq", "label": "Preguntas frecuentes"}], "sections": [{"id": "what-is-kilo", "heading": "Qué es realmente Kilo Code", "blocks": [{"kind": "p", "text": "Kilo Code es un agente de programación con IA de código abierto creado por Kilo Code, Inc. Se ejecuta como una extensión de VS Code, en los IDE de JetBrains y como interfaz de línea de comandos, leyendo tu repositorio, editando archivos, ejecutando comandos y planificando y verificando el trabajo a partir de tareas en lenguaje natural en lugar de limitarse a completar líneas. Su rasgo definitorio es que es agnóstico al modelo: tú eliges qué modelo lo gobierna y traes tus propias claves de proveedor."}, {"kind": "p", "text": "Para el trabajo de diseño destacan dos propiedades. Como es agnóstico al modelo, puedes apuntarlo al modelo potente con visión que mejor lea una captura de referencia y razone sobre la maquetación. Y como es de código abierto y BYOK, puedes inspeccionar exactamente qué contexto se envía y mantener las credenciales y el coste bajo tu propio control."}, {"kind": "steps", "items": [{"label": "Modos del agente", "body": "Kilo incluye modos especializados —Architect para planificar, Code para construir, Debug para corregir y Ask para preguntas— además de modos personalizados, así que puedes planificar un diseño y luego implementarlo en pasadas separadas y enfocadas."}, {"label": "Reglas personalizadas + MCP", "body": "Lee reglas personalizadas a nivel de proyecto para obtener contexto persistente y admite servidores MCP (con un mercado de MCP), así que puedes añadir contexto externo como un archivo de Figma en vivo o utillaje de diseño."}, {"label": "Trae tus propias claves", "body": "Kilo es BYOK con muchos proveedores —Anthropic, OpenAI, Google, OpenRouter y más— o puedes usar la propia pasarela de Kilo, que expone más de 500 modelos a coste de proveedor."}]}, {"kind": "ul", "items": ["Fabricante: Kilo Code, Inc. (código abierto)", "Credencial: tu propia clave de API de proveedor (BYOK: Anthropic, OpenAI, Google, OpenRouter y más) o la propia pasarela de Kilo", "Licencia: código abierto"]}]}, {"id": "why-design", "heading": "Por qué un agente abierto y agnóstico al modelo encaja con el diseño", "blocks": [{"kind": "p", "text": "La ventaja de Kilo Code para el diseño viene de su apertura y de la elección de modelo, pero, como ocurre con todo agente, el criterio estético hay que aportarlo igualmente."}, {"kind": "steps", "items": [{"label": "Agnóstico al modelo por diseño", "body": "Como tú eliges el modelo, puedes gobernar Kilo con el modelo con visión que mejor lea las capturas de referencia, y cambiarlo cuando aparezca uno mejor, sin alterar tu flujo de trabajo."}, {"label": "Abierto e inspeccionable", "body": "Kilo es de código abierto, así que puedes ver exactamente qué contexto y qué prompts se envían, útil cuando quieres que el agente reutilice tus primitivos de diseño reales en lugar de inventar estilos puntuales."}, {"label": "Convenciones en reglas personalizadas", "body": "Las reglas personalizadas del proyecto (más un servidor MCP para Figma) apuntan al agente hacia tus tokens, componentes y especificaciones reales, para que trabaje contra una marca en lugar de un aspecto por defecto."}]}, {"kind": "image", "src": "/agents/kilo-design/kilo-design-taste-triangle.webp", "alt": "Diagrama que muestra cómo un sistema de diseño, una skill y una imagen de referencia convergen en un buen resultado de diseño", "caption": "El criterio estético proviene de tres insumos que tú aportas: un sistema de diseño, una skill e imágenes de referencia reales."}, {"kind": "p", "text": "La lección es la misma que enseña todo agente: Kilo Code no tiene criterio estético por defecto. Produce buen diseño cuando le das restricciones: un sistema de diseño, una skill estética y referencias concretas. Open Design empaqueta exactamente esos insumos, por lo que ambos encajan (más abajo se explica)."}]}, {"id": "setup", "heading": "Configura Kilo Code para el trabajo de diseño, desde cero", "blocks": [{"kind": "p", "text": "Este es el recorrido completo, desde una máquina limpia hasta un Kilo Code capaz de construir y verificar interfaces."}, {"kind": "code", "lang": "bash", "code": "# 1. Install the Kilo Code extension from the VS Code\n#    (or JetBrains) marketplace, or install the CLI.\n\n# 2. Open your project and sign in / add a provider key\ncd your-project\nkilo              # connect your provider (BYOK) or Kilo's gateway\n\n# 3. Add project context\n#    create custom rules for this project's design conventions\n\n# 4. Wire the Figma MCP server (optional, for design handoff)\n#    add it from the MCP marketplace / MCP settings"}, {"kind": "image", "src": "/agents/kilo-design/kilo-design-setup-flow.webp", "alt": "Flujo de configuración en cinco pasos: instalar, autenticarse, añadir reglas personalizadas, añadir una skill, verificar", "caption": "La secuencia de configuración: instalar → conectar un proveedor → añadir reglas personalizadas → añadir una skill → habilitar la verificación en el navegador."}, {"kind": "steps", "items": [{"label": "Codifica tus reglas de diseño", "body": "Coloca tus tokens, primitivos y convenciones en las reglas personalizadas de Kilo y apunta el agente hacia ellas, para que el resultado se ajuste a una marca en lugar de caer en un aspecto genérico por defecto."}, {"label": "Añade verificación en el navegador", "body": "Conecta un Playwright o un MCP de navegador para que Kilo renderice en un navegador real y compruebe su resultado en los distintos breakpoints, en lugar de limitarse a confirmar que el build pasa."}]}]}, {"id": "screenshot-workflow", "heading": "El flujo de captura de pantalla a interfaz", "blocks": [{"kind": "p", "text": "El bucle de diseño de mayor rendimiento con Kilo Code consiste en convertir una imagen de referencia en una interfaz funcional y adaptable e iterar hasta que coincida, apoyándose en un modelo con visión para comparar el resultado con la referencia."}, {"kind": "ol", "items": ["Parte de las referencias visuales más claras que tengas, e incluye varios estados (escritorio y móvil, hover, vacío, cargando), no solo una imagen principal.", "Sé específico en el prompt; los prompts vagos producen interfaces genéricas incluso con un modelo potente.", "Mantén tu sistema de diseño y tus convenciones en las reglas personalizadas de Kilo, e indícale al agente dónde viven los tokens y los primitivos canónicos.", "Levanta un servidor de desarrollo y haz que Kilo renderice en un navegador real, redimensionando a los distintos breakpoints para comprobar el resultado.", "Itera haciendo que Kilo compare su implementación con las capturas de pantalla, no solo que confirme que compila."]}, {"kind": "p", "text": "Usa el modo Architect para planificar la construcción, luego cambia al modo Code y adjunta tus referencias con restricciones concretas:"}, {"kind": "code", "lang": "bash", "code": "# Plan in Architect mode, then build in Code mode:\n> Implement this design from @reference-desktop.png and\n  @reference-mobile.png in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens\n  from the custom rules.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the\n  references across breakpoints."}, {"kind": "p", "text": "Mantén los prompts breves y enfocados, confirma las buenas iteraciones y revierte las malas (avisando a Kilo cuando reviertas), para que cada pasada parta de una base limpia."}]}, {"id": "extend", "heading": "Modos, reglas personalizadas y MCP", "blocks": [{"kind": "p", "text": "Tres puntos de extensión hacen que Kilo Code sea práctico para un trabajo de diseño sostenido, y los tres encajan limpiamente en un flujo de diseño abierto."}, {"kind": "steps", "items": [{"label": "Modos (Architect → Code)", "body": "Planifica la estructura de una pantalla en el modo Architect, luego impleméntala en el modo Code y corrige problemas en el modo Debug, separando la intención de diseño de la implementación. Los modos personalizados te permiten codificar una pasada de revisión de diseño propia."}, {"label": "Reglas personalizadas", "body": "Las reglas personalizadas del proyecto son el hogar duradero de tus convenciones de diseño —tokens, primitivos y listas de revisión— leídas en cada ejecución para que el agente trabaje contra tu marca."}, {"label": "Servidores MCP", "body": "Kilo admite servidores MCP mediante su mercado: la forma portátil de incorporar contexto de diseño y herramientas externas —lo más relevante, un servidor MCP de Figma— que funcionan en distintos agentes, no solo en Kilo."}]}, {"kind": "p", "text": "Son capacidades portátiles y multiagente: exactamente el tipo de cosa que Open Design está diseñado para orquestar, en lugar de recrearla en cada proyecto."}]}, {"id": "vs", "heading": "Kilo Code frente a Codex, Claude Code, Cursor y Gemini CLI para diseño", "blocks": [{"kind": "p", "text": "No hay un único ganador para el trabajo de diseño: cada agente tiene una fortaleza distinta, y los equipos con experiencia los combinan. Un resumen honesto:"}, {"kind": "table", "columns": ["Agente", "Fortaleza de diseño", "Ideal para"], "rows": [["Kilo Code", "De código abierto y agnóstico al modelo con BYOK en muchos proveedores; modos Architect/Code y MCP", "Elegir tu propio modelo por tarea y mantener el coste y las credenciales bajo tu control"], ["Codex", "Gran acabado visual con una skill de frontend; builds asíncronos en entorno aislado", "Builds asíncronos delegados y reglas portátiles en AGENTS.md"], ["Claude Code", "Decisiones de diseño concretas (hex, espaciado, tipografía) y UX consciente del código base", "Razonamiento de frontend y refactorizaciones de contexto amplio"], ["Cursor", "Bucle visual de construir y ver con vista previa en vivo y ediciones en línea", "Trabajo de interfaz iterativo y supervisado dentro de un IDE"], ["Gemini CLI", "Gran comprensión multimodal de imágenes y un contexto de 1M de tokens", "Trabajo con muchas capturas de pantalla y mantener todo un sistema de diseño en contexto"]]}, {"kind": "p", "text": "El veredicto recurrente de la comunidad es que el criterio estético proviene de las personas: todos ellos tienden por defecto a una estética genérica sin skills, referencias ni restricciones. Ese es el verdadero problema a resolver, y tiene forma de herramienta de diseño, no de modelo."}]}, {"id": "pitfalls", "heading": "Errores comunes y cómo evitar el aspecto de «basura de IA»", "blocks": [{"kind": "p", "text": "La queja más común sobre el diseño generado por IA es que luce genérico: degradados suaves, paneles flotantes, esquinas redondeadas exageradas, sombras dramáticas, un aire de Inter y morado que «grita que esto lo hizo una IA». Otros problemas reportados incluyen maquetaciones móviles rotas e instrucciones que se filtran en el texto de la interfaz. Ninguno de estos es exclusivo de Kilo Code; son lo que ocurre cuando cualquier agente se ejecuta sin un contexto de diseño curado."}, {"kind": "steps", "items": [{"label": "Añade una skill estética", "body": "Una skill de diseño curada obliga al agente a comprometerse con una dirección real en lugar del aspecto por defecto."}, {"label": "Verifica en un navegador real", "body": "Usa un modelo con visión para renderizar y autoverificar en los distintos breakpoints para que las maquetaciones no se rompan en silencio en el móvil."}, {"label": "Aporta tokens y referencias", "body": "Los tokens de diseño reales y las capturas de referencia son la mayor palanca sobre la calidad del resultado."}, {"label": "Codifica reglas en las reglas personalizadas", "body": "Coloca reglas del estilo «sin tarjetas hero, máximo dos tipografías, jerarquía con la marca primero» donde el agente las lea en cada ejecución."}]}, {"kind": "p", "text": "Fíjate en que toda mitigación consiste en dar al agente un contexto de diseño curado. Mantener ese contexto a mano, proyecto a proyecto, es el trabajo tedioso que Open Design elimina."}]}, {"id": "open-design", "heading": "Diseñar con Kilo Code dentro de Open Design", "blocks": [{"kind": "p", "text": "Open Design es la capa de diseño de código abierto que el flujo de trabajo anterior reclama una y otra vez. Trata a Kilo Code como un adaptador de primera clase y lo envuelve en una biblioteca curada de skills y sistemas de diseño, una canalización de renderizado estructurada y una interfaz de escritorio local, para que el contexto de diseño que hace bueno a Kilo esté presente desde la primera ejecución, no ensamblado a mano cada vez. Ambos son de código abierto y local-first, lo que hace de esta combinación un encaje natural."}, {"kind": "ol", "items": ["Instala Open Design y selecciona Kilo Code como tu agente.", "Autentícate con tu propia clave de proveedor (BYOK) o con la pasarela de Kilo: las credenciales permanecen en tu máquina y nunca se enrutan a través de nosotros.", "Elige un sistema de diseño y una skill, y luego genera presentaciones, prototipos y páginas de aterrizaje con un criterio estético consistente.", "Cada artefacto y archivo DESIGN.md vive en tu propio repositorio, no en una nube alojada."]}, {"kind": "p", "text": "El mismo agente Kilo Code, las mismas claves, más un flujo de diseño real, portátil y de código abierto a su alrededor. Es local-first y de código abierto, así que nada de tu trabajo ni de tus credenciales sale de tu máquina."}]}], "faqTitle": "Preguntas frecuentes", "faq": [{"name": "¿De verdad puede Kilo Code hacer trabajo de diseño?", "text": "Sí: con una skill estética, un sistema de diseño e imágenes de referencia reales en contexto, Kilo Code produce interfaces adaptables de calidad de producción, y un modelo con visión verifica el resultado contra las referencias. Sin ese contexto tiende a caer en un aspecto genérico, que es la brecha que Open Design llena."}, {"name": "¿Necesito pagar para diseñar con Kilo Code?", "text": "Kilo Code es de código abierto y su instalación es gratuita. Traes tu propia clave de API de proveedor (BYOK) y pagas a ese proveedor directamente, o usas la propia pasarela de Kilo a coste de proveedor. En cualquier caso, Open Design nunca enruta tus credenciales."}, {"name": "¿Qué hace que Kilo Code sea bueno para el diseño en concreto?", "text": "Es agnóstico al modelo y de código abierto, así que puedes gobernarlo con el modelo con visión que mejor lea las capturas de referencia, inspeccionar exactamente qué contexto se envía y mantener el coste y las credenciales bajo tu control. El criterio estético sigue viniendo del sistema de diseño, la skill y las referencias que tú aportes."}, {"name": "¿Kilo Code o Claude Code para diseño de frontend?", "text": "Ambos son potentes. Claude Code es conocido por decisiones de diseño concretas y conscientes del código base; la ventaja de Kilo Code es ser de código abierto y agnóstico al modelo con BYOK, así que tú eliges el modelo. Muchos equipos usan los dos: Open Design te permite cambiar de agente sin cambiar tu flujo de diseño."}, {"name": "¿Cómo conecto Kilo Code a Figma?", "text": "Añade un servidor MCP de Figma desde el mercado de MCP o los ajustes de MCP de Kilo. Kilo puede entonces extraer contexto de diseño real —componentes, variables, datos de maquetación— para que el código generado coincida con la fuente en lugar de aproximarla."}, {"name": "¿Está Open Design afiliado a Kilo Code?", "text": "No. Kilo Code es un producto de Kilo Code, Inc.; Open Design es un proyecto de código abierto independiente que lo admite como adaptador de primera clase. Ambos resultan ser de código abierto, pero son proyectos separados."}, {"name": "¿Están seguros mis archivos y credenciales?", "text": "Sí: Open Design es local-first y de código abierto. Tus archivos, artefactos y DESIGN.md permanecen en tu propio repositorio, y tus credenciales de proveedor las usa directamente tu agente, sin pasar nunca por los servidores de Open Design."}], "ctaTitle": "Diseña con Kilo Code, a la manera abierta.", "ctaBody": "Trae tu propia clave de proveedor, mantén cada archivo en local y obtén una biblioteca de diseño curada en torno al agente que ya usas.", "ctaActions": [{"label": "Usa Kilo Code dentro de Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dale una estrella en GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Descarga la app de escritorio", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Ver todos los agentes compatibles"},
      },
      'vibe': {
        ...en['vibe']!,
        title: "Mistral Vibe CLI para diseño — Open Design",
        description: "Cómo se usa el Vibe CLI de Mistral para diseño de interfaces y web —sus modelos de programación Devstral de pesos abiertos, su edición agéntica de múltiples archivos, config.toml, MCP y ACP— y cómo Open Design convierte a Vibe CLI en un agente de diseño local-first y de código abierto.",
        breadcrumb: "Mistral Vibe CLI",
        label: "Agente · Mistral Vibe CLI",
        heading: "Mistral Vibe CLI para diseño.",
        lead: "Mistral Vibe CLI es el agente de programación de terminal de código abierto de Mistral AI, impulsado por la familia de modelos Devstral. Edita archivos, ejecuta comandos y trabaja sobre el Agent Client Protocol, lo que lo convierte en una verdadera herramienta de diseño una vez que le das referencias, convenciones y un bucle de verificación. Open Design lo integra en un flujo de diseño de código abierto: tu clave de API de Mistral (BYOK) o modelos locales, tus archivos, local-first.",
        rich: {"heroCtaLead": "Open Design convierte a Mistral Vibe CLI en un agente de diseño local-first y de código abierto: tu clave de API de Mistral o modelos Devstral locales, tus archivos y una biblioteca curada de skills y sistemas de diseño a su alrededor.", "heroCtaActions": [{"label": "Usa Vibe CLI dentro de Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dale una estrella en GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Descarga la app de escritorio", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Mistral Vibe CLI es el agente de programación de código abierto (Apache-2.0) que Mistral AI distribuye para la terminal. Analiza la estructura de archivos de tu proyecto y el estado de Git para obtener contexto, y luego explora, edita y ejecuta cambios por todo tu código base a partir de tareas en lenguaje natural. Dos cosas lo hacen interesante específicamente para el diseño: está impulsado por los modelos de programación Devstral de Mistral, parte de un ecosistema de pesos abiertos que puedes ejecutar en local o en la nube; y habla el Agent Client Protocol (ACP), así que se integra en editores y herramientas en lugar de vivir solo en una terminal. Combinado con las referencias, convenciones y un bucle de verificación adecuados, construye interfaces reales y adaptables. Esta es una guía práctica y de principio a fin para usar Vibe CLI en interfaces, frontend y trabajo con sistemas de diseño, y para integrarlo en un flujo de diseño estructurado con Open Design.", "Cubre qué es realmente Vibe CLI, por qué un agente de programación de pesos abiertos encaja con el diseño, cómo configurarlo desde cero, el bucle de referencia a interfaz, cómo lo extienden config.toml, MCP y ACP, cómo se compara con Codex, Claude Code, Cursor y Gemini CLI, los errores que hacen que el resultado de la IA luzca genérico, y cómo Open Design cierra la brecha como una capa de diseño abierta y local-first, una combinación natural, ya que ambos son de código abierto y se ejecutan en tu propia máquina."], "heroImage": {"src": "/agents/vibe-design/vibe-design-hero.webp", "alt": "Bucle de retroalimentación de diseño de Mistral Vibe CLI: un agente de terminal leyendo una referencia, un navegador renderizando la interfaz y un espacio de trabajo, con una flecha de retroalimentación que regresa", "caption": "El bucle central: Vibe CLI lee tus referencias en la terminal, construye y verifica la interfaz en un navegador real e itera contra ellas, gobernado por los modelos de programación Devstral de Mistral."}, "tocLabel": "En esta página", "toc": [{"id": "what-is-vibe", "label": "Qué es realmente Mistral Vibe CLI"}, {"id": "why-design", "label": "Por qué un agente de programación de pesos abiertos encaja con el diseño"}, {"id": "setup", "label": "Configura Vibe CLI para diseño (desde cero)"}, {"id": "screenshot-workflow", "label": "El flujo de referencia a interfaz"}, {"id": "extend", "label": "config.toml, MCP y ACP"}, {"id": "vs", "label": "Vibe CLI frente a Codex, Claude Code, Cursor y Gemini CLI"}, {"id": "pitfalls", "label": "Errores comunes y el aspecto de «basura de IA»"}, {"id": "open-design", "label": "Diseñar con Vibe CLI en Open Design"}, {"id": "faq", "label": "Preguntas frecuentes"}], "sections": [{"id": "what-is-vibe", "heading": "Qué es realmente Mistral Vibe CLI", "blocks": [{"kind": "p", "text": "Mistral Vibe CLI es un agente de programación de código abierto (Apache-2.0) que Mistral AI distribuye para la terminal. Ofrece una interfaz de chat interactiva con herramientas para manipular archivos, buscar en el código, controlar versiones y ejecutar comandos, y analiza automáticamente la estructura de archivos de tu proyecto y el estado de Git para dar al agente contexto relevante. Está impulsado por los modelos de programación Devstral de Mistral, planificando y verificando el trabajo a partir de tareas en lenguaje natural en lugar de limitarse a completar líneas."}, {"kind": "p", "text": "Para el trabajo de diseño destacan dos propiedades. Se ejecuta sobre la familia Devstral de pesos abiertos de Mistral (Devstral 2 y el más pequeño Devstral Small 2), así que puedes ejecutar el agente contra la API de Mistral en la nube o contra modelos locales, útil para trabajo de diseño sensible a la privacidad o sin conexión. Y habla el Agent Client Protocol, así que el mismo agente puede gobernar editores y herramientas, no solo una sesión de terminal."}, {"kind": "steps", "items": [{"label": "Archivos de configuración", "body": "Vibe CLI se configura mediante un archivo config.toml (a nivel de proyecto en ./.vibe/config.toml, con un respaldo en ~/.vibe/config.toml). Es un lugar práctico para codificar tus proveedores, tu elección de modelo y los ajustes del proyecto."}, {"label": "Herramientas integradas + MCP", "body": "Incluye herramientas de archivos, búsqueda, control de versiones y ejecución de comandos, y admite servidores MCP (configurados en una sección [[mcp_servers]]) para añadir contexto externo como un archivo de Figma en vivo."}, {"label": "BYOK o local", "body": "Autentícate con una clave de API de Mistral desde la consola de Mistral, o apúntalo a modelos locales/compatibles para que funcione totalmente sin conexión."}]}, {"kind": "ul", "items": ["Fabricante: Mistral AI", "Credencial: clave de API de Mistral (BYOK) desde la consola de Mistral, o modelos locales / compatibles", "Licencia: Apache-2.0, código abierto"]}]}, {"id": "why-design", "heading": "Por qué un agente de programación de pesos abiertos encaja con el diseño", "blocks": [{"kind": "p", "text": "La ventaja de Vibe CLI para el diseño viene de su familia de modelos de pesos abiertos y de su alcance de protocolo, pero, como ocurre con todo agente, el criterio estético hay que aportarlo igualmente."}, {"kind": "steps", "items": [{"label": "Modelos de programación Devstral", "body": "Vibe se ejecuta sobre la familia Devstral de Mistral, modelos ajustados para programación y construidos para el trabajo agéntico con múltiples archivos, así que el agente edita por todo un código base de frontend real en lugar de emitir fragmentos aislados."}, {"label": "Pesos abiertos y amigable con lo local", "body": "Devstral Small 2 es lo bastante pequeño para ejecutarse en hardware de consumo, así que el trabajo de diseño puede mantenerse totalmente en local y sin conexión: las referencias y el código no tienen que salir nunca de tu máquina."}, {"label": "Convenciones en config.toml + contexto", "body": "La configuración del proyecto y tus propias instrucciones apuntan al agente hacia tus tokens, componentes y especificaciones reales, para que trabaje contra una marca en lugar de un aspecto por defecto."}]}, {"kind": "image", "src": "/agents/vibe-design/vibe-design-taste-triangle.webp", "alt": "Diagrama que muestra cómo un sistema de diseño, una skill y una imagen de referencia convergen en un buen resultado de diseño", "caption": "El criterio estético proviene de tres insumos que tú aportas: un sistema de diseño, una skill e imágenes de referencia reales."}, {"kind": "p", "text": "La lección es la misma que enseña todo agente: Vibe CLI no tiene criterio estético por defecto. Produce buen diseño cuando le das restricciones: un sistema de diseño, una skill estética y referencias concretas. Open Design empaqueta exactamente esos insumos, por lo que ambos encajan (más abajo se explica)."}]}, {"id": "setup", "heading": "Configura Vibe CLI para el trabajo de diseño, desde cero", "blocks": [{"kind": "p", "text": "Este es el recorrido completo, desde una máquina limpia hasta un Vibe CLI capaz de construir y verificar interfaces."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Mistral Vibe CLI\nuv tool install mistral-vibe\n# or: pip install mistral-vibe\n\n# 2. Run the setup wizard to register your API key\nvibe --setup     # saves config to ~/.vibe/config.toml and ~/.vibe/.env\n#    or set it directly:  export MISTRAL_API_KEY=...\n\n# 3. Start Vibe in your project\ncd your-project\nvibe\n\n# 4. Wire the Figma MCP server (optional, for design handoff)\n#    add an [[mcp_servers]] entry in your config.toml"}, {"kind": "image", "src": "/agents/vibe-design/vibe-design-setup-flow.webp", "alt": "Flujo de configuración en cinco pasos: instalar, autenticarse, configurar config.toml, añadir una skill, verificar", "caption": "La secuencia de configuración: instalar → autenticarse → configurar config.toml → añadir una skill → habilitar la verificación en el navegador."}, {"kind": "steps", "items": [{"label": "Codifica tus reglas de diseño", "body": "Mantén tus tokens, primitivos y convenciones donde el agente los lea y apunta Vibe hacia ellos, para que el resultado se ajuste a una marca en lugar de caer en un aspecto genérico por defecto."}, {"label": "Añade verificación en el navegador", "body": "Conecta un Playwright o un MCP de navegador para que Vibe renderice en un navegador real y compruebe su resultado en los distintos breakpoints, en lugar de limitarse a confirmar que el build pasa."}]}]}, {"id": "screenshot-workflow", "heading": "El flujo de referencia a interfaz", "blocks": [{"kind": "p", "text": "El bucle de diseño de mayor rendimiento con Vibe CLI consiste en convertir una referencia clara en una interfaz funcional y adaptable e iterar hasta que coincida, apoyándose en las herramientas del agente para renderizar, inspeccionar y corregir su propio resultado."}, {"kind": "ol", "items": ["Parte de las referencias más claras que tengas, y describe varios estados (escritorio y móvil, hover, vacío, cargando), no solo una imagen principal.", "Sé específico en el prompt; los prompts vagos producen interfaces genéricas incluso con un modelo potente.", "Mantén tu sistema de diseño y tus convenciones donde Vibe las lea, e indícale dónde viven los tokens y los primitivos canónicos.", "Levanta un servidor de desarrollo y haz que Vibe renderice en un navegador real, redimensionando a los distintos breakpoints para comprobar el resultado.", "Itera haciendo que Vibe compare su implementación con las referencias, no solo que confirme que compila."]}, {"kind": "p", "text": "Referencia archivos con @ (Vibe autocompleta las rutas de archivo) y maneja los comandos de barra con /, luego da restricciones concretas:"}, {"kind": "code", "lang": "bash", "code": "vibe\n# in the prompt:\n> @design-spec.md @tokens.css\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, render it in the browser, and iterate until\n  it matches the references across breakpoints."}, {"kind": "p", "text": "Mantén los prompts breves y enfocados, confirma las buenas iteraciones y revierte las malas (avisando a Vibe cuando reviertas), para que cada pasada parta de una base limpia."}]}, {"id": "extend", "heading": "config.toml, MCP y ACP", "blocks": [{"kind": "p", "text": "Tres puntos de extensión hacen que Vibe CLI sea práctico para un trabajo de diseño sostenido, y los tres encajan limpiamente en un flujo de diseño abierto."}, {"kind": "steps", "items": [{"label": "config.toml", "body": "Las reglas de proyecto y los ajustes de proveedor/modelo viven en un config.toml (a nivel de proyecto, con un respaldo en ~/.vibe). Es el hogar duradero de cómo se integra el agente en tu proyecto, leído en cada ejecución."}, {"label": "Servidores MCP", "body": "Configura servidores MCP en tu config.toml ([[mcp_servers]], con transportes HTTP, HTTP transmitible y stdio): la forma portátil de incorporar contexto de diseño y herramientas externas —lo más relevante, el servidor MCP de Figma— que funcionan en distintos agentes, no solo en Vibe."}, {"label": "Agent Client Protocol", "body": "Vibe habla ACP, así que el mismo agente puede gobernarse desde editores y otros clientes ACP. Así es exactamente como Open Design lo integra: sobre ACP mediante el binario vibe-acp."}]}, {"kind": "p", "text": "Son capacidades portátiles y multiagente: exactamente el tipo de cosa que Open Design está diseñado para orquestar, en lugar de recrearla en cada proyecto."}]}, {"id": "vs", "heading": "Vibe CLI frente a Codex, Claude Code, Cursor y Gemini CLI para diseño", "blocks": [{"kind": "p", "text": "No hay un único ganador para el trabajo de diseño: cada agente tiene una fortaleza distinta, y los equipos con experiencia los combinan. Un resumen honesto:"}, {"kind": "table", "columns": ["Agente", "Fortaleza de diseño", "Ideal para"], "rows": [["Mistral Vibe CLI", "Modelos de programación Devstral de pesos abiertos que puedes ejecutar en local; Apache-2.0 y nativo de ACP", "Trabajo de diseño sensible a la privacidad o sin conexión y una pila de pesos abiertos"], ["Codex", "Gran acabado visual con una skill de frontend; builds asíncronos en entorno aislado", "Builds asíncronos delegados y reglas portátiles en AGENTS.md"], ["Claude Code", "Decisiones de diseño concretas (hex, espaciado, tipografía) y UX consciente del código base", "Razonamiento de frontend y refactorizaciones de contexto amplio"], ["Cursor", "Bucle visual de construir y ver con vista previa en vivo y ediciones en línea", "Trabajo de interfaz iterativo y supervisado dentro de un IDE"], ["Gemini CLI", "Gran comprensión multimodal de imágenes y una ventana de contexto muy amplia", "Trabajo con muchas capturas de pantalla y mantener todo un sistema de diseño en contexto"]]}, {"kind": "p", "text": "El veredicto recurrente de la comunidad es que el criterio estético proviene de las personas: todos ellos tienden por defecto a una estética genérica sin skills, referencias ni restricciones. Ese es el verdadero problema a resolver, y tiene forma de herramienta de diseño, no de modelo."}]}, {"id": "pitfalls", "heading": "Errores comunes y cómo evitar el aspecto de «basura de IA»", "blocks": [{"kind": "p", "text": "La queja más común sobre el diseño generado por IA es que luce genérico: degradados suaves, paneles flotantes, esquinas redondeadas exageradas, sombras dramáticas, un aire de Inter y morado que «grita que esto lo hizo una IA». Otros problemas reportados incluyen maquetaciones móviles rotas e instrucciones que se filtran en el texto de la interfaz. Ninguno de estos es exclusivo de Vibe CLI; son lo que ocurre cuando cualquier agente se ejecuta sin un contexto de diseño curado."}, {"kind": "steps", "items": [{"label": "Añade una skill estética", "body": "Una skill de diseño curada obliga al agente a comprometerse con una dirección real en lugar del aspecto por defecto."}, {"label": "Verifica en un navegador real", "body": "Haz que Vibe renderice y se autoverifique en los distintos breakpoints para que las maquetaciones no se rompan en silencio en el móvil."}, {"label": "Aporta tokens y referencias", "body": "Los tokens de diseño reales y las capturas de referencia son la mayor palanca sobre la calidad del resultado."}, {"label": "Codifica reglas en la configuración y el contexto", "body": "Coloca reglas del estilo «sin tarjetas hero, máximo dos tipografías, jerarquía con la marca primero» donde el agente las lea en cada ejecución."}]}, {"kind": "p", "text": "Fíjate en que toda mitigación consiste en dar al agente un contexto de diseño curado. Mantener ese contexto a mano, proyecto a proyecto, es el trabajo tedioso que Open Design elimina."}]}, {"id": "open-design", "heading": "Diseñar con Vibe CLI dentro de Open Design", "blocks": [{"kind": "p", "text": "Open Design es la capa de diseño de código abierto que el flujo de trabajo anterior reclama una y otra vez. Trata a Mistral Vibe CLI como un adaptador de primera clase —gobernándolo sobre ACP mediante el binario vibe-acp— y lo envuelve en una biblioteca curada de skills y sistemas de diseño, una canalización de renderizado estructurada y una interfaz de escritorio local. De modo que el contexto de diseño que hace bueno a Vibe está presente desde la primera ejecución, no ensamblado a mano cada vez. Ambos son de código abierto y local-first, lo que hace de esta combinación un encaje natural."}, {"kind": "ol", "items": ["Instala Open Design y selecciona Mistral Vibe CLI como tu agente.", "Autentícate con tu clave de API de Mistral (BYOK) o apunta Vibe a modelos locales: las credenciales permanecen en tu máquina y nunca se enrutan a través de nosotros.", "Elige un sistema de diseño y una skill, y luego genera presentaciones, prototipos y páginas de aterrizaje con un criterio estético consistente.", "Cada artefacto y archivo DESIGN.md vive en tu propio repositorio, no en una nube alojada."]}, {"kind": "p", "text": "El mismo agente Vibe CLI, la misma clave, más un flujo de diseño real, portátil y de código abierto a su alrededor. Es local-first y Apache-2.0, así que nada de tu trabajo ni de tus credenciales sale de tu máquina."}]}], "faqTitle": "Preguntas frecuentes", "faq": [{"name": "¿De verdad puede Mistral Vibe CLI hacer trabajo de diseño?", "text": "Sí: con una skill estética, un sistema de diseño y referencias reales en contexto, Vibe CLI produce interfaces adaptables de calidad de producción, y sus modelos Devstral editan por todo un código base de frontend real. Sin ese contexto tiende a caer en un aspecto genérico, que es la brecha que Open Design llena."}, {"name": "¿Cómo autentico Vibe CLI?", "text": "Ejecuta el asistente de configuración con vibe --setup para registrar una clave de API de Mistral (desde la consola de Mistral), o define MISTRAL_API_KEY en tu entorno. También puede ejecutarse contra modelos locales o compatibles, totalmente sin conexión. En cualquier caso, Open Design nunca enruta tus credenciales."}, {"name": "¿Qué hace que Vibe CLI sea bueno para el diseño en concreto?", "text": "Es un agente Apache-2.0 y nativo de ACP impulsado por los modelos de programación Devstral de pesos abiertos de Mistral, así que puedes ejecutarlo en local para trabajo sensible a la privacidad y editar por todo un código base real. Pero el criterio estético sigue viniendo del sistema de diseño, la skill y las referencias que tú aportes."}, {"name": "¿Vibe CLI o Claude Code para diseño de frontend?", "text": "Ambos son potentes. Claude Code es conocido por decisiones de diseño concretas y conscientes del código base; la ventaja de Vibe CLI es una pila Devstral de pesos abiertos que puedes ejecutar en local y una licencia Apache-2.0. Muchos equipos usan los dos: Open Design te permite cambiar de agente sin cambiar tu flujo de diseño."}, {"name": "¿Cómo conecto Vibe CLI a Figma?", "text": "Añade el servidor MCP de Figma como una entrada [[mcp_servers]] en tu config.toml. Vibe puede entonces extraer contexto de diseño real —componentes, variables, datos de maquetación— para que el código generado coincida con la fuente en lugar de aproximarla."}, {"name": "¿Está Open Design afiliado a Mistral AI?", "text": "No. Mistral Vibe CLI es un producto de Mistral AI; Open Design es un proyecto de código abierto independiente que lo admite como adaptador de primera clase, gobernado sobre ACP. Mistral es una marca registrada de Mistral AI."}, {"name": "¿Están seguros mis archivos y credenciales?", "text": "Sí: Open Design es local-first y Apache-2.0. Tus archivos, artefactos y DESIGN.md permanecen en tu propio repositorio, y tus credenciales de Mistral las usa directamente tu agente, sin pasar nunca por los servidores de Open Design."}], "ctaTitle": "Diseña con Mistral Vibe CLI, a la manera abierta.", "ctaBody": "Trae tu propia clave de API de Mistral o modelos locales, mantén cada archivo en local y obtén una biblioteca de diseño curada en torno al agente que ya usas.", "ctaActions": [{"label": "Usa Vibe CLI dentro de Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dale una estrella en GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Descarga la app de escritorio", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Ver todos los agentes compatibles"},
      },
      'qoder': {
        ...en['qoder']!,
        title: "Qoder CLI para diseño — Open Design",
        description: "Cómo se usa Qoder CLI —la plataforma de programación agéntica de Alibaba— para diseño de interfaces y web: sus modos agent y quest, su comprensión profunda del repositorio y su wiki del repositorio, y sus niveles de modelo Lite/Efficient/Auto, y cómo Open Design convierte a Qoder CLI en un agente de diseño local-first y de código abierto.",
        breadcrumb: "Qoder CLI",
        label: "Agente · Qoder CLI",
        heading: "Qoder CLI para diseño.",
        lead: "Qoder CLI es el agente de terminal de Qoder, la plataforma de programación agéntica de Alibaba. Comprende un repositorio entero —su arquitectura, sus patrones y las convenciones capturadas en su wiki del repositorio— y ejecuta trabajo autónomo guiado por especificaciones, lo que lo convierte en una verdadera herramienta de diseño una vez que le das referencias, convenciones y un bucle de verificación. Open Design lo integra en un flujo de diseño de código abierto: tu cuenta de Qoder, tus archivos, local-first.",
        rich: {"heroCtaLead": "Open Design convierte a Qoder CLI en un agente de diseño local-first y de código abierto: tu cuenta de Qoder, tus archivos y una biblioteca curada de skills y sistemas de diseño a su alrededor.", "heroCtaActions": [{"label": "Usa Qoder CLI dentro de Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dale una estrella en GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Descarga la app de escritorio", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Qoder CLI es el agente de terminal de Qoder, la plataforma de programación agéntica de Alibaba. Dos cosas lo hacen interesante específicamente para el diseño: construye un contexto profundo sobre tu repositorio —su arquitectura, sus patrones de diseño y las convenciones que destila en una wiki del repositorio— así que reutiliza tus primitivos reales en lugar de inventar estilos puntuales; y ejecuta quests autónomos guiados por especificaciones que planifican, implementan y verifican una tarea de principio a fin en lugar de limitarse a completar líneas. Combinado con las referencias, convenciones y un bucle de verificación adecuados, construye interfaces reales y adaptables. Esta es una guía práctica y de principio a fin para usar Qoder CLI en interfaces, frontend y trabajo con sistemas de diseño, y para integrarlo en un flujo de diseño estructurado con Open Design.", "Cubre qué es realmente Qoder CLI, por qué su comprensión del repositorio y sus quests agénticos encajan con el diseño, cómo configurarlo desde cero, el bucle de referencia a interfaz, cómo lo extienden las reglas, MCP y la wiki del repositorio, cómo se compara con Codex, Claude Code, Cursor y Gemini CLI, los errores que hacen que el resultado de la IA luzca genérico, y cómo Open Design cierra la brecha como una capa de diseño abierta y local-first en torno al agente que ya usas."], "heroImage": {"src": "/agents/qoder-design/qoder-design-hero.webp", "alt": "Bucle de retroalimentación de diseño de Qoder CLI: un agente de terminal leyendo una imagen de referencia con contexto de la wiki del repositorio, un navegador renderizando la interfaz y un espacio de trabajo, con una flecha de retroalimentación que regresa", "caption": "El bucle central: Qoder CLI lee tus referencias y el contexto del repositorio en la terminal, construye y verifica la interfaz en un navegador real e itera contra ellas."}, "tocLabel": "En esta página", "toc": [{"id": "what-is-qoder", "label": "Qué es realmente Qoder CLI"}, {"id": "why-design", "label": "Por qué lo agéntico y el contexto del repositorio encajan con el diseño"}, {"id": "setup", "label": "Configura Qoder CLI para diseño (desde cero)"}, {"id": "screenshot-workflow", "label": "El flujo de referencia a interfaz"}, {"id": "extend", "label": "Reglas, MCP y la wiki del repositorio"}, {"id": "vs", "label": "Qoder CLI frente a Codex, Claude Code, Cursor y Gemini CLI"}, {"id": "pitfalls", "label": "Errores comunes y el aspecto de «basura de IA»"}, {"id": "open-design", "label": "Diseñar con Qoder CLI en Open Design"}, {"id": "faq", "label": "Preguntas frecuentes"}], "sections": [{"id": "what-is-qoder", "heading": "Qué es realmente Qoder CLI", "blocks": [{"kind": "p", "text": "Qoder es una plataforma de programación agéntica de Alibaba: un entorno de desarrollo con IA, disponible como app de escritorio y como CLI, que comprende códigos base reales y gestiona tareas de desarrollo de principio a fin. Qoder CLI lleva ese motor a la terminal: lee tu repositorio, edita archivos, ejecuta comandos de shell y resuelve tareas a partir del lenguaje natural en lugar de limitarse a completar líneas. Inicia sesión con una cuenta de Qoder."}, {"kind": "p", "text": "Para el trabajo de diseño destacan dos propiedades. Qoder construye un contexto profundo sobre tu repositorio —su arquitectura, sus patrones de diseño y sus convenciones destiladas en una wiki del repositorio— así que fundamenta el resultado en tus primitivos reales. Y ejecuta un flujo de trabajo agéntico y guiado por especificaciones: esbozas lo que quieres y él planifica, implementa y verifica el trabajo, incluso a lo largo de varios pasos."}, {"kind": "steps", "items": [{"label": "Modos Agent y Quest", "body": "El modo Agent es programación en pareja conversacional con puntos de control con intervención humana; el modo Quest delega el trabajo más largo y de varios pasos a un agente autónomo que planifica, implementa y se autoverifica, el lugar natural para traspasar una tarea de diseño guiada por especificaciones."}, {"label": "Wiki del repositorio + MCP", "body": "Qoder destila tu código base en una wiki del repositorio con su arquitectura y convenciones, y admite servidores MCP para incorporar contexto externo como un archivo de Figma en vivo."}, {"label": "Niveles de modelo", "body": "Qoder CLI expone los niveles Lite, Efficient y Auto; Auto deja que su planificador elija un modelo por tarea, así que no gestionas la selección de modelo a mano."}]}, {"kind": "ul", "items": ["Fabricante: Alibaba", "Credencial: cuenta de Qoder (inicia sesión mediante el navegador, o un token de acceso personal de Qoder para uso no interactivo)", "Niveles de modelo: Lite, Efficient, Auto"]}]}, {"id": "why-design", "heading": "Por qué un agente agéntico y consciente del repositorio encaja con el diseño", "blocks": [{"kind": "p", "text": "La ventaja de Qoder CLI para el diseño viene de dos propiedades, pero, como ocurre con todo agente, el criterio estético hay que aportarlo igualmente."}, {"kind": "steps", "items": [{"label": "Comprensión profunda del repositorio", "body": "Como Qoder construye contexto sobre todo tu código base y lo destila en una wiki del repositorio, el agente reutiliza tus componentes y tokens existentes en lugar de inventar estilos puntuales para cada pantalla."}, {"label": "Quests autónomos guiados por especificaciones", "body": "El modo Quest convierte una especificación escrita en un resultado planificado, implementado y autoverificado, así que una tarea de diseño se ejecuta de principio a fin en lugar de detenerse en un primer borrador."}, {"label": "Convenciones que el agente lee", "body": "Las reglas de proyecto (más el servidor MCP de Figma) apuntan al agente hacia tus tokens, componentes y especificaciones reales, para que trabaje contra una marca en lugar de un aspecto por defecto."}]}, {"kind": "image", "src": "/agents/qoder-design/qoder-design-taste-triangle.webp", "alt": "Diagrama que muestra cómo un sistema de diseño, una skill y una imagen de referencia convergen en un buen resultado de diseño", "caption": "El criterio estético proviene de tres insumos que tú aportas: un sistema de diseño, una skill e imágenes de referencia reales."}, {"kind": "p", "text": "La lección es la misma que enseña todo agente: Qoder CLI no tiene criterio estético por defecto. Produce buen diseño cuando le das restricciones: un sistema de diseño, una skill estética y referencias concretas. Open Design empaqueta exactamente esos insumos, por lo que ambos encajan (más abajo se explica)."}]}, {"id": "setup", "heading": "Configura Qoder CLI para el trabajo de diseño, desde cero", "blocks": [{"kind": "p", "text": "Este es el recorrido completo, desde una máquina limpia hasta un Qoder CLI capaz de construir y verificar interfaces."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Qoder CLI (Node 20+)\nnpm install -g @qoder-ai/qodercli\n# (macOS/Linux via Homebrew also available)\n\n# 2. Verify the install\nqodercli --version\n\n# 3. Start it in your project and sign in on first run\ncd your-project\nqodercli          # then /login — sign in via browser or a Qoder access token\n\n# 4. Pick a model tier for the session\n#    Lite, Efficient, or Auto (Auto lets the scheduler choose per task)"}, {"kind": "image", "src": "/agents/qoder-design/qoder-design-setup-flow.webp", "alt": "Flujo de configuración en cinco pasos: instalar, autenticarse, configurar reglas, añadir una skill, verificar", "caption": "La secuencia de configuración: instalar → iniciar sesión → configurar las reglas de proyecto → añadir una skill → habilitar la verificación en el navegador."}, {"kind": "steps", "items": [{"label": "Codifica tus reglas de diseño", "body": "Coloca tus tokens, primitivos y convenciones donde el agente los lea, para que el resultado se ajuste a una marca en lugar de caer en un aspecto genérico por defecto. La wiki del repositorio de Qoder ayuda a mantener ese contexto actualizado."}, {"label": "Añade verificación en el navegador", "body": "Conecta un Playwright o un MCP de navegador para que Qoder renderice en un navegador real y compruebe su resultado en los distintos breakpoints, en lugar de limitarse a confirmar que el build pasa."}]}]}, {"id": "screenshot-workflow", "heading": "El flujo de referencia a interfaz", "blocks": [{"kind": "p", "text": "El bucle de diseño de mayor rendimiento con Qoder CLI consiste en convertir una referencia en una interfaz funcional y adaptable e iterar hasta que coincida, apoyándose en el contexto del repositorio del agente y en un bucle de verificación real para comparar el resultado con la referencia."}, {"kind": "ol", "items": ["Parte de las referencias visuales más claras que tengas, e incluye varios estados (escritorio y móvil, hover, vacío, cargando), no solo una imagen principal.", "Sé específico en el prompt; los prompts vagos producen interfaces genéricas incluso con un agente competente.", "Apunta Qoder a tu sistema de diseño y a tus convenciones, e indícale dónde viven los tokens y los primitivos canónicos.", "Levanta un servidor de desarrollo y haz que Qoder renderice en un navegador real, redimensionando a los distintos breakpoints para comprobar el resultado.", "Itera haciendo que Qoder compare su implementación con las referencias, no solo que confirme que compila."]}, {"kind": "p", "text": "Escribe la tarea como una especificación clara y deja que un quest la lleve a cabo, dando restricciones concretas:"}, {"kind": "code", "lang": "bash", "code": "qodercli\n# in the prompt:\n> Implement this design from reference-desktop.png and\n  reference-mobile.png in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the references\n  across breakpoints."}, {"kind": "p", "text": "Mantén los prompts breves y enfocados, confirma las buenas iteraciones y revierte las malas (avisando a Qoder cuando reviertas), para que cada pasada parta de una base limpia."}]}, {"id": "extend", "heading": "Reglas, MCP y la wiki del repositorio", "blocks": [{"kind": "p", "text": "Tres puntos de extensión hacen que Qoder CLI sea práctico para un trabajo de diseño sostenido, y los tres encajan limpiamente en un flujo de diseño abierto."}, {"kind": "steps", "items": [{"label": "Reglas de proyecto", "body": "Codifica tus convenciones de diseño como reglas de proyecto duraderas que el agente lee en cada ejecución: el hogar de los tokens, primitivos y listas de revisión."}, {"label": "Servidores MCP", "body": "MCP es la forma portátil de incorporar contexto de diseño y herramientas externas —lo más relevante, el servidor MCP de Figma— y funciona en distintos agentes, no solo en Qoder."}, {"label": "La wiki del repositorio", "body": "La wiki del repositorio de Qoder destila la arquitectura y las convenciones automáticamente, así que el agente sigue reutilizando tus componentes reales en lugar de reaprender el código base en cada tarea."}]}, {"kind": "p", "text": "Son capacidades portátiles y multiagente: exactamente el tipo de cosa que Open Design está diseñado para orquestar, en lugar de recrearla en cada proyecto."}]}, {"id": "vs", "heading": "Qoder CLI frente a Codex, Claude Code, Cursor y Gemini CLI para diseño", "blocks": [{"kind": "p", "text": "No hay un único ganador para el trabajo de diseño: cada agente tiene una fortaleza distinta, y los equipos con experiencia los combinan. Un resumen honesto:"}, {"kind": "table", "columns": ["Agente", "Fortaleza de diseño", "Ideal para"], "rows": [["Qoder CLI", "Comprensión profunda del repositorio con una wiki del repositorio y quests autónomos guiados por especificaciones; niveles Lite/Efficient/Auto", "Trabajo con mucho contexto de repositorio y delegación de construcciones de varios pasos guiadas por especificaciones"], ["Codex", "Gran acabado visual con una skill de frontend; builds asíncronos en entorno aislado", "Builds asíncronos delegados y reglas portátiles en AGENTS.md"], ["Claude Code", "Decisiones de diseño concretas (hex, espaciado, tipografía) y UX consciente del código base", "Razonamiento de frontend y refactorizaciones de contexto amplio"], ["Cursor", "Bucle visual de construir y ver con vista previa en vivo y ediciones en línea", "Trabajo de interfaz iterativo y supervisado dentro de un IDE"], ["Gemini CLI", "Gran comprensión multimodal de imágenes y un contexto de 1M de tokens; plan gratuito", "Trabajo con muchas capturas de pantalla y mantener todo un sistema de diseño en contexto"]]}, {"kind": "p", "text": "El veredicto recurrente de la comunidad es que el criterio estético proviene de las personas: todos ellos tienden por defecto a una estética genérica sin skills, referencias ni restricciones. Ese es el verdadero problema a resolver, y tiene forma de herramienta de diseño, no de modelo."}]}, {"id": "pitfalls", "heading": "Errores comunes y cómo evitar el aspecto de «basura de IA»", "blocks": [{"kind": "p", "text": "La queja más común sobre el diseño generado por IA es que luce genérico: degradados suaves, paneles flotantes, esquinas redondeadas exageradas, sombras dramáticas, un aire de Inter y morado que «grita que esto lo hizo una IA». Otros problemas reportados incluyen maquetaciones móviles rotas e instrucciones que se filtran en el texto de la interfaz. Ninguno de estos es exclusivo de Qoder CLI; son lo que ocurre cuando cualquier agente se ejecuta sin un contexto de diseño curado."}, {"kind": "steps", "items": [{"label": "Añade una skill estética", "body": "Una skill de diseño curada obliga al agente a comprometerse con una dirección real en lugar del aspecto por defecto."}, {"label": "Verifica en un navegador real", "body": "Renderiza y autoverifica en los distintos breakpoints para que las maquetaciones no se rompan en silencio en el móvil."}, {"label": "Aporta tokens y referencias", "body": "Los tokens de diseño reales y las capturas de referencia son la mayor palanca sobre la calidad del resultado."}, {"label": "Codifica reglas que el agente lea", "body": "Coloca reglas del estilo «sin tarjetas hero, máximo dos tipografías, jerarquía con la marca primero» en las reglas de proyecto y la wiki del repositorio, donde el agente las lea en cada ejecución."}]}, {"kind": "p", "text": "Fíjate en que toda mitigación consiste en dar al agente un contexto de diseño curado. Mantener ese contexto a mano, proyecto a proyecto, es el trabajo tedioso que Open Design elimina."}]}, {"id": "open-design", "heading": "Diseñar con Qoder CLI dentro de Open Design", "blocks": [{"kind": "p", "text": "Open Design es la capa de diseño de código abierto que el flujo de trabajo anterior reclama una y otra vez. Trata a Qoder CLI como un adaptador de primera clase y lo envuelve en una biblioteca curada de skills y sistemas de diseño, una canalización de renderizado estructurada y una interfaz de escritorio local, para que el contexto de diseño que hace bueno a Qoder esté presente desde la primera ejecución, no ensamblado a mano cada vez. Open Design es local-first, así que tu trabajo permanece en tu propia máquina."}, {"kind": "ol", "items": ["Instala Open Design y selecciona Qoder CLI como tu agente.", "Autentícate con tu cuenta de Qoder: las credenciales permanecen en tu máquina y nunca se enrutan a través de nosotros.", "Elige un sistema de diseño y una skill, y luego genera presentaciones, prototipos y páginas de aterrizaje con un criterio estético consistente.", "Cada artefacto y archivo DESIGN.md vive en tu propio repositorio, no en una nube alojada."]}, {"kind": "p", "text": "El mismo agente Qoder CLI, la misma cuenta, más un flujo de diseño real, portátil y de código abierto a su alrededor. Es local-first y Apache-2.0, así que nada de tu trabajo ni de tus credenciales sale de tu máquina."}]}], "faqTitle": "Preguntas frecuentes", "faq": [{"name": "¿De verdad puede Qoder CLI hacer trabajo de diseño?", "text": "Sí: con una skill estética, un sistema de diseño e imágenes de referencia reales en contexto, Qoder CLI produce interfaces adaptables de calidad de producción, y su comprensión profunda del repositorio le ayuda a reutilizar tus componentes reales. Sin ese contexto tiende a caer en un aspecto genérico, que es la brecha que Open Design llena."}, {"name": "¿Cómo autentico Qoder CLI?", "text": "Ejecuta qodercli y usa /login para iniciar sesión con tu cuenta de Qoder mediante el navegador, o aporta un token de acceso personal de Qoder para entornos no interactivos. Open Design nunca enruta tus credenciales: el agente las usa directamente."}, {"name": "¿Qué hace que Qoder CLI sea bueno para el diseño en concreto?", "text": "Dos cosas: construye un contexto profundo sobre tu repositorio —su arquitectura, sus convenciones y una wiki del repositorio— así que reutiliza tus primitivos reales, y sus quests guiados por especificaciones ejecutan una tarea de diseño de principio a fin. Ambas ayudan, pero el criterio estético sigue viniendo del sistema de diseño, la skill y las referencias que tú aportes."}, {"name": "¿Qué son los niveles de modelo Lite, Efficient y Auto?", "text": "Qoder CLI te permite elegir un nivel de modelo: Lite, Efficient o Auto. Auto deja que el planificador de Qoder elija un modelo por tarea, así que no gestionas la selección de modelo a mano. Elige el nivel que encaje con el trabajo; Auto es un valor por defecto sensato."}, {"name": "¿Cómo conecto Qoder CLI a Figma?", "text": "Añade el servidor MCP de Figma a la configuración de MCP de Qoder. Qoder puede entonces extraer contexto de diseño real —componentes, variables, datos de maquetación— para que el código generado coincida con la fuente en lugar de aproximarla."}, {"name": "¿Está Open Design afiliado a Qoder o Alibaba?", "text": "No. Qoder es un producto de Alibaba; Open Design es un proyecto de código abierto independiente que lo admite como adaptador de primera clase. Qoder es una marca registrada de su respectivo propietario."}, {"name": "¿Están seguros mis archivos y credenciales?", "text": "Sí: Open Design es local-first y Apache-2.0. Tus archivos, artefactos y DESIGN.md permanecen en tu propio repositorio, y tus credenciales de Qoder las usa directamente tu agente, sin pasar nunca por los servidores de Open Design."}], "ctaTitle": "Diseña con Qoder CLI, a la manera abierta.", "ctaBody": "Trae tu propia cuenta de Qoder, mantén cada archivo en local y obtén una biblioteca de diseño curada en torno al agente que ya usas.", "ctaActions": [{"label": "Usa Qoder CLI dentro de Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dale una estrella en GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Descarga la app de escritorio", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Ver todos los agentes compatibles"},
      },
    },
  };
}
